deps = {}
_ACTIVE_DB_HELPERS = ContextVar("registry_active_db_helpers", default=None)
ROOT_DIR = Path(__file__).resolve().parents[1]
MATERIAL_UPLOAD_DIR = ROOT_DIR / "static" / "uploads" / "materials"
DOCUMENT_UPLOAD_DIR = ROOT_DIR / "static" / "uploads" / "documents"
ALLOWED_ATTACHMENT_EXTENSIONS = {
    ".bmp",
    ".csv",
    ".doc",
    ".docx",
    ".jpeg",
    ".jpg",
    ".pdf",
    ".png",
    ".txt",
    ".xls",
    ".xlsx",
    ".zip",
}
PILOT_NAV_MODES = {"gt_pilot", "pilot_gtym", "gtym_pilot"}


def _validate_attachment_upload(file_storage):
    original_name = file_storage.filename or ""
    safe_name = secure_filename(original_name)
    suffix = Path(safe_name).suffix.lower()
    if not safe_name or suffix not in ALLOWED_ATTACHMENT_EXTENSIONS:
        return None, original_name
    return safe_name, original_name


def _is_pilot_mode():
    return os.environ.get("INVENTORY_NAV_MODE", "").strip().lower() in PILOT_NAV_MODES


def _system_option_enabled(key, default="0"):
    try:
        columns = {row.get("column_name") for row in _table_columns("system_options")}
        if {"option_key", "option_value"}.issubset(columns):
            row = _safe_one(
                "SELECT option_value FROM system_options WHERE option_key=%s LIMIT 1",
                (key,),
            )
            value = (row or {}).get("option_value")
        elif {"key", "value"}.issubset(columns):
            row = _safe_one(
                "SELECT value FROM system_options WHERE key=%s LIMIT 1",
                (key,),
            )
            value = (row or {}).get("value")
        else:
            value = default
    except Exception:
        value = default
    value = str(value if value is not None else default).strip().lower()
    return value in {"1", "true", "yes", "on", "enabled", "allow", "允许", "启用"}


def _project_serial_required():
    try:
        columns = {row.get("column_name") for row in _table_columns("system_options")}
        if {"option_key", "option_value"}.issubset(columns):
            row = _safe_one(
                "SELECT option_value FROM system_options WHERE option_key=%s LIMIT 1",
                ("require_project_serial",),
            )
            value = (row or {}).get("option_value")
        elif {"key", "value"}.issubset(columns):
            row = _safe_one(
                "SELECT value FROM system_options WHERE key=%s LIMIT 1",
                ("require_project_serial",),
            )
            value = (row or {}).get("value")
        else:
            value = ""
    except Exception as exc:
        try:
            deps.get("log_action", lambda *args, **kwargs: None)(
                "系统参数读取异常",
                "require_project_serial",
                str(exc)[:500],
            )
        except Exception:
            current_app.logger.warning("Failed to read system config", exc_info=True)
        return False
    value = str(value or "").strip().lower()
    return value in {"1", "true", "yes", "on", "启用", "强制"}


def _require_project_serial_or_redirect(back_url):
    if not _project_serial_required():
        return None
    missing = []
    if not _form_text("project_code"):
        missing.append("项目号")
    if not _form_text("serial_no"):
        missing.append("机号")
    if missing:
        flash(f"系统已启用强制项目号/机号，请填写：{', '.join(missing)}。", "warning")
        return redirect(back_url)
    return None


def _require_project_serial_json(project_code, serial_no):
    if _project_serial_required():
        missing = []
        if not (project_code or "").strip():
            missing.append("项目号")
        if not (serial_no or "").strip():
            missing.append("机号")
        if missing:
            return jsonify({"status": "error", "msg": f"系统已启用强制项目号/机号，请填写：{', '.join(missing)}。"}), 400
    return None


def _require_project_serial_values_or_redirect(project_code, serial_no, back_url):
    if _project_serial_required():
        missing = []
        if not (project_code or "").strip():
            missing.append("项目号")
