def _validate_sales_order_master_project_serial(back_url):
    project_code = _form_text("project_code")
    serial_no = _form_text("serial_no")
    if project_code:
        project = _safe_one(
            """
            SELECT id, project_code
            FROM project_masters
            WHERE project_code=%s
              AND COALESCE(status, '') NOT IN ('停用','disabled','inactive')
            LIMIT 1
            """,
            (project_code,),
        )
        if not project:
            flash("销售订单项目号必须从基础资料的项目档案选取。", "warning")
            return None, None, redirect(back_url)
    else:
        project = None
    if serial_no:
        machine = _safe_one(
            """
            SELECT id, serial_no, project_id, project_code
            FROM machine_serial_masters
            WHERE serial_no=%s
              AND COALESCE(status, '') NOT IN ('停用','disabled','inactive')
            LIMIT 1
            """,
            (serial_no,),
        )
        if not machine:
            flash("销售订单机号必须从基础资料的机号档案选取。", "warning")
            return None, None, redirect(back_url)
        machine_project_code = (machine.get("project_code") or "").strip()
        if project_code and machine_project_code and machine_project_code != project_code:
            flash("销售订单机号所属项目与已选项目号不一致。", "warning")
            return None, None, redirect(back_url)
        if project_code and machine.get("project_id") and project and machine.get("project_id") != project.get("id"):
            flash("销售订单机号所属项目与已选项目号不一致。", "warning")
            return None, None, redirect(back_url)
    return project_code, serial_no, None


def _submitted_row_version(record):
    submitted = _form_int("row_version")
    if submitted is None:
        return record.get("row_version") or 1
    return submitted


def bind_route_dependencies(values):
    deps.clear()
    deps.update(values)
    clear_column_cache()


def _query_db(sql, params=None, one=False):
    helpers = _ACTIVE_DB_HELPERS.get()
    if helpers:
        query_db, _execute_db_fn, _execute_and_return_fn = helpers
        return query_db(sql, params or (), one=one)
    return deps["query_db"](sql, params or (), one=one)


def _is_schema_statement(sql):
    text = re.sub(r"\s+", " ", str(sql or "").strip()).upper()
    return text.startswith(("CREATE ", "ALTER ", "DROP ", "DO "))


def _execute_db(sql, params=None):
    if _is_schema_statement(sql):
        return None
    helpers = _ACTIVE_DB_HELPERS.get()
    if helpers:
        _query_db_fn, execute_db_fn, _execute_and_return_fn = helpers
        return execute_db_fn(sql, params or ())
    return deps["execute_db"](sql, params or ())


def _execute_and_return(sql, params=None):
    helpers = _ACTIVE_DB_HELPERS.get()
    if helpers:
        _query_db_fn, _execute_db_fn, execute_and_return_fn = helpers
        return execute_and_return_fn(sql, params or ())
    return deps["execute_and_return"](sql, params or ())


def _registry_transaction_callables(cursor):
    if cursor is None:
        return _safe_one, _safe_rows, _execute_db, _execute_and_return
    query_db, execute_db, execute_and_return = cursor_db_helpers(cursor)
    query_one = lambda sql, params=None: query_db(sql, params, one=True)
    query_rows = lambda sql, params=None: query_db(sql, params)
    return query_one, query_rows, execute_db, execute_and_return


def _run_registry_transaction(operation):
    try:
        runner = current_app.extensions.get("run_in_transaction")
    except RuntimeError:
        runner = None
    if runner:
        def wrapped(cursor):
            token = _ACTIVE_DB_HELPERS.set(cursor_db_helpers(cursor))
            try:
                return operation(cursor)
            finally:
                _ACTIVE_DB_HELPERS.reset(token)

        return runner(wrapped)
    return operation(None)


def _login_required(func):
    return deps["login_required"](func)


def _role_required(*roles):
    return deps["role_required"](*roles)


def _log_action(action, target="", remark=""):
    log_action = deps.get("log_action")
    if log_action:
        log_action(action, target, remark)


def _current_user_id():
    return session.get("user_id")


def _current_role():
    return session.get("role", "staff")


def _current_data_scope(permission="view"):
    return get_data_scope(_safe_rows, user_id=_current_user_id(), role=_current_role(), permission=permission)


def _data_scope_filter(field_map, *, params=(), permission="view"):
    return build_scope_filter(_current_data_scope(permission), field_map, params=params)


def _record_data_access(resource_type, resource_id, action, allowed, reason=""):
    try:
        log_data_access(
            _execute_db,
            user_id=_current_user_id(),
            role=_current_role(),
            resource_type=resource_type,
            resource_id=resource_id,
            action=action,
            allowed=allowed,
            reason=reason,
        )
    except Exception:
        current_app.logger.exception("Failed to record data access for %s %s", resource_type, resource_id)


def _export_scope_filter(table, rows):
    """Filter exported rows by the current user's data scope.

    Only sensitive business document tables are filtered; master data and
    reference tables are returned unchanged. Uses the SENSITIVE_EXPORTS
    field map declared in routes.export_route_registration.
    """
    try:
        from routes.export_route_registration import SENSITIVE_EXPORTS
    except Exception:
        return rows
    field_map = SENSITIVE_EXPORTS.get(table)
    if not field_map:
        return rows
    scope = _current_data_scope("view")
    if not scope_has_rules(scope):
        return rows
    return [row for row in rows if row_allowed(scope, row, field_map)]


def _work_order_scope_allowed(order, *, action="view", log=True):
    scope = _current_data_scope("view")
    if not scope_has_rules(scope):
        return True
    allowed = row_allowed(scope, order or {}, {"project": "project_code", "serial": "serial_no"})
    if log:
        _record_data_access(
            "work_order",
            (order or {}).get("id"),
            action,
            allowed,
            "scope_match" if allowed else "scope_denied",
        )
    return allowed


def _require_work_order_scope(work_order_id, *, action="view"):
    order = _safe_one(
        "SELECT id, wo_no, project_code, serial_no FROM work_orders WHERE id=%s",
        (work_order_id,),
    )
    if not order:
        return None
    if _work_order_scope_allowed(order, action=action):
        return order
    abort(403)


def qident(name):
    text = str(name or "")
    if not text.replace("_", "").isalnum():
        raise ValueError(f"invalid SQL identifier: {name!r}")
    return '"' + text.replace('"', '""') + '"'


_seq_initialized: set = set()
_code_rules_ready = False


def _ensure_code_rule_tables():
    global _code_rules_ready
    if _code_rules_ready:
        return
    _execute_db(
        """
        CREATE TABLE IF NOT EXISTS erp_code_rules (
            rule_key VARCHAR(120) PRIMARY KEY,
            target_type VARCHAR(40) NOT NULL,
            prefix VARCHAR(40) NOT NULL,
            date_format VARCHAR(20) NOT NULL DEFAULT 'YYYYMMDD',
            sequence_length INTEGER NOT NULL DEFAULT 4,
            separator VARCHAR(8) NOT NULL DEFAULT '',
            reset_scope VARCHAR(20) NOT NULL DEFAULT 'daily',
            manual_allowed BOOLEAN NOT NULL DEFAULT TRUE,
            is_active BOOLEAN NOT NULL DEFAULT TRUE,
            remark TEXT,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
        """
    )
    _execute_db(
        """
        INSERT INTO erp_code_rules
            (rule_key, target_type, prefix, date_format, sequence_length, separator, reset_scope, manual_allowed, is_active, remark)
        VALUES
            ('material:products.code', 'material', 'MAT', 'NONE', 4, '', 'continuous', TRUE, TRUE, 'Default category-based material code rule')
        ON CONFLICT (rule_key) DO NOTHING
        """
    )
    _code_rules_ready = True


def _load_code_rule(*rule_keys):
    try:
        _ensure_code_rule_tables()
        for rule_key in rule_keys:
            if not rule_key:
                continue
            row = _safe_one(
                """
                SELECT *
                FROM erp_code_rules
                WHERE rule_key=%s AND is_active=TRUE
                LIMIT 1
                """,
                (rule_key,),
            )
            if row:
                return row
    except Exception:
        return None
    return None


def _code_rule_date_part(date_format):
    fmt = (date_format or "").strip().upper()
    if fmt in {"", "NONE", "NO_DATE"}:
        return ""
    if fmt == "YYYYMM":
        return f"{datetime.now():%Y%m}"
    if fmt == "YYMMDD":
        return f"{datetime.now():%y%m%d}"
    return f"{datetime.now():%Y%m%d}"


def _code_rule_base(rule):
    prefix = str(rule.get("prefix") or "")
    separator = str(rule.get("separator") or "")
    date_part = _code_rule_date_part(rule.get("date_format"))
    if separator:
        parts = [part for part in (prefix, date_part) if part]
        return separator.join(parts) + separator
    return f"{prefix}{date_part}"


def _next_code_by_rule(rule, table, field):
    base = _code_rule_base(rule)
    sequence_length = int(rule.get("sequence_length") or 4)
    if (rule.get("reset_scope") or "daily").strip().lower() in {"daily", "monthly"}:
        row = _safe_one(
            f"SELECT {qident(field)} AS code FROM {qident(table)} WHERE {qident(field)} LIKE %s ORDER BY {qident(field)} DESC LIMIT 1",
            (f"{base}%",),
        )
        if row and row.get("code"):
            suffix = str(row["code"]).replace(base, "", 1)
            try:
                return f"{base}{int(suffix or '0') + 1:0{sequence_length}d}"
            except ValueError:
                pass
        return f"{base}{1:0{sequence_length}d}"
    scope = str(rule.get("rule_key") or f"{table}.{field}")
    row = _execute_and_return(
        """
        INSERT INTO document_sequences (prefix, scope, last_value, updated_at)
        VALUES (%s, %s, 1, NOW())
        ON CONFLICT (prefix, scope) DO UPDATE
        SET last_value=document_sequences.last_value + 1,
            updated_at=NOW()
        RETURNING last_value
        """,
        (base, scope),
    )
    n = int(row["last_value"]) if row else 1
    return f"{base}{n:0{sequence_length}d}"


def _next_doc_no(prefix, table, field="order_no"):
    rule = _load_code_rule(f"document:{table}.{field}", f"document:{prefix}", "document:default")
    if rule:
        return _next_code_by_rule(rule, table, field)
    next_doc_no = deps.get("next_doc_no")
    if next_doc_no:
        return next_doc_no(prefix, table, field)
    try:
        from datetime import datetime as _dt
        base = f"{prefix}{_dt.now():%Y%m%d}"
        scope = f"registry:{table}.{field}"
        row = _execute_and_return(
            """
            INSERT INTO document_sequences (prefix, scope, last_value, updated_at)
            VALUES (%s, %s, 1, NOW())
            ON CONFLICT (prefix, scope) DO UPDATE
            SET last_value=document_sequences.last_value + 1,
                updated_at=NOW()
            RETURNING last_value
            """,
            (base, scope),
        )
        n = int(row["last_value"]) if row else 1
    except Exception:
        from datetime import datetime as _dt
        return f"{prefix}{_dt.now():%Y%m%d%H%M%S}"
    return f"{base}{n:06d}"


def _next_daily_doc_no(prefix, table, field):
    rule = _load_code_rule(f"document:{table}.{field}", f"document:{prefix}", "document:default")
    if rule:
        return _next_code_by_rule(rule, table, field)
    daily_prefix = f"{prefix}{datetime.now():%Y%m%d}"
    next_doc_no = deps.get("next_doc_no")
    if next_doc_no:
        return next_doc_no(daily_prefix, table, field)
    row = _safe_one(
        f"SELECT {qident(field)} AS doc_no FROM {qident(table)} WHERE {qident(field)} LIKE %s ORDER BY {qident(field)} DESC LIMIT 1",
        (f"{daily_prefix}%",),
    )
    if not row or not row.get("doc_no"):
        return f"{daily_prefix}001"
    suffix = str(row["doc_no"]).replace(daily_prefix, "", 1)
    try:
        return f"{daily_prefix}{int(suffix or '0') + 1:03d}"
    except ValueError:
        return f"{daily_prefix}{datetime.now():%H%M%S}"


PURCHASE_RECEIVE_READY_STATUSES = {"已审核", "已审批", "待收货", "部分收货", "approved", "partial"}

PRODUCTION_STAGES = ("创建", "投产", "加工", "装配", "调试", "入库")


def _production_stage_index(stage):
    try:
        return PRODUCTION_STAGES.index((stage or "").strip())
    except ValueError:
        return -1


def _production_stage_from_order(order):
    stage = (order.get("production_stage") or "").strip()
    status = (order.get("status") or "").strip()
    status_map = {
        "创建": "创建",
        "新建": "创建",
        "投产": "投产",
        "加工": "加工",
        "生产中": "加工",
        "装配": "装配",
        "调试": "调试",
        "部分完工": "调试",
        "入库": "入库",
        "已完工": "入库",
        "已完成": "入库",
        "completed": "入库",
        "closed": "入库",
    }
    status_stage = status_map.get(status)
    if stage in PRODUCTION_STAGES and not status_stage:
        return stage
    if stage in PRODUCTION_STAGES and status_stage:
        return PRODUCTION_STAGES[max(_production_stage_index(stage), _production_stage_index(status_stage))]
    return status_stage or "创建"


def _set_work_order_stage(work_order_id, next_stage, remark="", query_one=None, execute_db_fn=None):
    query_one = query_one or _safe_one
    execute_db_fn = execute_db_fn or _execute_db
    if next_stage not in PRODUCTION_STAGES:
        return False, "生产阶段不在允许范围内。"
    order = query_one("SELECT id, wo_no, status, production_stage FROM work_orders WHERE id=%s", (work_order_id,))
    if not order:
        return False, "工单不存在。"
    current_stage = _production_stage_from_order(order)
    current_index = _production_stage_index(current_stage)
    next_index = _production_stage_index(next_stage)
    if current_index >= 0 and next_index > current_index + 1:
        return False, f"工单必须按顺序流转，当前为{current_stage}，下一步只能到{PRODUCTION_STAGES[current_index + 1]}。"
    if current_stage == next_stage and (order.get("status") or "") == next_stage:
        return True, "状态未变化。"
    user_id = session.get("user_id")
    execute_db_fn(
        """
        INSERT INTO work_order_status_logs
            (work_order_id, from_status, to_status, from_stage, to_stage, changed_by, remark)
        VALUES (%s,%s,%s,%s,%s,%s,%s)
        """,
        (work_order_id, order.get("status"), next_stage, current_stage, next_stage, user_id, remark),
    )
    execute_db_fn(
        """
        UPDATE work_orders
        SET status=%s,
            production_stage=%s,
            status_changed_at=NOW(),
            status_changed_by=%s,
            actual_start_date=CASE WHEN %s IN ('投产','加工','装配','调试','入库')
                                   THEN COALESCE(actual_start_date, CURRENT_DATE)
                                   ELSE actual_start_date END,
            actual_end_date=CASE WHEN %s='入库'
                                 THEN COALESCE(actual_end_date, CURRENT_DATE)
                                 ELSE actual_end_date END
        WHERE id=%s
        """,
        (next_stage, next_stage, user_id, next_stage, next_stage, work_order_id),
    )
    _log_action("生产工单状态流转", order.get("wo_no"), f"{current_stage}->{next_stage} {remark}".strip())
    _p0_on_work_order_stage_change(work_order_id, next_stage, order, query_one, execute_db_fn)
    return True, "状态已更新。"


def _p0_on_work_order_stage_change(work_order_id, next_stage, order, query_one, execute_db_fn):
    """P0 引擎集成：工单阶段流转时自动触发快照创建和 MRP 运行。"""
    if next_stage != "投产":
        return
    try:
        _p0_create_bom_snapshot(query_one, execute_db_fn, work_order_id)
    except Exception:
        current_app.logger.exception("P0 BOM snapshot failed for work_order_id=%s", work_order_id)
    try:
        _p0_create_process_snapshot(query_one, execute_db_fn, work_order_id)
    except Exception:
        current_app.logger.exception("P0 process snapshot failed for work_order_id=%s", work_order_id)
    try:
        _p0_create_drawing_snapshot(query_one, execute_db_fn, work_order_id)
    except Exception:
        current_app.logger.exception("P0 drawing snapshot failed for work_order_id=%s", work_order_id)
    try:
        wo = query_one(
            "SELECT id, wo_no, product_id, bom_id, quantity, project_code, serial_no FROM work_orders WHERE id=%s",
            (work_order_id,),
        )
        if wo and wo.get("bom_id"):
            _p0_run_mrp(
                query_one,
                _safe_rows,
                execute_db_fn,
                _execute_and_return,
                source_type="work_order",
                source_id=work_order_id,
                source_no=wo.get("wo_no"),
                project_code=wo.get("project_code") or "",
                serial_no=wo.get("serial_no") or "",
                bom_id=wo.get("bom_id"),
                quantity=wo.get("quantity") or 1,
                created_by=session.get("user_id"),
            )
    except Exception:
        current_app.logger.exception("P0 MRP run failed for work_order_id=%s", work_order_id)


def _change_work_order_status(work_order_id):
    _require_work_order_scope(work_order_id, action="operate")
    next_stage = _form_text("next_stage")
    remark = _form_text("remark")
    ok, message = _set_work_order_stage(work_order_id, next_stage, remark)
    flash(message, "success" if ok else "warning")
    return redirect(f"/work-orders/{work_order_id}")


def _handle_safe_query_exception(kind, sql, params, exc):
    sql_summary = " ".join(str(sql or "").split())[:500]
    # 脱敏：只记录参数类型和长度，不记录原始值
    safe_params = tuple(
        f"<{type(p).__name__} len={len(str(p))}>" if p is not None else "NULL"
        for p in (params or ())
    )
    message = f"{datetime.now():%Y-%m-%d %H:%M:%S} | {kind} | {type(exc).__name__}: {exc} | sql={sql_summary} | params={safe_params}"
    testing = False
    try:
        current_app.logger.exception("safe query failed: %s", message)
        testing = bool(current_app.testing)
        # 标记请求有查询错误，供 after_request 感知
        try:
            from flask import g
            g._safe_query_error = True
        except RuntimeError:
            pass
        log_dir = ROOT_DIR / "logs"
        log_dir.mkdir(exist_ok=True)
        with (log_dir / "registry_query_errors.log").open("a", encoding="utf-8") as fh:
            fh.write(message + "\n")
            fh.write(traceback.format_exc(limit=8))
            fh.write("\n")
    except RuntimeError:
        log_dir = ROOT_DIR / "logs"
        log_dir.mkdir(exist_ok=True)
        with (log_dir / "registry_query_errors.log").open("a", encoding="utf-8") as fh:
            fh.write(message + "\n")
    if testing:
        raise exc


def _rollback_read_connections():
    try:
        from flask import g
    except RuntimeError:
        return
    for cache_key in ("_db_conn_real_dict", "_db_conn_plain"):
        try:
            conn = getattr(g, cache_key, None)
            if conn is not None and not conn.closed:
                conn.rollback()
        except Exception:
            continue


def _safe_rows(sql, params=None):
    try:
        return _query_db(sql, params or ())
    except Exception as exc:
        _rollback_read_connections()
        _handle_safe_query_exception("rows", sql, params or (), exc)
        return []


def _safe_one(sql, params=None):
    try:
        return _query_db(sql, params or (), one=True)
    except Exception as exc:
        _rollback_read_connections()
        _handle_safe_query_exception("one", sql, params or (), exc)
        return None


def _system_option_value(key, default=""):
    row = _safe_one(
        """
        SELECT COALESCE(option_value, value) AS option_value
        FROM system_options
        WHERE option_key=%s OR key=%s
        ORDER BY updated_at DESC NULLS LAST, id DESC
        LIMIT 1
        """,
        (key, key),
    )
    return str((row or {}).get("option_value") or default).strip()


def _opening_data_locked():
    return _system_option_value("opening_data_locked", "0").lower() in {"1", "true", "yes", "on", "启用", "锁定"}


def _block_opening_entry_if_locked(back_url):
    if not _opening_data_locked():
        return None
    lock_date = _system_option_value("opening_lock_date")
    detail = f"锁定日期：{lock_date}。" if lock_date else ""
    flash(f"期初数据已锁定，不能继续新增期初单据。{detail}如需调整，请先由系统管理员在“开账时间/启用期间”中解除锁定。", "warning")
    return redirect(back_url)


