def _delete_basic_record(kind, record_id):
    config = _BASIC_DELETE_CONFIG.get(kind)
    if not config:
        return redirect("/master-data")
    record = _safe_one(f"SELECT * FROM {config['table']} WHERE id=%s", (record_id,))
    if not record:
        flash(f"{config['label']}不存在或已删除。", "warning")
        return redirect(config["list_url"])

    blockers = basic_delete_blockers(
        kind,
        record,
        has_table=_has_table,
        has_column=_has_column,
        count_rows=_count_rows,
    )
    if blockers:
        flash(f"{config['label']}已被业务单据引用，不能删除：{'、'.join(blockers)}。", "warning")
        return redirect(f"{config['detail_url']}/{record_id}")

    _execute_db(f"DELETE FROM {config['table']} WHERE id=%s", (record_id,))
    name = record.get("name") or record.get("code") or str(record_id)
    _log_action(f"删除{config['label']}", name, f"id={record_id}")
    flash(f"{config['label']}已删除。", "success")
    return redirect(config["list_url"])

