def _inventory_doc_next_step(status, posted_text):
    value = (status or "").strip()
    if value in INVENTORY_PENDING_STATUSES or not value:
        return "确认过账"
    if value in {INVENTORY_STATUS_POSTED, "posted", "completed", "已完成"}:
        return posted_text
    return "处理单据状态"


def _render_inventory_movement_list(direction):
    """Render other inbound/outbound document list grouped by doc_no.

    Data source: inventory_movement_documents header + inventory_movement_lines.
    Draft rows (not yet audited) appear here so operators can find them and
    click through to the detail page to audit.
    """
    movement_kind = "other_inbound" if direction == "in" else "other_outbound"
    tx_type = "其他入库" if direction == "in" else "其他出库"
    title = "其他入库单列表" if direction == "in" else "其他出库单列表"
    subtitle = (
        "单据信息：其他入库单据列表，按单据号、来源单据、物料明细、批号、项目号和机号汇总数量和成本金额；新增入库单从库存单据入口进入，保存后请在详情页审核完成过账。"
        if direction == "in"
        else "单据信息：其他出库单据列表，按单据号、来源单据、物料明细、批号、项目号和机号汇总数量和成本金额；新增出库单从库存单据入口进入，保存后请在详情页审核完成过账。"
    )
    doc_no_label = "入库单" if direction == "in" else "出库单"
    add_url = "/inventory/inbound/new" if direction == "in" else "/inventory/outbound/new"
    status_label_map = {"draft": "草稿", "posted": "已过账", "void": "已作废"}
    rows = _safe_rows(
        """
        SELECT d.id, d.doc_no AS reference_no,
               d.transaction_type, d.tx_date, d.warehouse_id,
               d.project_code, d.status, d.remark,
               COALESCE(line_agg.line_count, 0) AS line_count,
               COALESCE(line_agg.quantity, 0) AS quantity,
               line_agg.unit_cost AS unit_cost,
               COALESCE(line_agg.cost_amount, 0) AS cost_amount,
               line_agg.lot_no AS lot_no,
               line_agg.source_doc_no AS source_doc_no,
               line_agg.serial_no AS serial_no
        FROM inventory_movement_documents d
        LEFT JOIN LATERAL (
            SELECT COUNT(*) AS line_count,
                   SUM(COALESCE(quantity, 0)) AS quantity,
                   MAX(unit_cost) AS unit_cost,
                   SUM(COALESCE(amount, COALESCE(quantity, 0) * COALESCE(unit_cost, 0))) AS cost_amount,
                   MAX(lot_no) AS lot_no,
                   MAX(source_doc_no) AS source_doc_no,
                   MAX(serial_no) AS serial_no
            FROM inventory_movement_lines
            WHERE doc_id = d.id
        ) line_agg ON true
        WHERE d.movement_kind = %s
        ORDER BY d.tx_date DESC NULLS LAST, d.id DESC
        LIMIT 300
        """,
        (movement_kind,),
    )
    data = []
    detail_base = "/inventory/inbound" if direction == "in" else "/inventory/outbound"
    for row in rows:
        item = dict(row)
        item["detail_url"] = f"{detail_base}/{item.get('reference_no')}"
        item["status"] = status_label_map.get((item.get("status") or "").strip(), item.get("status") or "草稿")
        item["next_step"] = "审核并过账" if item.get("status") == "草稿" else "查看流水明细"
        data.append(item)
    return render_template(
        "simple_list.html",
        title=title,
        subtitle=subtitle,
        rows=data,
        columns=_columns(
            ("reference_no", doc_no_label),
            ("tx_date", "日期"),
            ("source_doc_no", "来源单据"),
            ("line_count", "物料明细"),
            ("quantity", "数量"),
            ("unit_cost", "库存成本单价"),
            ("cost_amount", "成本金额"),
            ("lot_no", "批号"),
            ("project_code", "项目号"),
            ("serial_no", "机号"),
            ("status", "状态"),
            ("next_step", "下一步"),
        ),
        detail_base=detail_base,
        add_url=add_url,
        status_options=[
            ("草稿", "草稿"),
            ("已过账", "已过账"),
            ("已作废", "已作废"),
        ],
    )


def _render_inventory_movement_detail(doc_no, direction):
    """Render other inbound/outbound document detail page.

    Reads from the inventory_movement_documents header + inventory_movement_lines
    so draft (not-yet-audited) documents can be inspected. For legacy rows that
    predate the header table (or sales_return/purchase_return variants that still
    post directly), falls back to the stock_transactions-grouped view.
    """
    tx_type = "其他入库" if direction == "in" else "其他出库"
    title = "其他入库单详情" if direction == "in" else "其他出库单详情"
    back_url = "/inventory/inbound" if direction == "in" else "/inventory/outbound"
    # doc_no may be a numeric id (from simple_list detail_base) or a reference_no string
    if doc_no.isdigit():
        ref_row = _safe_one(
            "SELECT reference_no FROM stock_transactions WHERE id=%s AND transaction_type=%s",
            (int(doc_no), tx_type),
        )
        if not ref_row:
            flash("未找到该单据。", "warning")
            return redirect(back_url)
        doc_no = ref_row["reference_no"]
    header = _safe_one(
        """
        SELECT id, doc_no AS reference_no, transaction_type, tx_date, warehouse_id,
               location_id, project_code, remark, status, movement_kind,
               audited_at, audited_by, created_at
        FROM inventory_movement_documents
        WHERE doc_no=%s
        """,
        (doc_no,),
    )
    use_legacy_lines = False
    if not header:
        # Legacy fallback: header not in inventory_movement_documents (e.g. rows
        # inserted before the migration backfill ran, or sales_return variant
        # written directly to stock_transactions before the create function was
        # extended). Aggregate from stock_transactions for display only.
        use_legacy_lines = True
        header = _safe_one(
            """
            SELECT reference_no,
                   MAX(transaction_type) AS transaction_type,
                   MAX(transaction_date)::date AS tx_date,
                   MAX(warehouse_id) AS warehouse_id,
                   MAX(project_code) AS project_code,
                   MAX(serial_no) AS serial_no,
                   MAX(remark) AS remark,
                   'posted' AS status,
                   COUNT(*) AS line_count,
                   SUM(COALESCE(quantity, 0)) AS total_qty,
                   SUM(COALESCE(amount, COALESCE(quantity, 0) * COALESCE(unit_cost, 0))) AS total_amount
            FROM stock_transactions
            WHERE transaction_type = %s AND reference_no = %s
            GROUP BY reference_no
            """,
            (tx_type, doc_no),
        )
        if not header:
            flash("未找到该单据。", "warning")
            return redirect(back_url)
    else:
        # New header-table path: load lines from inventory_movement_lines and
        # compute totals so the template footer can render the same way.
        line_agg = _safe_one(
            """
            SELECT COUNT(*) AS line_count,
                   SUM(COALESCE(quantity, 0)) AS total_qty,
                   SUM(COALESCE(amount, COALESCE(quantity, 0) * COALESCE(unit_cost, 0))) AS total_amount
            FROM inventory_movement_lines
            WHERE doc_id=%s
            """,
            (header.get("id"),),
        )
        header["line_count"] = (line_agg or {}).get("line_count") or 0
        header["total_qty"] = (line_agg or {}).get("total_qty") or 0
        header["total_amount"] = (line_agg or {}).get("total_amount") or 0
        # serial_no was a line-level field in the legacy query; expose it at the
        # header level for the template's existing "机号" cell.
        header["serial_no"] = header.get("project_code") or ""
    wh = _safe_one("SELECT code, name FROM warehouses WHERE id=%s", (header.get("warehouse_id"),))
    if use_legacy_lines:
        lines = _safe_rows(
            """
            SELECT st.id, st.product_id, st.quantity, st.unit_cost, st.lot_no, st.serial_no,
                   st.project_code, st.location, st.remark,
                   p.code AS product_code, p.name AS product_name,
                   p.specification, p.unit AS product_unit,
                   COALESCE(st.amount, st.quantity * st.unit_cost) AS amount
            FROM stock_transactions st
            LEFT JOIN products p ON p.id = st.product_id
            WHERE st.transaction_type = %s AND st.reference_no = %s
            ORDER BY st.id
            """,
            (tx_type, doc_no),
        )
    else:
        lines = _safe_rows(
            """
            SELECT ml.id, ml.product_id, ml.quantity, ml.unit_cost, ml.lot_no,
                   ml.serial_no, ml.line_project_code AS project_code,
                   ml.line_warehouse_id, ml.line_location_id, ml.usage_reason AS remark,
                   p.code AS product_code, p.name AS product_name,
                   p.specification, p.unit AS product_unit,
                   COALESCE(ml.amount, ml.quantity * ml.unit_cost) AS amount
            FROM inventory_movement_lines ml
            LEFT JOIN products p ON p.id = ml.product_id
            WHERE ml.doc_id=%s
            ORDER BY ml.line_no
            """,
            (header.get("id"),),
        )
    # Status-aware action buttons. All inbound/outbound documents use
    # draft -> audit/post -> reverse-audit.
    status = (header.get("status") or "").strip()
    movement_kind = header.get("movement_kind") or ""
    supports_audit = movement_kind in ("other_inbound", "other_outbound", "sales_return", "purchase_return")
    can_audit = supports_audit and status in ("draft", "待过账", "草稿", "")
    can_unaudit = supports_audit and status == "posted"
    can_delete = supports_audit and status in ("draft", "待过账", "草稿", "")
    stock_audit_allowed, stock_audit_reason = _inventory_movement_can_audit(lines, header.get("direction"))
    if not stock_audit_allowed:
        can_audit = False
    audit_disabled_reason = "" if can_audit else (
        stock_audit_reason if stock_audit_reason else ("当前状态不能审核；只有草稿/待过账单据可以审核。" if supports_audit else "该单据类型不支持审核。")
    )
    unaudit_disabled_reason = "" if can_unaudit else (
        "当前状态不能反审；只有已过账单据可以反审。" if supports_audit else "该单据类型不支持反审。"
    )
    delete_disabled_reason = "" if can_delete else (
        "当前状态不能删除；已过账单据请先反审回草稿。" if supports_audit else "该单据类型不支持删除。"
    )
    status_label_map = {
        "draft": "草稿",
        "posted": "已过账",
        "void": "已作废",
    }
    status_label = status_label_map.get(status, status or "草稿")
    status_badge_class = {
        "draft": "bg-secondary",
        "posted": "bg-success",
        "void": "bg-danger",
    }.get(status, "bg-secondary")
    return render_template(
        "inventory_movement_detail.html",
        title=title,
        doc_no=doc_no,
        tx_type=tx_type,
        header=header,
        warehouse=wh or {},
        lines=lines,
        back_url=back_url,
        is_inbound=(direction == "in"),
        status=status,
        status_label=status_label,
        status_badge_class=status_badge_class,
        can_audit=can_audit,
        can_unaudit=can_unaudit,
        can_delete=can_delete,
        audit_disabled_reason=audit_disabled_reason,
        unaudit_disabled_reason=unaudit_disabled_reason,
        delete_disabled_reason=delete_disabled_reason,
        audit_url=f"{back_url}/{doc_no}/audit",
        unaudit_url=f"{back_url}/{doc_no}/unaudit",
        delete_url=f"{back_url}/{doc_no}/delete",
        copy_url=f"{back_url}/{doc_no}/copy",
    )


