def _module_report_config(kind):
    class _ScopedReportArgs:
        def __init__(self, base_args, scope_filter):
            self._base_args = base_args
            self._scope_filter = scope_filter

        def get(self, key, default=None):
            if key == "_data_scope_filter":
                return self._scope_filter
            return self._base_args.get(key, default)

        def items(self):
            return self._base_args.items()

    report_args = _ScopedReportArgs(request.args, _data_scope_filter)
    return build_module_report_config(
        kind,
        _safe_rows,
        _sum_value,
        _as_decimal,
        _money_metric,
        _qty_metric,
        _columns,
        report_args,
    )

def _render_module_report(kind):
    return render_module_report_adapter(
        kind,
        _module_report_config,
        _csv_response,
        render_template,
        request.args,
        request.path,
        not_found_title="\u62a5\u8868\u4e0d\u5b58\u5728",
    )

def _render_module_report_section(kind, section_path):
    class _SectionReportArgs:
        def __init__(self, base_args, path, scope_filter):
            self._base_args = base_args
            self._path = path
            self._scope_filter = scope_filter

        def get(self, key, default=None):
            if key == "_section_path":
                return self._path
            if key == "_data_scope_filter":
                return self._scope_filter
            return self._base_args.get(key, default)

        def items(self):
            return self._base_args.items()

    report_args = _SectionReportArgs(request.args, section_path, _data_scope_filter)
    return render_module_report_adapter(
        kind,
        lambda report_kind: build_module_report_config(
            report_kind,
            _safe_rows,
            _sum_value,
            _as_decimal,
            _money_metric,
            _qty_metric,
            _columns,
            report_args,
        ),
        _csv_response,
        render_template,
        report_args,
        request.path,
        not_found_title="\u62a5\u8868\u4e0d\u5b58\u5728",
    )

