def _page_number(default=1):
    try:
        value = int(request.args.get("page") or default)
    except (TypeError, ValueError):
        value = default
    return max(value, 1)


def _per_page(default=50, minimum=20, maximum=200):
    try:
        value = int(request.args.get("per_page") or default)
    except (TypeError, ValueError):
        value = default
    return min(max(value, minimum), maximum)


class _Pagination:
    def __init__(self, page, per_page, total_count):
        self.total = int(total_count or 0)
        self.per_page = int(per_page or 50)
        self.pages = max((self.total + self.per_page - 1) // self.per_page, 1)
        self.page = min(max(int(page or 1), 1), self.pages)
        self.has_prev = self.page > 1
        self.has_next = self.page < self.pages
        self.prev_num = self.page - 1 if self.has_prev else 1
        self.next_num = self.page + 1 if self.has_next else self.pages
        self.total_pages = self.pages
        self.per_page_options = [20, 50, 100, 200]

    def iter_pages(self, left_edge=2, left_current=2, right_current=3, right_edge=2):
        last = 0
        for num in range(1, self.pages + 1):
            if (
                num <= left_edge
                or (self.page - left_current - 1 < num < self.page + right_current)
                or num > self.pages - right_edge
            ):
                if last + 1 != num:
                    yield None
                yield num
                last = num


def _paginate(page, per_page, total_count):
    return _Pagination(page, per_page, total_count)


def _render_chart_of_accounts():
    """渲染会计科目表列表页面"""
    search = (request.args.get("search") or "").strip()
    account_type = (request.args.get("account_type") or "").strip()
    status = (request.args.get("status") or "").strip()
    page = _page_number()
    per_page = _per_page(default=50)

    where = []
    params = []
    if search:
        where.append("(code ILIKE %s OR name ILIKE %s OR remark ILIKE %s)")
        params.extend([f"%{search}%", f"%{search}%", f"%{search}%"])
    if account_type:
        where.append("account_type = %s")
        params.append(account_type)
    if status:
        where.append("status = %s")
        params.append(status)

    where_clause = " AND ".join(where) if where else "TRUE"
    count = _safe_one(f"SELECT COUNT(*) as cnt FROM chart_of_accounts WHERE {where_clause}", params).get("cnt", 0)

    offset = (page - 1) * per_page
    accounts = _safe_rows(
        f"SELECT * FROM chart_of_accounts WHERE {where_clause} ORDER BY code ASC LIMIT %s OFFSET %s",
        params + [per_page, offset],
    )

    parent_accounts = _safe_rows(
        "SELECT id, code, name FROM chart_of_accounts WHERE status='active' AND is_leaf=FALSE ORDER BY code"
    )

    pagination = _paginate(page, per_page, count)
    return render_template(
        "chart_of_accounts.html",
        accounts=accounts,
        parent_accounts=parent_accounts,
        pagination=pagination,
        filters={"search": search, "account_type": account_type, "status": status},
    )



