def _render_production_routing_detail(routing_id, back_url="/production-routings"):
    routing = _safe_one(
        """
        SELECT pr.*, p.code AS product_code, p.name AS product_name, p.specification AS product_specification
        FROM production_routings pr
        LEFT JOIN products p ON p.id=pr.product_id
        WHERE pr.id=%s
        """,
        (routing_id,),
    )
    operations = _safe_rows(
        """
        SELECT ro.sequence, ro.operation_no, ro.operation_name, wc.name AS work_center,
               ro.process_note, ro.quality_note, ro.setup_time, ro.run_time
        FROM routing_operations ro
        LEFT JOIN work_centers wc ON wc.id=ro.work_center_id
        WHERE ro.routing_id=%s
        ORDER BY ro.sequence, ro.id
        """,
        (routing_id,),
    )
    operation_groups = [
        {
            "title": "前置准备",
            "hint": "技术确认、委外回厂、小件加工和总装前齐套准备。",
            "rows": [op for op in operations if (op.get("sequence") or 0) <= 40],
        },
        {
            "title": "机械装配",
            "hint": "床身、立柱、进给系统、主轴箱、磨削主轴和刀盘安装。",
            "rows": [op for op in operations if 50 <= (op.get("sequence") or 0) <= 100],
        },
        {
            "title": "液压电气与安全",
            "hint": "液压、润滑、冷却、电气接线、防护、限位和防撞装置。",
            "rows": [op for op in operations if 110 <= (op.get("sequence") or 0) <= 140],
        },
        {
            "title": "调试检验",
            "hint": "空载调试、几何精度、试切试磨和连续运行验证。",
            "rows": [op for op in operations if 150 <= (op.get("sequence") or 0) <= 180],
        },
        {
            "title": "终检交付",
            "hint": "终检、资料、附件、安全确认和交付条件关闭。",
            "rows": [op for op in operations if (op.get("sequence") or 0) >= 190],
        },
    ]
    return render_template(
        "production_routing_detail.html",
        routing=routing,
        operations=operations,
        operation_groups=operation_groups,
        back_url=back_url,
    )


def _render_production_routing_list():
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    status = (request.args.get("status") or "").strip()
    where_parts = [
        """
        (
            pr.routing_no='RT-LM-MG-STD'
            OR (
                (pr.routing_no LIKE 'RT2026%%' OR COALESCE(pr.name, '') NOT LIKE '%%-%%')
                AND COALESCE(pr.routing_no, '') NOT LIKE 'RT-%%-%%'
                AND COALESCE(p.code, '') NOT LIKE 'FG-%%-%%'
                AND COALESCE(p.code, '') NOT LIKE 'SF-%%-%%'
                AND COALESCE(p.name, '') NOT ILIKE '%%fg %%'
            )
        )
        """,
    ]
    params = []
    if keyword:
        where_parts.append(
            """
            (
                pr.routing_no ILIKE %s OR pr.name ILIKE %s OR COALESCE(p.code, '') ILIKE %s
                OR COALESCE(p.name, '') ILIKE %s OR COALESCE(p.specification, '') ILIKE %s
            )
            """
        )
        params.extend([f"%{keyword}%"] * 5)
    if status == "enabled":
        where_parts.append("COALESCE(pr.is_active, FALSE)=TRUE")
    elif status == "disabled":
        where_parts.append("COALESCE(pr.is_active, FALSE)=FALSE")
    where_sql = "WHERE " + " AND ".join(where_parts)
    rows = _safe_rows(
        f"""
        SELECT pr.id, pr.routing_no, pr.name, pr.revision, pr.is_active,
               p.code AS product_code, p.name AS product_name, p.specification AS product_specification,
               COUNT(ro.id) AS operation_count,
               MIN(ro.operation_name) FILTER (WHERE ro.sequence = 10) AS first_operation,
               MAX(ro.operation_name) FILTER (
                   WHERE ro.sequence = (
                       SELECT MAX(last_ro.sequence)
                       FROM routing_operations last_ro
                       WHERE last_ro.routing_id=pr.id
                   )
               ) AS last_operation
        FROM production_routings pr
        LEFT JOIN products p ON p.id=pr.product_id
        LEFT JOIN routing_operations ro ON ro.routing_id=pr.id
        {where_sql}
        GROUP BY pr.id, p.code, p.name, p.specification
        ORDER BY
            CASE WHEN pr.routing_no='RT-LM-MG-STD' THEN 0 ELSE 1 END,
            pr.id DESC
        LIMIT 100
        """,
        tuple(params),
    )
    display_rows = []
    for row in rows:
        item = dict(row)
        product_text = " ".join(
            part for part in [item.get("product_code"), item.get("product_name"), item.get("product_specification")] if part
        )
        item["product_display"] = product_text or "-"
        item["status_display"] = "启用" if item.get("is_active") else "停用"
        item["status_class"] = "success" if item.get("is_active") else "secondary"
        item["operation_summary"] = f"{item.get('operation_count') or 0} 道"
        if item.get("first_operation") or item.get("last_operation"):
            item["operation_summary"] = f"{item['operation_summary']}：{item.get('first_operation') or '-'} → {item.get('last_operation') or '-'}"
        item["next_action"] = "可被技术确认和工单引用" if item.get("is_active") else "停用路线仅保留历史查看"
        display_rows.append(item)
    return render_template(
        "production_routing_list.html",
        title="工艺路线",
        subtitle="技术主数据页：维护和查看产品标准工序、工作中心和质量控制点，不生成生产事务、不做报表分析。",
        rows=display_rows,
        filters={"keyword": keyword, "status": status},
    )


def _render_work_center_list():
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    status = (request.args.get("status") or "").strip()
    where_parts = ["TRUE"]
    params = []
    if keyword:
        where_parts.append(
            """
            (
                code ILIKE %s OR name ILIKE %s OR COALESCE(description, '') ILIKE %s
                OR COALESCE(location, '') ILIKE %s OR COALESCE(responsible_person, '') ILIKE %s
            )
            """
        )
        params.extend([f"%{keyword}%"] * 5)
    if status == "enabled":
        where_parts.append("COALESCE(is_active, FALSE)=TRUE")
    elif status == "disabled":
        where_parts.append("COALESCE(is_active, FALSE)=FALSE")
    rows = _safe_rows(
        f"""
        SELECT id, code, name, description, location, responsible_person, is_active
        FROM work_centers
        WHERE {" AND ".join(where_parts)}
        ORDER BY
            CASE WHEN COALESCE(location, '')='工程标准' THEN 0 ELSE 1 END,
            id DESC
        LIMIT 100
        """,
        tuple(params),
    )
    display_rows = []
    for row in rows:
        item = dict(row)
        item["status_display"] = "启用" if item.get("is_active") else "停用"
        item["status_class"] = "success" if item.get("is_active") else "secondary"
        item["owner_display"] = item.get("responsible_person") or "-"
        item["usage_boundary"] = "工程资源参考"
        item["next_action"] = "可被工艺路线引用" if item.get("is_active") else "停用中心仅保留历史引用"
        display_rows.append(item)
    return render_template(
        "work_center_list.html",
        title="工作中心",
        subtitle="技术主数据页：用于工艺路线归类、责任识别和工程标准引用，不做生产排程、不计算产能负荷。",
        rows=display_rows,
        filters={"keyword": keyword, "status": status},
    )


