def _ensure_production_routing_status_column_clean():
    if _has_table("production_routings") and not _has_column("production_routings", "status"):
        _execute_db("ALTER TABLE production_routings ADD COLUMN IF NOT EXISTS status VARCHAR(40)")
        _execute_db(
            "UPDATE production_routings SET status=CASE WHEN COALESCE(is_active, FALSE) THEN 'enabled' ELSE 'disabled' END WHERE status IS NULL"
        )
        clear_column_cache()
    if _has_table("production_routings") and not _has_column("production_routings", "remark"):
        _execute_db("ALTER TABLE production_routings ADD COLUMN IF NOT EXISTS remark TEXT")
        clear_column_cache()


def _production_routing_status_key_clean(row):
    text = str((row or {}).get("status") or "").strip().lower()
    if text in {"draft", "enabled", "disabled"}:
        return text
    if text == "草稿":
        return "draft"
    if text in {"启用", "active", "released"}:
        return "enabled"
    if text in {"停用", "inactive"}:
        return "disabled"
    return "enabled" if (row or {}).get("is_active") else "disabled"


def _production_routing_status_label_clean(status):
    return {"draft": "草稿", "enabled": "启用", "disabled": "停用"}.get(status, "停用")


def _production_routing_form_options_clean():
    products = _safe_rows(
        """
        SELECT id, code, name, specification, unit
        FROM products
        ORDER BY code NULLS LAST, name NULLS LAST, id DESC
        LIMIT 500
        """
    )
    work_centers = _safe_rows(
        """
        SELECT id, code, name
        FROM work_centers
        ORDER BY code NULLS LAST, name NULLS LAST, id DESC
        LIMIT 300
        """
    )
    return products, work_centers


def _production_routing_next_no_clean():
    prefix = f"RT{datetime.now():%Y%m%d}"
    row = _safe_one(
        "SELECT routing_no FROM production_routings WHERE routing_no LIKE %s ORDER BY routing_no DESC LIMIT 1",
        (f"{prefix}%",),
    )
    if not row or not row.get("routing_no"):
        return f"{prefix}001"
    suffix = str(row.get("routing_no") or "").replace(prefix, "", 1)
    try:
        return f"{prefix}{int(suffix or '0') + 1:03d}"
    except ValueError:
        return f"{prefix}{datetime.now():%H%M%S}"


def _routing_int_clean(value, default=0):
    try:
        return int(str(value or "").strip())
    except (TypeError, ValueError):
        return default


def _routing_decimal_clean(value):
    text = str(value or "").strip()
    if text == "":
        return None
    try:
        return Decimal(text)
    except Exception:
        return Decimal("0")


def _production_routing_blank_form_clean():
    return {
        "routing_no": _production_routing_next_no_clean(),
        "name": "",
        "product_id": "",
        "revision": "V1.0",
        "status": "draft",
        "remark": "",
        "operations": [
            {"sequence": 10, "operation_no": "OP10", "operation_name": "", "work_center_id": "", "process_note": "", "quality_note": "", "setup_time": "", "run_time": ""},
            {"sequence": 20, "operation_no": "OP20", "operation_name": "", "work_center_id": "", "process_note": "", "quality_note": "", "setup_time": "", "run_time": ""},
            {"sequence": 30, "operation_no": "OP30", "operation_name": "", "work_center_id": "", "process_note": "", "quality_note": "", "setup_time": "", "run_time": ""},
        ],
    }


def _production_routing_form_from_request_clean(existing_no=None):
    sequences = request.form.getlist("operation_sequence")
    operation_nos = request.form.getlist("operation_no")
    operation_names = request.form.getlist("operation_name")
    work_center_ids = request.form.getlist("operation_work_center_id")
    process_notes = request.form.getlist("operation_process_note")
    quality_notes = request.form.getlist("operation_quality_note")
    setup_times = request.form.getlist("operation_setup_time")
    run_times = request.form.getlist("operation_run_time")
    operations = []
    row_count = max(len(sequences), len(operation_names), len(operation_nos))
    for index in range(row_count):
        name = (operation_names[index] if index < len(operation_names) else "").strip()
        op_no = (operation_nos[index] if index < len(operation_nos) else "").strip()
        if not name and not op_no:
            continue
        sequence = _routing_int_clean(sequences[index] if index < len(sequences) else "", (index + 1) * 10)
        operations.append(
            {
                "sequence": sequence,
                "operation_no": op_no or f"OP{sequence}",
                "operation_name": name,
                "work_center_id": (work_center_ids[index] if index < len(work_center_ids) else "").strip(),
                "process_note": (process_notes[index] if index < len(process_notes) else "").strip(),
                "quality_note": (quality_notes[index] if index < len(quality_notes) else "").strip(),
                "setup_time": (setup_times[index] if index < len(setup_times) else "").strip(),
                "run_time": (run_times[index] if index < len(run_times) else "").strip(),
            }
        )
    return {
        "routing_no": (existing_no or request.form.get("routing_no") or "").strip(),
        "name": (request.form.get("name") or "").strip(),
        "product_id": (request.form.get("product_id") or "").strip(),
        "revision": (request.form.get("revision") or "").strip() or "V1.0",
        "status": (request.form.get("status") or "draft").strip(),
        "remark": (request.form.get("remark") or "").strip(),
        "operations": operations,
    }


def _production_routing_validate_clean(form_state, routing_id=None):
    errors = []
    if not form_state.get("routing_no"):
        errors.append("路线编号不能为空。")
    if not form_state.get("name"):
        errors.append("路线名称不能为空。")
    if form_state.get("status") not in {"draft", "enabled", "disabled"}:
        errors.append("状态必须是草稿、启用或停用。")
    duplicate = _safe_one(
        "SELECT id FROM production_routings WHERE routing_no=%s AND (%s IS NULL OR id<>%s) LIMIT 1",
        (form_state.get("routing_no"), routing_id, routing_id),
    )
    if duplicate:
        errors.append("路线编号已存在。")
    if not [op for op in form_state.get("operations") or [] if op.get("operation_name")]:
        errors.append("至少录入一道工序名称。")
    return errors


def _production_routing_row_for_form_clean(routing_id):
    routing = _safe_one(
        "SELECT id, routing_no, name, product_id, revision, status, is_active, remark FROM production_routings WHERE id=%s",
        (routing_id,),
    )
    if not routing:
        return None
    operations = _safe_rows(
        """
        SELECT sequence, operation_no, operation_name, work_center_id, process_note, quality_note, setup_time, run_time
        FROM routing_operations
        WHERE routing_id=%s
        ORDER BY sequence, id
        """,
        (routing_id,),
    )
    form_state = dict(routing)
    form_state["status"] = _production_routing_status_key_clean(routing)
    form_state["operations"] = [dict(row) for row in operations] or _production_routing_blank_form_clean()["operations"]
    return form_state


def _render_production_routing_detail(routing_id, back_url="/production-routings"):
    _ensure_production_routing_status_column_clean()
    routing = _safe_one(
        """
        SELECT pr.*, p.code AS product_code, p.name AS product_name, p.specification AS product_specification
        FROM production_routings pr
        LEFT JOIN products p ON p.id=pr.product_id
        WHERE pr.id=%s
        """,
        (routing_id,),
    )
    if routing:
        routing = dict(routing)
        routing["status_key"] = _production_routing_status_key_clean(routing)
        routing["status_display"] = _production_routing_status_label_clean(routing["status_key"])
    operations = _safe_rows(
        """
        SELECT ro.sequence, ro.operation_no, ro.operation_name, ro.work_center_id,
               wc.name AS work_center, ro.process_note, ro.quality_note, ro.setup_time, ro.run_time
        FROM routing_operations ro
        LEFT JOIN work_centers wc ON wc.id=ro.work_center_id
        WHERE ro.routing_id=%s
        ORDER BY ro.sequence, ro.id
        """,
        (routing_id,),
    )
    operation_groups = [
        {"title": "前置准备", "hint": "技术确认、委外回厂、小件加工和总装前齐套准备。", "rows": [op for op in operations if (op.get("sequence") or 0) <= 40]},
        {"title": "机械装配", "hint": "床身、立柱、进给系统、主轴箱、磨削主轴和刀盘安装。", "rows": [op for op in operations if 50 <= (op.get("sequence") or 0) <= 100]},
        {"title": "液压电气与安全", "hint": "液压、润滑、冷却、电气接线、防护、限位和防撞装置。", "rows": [op for op in operations if 110 <= (op.get("sequence") or 0) <= 140]},
        {"title": "调试检验", "hint": "空载调试、几何精度、试切试磨和连续运行验证。", "rows": [op for op in operations if 150 <= (op.get("sequence") or 0) <= 180]},
        {"title": "终检交付", "hint": "终检、资料、附件、安全确认和交付条件关闭。", "rows": [op for op in operations if (op.get("sequence") or 0) >= 190]},
    ]
    return render_template("production_routing_detail.html", routing=routing, operations=operations, operation_groups=operation_groups, back_url=back_url)


def _render_production_routing_list():
    _ensure_production_routing_status_column_clean()
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    status = (request.args.get("status") or "").strip()
    where_parts = ["TRUE"]
    params = []
    if keyword:
        where_parts.append(
            """
            (
                pr.routing_no ILIKE %s OR pr.name ILIKE %s OR COALESCE(p.code, '') ILIKE %s
                OR COALESCE(p.name, '') ILIKE %s OR COALESCE(p.specification, '') ILIKE %s
            )
            """
        )
        params.extend([f"%{keyword}%"] * 5)
    if status == "enabled":
        where_parts.append("(COALESCE(pr.status, '')='enabled' OR (COALESCE(pr.status, '')='' AND COALESCE(pr.is_active, FALSE)=TRUE))")
    elif status == "disabled":
        where_parts.append("COALESCE(pr.status, CASE WHEN COALESCE(pr.is_active, FALSE) THEN 'enabled' ELSE 'disabled' END)='disabled'")
    elif status == "draft":
        where_parts.append("COALESCE(pr.status, '')='draft'")
    where_sql = "WHERE " + " AND ".join(where_parts)
    rows = _safe_rows(
        f"""
        SELECT pr.id, pr.routing_no, pr.name, pr.revision, pr.is_active, pr.status,
               p.code AS product_code, p.name AS product_name, p.specification AS product_specification,
               COUNT(ro.id) AS operation_count,
               MIN(ro.operation_name) FILTER (WHERE ro.sequence = 10) AS first_operation,
               MAX(ro.operation_name) FILTER (
                   WHERE ro.sequence = (
                       SELECT MAX(last_ro.sequence)
                       FROM routing_operations last_ro
                       WHERE last_ro.routing_id=pr.id
                   )
               ) AS last_operation
        FROM production_routings pr
        LEFT JOIN products p ON p.id=pr.product_id
        LEFT JOIN routing_operations ro ON ro.routing_id=pr.id
        {where_sql}
        GROUP BY pr.id, p.code, p.name, p.specification
        ORDER BY pr.id DESC
        LIMIT 100
        """,
        tuple(params),
    )
    display_rows = []
    for row in rows:
        item = dict(row)
        product_text = " ".join(part for part in [item.get("product_code"), item.get("product_name"), item.get("product_specification")] if part)
        item["product_display"] = product_text or "-"
        item["status_key"] = _production_routing_status_key_clean(item)
        item["status_display"] = _production_routing_status_label_clean(item["status_key"])
        item["status_class"] = {"enabled": "success", "draft": "warning", "disabled": "secondary"}.get(item["status_key"], "secondary")
        item["operation_summary"] = f"{item.get('operation_count') or 0} 道"
        if item.get("first_operation") or item.get("last_operation"):
            item["operation_summary"] = f"{item['operation_summary']}：{item.get('first_operation') or '-'} -> {item.get('last_operation') or '-'}"
        if item["status_key"] == "enabled":
            item["next_action"] = "可被技术确认和工单引用"
        elif item["status_key"] == "draft":
            item["next_action"] = "补齐工序后启用"
        else:
            item["next_action"] = "停用路线仅保留历史查看"
        display_rows.append(item)
    return render_template(
        "production_routing_list.html",
        title="工艺路线",
        subtitle="技术主数据页：维护和查看产品标准工序、工作中心和质量控制点，不生成生产事务、不做报表分析。",
        rows=display_rows,
        filters={"keyword": keyword, "status": status},
    )


def _render_production_routing_form(routing_id=None, form_state=None, errors=None):
    _ensure_production_routing_status_column_clean()
    routing = None
    mode = "new"
    if routing_id:
        routing = _safe_one("SELECT id, routing_no FROM production_routings WHERE id=%s", (routing_id,))
        if not routing:
            flash("工艺路线不存在。", "warning")
            return redirect("/production-routings")
        mode = "edit"
    if form_state is None:
        form_state = _production_routing_row_for_form_clean(routing_id) if routing_id else _production_routing_blank_form_clean()
    products, work_centers = _production_routing_form_options_clean()
    return render_template(
        "production_routing_form.html",
        mode=mode,
        routing=routing,
        form_state=form_state,
        form_errors=errors or [],
        products=products,
        work_centers=work_centers,
        status_options=[("draft", "草稿"), ("enabled", "启用"), ("disabled", "停用")],
    )


def _save_production_routing(routing_id=None):
    _ensure_production_routing_status_column_clean()
    existing = _safe_one("SELECT id, routing_no FROM production_routings WHERE id=%s", (routing_id,)) if routing_id else None
    if routing_id and not existing:
        flash("工艺路线不存在。", "warning")
        return redirect("/production-routings")
    form_state = _production_routing_form_from_request_clean(existing.get("routing_no") if existing else None)
    if not routing_id and not form_state.get("routing_no"):
        form_state["routing_no"] = _production_routing_next_no_clean()
    errors = _production_routing_validate_clean(form_state, routing_id)
    if errors:
        return _render_production_routing_form(routing_id, form_state, errors)
    product_id = _routing_int_clean(form_state.get("product_id"), 0) or None
    is_active = form_state.get("status") == "enabled"
    if routing_id:
        _execute_db(
            """
            UPDATE production_routings
            SET name=%s, product_id=%s, revision=%s, status=%s, is_active=%s, remark=%s
            WHERE id=%s
            """,
            (form_state["name"], product_id, form_state["revision"], form_state["status"], is_active, form_state["remark"], routing_id),
        )
        saved_id = routing_id
        _execute_db("DELETE FROM routing_operations WHERE routing_id=%s", (saved_id,))
    else:
        created = _execute_and_return(
            """
            INSERT INTO production_routings (routing_no, name, product_id, revision, status, is_active, remark)
            VALUES (%s,%s,%s,%s,%s,%s,%s)
            RETURNING id
            """,
            (form_state["routing_no"], form_state["name"], product_id, form_state["revision"], form_state["status"], is_active, form_state["remark"]),
        )
        saved_id = created.get("id") if isinstance(created, dict) else created
    for op in form_state.get("operations") or []:
        if not op.get("operation_name"):
            continue
        _execute_db(
            """
            INSERT INTO routing_operations
                (routing_id, sequence, operation_no, operation_name, work_center_id, process_note, quality_note, setup_time, run_time)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """,
            (
                saved_id,
                _routing_int_clean(op.get("sequence"), 0),
                op.get("operation_no"),
                op.get("operation_name"),
                _routing_int_clean(op.get("work_center_id"), 0) or None,
                op.get("process_note"),
                op.get("quality_note"),
                _routing_decimal_clean(op.get("setup_time")),
                _routing_decimal_clean(op.get("run_time")),
            ),
        )
    _log_action("保存工艺路线", form_state.get("routing_no"), "技术主数据维护")
    flash("工艺路线已保存。", "success")
    return redirect(f"/production-routings/{saved_id}")


def _delete_production_routing(routing_id):
    routing = _safe_one("SELECT id, routing_no FROM production_routings WHERE id=%s", (routing_id,))
    if not routing:
        flash("工艺路线不存在。", "warning")
        return redirect("/production-routings")
    checks = [
        ("work_orders", "routing_id"),
        ("work_order_processes", "routing_operation_id"),
        ("operation_reports", "routing_operation_id"),
        ("engineering_technical_confirmations", "routing_id"),
    ]
    referenced = 0
    for table, column in checks:
        if not (_has_table(table) and _has_column(table, column)):
            continue
        if column == "routing_operation_id":
            row = _safe_one(
                f"SELECT COUNT(*) AS value FROM {table} t JOIN routing_operations ro ON ro.id=t.{column} WHERE ro.routing_id=%s",
                (routing_id,),
            )
        else:
            row = _safe_one(f"SELECT COUNT(*) AS value FROM {table} WHERE {column}=%s", (routing_id,))
        referenced += int((row or {}).get("value") or 0)
    if referenced:
        flash("该工艺路线已被工单、报工或技术确认引用，不能删除；如不再使用请改为停用。", "warning")
        return redirect(f"/production-routings/{routing_id}")
    _execute_db("DELETE FROM routing_operations WHERE routing_id=%s", (routing_id,))
    _execute_db("DELETE FROM production_routings WHERE id=%s", (routing_id,))
    _log_action("删除工艺路线", routing.get("routing_no"), "未被下游单据引用")
    flash("工艺路线已删除。", "success")
    return redirect("/production-routings")


