def _category_id_by_name(name):
    name = (name or "").strip()
    if not name:
        return None
    row = _safe_one("SELECT id FROM product_categories WHERE name=%s LIMIT 1", (name,))
    return row.get("id") if row else None


def _lookup_id(table, value, *columns):
    text = str(value or "").strip()
    if not text:
        return None
    for column in columns:
        if not _has_column(table, column):
            continue
        row = _safe_one(f"SELECT id FROM {table} WHERE {column}=%s LIMIT 1", (text,))
        if row:
            return row.get("id")
    return None


def _master_reference_select_sql(table):
    columns = ["id"]
    if _has_column(table, "code"):
        columns.append("code")
    if _has_column(table, "name"):
        columns.append("name")
    return ", ".join(columns)


def _lookup_master_reference(table, value, *columns):
    text = str(value or "").strip()
    if not text:
        return None
    select_sql = _master_reference_select_sql(table)
    for column in columns:
        if not _has_column(table, column):
            continue
        row = _safe_one(f"SELECT {select_sql} FROM {table} WHERE {column}=%s LIMIT 1", (text,))
        if row:
            return row
    return None


MASTER_DISABLED_STATUS_VALUES = {"停用", "disabled", "inactive", "void", "作废", "已作废"}


def _status_is_disabled(status):
    text = str(status or "").strip()
    return text in MASTER_DISABLED_STATUS_VALUES or text.lower() in MASTER_DISABLED_STATUS_VALUES


def _master_active_where(table, alias=""):
    prefix = f"{alias}." if alias else ""
    clauses = []
    if _has_column(table, "status"):
        clauses.append(f"COALESCE({prefix}status, '启用') NOT IN ('停用','disabled','inactive','作废','已作废')")
    if _has_column(table, "is_active"):
        clauses.append(f"COALESCE({prefix}is_active, TRUE)=TRUE")
    return " AND ".join(clauses) or "TRUE"


def _lookup_active_master_reference(table, value, *columns):
    text = str(value or "").strip()
    if not text:
        return None
    active_where = _master_active_where(table)
    select_sql = _master_reference_select_sql(table)
    for column in columns:
        if not _has_column(table, column):
            continue
        row = _safe_one(f"SELECT {select_sql} FROM {table} WHERE {column}=%s AND {active_where} LIMIT 1", (text,))
        if row:
            return row
    return None


def _active_master_exists(table, row_id):
    if not row_id:
        return False
    row = _safe_one(f"SELECT id FROM {table} WHERE id=%s AND {_master_active_where(table)} LIMIT 1", (row_id,))
    return bool(row)


def _inactive_master_error(table, row_id, label):
    if not row_id:
        return ""
    if _active_master_exists(table, row_id):
        return ""
    return f"{label}不存在或已停用，请重新选择启用资料。"


def _master_code_exists(table, code, exclude_id=None):
    if not code or not _has_table(table) or not _has_column(table, "code"):
        return False
    if exclude_id:
        row = _safe_one(f"SELECT id FROM {table} WHERE code=%s AND id<>%s LIMIT 1", (code, exclude_id))
    else:
        row = _safe_one(f"SELECT id FROM {table} WHERE code=%s LIMIT 1", (code,))
    return bool(row)


