def _resolve_basic_import_references(kind, values, line_no):
    errors = []
    if kind == "customer":
        category_value = values.pop("category_code", "") or values.pop("category_name", "")
        if category_value:
            category_id = _lookup_id("customer_categories", category_value, "code", "name")
            if not category_id:
                errors.append(f"\u7b2c {line_no} \u884c\u5ba2\u6237\u5206\u7c7b\u4e0d\u5b58\u5728\uff1a{category_value}")
            values["category_id"] = category_id
        settlement_value = values.pop("settlement_term_code", "") or values.pop("settlement_term_name", "")
        if settlement_value:
            settlement_term_id = _lookup_id("settlement_terms", settlement_value, "code", "name")
            if not settlement_term_id:
                errors.append(f"\u7b2c {line_no} \u884c\u7ed3\u7b97\u671f\u9650\u4e0d\u5b58\u5728\uff1a{settlement_value}")
            values["settlement_term_id"] = settlement_term_id
        payment_value = values.pop("payment_term_code", "") or values.pop("payment_term_name", "")
        if payment_value:
            payment_term_id = _lookup_id("payment_terms", payment_value, "code", "name")
            if not payment_term_id:
                errors.append(f"\u7b2c {line_no} \u884c\u6536\u6b3e\u6761\u4ef6\u4e0d\u5b58\u5728\uff1a{payment_value}")
            values["payment_term_id"] = payment_term_id
    elif kind == "supplier":
        category_value = values.pop("category_code", "") or values.pop("category_name", "")
        if category_value:
            category_id = _lookup_id("supplier_categories", category_value, "code", "name")
            if not category_id:
                errors.append(f"\u7b2c {line_no} \u884c\u4f9b\u5e94\u5546\u5206\u7c7b\u4e0d\u5b58\u5728\uff1a{category_value}")
            values["category_id"] = category_id
        settlement_value = values.pop("settlement_term_code", "") or values.pop("settlement_term_name", "")
        if settlement_value:
            settlement_term_id = _lookup_id("settlement_terms", settlement_value, "code", "name")
            if not settlement_term_id:
                errors.append(f"\u7b2c {line_no} \u884c\u7ed3\u7b97\u671f\u9650\u4e0d\u5b58\u5728\uff1a{settlement_value}")
            values["settlement_term_id"] = settlement_term_id
        payment_value = values.pop("payment_term_code", "") or values.pop("payment_term_name", "")
        if payment_value:
            payment_term_id = _lookup_id("payment_terms", payment_value, "code", "name")
            if not payment_term_id:
                errors.append(f"\u7b2c {line_no} \u884c\u4ed8\u6b3e\u6761\u4ef6\u4e0d\u5b58\u5728\uff1a{payment_value}")
            values["payment_term_id"] = payment_term_id
    elif kind == "warehouse":
        category_value = values.pop("category_code", "") or values.pop("category_name", "")
        if category_value:
            category_id = _lookup_id("warehouse_categories", category_value, "code", "name")
            if not category_id:
                errors.append(f"\u7b2c {line_no} \u884c\u4ed3\u5e93\u5206\u7c7b\u4e0d\u5b58\u5728\uff1a{category_value}")
            values["category_id"] = category_id
        location_value = values.pop("default_location_code", "") or values.pop("default_location_name", "")
        if location_value:
            location_id = _lookup_id("locations", location_value, "code", "name")
            if not location_id:
                errors.append(f"\u7b2c {line_no} \u884c\u9ed8\u8ba4\u5e93\u4f4d\u4e0d\u5b58\u5728\uff1a{location_value}")
            values["default_location_id"] = location_id
    if kind == "location":
        warehouse_value = values.pop("warehouse_code", "") or values.pop("warehouse_name", "")
        warehouse_id = _lookup_id("warehouses", warehouse_value, "code", "name")
        if not warehouse_id:
            errors.append(f"第 {line_no} 行所属仓库不存在：{warehouse_value}")
        values["warehouse_id"] = warehouse_id
    elif kind == "unit":
        base_unit_code = values.pop("base_unit_code", "")
        if base_unit_code:
            base_unit_id = _lookup_id("units", base_unit_code, "code", "name")
            if not base_unit_id:
                errors.append(f"第 {line_no} 行基本单位不存在：{base_unit_code}")
            values["base_unit_id"] = base_unit_id
    elif kind == "department":
        parent_name = values.pop("parent_name", "")
        if parent_name:
            parent_id = _lookup_id("departments", parent_name, "name", "code")
            if not parent_id:
                errors.append(f"第 {line_no} 行上级部门不存在：{parent_name}")
            values["parent_id"] = parent_id
    elif kind == "employee":
        department_name = values.pop("department_name", "")
        if department_name:
            dept_id = _lookup_id("departments", department_name, "name", "code")
            if not dept_id:
                errors.append(f"第 {line_no} 行部门不存在：{department_name}")
            values["dept_id"] = dept_id
    elif kind == "project":
        customer_name = values.pop("customer_name", "")
        if customer_name:
            customer_id = _lookup_id("customers", customer_name, "name")
            if not customer_id:
                errors.append(f"第 {line_no} 行客户不存在：{customer_name}")
            values["customer_id"] = customer_id
        values["status"] = values.get("status") or "准备"
    elif kind == "machine_serial":
        project_code = values.get("project_code") or values.pop("project_no", "")
        project = _safe_one("SELECT * FROM project_masters WHERE project_code=%s LIMIT 1", (project_code,)) if project_code else None
        if project_code and not project:
            errors.append(f"第 {line_no} 行所属项目不存在：{project_code}")
        values["project_id"] = project.get("id") if project else None
        values["project_code"] = project_code or ""
        customer_name = values.pop("customer_name", "")
        customer_id = _lookup_id("customers", customer_name, "name") if customer_name else None
        if customer_name and not customer_id:
            errors.append(f"第 {line_no} 行客户不存在：{customer_name}")
        values["customer_id"] = customer_id or (project.get("customer_id") if project else None)
        product_code = values.pop("product_code", "")
        product_id = _lookup_id("products", product_code, "code", "name") if product_code else None
        if product_code and not product_id:
            errors.append(f"第 {line_no} 行成品物料不存在：{product_code}")
        values["product_id"] = product_id
        values["product_family"] = values.get("product_family") or (project.get("product_family") if project else "")
        values["machine_model"] = values.get("machine_model") or (project.get("machine_model") if project else "")
        values["production_stage"] = values.get("production_stage") or "准备"
        values["service_status"] = values.get("service_status") or "未安装"
        values["status"] = values.get("status") or "启用"
    return errors


