def _basic_import_active_reference_errors(kind, values, line_no):
    checks = {
        "customer": [
            ("settlement_terms", values.get("settlement_term_id"), "结算期限"),
            ("payment_terms", values.get("payment_term_id"), "收款条件"),
        ],
        "supplier": [
            ("settlement_terms", values.get("settlement_term_id"), "结算期限"),
            ("payment_terms", values.get("payment_term_id"), "付款条件"),
        ],
        "warehouse": [
            ("locations", values.get("default_location_id"), "默认库位"),
        ],
        "location": [
            ("warehouses", values.get("warehouse_id"), "所属仓库"),
        ],
        "unit": [
            ("units", values.get("base_unit_id"), "基本单位"),
        ],
        "department": [
            ("departments", values.get("parent_id"), "上级部门"),
        ],
        "employee": [
            ("departments", values.get("dept_id"), "部门"),
        ],
        "project": [
            ("customers", values.get("customer_id"), "客户"),
        ],
        "machine_serial": [
            ("customers", values.get("customer_id"), "客户"),
            ("products", values.get("product_id"), "成品物料"),
        ],
    }.get(kind, [])
    errors = []
    for table, row_id, label in checks:
        if row_id and not _active_master_exists(table, row_id):
            errors.append(f"第 {line_no} 行{label}已停用，请改为启用资料")
    return errors


def _coerce_registry_basic_import_value(column, value):
    if column in {
        "hire_date",
        "planned_delivery_date",
        "warranty_start_date",
        "warranty_end_date",
    }:
        return str(value or "").strip() or None
    if column in {
        "default_tax_rate",
        "credit_limit",
        "conversion_rate",
        "standard_labor_rate_per_hour",
    }:
        return _decimal_text(value, "1" if column == "conversion_rate" else "0")
    if column in {"lead_time_days"}:
        try:
            return int(_decimal_text(value, "0"))
        except Exception:
            return 0
    if column in {"is_sales", "is_active", "is_outsourced_processor"}:
        return str(value or "").strip() in {"\u662f", "true", "True", "1", "Y", "y", "yes"}
    return _coerce_basic_import_value(column, value)


def _basic_import_report_row(kind, config, table, table_cols, allowed_columns, key, row, line_no):
    values = {}
    missing = []
    for label, column, required in allowed_columns:
        value = _csv_cell(row, label, column)
        if required and not value:
            missing.append(label)
        if not required and not value:
            continue
        values[column] = _coerce_registry_basic_import_value(column, value)
    if missing:
        return None, f"第 {line_no} 行缺少必填字段：{','.join(missing)}"
    reference_errors = _resolve_basic_import_references(kind, values, line_no)
    reference_errors.extend(_basic_import_active_reference_errors(kind, values, line_no))
    if reference_errors:
        return None, "；".join(reference_errors)
    key_value = values.get(key)
    if not key_value:
        return None, f"第 {line_no} 行缺少主键字段"
    existing = _safe_one(f"SELECT id FROM {table} WHERE {key}=%s LIMIT 1", (key_value,))
    return {"values": values, "existing": bool(existing), "key_value": key_value}, None


def _build_basic_import_precheck_report(kind, config, table, table_cols, allowed_columns, key, rows, validation_errors):
    report = {
        "total_rows": len(rows or []),
        "created": 0,
        "updated": 0,
        "skipped": 0,
        "error_count": 0,
        "errors": [],
    }
    seen_keys = set()
    for error in validation_errors or []:
        report["errors"].append({"line": "-", "message": error})
    for line_no, row in enumerate(rows or [], start=2):
        result, error = _basic_import_report_row(kind, config, table, table_cols, allowed_columns, key, row, line_no)
        if error:
            report["skipped"] += 1
            report["errors"].append({"line": line_no, "message": error})
            continue
        key_value = str(result["key_value"] or "").strip()
        if key_value in seen_keys:
            report["skipped"] += 1
            report["errors"].append({"line": line_no, "message": f"第 {line_no} 行主键重复：{key_value}"})
            continue
        seen_keys.add(key_value)
        if result["existing"]:
            report["updated"] += 1
        else:
            report["created"] += 1
    report["error_count"] = len(report["errors"])
    return report


def _import_basic_csv(kind):
    config = BASIC_IMPORT_CONFIGS.get(kind)
    if not config:
        return redirect("/master-data")
    file = request.files.get("file")
    if not file or not file.filename:
        flash("请选择要导入的 CSV 文件。", "warning")
        return redirect(config["import_url"])
    mode = _form_text("mode", "upsert")
    table = config["table"]
    table_cols = {row["column_name"] for row in _table_columns(table)}
    virtual_columns = {
        "warehouse_code", "warehouse_name", "base_unit_code", "parent_name",
        "department_name", "customer_name", "project_no", "product_code",
        "category_code", "category_name", "settlement_term_code",
        "settlement_term_name", "payment_term_code", "payment_term_name",
        "default_location_code", "default_location_name",
    }
    allowed_columns = [
        (label, column, required)
        for label, column, required in config["columns"] + _basic_import_extra_columns(kind)
        if column in table_cols or column in virtual_columns
    ]
    key = config["key"] if config["key"] in table_cols else allowed_columns[0][1]
    created = 0
    updated = 0
    skipped = 0
    errors = []
    rows, validation_errors = _read_validated_csv_upload(file)
    if request.form.get("action") == "precheck":
        report = _build_basic_import_precheck_report(
            kind, config, table, table_cols, allowed_columns, key, rows, validation_errors
        )
        _log_action(f"{config['label']}导入预检", file.filename, f"errors={report['error_count']}")
        return _render_basic_import(kind, report)
    blocked = _flash_import_validation_errors(config["import_url"], validation_errors)
    if blocked:
        _log_action(f"{config['label']}\u5bfc\u5165\u6821\u9a8c\u5931\u8d25", file.filename, "\uff1b".join(validation_errors[:5]))
        return blocked
    for line_no, row in enumerate(rows, start=2):
        values = {}
        missing = []
        for label, column, required in allowed_columns:
            value = _csv_cell(row, label, column)
            if required and not value:
                missing.append(label)
            if not required and not value:
                continue
            values[column] = _coerce_registry_basic_import_value(column, value)
        if missing:
            skipped += 1
            errors.append(f"第 {line_no} 行缺少必填字段：{','.join(missing)}")
            continue
        reference_errors = _resolve_basic_import_references(kind, values, line_no)
        reference_errors.extend(_basic_import_active_reference_errors(kind, values, line_no))
        if reference_errors:
            skipped += 1
            errors.extend(reference_errors)
            continue
        key_value = values.get(key)
        if not key_value:
            skipped += 1
            errors.append(f"第 {line_no} 行缺少主键字段")
            continue
        existing = _safe_one(f"SELECT id FROM {table} WHERE {key}=%s LIMIT 1", (key_value,))
        if existing:
            if mode == "insert_only":
                skipped += 1
                continue
            update_columns = [column for column in values if column != key and column in table_cols]
            if update_columns:
                set_sql = ", ".join(f"{column}=%s" for column in update_columns)
                _execute_db(
                    f"UPDATE {table} SET {set_sql} WHERE {key}=%s",
                    tuple(values[column] for column in update_columns) + (key_value,),
                )
            updated += 1
        else:
            insert_columns = [column for column in values if column in table_cols]
            placeholders = ",".join(["%s"] * len(insert_columns))
            _execute_db(
                f"INSERT INTO {table} ({', '.join(insert_columns)}) VALUES ({placeholders})",
                tuple(values[column] for column in insert_columns),
            )
            created += 1
    msg = f"{config['label']}导入完成：新增 {created} 条，更新 {updated} 条，跳过 {skipped} 条。"
    if errors:
        msg += " " + "；".join(errors[:3])
    flash(msg, "success" if not errors else "warning")
    _log_action(f"{config['label']}导入", file.filename, msg)
    return redirect(config["back_url"])

