def _import_category_csv(kind):
    config = CATEGORY_TYPES.get(kind)
    if not config:
        return redirect("/master-data")
    file = request.files.get("file")
    if not file or not file.filename:
        flash("请选择要导入的 CSV 文件。", "warning")
        return redirect(f"/categories/{kind}/import")
    mode = _form_text("mode", "upsert")
    table = config["table"]
    created = 0
    updated = 0
    skipped = 0
    errors = []
    for line_no, row in enumerate(_read_csv_upload(file), start=2):
        code = _csv_cell(row, "分类编码", "编码", "code")
        name = _csv_cell(row, "分类名称", "名称", "name")
        parent_code = _csv_cell(row, "上级分类编码", "parent_code")
        parent_name = _csv_cell(row, "上级分类名称", "parent_name")
        remark = _csv_cell(row, "备注", "remark")
        if not name:
            skipped += 1
            errors.append(f"第 {line_no} 行缺少分类名称")
            continue
        parent_id = None
        parent_value = parent_code or parent_name
        if parent_value:
            parent_id = _lookup_id(table, parent_value, "code", "name")
            if not parent_id:
                skipped += 1
                errors.append(f"第 {line_no} 行上级分类不存在：{parent_value}")
                continue
        existing = _safe_one(f"SELECT id FROM {table} WHERE name=%s LIMIT 1", (name,))
        if existing:
            if mode == "insert_only":
                skipped += 1
                continue
            _execute_db(
                f"UPDATE {table} SET code=COALESCE(NULLIF(%s,''), code), parent_id=%s, remark=COALESCE(NULLIF(%s,''), remark) WHERE id=%s",
                (code, parent_id, remark, existing["id"]),
            )
            updated += 1
        else:
            _execute_db(f"INSERT INTO {table} (code, name, parent_id, remark) VALUES (%s,%s,%s,%s)", (code, name, parent_id, remark))
            created += 1
    msg = f"{config['title']}导入完成：新增 {created} 条，更新 {updated} 条，跳过 {skipped} 条。"
    if errors:
        msg += " " + "；".join(errors[:3])
    flash(msg, "success" if not errors else "warning")
    _log_action(f"{config['title']}导入", file.filename, msg)
    return redirect(config["back_url"])

