def _quality_inspection_control_text(row):
    labels = []
    if row.get("batch_control"):
        labels.append("批次管理")
    if row.get("serial_control"):
        labels.append("序列号管理")
    if row.get("inspection_required"):
        labels.append("需质检")
    return " / ".join(labels) if labels else "-"

def _quality_inspection_bom_text(row):
    parts = [row.get("default_bom_no"), row.get("default_bom_version")]
    return " / ".join(str(part) for part in parts if part) or "-"


def _quality_inspection_source_text(row):
    source_no = row.get("source_no") or row.get("wo_no") or row.get("receipt_no") or row.get("receive_no")
    if source_no:
        return source_no
    source_type = row.get("source_document_type")
    source_id = row.get("source_document_id")
    if source_type and source_id:
        return f"{source_type} #{source_id}"
    return "-"


def _render_quality_inspection_dashboard():
    _ensure_quality_inspection_columns()
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    where_parts = []
    params = []
    if keyword:
        where_parts.append(
            """
            (qi.inspection_no ILIKE %s OR qi.batch_no ILIKE %s OR qi.project_code ILIKE %s
             OR qi.serial_no ILIKE %s OR qi.status ILIKE %s OR qi.inspection_result ILIKE %s
             OR p.code ILIKE %s OR p.name ILIKE %s OR p.specification ILIKE %s
             OR pc.name ILIKE %s OR wo.wo_no ILIKE %s)
            """
        )
        params.extend([f"%{keyword}%"] * 11)
    scope_clause, scope_params = _data_scope_filter(
        {"project": "qi.project_code", "serial": "qi.serial_no"}
    )
    if scope_clause:
        params.extend(scope_params)
    where_sql = ("WHERE 1=1" if (where_parts or scope_clause) else "") + scope_clause
    if where_parts:
        where_sql += " AND " + " AND ".join(where_parts)
    rows = _safe_rows(
        f"""
        SELECT qi.id, qi.inspection_no, qi.source_document_type, qi.source_document_id, qi.source_no,
               qi.project_code, qi.serial_no, qi.inspection_type, qi.inspection_date,
               qi.batch_no, qi.sample_size, qi.passed_quantity, qi.failed_quantity,
               qi.inspection_result, qi.status, qi.defect_category, qi.severity_level,
               qi.disposition, qi.nonconformance_status, qi.responsible_party,
               qi.owner_role, qi.blocked_reason, qi.next_action, qi.downstream_impact,
               qi.capa_required, qi.capa_status, qi.quality_cost_amount, qi.cost_category,
               p.code AS product_code, p.name AS product_name, p.specification,
               COALESCE(pc.name, p.category, '') AS product_family,
               bom.bom_no AS default_bom_no,
               bom.version AS default_bom_version,
               COALESCE(p.batch_control, FALSE) AS batch_control,
               COALESCE(p.serial_control, FALSE) AS serial_control,
               COALESCE(p.inspection_required, FALSE) AS inspection_required,
               wo.wo_no
        FROM quality_inspection_records qi
        LEFT JOIN products p ON p.id=qi.product_id
        LEFT JOIN product_categories pc ON pc.id=p.category_id
        LEFT JOIN work_orders wo
          ON qi.source_document_type='work_order' AND wo.id=qi.source_document_id
        LEFT JOIN LATERAL (
            SELECT b.bom_no, b.version
            FROM boms b
            WHERE b.product_id=p.id AND COALESCE(b.status, '') NOT IN ('停用','inactive','disabled')
            ORDER BY
                CASE WHEN b.bom_type='production' THEN 0 ELSE 1 END,
                b.id DESC
            LIMIT 1
        ) bom ON TRUE
        {where_sql}
        ORDER BY qi.id DESC
        LIMIT 100
        """,
        tuple(params),
    )
    enhanced_rows = []
    for row in rows:
        item = dict(row)
        product_parts = [item.get("product_code"), item.get("product_name"), item.get("specification")]
        item["source_display"] = _quality_inspection_source_text(item)
        item["product_display"] = " / ".join(str(part) for part in product_parts if part) or "-"
        item["bom_display"] = _quality_inspection_bom_text(item)
        item["control_display"] = _quality_inspection_control_text(item)
        item["inspection_type_display"] = _quality_inspection_type_label(item.get("inspection_type"))
        item["inspection_result_display"] = _quality_result_label(item.get("inspection_result"))
        item["status_display"] = _quality_status_label(item.get("status"))
        item["disposition_display"] = _quality_disposition_label(item.get("disposition"))
        item["nonconformance_status_display"] = _quality_nonconformance_status(item)
        release = _quality_release_view(item)
        item["release_status"] = release["label"]
        item["blocked_reason"] = release["blocked_reason"] or "-"
        item["next_step"] = release["next_action"]
        item["completion_impact"] = release["completion_impact"]
        enhanced_rows.append(item)
    return render_template(
        "simple_list.html",
        title="质量检验单",
        subtitle="跟踪生产、售后等来源单据的质检结果和后续处理。",
        rows=enhanced_rows,
        columns=_columns(
            ("inspection_no", "检验单号"),
            ("source_display", "来源单据"),
            ("product_display", "物料"),
            ("product_family", "产品系列"),
            ("bom_display", "BOM"),
            ("control_display", "管控要求"),
            ("project_code", "项目号"),
            ("serial_no", "机号"),
            ("inspection_date", "检验日期"),
            ("inspection_type_display", "检验类型"),
            ("inspection_result_display", "检验结果"),
            ("status_display", "单据状态"),
            ("release_status", "放行状态"),
            ("nonconformance_status_display", "不合格状态"),
            ("disposition_display", "处置方式"),
            ("owner_role", "责任岗位"),
            ("blocked_reason", "阻断原因"),
            ("next_step", "下一步"),
            ("completion_impact", "完工影响"),
            ("quality_cost_amount", "质量成本估算"),
        ),
        detail_base="/production-enhance/quality-inspections",
    )


