        "ALTER TABLE quality_inspection_records ADD COLUMN IF NOT EXISTS responsible_party TEXT",
        "ALTER TABLE quality_inspection_records ADD COLUMN IF NOT EXISTS responsible_supplier_id INTEGER",
        "ALTER TABLE quality_inspection_records ADD COLUMN IF NOT EXISTS owner_role TEXT",
