def _after_sale_control_text(row):
    labels = []
    if row.get("batch_control"):
        labels.append("批次管理")
    if row.get("serial_control"):
        labels.append("序列号管理")
    if row.get("inspection_required"):
        labels.append("需质检")
    return " / ".join(labels) if labels else "-"

def _after_sale_bom_text(row):
    parts = [row.get("bom_no") or row.get("default_bom_no"), row.get("bom_version") or row.get("default_bom_version")]
    return " / ".join(str(part) for part in parts if part) or "-"


def _after_sale_product_text(row):
    parts = [row.get("product_code"), row.get("product_name"), row.get("product_specification")]
    return " / ".join(str(part) for part in parts if part) or "-"


def _after_sale_keyword_filter(alias):
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    if not keyword:
        return "", ()
    pattern = f"%{keyword}%"
    if alias == "so":
        clause = """
        WHERE (
            so.order_no ILIKE %s OR so.service_type ILIKE %s OR so.project_code ILIKE %s
            OR so.serial_no ILIKE %s OR so.status ILIKE %s OR c.name ILIKE %s
            OR p.code ILIKE %s OR p.name ILIKE %s OR p.specification ILIKE %s
            OR COALESCE(pc.name, p.category, '') ILIKE %s OR wo.wo_no ILIKE %s
        )
        """
    else:
        clause = """
        WHERE (
            r.rma_no ILIKE %s OR so.order_no ILIKE %s OR r.project_code ILIKE %s
            OR r.serial_no ILIKE %s OR r.status ILIKE %s OR c.name ILIKE %s
            OR p.code ILIKE %s OR p.name ILIKE %s OR p.specification ILIKE %s
            OR COALESCE(pc.name, p.category, '') ILIKE %s OR wo.wo_no ILIKE %s
        )
        """
    return clause, tuple([pattern] * 11)


def _render_service_order_dashboard():
    where_sql, params = _after_sale_keyword_filter("so")
    scope_clause, scope_params = _data_scope_filter(
        {"project": "so.project_code", "serial": "so.serial_no"}
    )
    if scope_clause:
        if where_sql:
            where_sql = where_sql.rstrip() + scope_clause
        else:
            where_sql = "WHERE 1=1" + scope_clause
        params = tuple(params) + tuple(scope_params)
    rows = _safe_rows(
        f"""
        SELECT so.id, so.order_no, so.service_date, so.service_type, so.project_code,
               so.serial_no, so.status, so.total_cost, so.settlement_status,
               c.name AS customer_name, sc.machine_model,
               p.code AS product_code, p.name AS product_name, p.specification AS product_specification,
               COALESCE(pc.name, p.category, '') AS product_family,
               COALESCE(p.batch_control, FALSE) AS batch_control,
               COALESCE(p.serial_control, FALSE) AS serial_control,
               COALESCE(p.inspection_required, FALSE) AS inspection_required,
               wo.wo_no, sales.order_no AS sales_order_no,
               COALESCE(b.bom_no, default_bom.bom_no) AS bom_no,
               COALESCE(b.version, default_bom.version) AS bom_version
        FROM machine_service_orders so
        LEFT JOIN machine_service_cards sc ON sc.id=so.service_card_id
        LEFT JOIN customers c ON c.id=sc.customer_id
        LEFT JOIN products p ON p.id=sc.product_id
        LEFT JOIN product_categories pc ON pc.id=p.category_id
        LEFT JOIN work_orders wo ON wo.id=COALESCE(so.wo_id, sc.wo_id)
        LEFT JOIN sales_orders sales ON sales.id=COALESCE(so.sales_order_id, sc.sales_order_id)
        LEFT JOIN boms b ON b.id=wo.bom_id
        LEFT JOIN LATERAL (
            SELECT db.bom_no, db.version
            FROM boms db
            WHERE db.product_id=p.id AND COALESCE(db.status, '') NOT IN ('停用','inactive','disabled')
            ORDER BY CASE WHEN db.bom_type='production' THEN 0 ELSE 1 END, db.id DESC
            LIMIT 1
        ) default_bom ON TRUE
        {where_sql}
        ORDER BY so.id DESC
        LIMIT 100
        """,
        params,
    )
    enhanced_rows = []
    for row in rows:
        item = dict(row)
        item["product_display"] = _after_sale_product_text(item)
        item["bom_display"] = _after_sale_bom_text(item)
        item["control_display"] = _after_sale_control_text(item)
        item["next_step"] = service_order_next_step(item.get("status"))
        marker_text = " ".join(str(item.get(key) or "") for key in ("order_no", "issue_summary", "remark", "project_code", "serial_no"))
        item["data_source"] = "测试/审计数据" if any(marker in marker_text for marker in ("pytest", "PYTEST", "SVC-", "GT-TRIAL")) else "业务数据"
        enhanced_rows.append(item)
    return render_template(
        "simple_list.html",
        title="售后服务单",
        subtitle="跟踪客户、项目号、机号和 BOM 等售后关键信息。",
        rows=enhanced_rows,
        columns=_columns(
            ("order_no", "服务单号"),
            ("service_date", "服务日期"),
            ("service_type", "服务类型"),
            ("customer_name", "客户"),
            ("project_code", "项目号"),
            ("serial_no", "机号"),
            ("product_display", "物料"),
            ("product_family", "产品系列"),
            ("bom_display", "BOM"),
            ("control_display", "管控要求"),
            ("status", "状态"),
            ("next_step", "下一步"),
            ("data_source", "数据来源"),
        ),
        detail_base="/service-orders",
        add_url="/service-orders/new",
    )


def _render_service_card_dashboard():
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    where_parts = []
    params = []
    if keyword:
        pattern = f"%{keyword}%"
        where_parts.append(
            """
            (
                sc.card_no ILIKE %s OR sc.serial_no ILIKE %s OR sc.project_code ILIKE %s OR sc.machine_model ILIKE %s
                OR sc.status ILIKE %s OR c.name ILIKE %s OR p.code ILIKE %s OR p.name ILIKE %s
                OR so.order_no ILIKE %s OR wo.wo_no ILIKE %s
            )
            """
        )
        params.extend([pattern] * 9)
    scope_clause, scope_params = _data_scope_filter(
        {"project": "sc.project_code", "serial": "sc.serial_no"}
    )
    if scope_clause:
        params.extend(scope_params)
    where_sql = ("WHERE 1=1" if (where_parts or scope_clause) else "") + scope_clause
    if where_parts:
        where_sql += " AND " + " AND ".join(where_parts)
    rows = _safe_rows(
        f"""
        SELECT sc.id, sc.card_no, sc.serial_no, sc.project_code, sc.machine_model, sc.status,
               c.name AS customer_name, p.code AS product_code, p.name AS product_name,
               p.specification, p.unit,
               so.order_no AS sales_order_no, wo.wo_no
        FROM machine_service_cards sc
        LEFT JOIN customers c ON c.id=sc.customer_id
        LEFT JOIN products p ON p.id=sc.product_id
        LEFT JOIN sales_orders so ON so.id=sc.sales_order_id
        LEFT JOIN work_orders wo ON wo.id=sc.wo_id
        {where_sql}
        ORDER BY sc.id DESC
        LIMIT 100
        """,
        tuple(params),
    )
    return render_template(
        "simple_list.html",
        title="设备服务档案",
        subtitle="按机号、项目号、客户和机型管理设备售后档案。",
        rows=list(rows),
        columns=_columns(
            ("card_no", "服务档案号"),
            ("serial_no", "机号"),
            ("project_code", "项目号"),
            ("machine_model", "机型"),
            ("customer_name", "客户"),
            ("product_code", "物料编码"),
            ("product_name", "物料名称"),
            ("specification", "规格"),
            ("unit", "单位"),
            ("sales_order_no", "销售订单"),
            ("wo_no", "工单"),
            ("status", "状态"),
        ),
        detail_base="/service-cards",
        add_url=None,
    )


def _render_service_acceptance_dashboard():
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    where_parts = []
