def _render_shipment_dashboard():
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    where_parts = []
    params = []
    if keyword:
        where_parts.append(
            """
            (
                ss.shipment_no ILIKE %s OR so.order_no ILIKE %s OR ss.project_code ILIKE %s
                OR ss.serial_no ILIKE %s OR ss.status ILIKE %s OR COALESCE(c.name, '') ILIKE %s
            )
            """
        )
        params.extend([f"%{keyword}%"] * 6)
    scope_clause, scope_params = _data_scope_filter(
        {"project": "ss.project_code", "serial": "ss.serial_no"}
    )
    if scope_clause:
        params.extend(scope_params)
    where_sql = ("WHERE 1=1" if (where_parts or scope_clause) else "") + scope_clause
    if where_parts:
        where_sql += " AND " + " AND ".join(where_parts)
    rows = _safe_rows(
        f"""
        SELECT ss.id, ss.shipment_no, ss.shipment_date, ss.project_code, ss.serial_no,
               ss.status, so.order_no, c.name AS customer_name,
               sc.id AS service_card_id,
               COALESCE(sc.status, '未建档') AS service_card_status,
               sc.machine_model
        FROM sales_shipments ss
        LEFT JOIN sales_orders so ON so.id=ss.order_id
        LEFT JOIN customers c ON c.id=so.customer_id
        LEFT JOIN machine_service_cards sc
          ON sc.sales_order_id=ss.order_id AND sc.serial_no=ss.serial_no
        {where_sql}
        ORDER BY
            CASE WHEN sc.id IS NULL THEN 0 ELSE 1 END,
            ss.id DESC
        LIMIT 120
        """,
        tuple(params),
    )
    enhanced_rows = []
    for row in rows:
        item = dict(row)
        item["next_step"] = "生成或补齐服务档案" if not item.get("service_card_id") else shipment_next_step(item.get("status"))
        enhanced_rows.append(item)
    return render_template(
        "simple_list.html",
        title="销售发货列表",
        subtitle="按发货单、销售订单、项目号、机号和服务档案追踪交付到售后。",
        rows=enhanced_rows,
        columns=_columns(
            ("shipment_no", "发货单"),
            ("order_no", "销售订单"),
            ("customer_name", "客户"),
            ("project_code", "项目号"),
            ("serial_no", "机号"),
            ("shipment_date", "发货日期"),
            ("service_card_status", "服务档案"),
            ("machine_model", "机型"),
            ("status", "状态"),
            ("next_step", "下一步"),
        ),
        detail_base="/shipments",
    )


def _subcontract_execution_state(row):
    status = (row.get("status") or "").strip()
    ordered_qty = _as_decimal(row.get("quantity"))
    issued_qty = _as_decimal(row.get("issued_qty"))
    received_qty = _as_decimal(row.get("received_qty"))
    scrap_qty = _as_decimal(row.get("scrap_qty"))
    payable_balance = _as_decimal(row.get("payable_balance"))
    if not (row.get("project_code") or "").strip() or not (row.get("serial_no") or "").strip():
        return "追溯缺失", "补齐项目号/机号", "计划"
    if status in {"已作废", "void", "cancelled"}:
        return "已作废", "保留追溯", "采购"
    if scrap_qty > 0:
        return "收货异常", "处理报废/短收并核价", "采购/质量"
    if status in {"已关闭", "已完成", "closed", "completed"}:
        return "已完成", "保留质量和应付追溯", "采购/财务"
    if issued_qty <= 0:
        return "待发料", "委外发料", "仓库"
    if ordered_qty > 0 and received_qty + scrap_qty < ordered_qty:
        return "待收货", "跟催委外收货", "采购/仓库"
    if ordered_qty <= 0 and received_qty <= 0:
        return "数量待确认", "确认委外数量", "计划"
    if payable_balance > 0:
        return "待付款", "核对应付并安排付款", "采购/财务"
    return "已完成", "关闭委外并归档", "采购/财务"


def _render_subcontract_dashboard(back_url="/subcontract"):
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    order_qty_expr = "COALESCE(sc.quantity, 0)" if _has_column("subcontract_orders", "quantity") else "0"
    unit_price_expr = "COALESCE(sc.unit_price, 0)" if _has_column("subcontract_orders", "unit_price") else "0"
    where_parts = []
    params = []
    if keyword:
        where_parts.append(
            """
            (
                sc.order_no ILIKE %s OR sc.project_code ILIKE %s OR sc.serial_no ILIKE %s
                OR sc.status ILIKE %s OR COALESCE(s.name, '') ILIKE %s
            )
            """
        )
        params.extend([f"%{keyword}%"] * 5)
    scope_clause, scope_params = _data_scope_filter(
        {"project": "sc.project_code", "serial": "sc.serial_no"}
    )
    if scope_clause:
        params.extend(scope_params)
    where_sql = ("WHERE 1=1" if (where_parts or scope_clause) else "") + scope_clause
    if where_parts:
        where_sql += " AND " + " AND ".join(where_parts)
    rows = _safe_rows(
        f"""
        SELECT sc.id, sc.order_no, sc.order_date, sc.project_code, sc.serial_no,
               {order_qty_expr} AS quantity, {unit_price_expr} AS unit_price,
               sc.total_amount, sc.status,
               COALESCE(s.name, sc.supplier_id::text, '-') AS supplier_name,
               COALESCE(issue_sum.issued_qty, 0) AS issued_qty,
               COALESCE(receive_sum.received_qty, 0) AS received_qty,
               COALESCE(receive_sum.scrap_qty, 0) AS scrap_qty,
               GREATEST({order_qty_expr} - COALESCE(receive_sum.received_qty, 0) - COALESCE(receive_sum.scrap_qty, 0), 0) AS pending_receive_qty,
               COALESCE(payable_sum.payable_amount, 0) AS payable_amount,
               COALESCE(payable_sum.payable_balance, 0) AS payable_balance
        FROM subcontract_orders sc
        LEFT JOIN suppliers s ON s.id=sc.supplier_id
        LEFT JOIN LATERAL (
            SELECT COALESCE(SUM(total_quantity), 0) AS issued_qty
            FROM subcontract_issue_orders sio
            WHERE sio.subcontract_order_id=sc.id
              AND COALESCE(sio.status, '') NOT IN ('已作废','void','cancelled')
        ) issue_sum ON TRUE
        LEFT JOIN LATERAL (
            SELECT COALESCE(SUM(total_quantity), 0) AS received_qty,
                   COALESCE(SUM(total_scrap), 0) AS scrap_qty
            FROM subcontract_receive_orders sro
            WHERE sro.subcontract_order_id=sc.id
              AND COALESCE(sro.status, '') NOT IN ('已作废','void','cancelled')
        ) receive_sum ON TRUE
        LEFT JOIN LATERAL (
            SELECT COALESCE(SUM(amount), 0) AS payable_amount,
                   COALESCE(SUM(balance), 0) AS payable_balance
            FROM supplier_payables sp
            WHERE sp.doc_type='subcontract_order'
              AND (sp.doc_id=sc.id OR sp.doc_no=sc.order_no)
        ) payable_sum ON TRUE
        {where_sql}
        ORDER BY
            CASE
                WHEN COALESCE(sc.project_code, '')='' OR COALESCE(sc.serial_no, '')='' THEN 0
                WHEN COALESCE(issue_sum.issued_qty, 0)=0 THEN 1
                WHEN COALESCE(receive_sum.received_qty, 0)+COALESCE(receive_sum.scrap_qty, 0) < {order_qty_expr} THEN 2
                ELSE 3
            END,
            sc.id DESC
        LIMIT 120
        """,
        tuple(params),
    )
    enhanced_rows = []
    for row in rows:
        item = dict(row)
        item["execution_status"], item["next_step"], item["owner_role"] = _subcontract_execution_state(item)
        item["issue_action"] = "发料"
        item["receive_action"] = "收货"
        item["payable_action"] = "应付"
        enhanced_rows.append(item)
    return render_template(
        "simple_list.html",
        title="委外订单列表",
        subtitle="按委外单、加工商、项目号、机号、发料数量、收货数量和未收数量追踪外协闭环。",
        rows=enhanced_rows,
        columns=_columns(
            ("order_no", "委外单"),
            ("order_date", "日期"),
            ("supplier_name", "加工商"),
            ("project_code", "项目号"),
            ("serial_no", "机号"),
            ("quantity", "委外数量"),
            ("issued_qty", "发料数量"),
            ("received_qty", "收货数量"),
            ("pending_receive_qty", "未收数量"),
            ("payable_amount", "应付金额"),
            ("payable_balance", "应付余额"),
            ("status", "单据状态"),
            ("execution_status", "执行状态"),
            ("next_step", "下一步"),
            ("owner_role", "责任"),
            ("issue_action", "发料入口"),
            ("receive_action", "收货入口"),
            ("payable_action", "应付入口"),
        ),
        detail_base="/subcontract",
    )


def _subcontract_status_label(status):
    value = (status or "").strip()
    labels = {
        "新建": "新建",
        "pending": "待发料",
        "draft": "草稿",
        "已下达": "已下达",
        "issued": "已发料",
        "processing": "加工中",
        "partial_received": "部分收货",
        "completed": "已完成",
        "已完成": "已完成",
        "closed": "已关闭",
        "已关闭": "已关闭",
        "cancelled": "已作废",
        "已作废": "已作废",
        "void": "已作废",
    }
    return labels.get(value, value or "未定")


def _subcontract_summary(order_id):
    order = _safe_one(
        """
        SELECT sc.id, sc.order_no, sc.order_date, sc.required_date, sc.project_code, sc.serial_no,
               sc.product_id,
               COALESCE(sc.quantity, 0) AS quantity, COALESCE(sc.unit_price, 0) AS unit_price,
               COALESCE(sc.total_amount, 0) AS total_amount, sc.status, sc.remark,
               COALESCE(s.name, sc.supplier_id::text, '-') AS supplier_name,
               COALESCE(p.code, '') AS product_code, COALESCE(p.name, '') AS product_name,
               COALESCE(p.specification, '') AS specification,
               COALESCE(p.unit, '') AS unit,
               COALESCE(p.unit, '') AS unit_name,
               COALESCE(issue_sum.issued_qty, 0) AS issued_qty,
               COALESCE(receive_sum.received_qty, 0) AS received_qty,
               COALESCE(receive_sum.scrap_qty, 0) AS scrap_qty,
               GREATEST(COALESCE(sc.quantity, 0) - COALESCE(receive_sum.received_qty, 0) - COALESCE(receive_sum.scrap_qty, 0), 0) AS open_qty,
               COALESCE(payable_sum.payable_amount, 0) AS payable_amount,
               COALESCE(payable_sum.payable_balance, 0) AS payable_balance
        FROM subcontract_orders sc
        LEFT JOIN suppliers s ON s.id=sc.supplier_id
        LEFT JOIN products p ON p.id=sc.product_id
        LEFT JOIN LATERAL (
            SELECT COALESCE(SUM(total_quantity), 0) AS issued_qty
            FROM subcontract_issue_orders sio
            WHERE sio.subcontract_order_id=sc.id
              AND COALESCE(sio.status, '') NOT IN ('已作废','void','cancelled')
        ) issue_sum ON TRUE
        LEFT JOIN LATERAL (
            SELECT COALESCE(SUM(total_quantity), 0) AS received_qty,
                   COALESCE(SUM(total_scrap), 0) AS scrap_qty
            FROM subcontract_receive_orders sro
            WHERE sro.subcontract_order_id=sc.id
              AND COALESCE(sro.status, '') NOT IN ('已作废','void','cancelled')
        ) receive_sum ON TRUE
        LEFT JOIN LATERAL (
            SELECT COALESCE(SUM(amount), 0) AS payable_amount,
                   COALESCE(SUM(balance), 0) AS payable_balance
            FROM supplier_payables sp
            WHERE sp.doc_type='subcontract_order'
              AND (sp.doc_id=sc.id OR sp.doc_no=sc.order_no)
        ) payable_sum ON TRUE
        WHERE sc.id=%s
        """,
        (order_id,),
    )
    if not order:
        return None
    item = dict(order)
    item["status_label"] = _subcontract_status_label(item.get("status"))
    item["execution_status"], item["next_step"], item["owner_role"] = _subcontract_execution_state(item)
    return item


def _render_subcontract_detail(order_id, back_url="/subcontract"):
    order = _subcontract_summary(order_id)
    if not order:
        return render_template("simple_detail.html", title="委外订单详情", row=None, back_url=back_url, labels={})
    issue_rows = _safe_rows(
        """
        SELECT sio.id, sio.issue_no, sio.date, sio.status, sio.total_quantity, sio.remark,
               COALESCE(u.username, '') AS operator_name
        FROM subcontract_issue_orders sio
        LEFT JOIN users u ON u.id=sio.operator_id
        WHERE sio.subcontract_order_id=%s
        ORDER BY sio.id DESC
        LIMIT 50
        """,
        (order_id,),
    )
    receive_rows = _safe_rows(
        """
        SELECT sro.id, sro.receive_no, sro.date, sro.status, sro.total_quantity, sro.total_scrap, sro.remark,
               COALESCE(u.username, '') AS operator_name
        FROM subcontract_receive_orders sro
        LEFT JOIN users u ON u.id=sro.operator_id
        WHERE sro.subcontract_order_id=%s
        ORDER BY sro.id DESC
        LIMIT 50
        """,
        (order_id,),
    )
    payable_rows = _safe_rows(
        """
        SELECT id, doc_no, doc_date, amount, paid_amount, balance, status
        FROM supplier_payables
        WHERE doc_type='subcontract_order' AND (doc_id=%s OR doc_no=%s)
        ORDER BY id DESC
        LIMIT 20
        """,
        (order_id, order.get("order_no")),
    )
    return render_template(
        "subcontract_execution_detail.html",
        order=order,
        issue_rows=issue_rows,
        receive_rows=receive_rows,
        payable_rows=payable_rows,
        back_url=back_url,
    )


def _subcontract_order_options():
    return _filter_clean_rows(
        _safe_rows(
            """
            SELECT sc.id, sc.order_no, sc.supplier_id, COALESCE(s.name, '') AS supplier_name,
                   sc.project_code, sc.serial_no, sc.product_id,
                   COALESCE(p.code, '') AS product_code, COALESCE(p.name, '') AS product_name,
                   COALESCE(p.specification, '') AS specification, COALESCE(p.unit, '') AS unit,
                   COALESCE(sc.quantity, 0) AS quantity,
                   GREATEST(COALESCE(sc.quantity,0)-COALESCE(receive_sum.received_qty,0)-COALESCE(receive_sum.scrap_qty,0),0) AS open_qty
            FROM subcontract_orders sc
            LEFT JOIN suppliers s ON s.id=sc.supplier_id
            LEFT JOIN products p ON p.id=sc.product_id
            LEFT JOIN LATERAL (
                SELECT COALESCE(SUM(total_quantity),0) AS received_qty, COALESCE(SUM(total_scrap),0) AS scrap_qty
                FROM subcontract_receive_orders sro
                WHERE sro.subcontract_order_id=sc.id AND COALESCE(sro.status,'') NOT IN ('已作废','void','cancelled')
            ) receive_sum ON TRUE
            WHERE COALESCE(sc.status, '') NOT IN ('已作废','void','cancelled','已关闭','closed')
            ORDER BY sc.id DESC
            LIMIT 1000
            """
        ),
        "order_no",
        "supplier_name",
        "project_code",
        "serial_no",
        "product_code",
        "product_name",
    )


