def _save_subcontract_issue_order():
    save_action = _form_text("save_action", "save")
    if save_action == "unaudit":
        flash("反审请在已审核过账的委外发料单详情页执行。", "warning")
        return redirect("/subcontract_issue/new")
    order_id = _form_int("subcontract_order_id")
    order = _subcontract_summary(order_id) if order_id else None
    if not order:
        flash("请选择有效的委外订单。", "warning")
        return redirect("/subcontract_issue/new")
    quantity = _form_decimal("quantity", "0")
    if quantity <= 0:
        flash("发料数量必须大于 0。", "warning")
        return redirect(f"/subcontract_issue/new?subcontract_order_id={order_id}")
    line_warehouse_ids = request.form.getlist("line_warehouse_id[]")
    line_location_ids = request.form.getlist("line_location_id[]")
    issue_warehouse_id = _as_int(line_warehouse_ids[0]) if line_warehouse_ids else 0
    issue_location_id = _as_int(line_location_ids[0]) if line_location_ids else 0
    if not issue_warehouse_id:
        flash("请选择发料明细仓库。", "warning")
        return redirect(f"/subcontract_issue/new?subcontract_order_id={order_id}")
    if issue_location_id and not _warehouse_has_locations(issue_warehouse_id):
        issue_location_id = 0
    issue_no = _next_daily_doc_no("OSI", "subcontract_issue_orders", "issue_no")
    row = _execute_and_return(
        """
        INSERT INTO subcontract_issue_orders
            (issue_no, date, subcontract_order_id, supplier_id, status, total_quantity, warehouse_id, location_id, remark, operator_id, updated_at)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,CURRENT_TIMESTAMP)
        RETURNING id
        """,
        (
            issue_no,
            _form_text("date", datetime.now().date().isoformat()),
            order_id,
            order.get("supplier_id"),
            "pending",
            quantity,
            issue_warehouse_id,
            issue_location_id,
            _form_text("remark"),
            session.get("user_id"),
        ),
    )
    if not row:
        flash("委外发料单创建失败。", "danger")
        return redirect(f"/subcontract_issue/new?subcontract_order_id={order_id}")
    issue_id = row["id"] if isinstance(row, dict) else row[0]
    _execute_db(
        """
        INSERT INTO subcontract_issue_lines
            (issue_id, subcontract_order_id, product_id, material_code, material_name, material_spec, unit,
             quantity, warehouse_id, location_id, lot_no, project_code, serial_no, remark)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        """,
        (
            issue_id,
            order_id,
            order.get("product_id"),
            order.get("product_code"),
            order.get("product_name"),
            order.get("specification"),
            order.get("unit"),
            quantity,
            issue_warehouse_id,
            issue_location_id,
            _form_text("lot_no"),
            order.get("project_code"),
            order.get("serial_no"),
            _form_text("remark"),
        ),
    )
    _log_action("新增委外发料单", issue_no)
    if save_action == "save_new":
        flash(f"已新增委外发料单 {issue_no}。", "success")
        return redirect("/subcontract_issue/new")
    flash(f"已新增委外发料单 {issue_no}。", "success")
    return redirect(f"/subcontract_issue/{issue_id}")


def _edit_subcontract_issue_order(issue_id):
    save_action = _form_text("save_action", "save")
    if save_action == "unaudit":
        return _update_subcontract_document_status("issue", issue_id, "unaudit")
    issue = _safe_one("SELECT * FROM subcontract_issue_orders WHERE id=%s", (issue_id,))
    if not issue:
        flash("委外发料单不存在。", "warning")
        return redirect("/subcontract_issue")
    if not _document_can_edit_status(issue.get("status"), {"", "pending", "draft", "新建", "草稿", "待发料"}):
        flash("委外发料单已提交、已审核、已作废或已有下游影响，不能普通编辑。", "warning")
        return redirect(f"/subcontract_issue/{issue_id}")
    order_id = _form_int("subcontract_order_id")
    order = _subcontract_summary(order_id) if order_id else None
    if not order:
        flash("请选择有效的委外订单。", "warning")
        return redirect(f"/subcontract_issue/{issue_id}/edit")
    quantity = _form_decimal("quantity", "0")
    if quantity <= 0:
        flash("发料数量必须大于 0。", "warning")
        return redirect(f"/subcontract_issue/{issue_id}/edit")
    line_warehouse_ids = request.form.getlist("line_warehouse_id[]")
    line_location_ids = request.form.getlist("line_location_id[]")
    issue_warehouse_id = _as_int(line_warehouse_ids[0]) if line_warehouse_ids else 0
    issue_location_id = _as_int(line_location_ids[0]) if line_location_ids else 0
    if not issue_warehouse_id:
        flash("请选择发料明细仓库。", "warning")
        return redirect(f"/subcontract_issue/{issue_id}/edit")
    if issue_location_id and not _warehouse_has_locations(issue_warehouse_id):
        issue_location_id = 0
    _execute_db(
        """
        UPDATE subcontract_issue_orders
        SET date=%s, subcontract_order_id=%s, supplier_id=%s, total_quantity=%s,
            warehouse_id=%s, location_id=%s, remark=%s, operator_id=%s, updated_at=CURRENT_TIMESTAMP
        WHERE id=%s
        """,
        (_form_text("date", datetime.now().date().isoformat()), order_id, order.get("supplier_id"), quantity, issue_warehouse_id, issue_location_id, _form_text("remark"), session.get("user_id"), issue_id),
    )
    _execute_db("DELETE FROM subcontract_issue_lines WHERE issue_id=%s", (issue_id,))
    _execute_db(
        """
        INSERT INTO subcontract_issue_lines
            (issue_id, subcontract_order_id, product_id, material_code, material_name, material_spec, unit,
             quantity, warehouse_id, location_id, lot_no, project_code, serial_no, remark)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        """,
        (issue_id, order_id, order.get("product_id"), order.get("product_code"), order.get("product_name"), order.get("specification"), order.get("unit"), quantity, issue_warehouse_id, issue_location_id, _form_text("lot_no"), order.get("project_code"), order.get("serial_no"), _form_text("remark")),
    )
    _log_action("编辑委外发料单", issue.get("issue_no") or str(issue_id))
    flash("委外发料单已保存，尚未审核过账。", "success")
    return redirect(f"/subcontract_issue/{issue_id}")


def _save_subcontract_receive_order():
    save_action = _form_text("save_action", "save")
    if save_action == "unaudit":
        flash("反审请在已审核过账的委外收货单详情页执行。", "warning")
        return redirect("/subcontract_receive/new")
    order_id = _form_int("subcontract_order_id")
    order = _subcontract_summary(order_id) if order_id else None
    if not order:
        flash("请选择有效的委外订单。", "warning")
        return redirect("/subcontract_receive/new")
    good_qty = _form_decimal("quantity", "0")
    scrap_qty = _form_decimal("scrap_quantity", "0")
    short_qty = _form_decimal("short_quantity", "0")
    if good_qty <= 0 and scrap_qty <= 0 and short_qty <= 0:
        flash("收货数量或报废数量必须大于 0。", "warning")
        return redirect(f"/subcontract_receive/new?subcontract_order_id={order_id}")
    receive_no = _next_daily_doc_no("OSR", "subcontract_receive_orders", "receive_no")
    row = _execute_and_return(
        """
        INSERT INTO subcontract_receive_orders
            (receive_no, date, subcontract_order_id, supplier_id, status, total_quantity, total_scrap,
             short_qty, scrap_qty, warehouse_id, location_id, remark, operator_id, updated_at)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,CURRENT_TIMESTAMP)
        RETURNING id
        """,
        (
            receive_no,
            _form_text("date", datetime.now().date().isoformat()),
            order_id,
            order.get("supplier_id"),
            "pending",
            good_qty,
            scrap_qty,
            short_qty,
            scrap_qty,
            _form_int("warehouse_id"),
            _form_int("location_id"),
            _form_text("remark"),
            session.get("user_id"),
        ),
    )
    if not row:
        flash("委外收货单创建失败。", "danger")
        return redirect(f"/subcontract_receive/new?subcontract_order_id={order_id}")
    receive_id = row["id"] if isinstance(row, dict) else row[0]
    # 行级仓库/库位优先；为空时回退表头仓库/库位；仓库未启用库位时清空库位避免脏值
    line_warehouse_ids = request.form.getlist("line_warehouse_id[]")
    line_location_ids = request.form.getlist("line_location_id[]")
    line_warehouse_id = _as_int(line_warehouse_ids[0]) if line_warehouse_ids else 0
    line_location_id = _as_int(line_location_ids[0]) if line_location_ids else 0
    recv_warehouse_id = line_warehouse_id or _form_int("warehouse_id")
    recv_location_id = line_location_id or _form_int("location_id")
    if recv_location_id and not _warehouse_has_locations(recv_warehouse_id):
        recv_location_id = 0
    _execute_db(
        """
        INSERT INTO subcontract_receive_lines
            (receive_id, subcontract_order_id, product_id, material_code, material_name, material_spec, unit,
             quantity, scrap_quantity, warehouse_id, location_id, lot_no, project_code, serial_no, remark)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        """,
        (
            receive_id,
            order_id,
            order.get("product_id"),
            order.get("product_code"),
            order.get("product_name"),
            order.get("specification"),
            order.get("unit"),
            good_qty,
            scrap_qty,
            recv_warehouse_id,
            recv_location_id,
            _form_text("lot_no"),
            order.get("project_code"),
            order.get("serial_no"),
            _form_text("remark"),
        ),
    )
    new_received = _as_decimal(order.get("received_qty")) + good_qty
    new_open = max(_as_decimal(order.get("quantity")) - new_received - (_as_decimal(order.get("scrap_qty")) + scrap_qty) - short_qty, Decimal("0"))
    _execute_db(
        """
        UPDATE subcontract_orders
        SET status=%s, arrival_status=%s, received_qty=%s, shortage_qty=%s, updated_at=CURRENT_TIMESTAMP
        WHERE id=%s
        """,
        ("partial_received" if new_open > 0 else "completed", "部分回厂" if new_open > 0 else "已回厂", new_received, new_open, order_id),
    )
    _log_action("新增委外收货单", receive_no)
    flash(f"已新增委外收货单 {receive_no}。", "success")
    return redirect(f"/subcontract_receive/{receive_id}")


