def _subcontract_status_key(value):
    text = (value or "").strip()
    labels = {
        "pending": "pending",
        "草稿": "pending",
        "新建": "pending",
        "submitted": "submitted",
        "已提交": "submitted",
        "audited": "audited",
        "已审核": "audited",
        "completed": "audited",
        "已完成": "audited",
        "void": "void",
        "voided": "void",
        "已作废": "void",
        "cancelled": "void",
    }
    return labels.get(text, text)


def _subcontract_document_status_label(value):
    labels = {
        "pending": "草稿",
        "草稿": "草稿",
        "新建": "草稿",
        "submitted": "已提交",
        "已提交": "已提交",
        "audited": "已审核",
        "已审核": "已审核",
        "completed": "已完成",
        "已完成": "已完成",
        "void": "已作废",
        "voided": "已作废",
        "已作废": "已作废",
        "cancelled": "已作废",
    }
    text = (value or "").strip()
    return labels.get(text, text or "未定")


def _subcontract_line_rows(kind, doc_id, query_one=None, query_rows=None):
    query_one = query_one or _safe_one
    query_rows = query_rows or _safe_rows
    if kind == "issue":
        rows = query_rows(
            """
            SELECT sil.*, COALESCE(sil.product_id, sc.product_id) AS product_id,
                   COALESCE(p.code, '') AS product_code,
                   COALESCE(p.name, '') AS product_name,
                   COALESCE(p.specification, '') AS specification,
                   COALESCE(p.unit, '') AS unit,
                   COALESCE(w.name, '') AS warehouse_name,
                   COALESCE(l.code, '') AS location_code,
                   COALESCE(l.name, '') AS location_name,
                   COALESCE(NULLIF(sil.project_code, ''), sc.project_code) AS project_code,
                   COALESCE(NULLIF(sil.serial_no, ''), sc.serial_no) AS serial_no,
                   COALESCE(sio.issue_no, '') AS doc_no, sio.date AS doc_date
            FROM subcontract_issue_lines sil
            JOIN subcontract_issue_orders sio ON sio.id=sil.issue_id
            LEFT JOIN subcontract_orders sc ON sc.id=sio.subcontract_order_id
            LEFT JOIN products p ON p.id=COALESCE(sil.product_id, sc.product_id)
            LEFT JOIN warehouses w ON w.id=sil.warehouse_id
            LEFT JOIN locations l ON l.id=sil.location_id
            WHERE sil.issue_id=%s
            ORDER BY sil.id
            """,
            (doc_id,),
        )
        if rows:
            return rows
        row = query_one(
            """
            SELECT sio.id AS issue_id, sio.subcontract_order_id, sc.product_id,
                   p.code AS material_code, p.name AS material_name, p.specification AS material_spec,
                   p.unit, sio.total_quantity AS quantity, sio.warehouse_id, sio.location_id,
                   w.name AS warehouse_name, l.code AS location_code, l.name AS location_name,
                   sio.issue_no AS doc_no, sio.date AS doc_date, sc.project_code, sc.serial_no, sio.remark
            FROM subcontract_issue_orders sio
            LEFT JOIN subcontract_orders sc ON sc.id=sio.subcontract_order_id
            LEFT JOIN products p ON p.id=sc.product_id
            LEFT JOIN warehouses w ON w.id=sio.warehouse_id
            LEFT JOIN locations l ON l.id=sio.location_id
            WHERE sio.id=%s
            """,
            (doc_id,),
        )
        return [row] if row else []
    rows = query_rows(
        """
        SELECT srl.*, COALESCE(srl.product_id, sc.product_id) AS product_id,
               COALESCE(p.code, '') AS product_code,
               COALESCE(p.name, '') AS product_name,
               COALESCE(p.specification, '') AS specification,
               COALESCE(p.unit, '') AS unit,
               COALESCE(w.name, '') AS warehouse_name,
               COALESCE(l.code, '') AS location_code,
               COALESCE(l.name, '') AS location_name,
               COALESCE(NULLIF(srl.project_code, ''), sc.project_code) AS project_code,
               COALESCE(NULLIF(srl.serial_no, ''), sc.serial_no) AS serial_no,
               COALESCE(sro.receive_no, '') AS doc_no, sro.date AS doc_date
        FROM subcontract_receive_lines srl
        JOIN subcontract_receive_orders sro ON sro.id=srl.receive_id
        LEFT JOIN subcontract_orders sc ON sc.id=sro.subcontract_order_id
        LEFT JOIN products p ON p.id=COALESCE(srl.product_id, sc.product_id)
        LEFT JOIN warehouses w ON w.id=srl.warehouse_id
        LEFT JOIN locations l ON l.id=srl.location_id
        WHERE srl.receive_id=%s
        ORDER BY srl.id
        """,
        (doc_id,),
    )
    if rows:
        return rows
    row = query_one(
        """
        SELECT sro.id AS receive_id, sro.subcontract_order_id, sc.product_id,
               p.code AS material_code, p.name AS material_name, p.specification AS material_spec,
               p.unit, sro.total_quantity AS quantity, sro.total_scrap AS scrap_quantity,
               sro.warehouse_id, sro.location_id, sro.receive_no AS doc_no, sro.date AS doc_date,
               w.name AS warehouse_name, l.code AS location_code, l.name AS location_name,
               sc.project_code, sc.serial_no, sro.remark
        FROM subcontract_receive_orders sro
        LEFT JOIN subcontract_orders sc ON sc.id=sro.subcontract_order_id
        LEFT JOIN products p ON p.id=sc.product_id
        LEFT JOIN warehouses w ON w.id=sro.warehouse_id
        LEFT JOIN locations l ON l.id=sro.location_id
        WHERE sro.id=%s
        """,
        (doc_id,),
    )
    return [row] if row else []


def _post_subcontract_inventory(kind, doc_id, reverse=False, query_one=None, query_rows=None, execute_db_fn=None):
    query_one = query_one or _safe_one
    query_rows = query_rows or _safe_rows
    execute_db_fn = execute_db_fn or _execute_db
    rows = _subcontract_line_rows(kind, doc_id, query_one=query_one, query_rows=query_rows)
    for row in rows:
        product_id = row.get("product_id")
        if not product_id:
            continue
        qty = _as_decimal(row.get("quantity"))
        if qty <= 0:
            continue
        doc_no = row.get("doc_no") or ""
        tx_date = row.get("doc_date") or datetime.now().date().isoformat()
        remark = row.get("remark") or ("委外反审核冲回" if reverse else "委外审核过账")
        if kind == "issue":
            if reverse:
                inventory_inbound_weighted_avg(query_one, execute_db_fn, product_id, qty, 0, "", doc_no, remark, tx_date, "subcontract_issue_reverse")
            else:
                inventory_outbound(query_one, execute_db_fn, product_id, qty, "", doc_no, remark, tx_date, "subcontract_issue", lot_no=row.get("lot_no") or "", serial_no=row.get("serial_no") or "")
        else:
            if reverse:
                inventory_outbound(query_one, execute_db_fn, product_id, qty, "", doc_no, remark, tx_date, "subcontract_receive_reverse", lot_no=row.get("lot_no") or "", serial_no=row.get("serial_no") or "")
            else:
                inventory_inbound_weighted_avg(query_one, execute_db_fn, product_id, qty, 0, "", doc_no, remark, tx_date, "subcontract_receive", lot_no=row.get("lot_no") or "", serial_no=row.get("serial_no") or "")
        # Link the subcontract document to the inventory movement for traceability.
        st_row = query_one(
            "SELECT id FROM stock_transactions WHERE reference_no=%s AND product_id=%s ORDER BY id DESC LIMIT 1",
            (doc_no, product_id),
        ) or {}
        st_id = st_row.get("id")
        if st_id:
            source_doc_type = "subcontract_issue" if kind == "issue" else "subcontract_receive"
            try:
                create_trace_link(
                    query_one,
                    execute_db_fn,
                    source_doc_type=source_doc_type,
                    source_doc_id=doc_id,
                    source_doc_no=doc_no,
                    target_doc_type="stock_transaction",
                    target_doc_id=st_id,
                    link_type="reverses" if reverse else "posts_to",
                    link_strength="soft",
                    project_code=row.get("project_code"),
                    serial_no=row.get("serial_no"),
                    created_by=None,
                    created_event="subcontract_inventory",
                )
            except Exception:
                current_app.logger.exception("Subcontract traceability link failed for doc_no=%s", doc_no)


def _sync_subcontract_receive_work_order_cost(receive_id, query_one=None, query_rows=None, execute_db_fn=None):
    query_one = query_one or _safe_one
    query_rows = query_rows or _safe_rows
    execute_db_fn = execute_db_fn or _execute_db
    row = query_one(
        """
        SELECT sro.receive_no, sc.parent_work_order_id
        FROM subcontract_receive_orders sro
        LEFT JOIN subcontract_orders sc ON sc.id=sro.subcontract_order_id
        WHERE sro.id=%s
        """,
        (receive_id,),
    )
    if not row or not row.get("parent_work_order_id"):
        return {"synced": False, "reason": "missing_parent_work_order"}
    return sync_work_order_costs(
        query_one,
        query_rows,
        execute_db_fn,
        row.get("parent_work_order_id"),
        source_type="subcontract_receive",
        source_no=row.get("receive_no"),
        remark="subcontract receive audit cost sync",
    )


def _update_subcontract_document_status(kind, doc_id, action):
    config = {
        "issue": {
            "table": "subcontract_issue_orders",
            "no_field": "issue_no",
            "detail": "/subcontract_issue",
            "label": "委外发料单",
            "log": {"submit": "提交委外发料单", "audit": "审核委外发料单", "unaudit": "反审核委外发料单", "void": "作废委外发料单"},
        },
        "receive": {
            "table": "subcontract_receive_orders",
            "no_field": "receive_no",
            "detail": "/subcontract_receive",
            "label": "委外收货单",
            "log": {"submit": "提交委外收货单", "audit": "审核委外收货单", "unaudit": "反审核委外收货单", "void": "作废委外收货单"},
        },
    }[kind]
    row = _safe_one(f"SELECT * FROM {config['table']} WHERE id=%s", (doc_id,))
    if not row:
        flash(f"{config['label']}不存在。", "warning")
        return redirect(config["detail"])
    status = _subcontract_status_key(row.get("status"))
    doc_no = row.get(config["no_field"])
    if action == "submit":
        if status != "pending":
            flash("只有草稿/待处理单据可以提交。", "warning")
        else:
            _execute_db(
                f"UPDATE {config['table']} SET status='submitted', submitted_by=%s, submitted_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                (session.get("user_id"), doc_id),
            )
            _log_action(config["log"][action], doc_no)
            flash("单据已提交。", "success")
    elif action == "audit":
        if status not in {"submitted"}:
            flash("只有已提交单据可以审核。", "warning")
        else:
            def operation(cursor):
                query_db, execute_db, _ = cursor_db_helpers(cursor)
                query_one = lambda sql, params=None: query_db(sql, params, one=True)
                locked = query_one(f"SELECT * FROM {qident(config['table'])} WHERE id=%s FOR UPDATE", (doc_id,))
                if not locked:
                    return "missing"
                if _subcontract_status_key(locked.get("status")) != "submitted":
                    return "status_changed"
                _post_subcontract_inventory(kind, doc_id, reverse=False, query_one=query_one, query_rows=query_db, execute_db_fn=execute_db)
                if kind == "issue" and locked.get("subcontract_order_id"):
                    execute_db(
                        "UPDATE subcontract_orders SET status=%s, arrival_status=%s, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                        ("released", "已发料", locked.get("subcontract_order_id")),
                    )
                if kind == "receive":
                    sc_row = query_one(
                        """
                        SELECT COALESCE(sro.supplier_id, sc.supplier_id) AS supplier_id,
                               sro.total_quantity, sro.date,
                               sro.receive_no, sc.order_no AS subcontract_no,
                               sc.unit_price, sc.project_code, sc.serial_no, sc.cost_object_id
                        FROM subcontract_receive_orders sro
                        LEFT JOIN subcontract_orders sc ON sc.id=sro.subcontract_order_id
                        WHERE sro.id=%s
                        """,
                        (doc_id,),
                    )
                    if sc_row and sc_row.get("supplier_id"):
                        amount = _as_decimal(sc_row.get("total_quantity")) * _as_decimal(sc_row.get("unit_price"))
                        execute_db(
                            """
                            INSERT INTO supplier_payables
                                (supplier_id, payable_no, doc_type, doc_id, doc_no, doc_date, amount, paid_amount, balance, status, finance_remark, project_code, serial_no)
                            VALUES (%s,%s,'subcontract_receive',%s,%s,%s,%s,0,%s,%s,%s,%s,%s)
                            ON CONFLICT (doc_type, doc_id) WHERE doc_type IS NOT NULL AND doc_id IS NOT NULL DO NOTHING
                            """,
                            (
                                sc_row["supplier_id"],
                                _next_doc_no("AP", "supplier_payables", "payable_no"),
                                doc_id,
                                sc_row.get("receive_no"),
                                sc_row.get("date"),
                                amount,
                                amount,
                                "\u672a\u4ed8\u6b3e",
                                f"subcontract receive audit generated from {sc_row.get('subcontract_no') or ''}",
                                sc_row.get("project_code"),
                                sc_row.get("serial_no"),
                            ),
                        )
                    _sync_subcontract_receive_work_order_cost(doc_id, query_one=query_one, query_rows=query_db, execute_db_fn=execute_db)
                execute_db(
                    f"UPDATE {qident(config['table'])} SET status='audited', audited_by=%s, audited_at=CURRENT_TIMESTAMP, posted=TRUE, posted_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                    (session.get("user_id"), doc_id),
                )
                return "audited"

            result = current_app.extensions["run_in_transaction"](operation)
            if result == "missing":
                flash("\u59d4\u5916\u5355\u636e\u4e0d\u5b58\u5728\u3002", "warning")
                return redirect(config["detail"])
            if result == "status_changed":
                flash("\u5355\u636e\u72b6\u6001\u5df2\u53d8\u66f4\uff0c\u8bf7\u5237\u65b0\u540e\u91cd\u8bd5\u3002", "warning")
                return redirect(f"{config['detail']}/{doc_id}")
            _log_action(config["log"][action], doc_no)
            flash("\u5355\u636e\u5df2\u5ba1\u6838\uff0c\u5e93\u5b58\u6d41\u6c34\u548c\u5e94\u4ed8\u8d26\u6b3e\u5df2\u767b\u8bb0\u3002", "success")
            return redirect(f"{config['detail']}/{doc_id}")
    elif action == "unaudit":
        if status != "audited":
            flash("只有已审核单据可以反审核。", "warning")
        elif not row.get("posted"):
            flash("该历史单据没有本系统审核过账标记，不能直接反审核冲回库存。", "warning")
        else:
            def operation(cursor):
                query_db, execute_db, _ = cursor_db_helpers(cursor)
                query_one = lambda sql, params=None: query_db(sql, params, one=True)
                locked = query_one(f"SELECT * FROM {qident(config['table'])} WHERE id=%s FOR UPDATE", (doc_id,))
                if not locked:
                    return "missing"
                if _subcontract_status_key(locked.get("status")) != "audited":
                    return "status_changed"
                if not locked.get("posted"):
                    return "not_posted"
                _post_subcontract_inventory(kind, doc_id, reverse=True, query_one=query_one, query_rows=query_db, execute_db_fn=execute_db)
                if kind == "issue" and locked.get("subcontract_order_id"):
                    other_issue = query_one(
                        """
                        SELECT id
                        FROM subcontract_issue_orders
                        WHERE subcontract_order_id=%s
                          AND id<>%s
                          AND COALESCE(status,'') IN ('audited','已审核')
                          AND COALESCE(posted,FALSE)=TRUE
                        LIMIT 1
                        """,
                        (locked.get("subcontract_order_id"), doc_id),
                    )
                    if not other_issue:
                        execute_db(
                            "UPDATE subcontract_orders SET status=%s, arrival_status=%s, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                            ("pending", "待发料", locked.get("subcontract_order_id")),
                        )
                if kind == "receive":
                    execute_db(
                        """
                        UPDATE supplier_payables
                        SET amount=0,
                            balance=0,
                            confirmed_amount=0,
                            variance_amount=0,
                            status='void',
                            finance_remark=COALESCE(finance_remark, '') || E'\nsubcontract receive unaudit reversed payable'
                        WHERE doc_type='subcontract_receive' AND doc_id=%s
                        """,
                        (doc_id,),
                    )
                execute_db(
                    f"UPDATE {qident(config['table'])} SET status='submitted', audited_by=NULL, audited_at=NULL, posted=FALSE, reverse_posted_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                    (doc_id,),
                )
                if kind == "receive":
                    _sync_subcontract_receive_work_order_cost(doc_id, query_one=query_one, query_rows=query_db, execute_db_fn=execute_db)
                return "unaudited"

            result = current_app.extensions["run_in_transaction"](operation)
            if result == "missing":
                flash("\u59d4\u5916\u5355\u636e\u4e0d\u5b58\u5728\u3002", "warning")
                return redirect(config["detail"])
            if result == "status_changed":
                flash("\u5355\u636e\u72b6\u6001\u5df2\u53d8\u66f4\uff0c\u8bf7\u5237\u65b0\u540e\u91cd\u8bd5\u3002", "warning")
                return redirect(f"{config['detail']}/{doc_id}")
            if result == "not_posted":
                flash("\u8be5\u5355\u636e\u6ca1\u6709\u672c\u7cfb\u7edf\u8fc7\u8d26\u6807\u8bb0\uff0c\u4e0d\u80fd\u76f4\u63a5\u53cd\u5ba1\u6838\u3002", "warning")
                return redirect(f"{config['detail']}/{doc_id}")
            _log_action(config["log"][action], doc_no)
            flash("\u5355\u636e\u5df2\u53cd\u5ba1\u6838\uff0c\u5e76\u5199\u5165\u53cd\u5411\u5e93\u5b58\u6d41\u6c34\u3002", "success")
            return redirect(f"{config['detail']}/{doc_id}")
            _post_subcontract_inventory(kind, doc_id, reverse=True)
            if kind == "receive":
                _execute_db(
                    """
                    UPDATE supplier_payables
                    SET amount=0,
                        balance=0,
                        confirmed_amount=0,
                        variance_amount=0,
                        status='void',
                        finance_remark=COALESCE(finance_remark, '') || E'\nsubcontract receive unaudit reversed payable'
                    WHERE doc_type='subcontract_receive' AND doc_id=%s
                    """,
                    (doc_id,),
                )
            _execute_db(
                f"UPDATE {qident(config['table'])} SET status='submitted', audited_by=NULL, audited_at=NULL, posted=FALSE, reverse_posted_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                (doc_id,),
            )
            if kind == "receive":
                _sync_subcontract_receive_work_order_cost(doc_id)
            _log_action(config["log"][action], doc_no)
            flash("单据已反审核，并写入反向库存流水。", "success")
    elif action == "void":
        if status == "audited":
            flash("已审核单据需先反审核，不能直接作废。", "warning")
        elif status == "void":
            flash("单据已作废。", "info")
        else:
            _execute_db(
                f"UPDATE {config['table']} SET status='void', voided_by=%s, voided_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                (session.get("user_id"), doc_id),
            )
            _log_action(config["log"][action], doc_no)
            flash("单据已作废。", "success")
    return redirect(f"{config['detail']}/{doc_id}")


def _delete_subcontract_document_draft(kind, doc_id):
    config = {
        "issue": {
            "table": "subcontract_issue_orders",
            "line_table": "subcontract_issue_lines",
            "line_fk": "issue_id",
            "no_field": "issue_no",
            "detail": "/subcontract_issue",
            "label": "委外发料单",
        },
        "receive": {
            "table": "subcontract_receive_orders",
            "line_table": "subcontract_receive_lines",
            "line_fk": "receive_id",
            "no_field": "receive_no",
            "detail": "/subcontract_receive",
            "label": "委外收货单",
        },
    }[kind]
    row = _safe_one(f"SELECT * FROM {config['table']} WHERE id=%s", (doc_id,))
    if not row:
        flash(f"{config['label']}不存在或已删除。", "warning")
        return redirect(config["detail"])
    status = _subcontract_status_key(row.get("status"))
    doc_no = row.get(config["no_field"]) or str(doc_id)
    if status == "audited" or row.get("posted"):
        flash(f"已审核{config['label']}不能直接删除，请先反审。", "warning")
        return redirect(f"{config['detail']}/{doc_id}")
    if status in {"void", "legacy_completed"}:
        flash(f"已作废或已完成{config['label']}不能删除。", "warning")
        return redirect(f"{config['detail']}/{doc_id}")
    if _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s OR source_doc_no=%s LIMIT 1", (doc_no, doc_no)):
        flash(f"该{config['label']}已有库存流水，不能直接删除，请先反审。", "warning")
        return redirect(f"{config['detail']}/{doc_id}")

    def operation(_cursor):
        _execute_db(f"DELETE FROM {config['line_table']} WHERE {config['line_fk']}=%s", (doc_id,))
        _execute_db(f"DELETE FROM {config['table']} WHERE id=%s", (doc_id,))

    _run_registry_transaction(operation)
    _log_action(f"删除{config['label']}草稿", doc_no)
    flash(f"{config['label']} {doc_no} 已删除。", "success")
    return redirect(config["detail"])


def _render_subcontract_document_print(kind, doc_id):
    if kind == "issue":
        order = _safe_one(
            """
            SELECT sio.*, sc.order_no, sc.project_code, sc.serial_no, s.name AS partner_name
            FROM subcontract_issue_orders sio
            LEFT JOIN subcontract_orders sc ON sc.id=sio.subcontract_order_id
            LEFT JOIN suppliers s ON s.id=sio.supplier_id
            WHERE sio.id=%s
            """,
            (doc_id,),
        )
        rows = _subcontract_line_rows("issue", doc_id)
        title = "委外发料单"
        number = order.get("issue_no") if order else ""
        date_value = order.get("date") if order else ""
        quantity_label = "发料数量"
        back_url = f"/subcontract_issue/{doc_id}"
    else:
        order = _safe_one(
            """
            SELECT sro.*, sc.order_no, sc.project_code, sc.serial_no, s.name AS partner_name
            FROM subcontract_receive_orders sro
            LEFT JOIN subcontract_orders sc ON sc.id=sro.subcontract_order_id
            LEFT JOIN suppliers s ON s.id=sro.supplier_id
            WHERE sro.id=%s
            """,
            (doc_id,),
        )
        rows = _subcontract_line_rows("receive", doc_id)
        title = "委外收货单"
        number = order.get("receive_no") if order else ""
        date_value = order.get("date") if order else ""
        quantity_label = "合格数量"
        back_url = f"/subcontract_receive/{doc_id}"
    if not order:
        return render_template("simple_detail.html", title="单据不存在", row=None, back_url="/subcontract")
    for row in rows:
        for key in ("material_code", "material_name", "material_spec", "unit", "lot_no"):
            if row.get(key) is None:
                row[key] = ""
    columns = [
        ("material_code", "物料编码", ""),
        ("material_name", "物料名称", ""),
        ("material_spec", "规格", ""),
        ("unit", "单位", "center"),
        ("quantity", quantity_label, "right"),
        ("lot_no", "批号", ""),
    ]
    if kind == "receive":
        columns.insert(5, ("scrap_quantity", "报废数量", "right"))
    doc = {
        "title": title,
        "subtitle": "机床 ERP 委外单据打印",
        "number": number,
        "number_label": "单据编号",
        "date": date_value,
        "date_label": "单据日期",
        "status_label": _subcontract_document_status_label(order.get("status")),
        "info": [
            ("委外订单", order.get("order_no")),
            ("加工商", order.get("partner_name")),
            ("项目号", order.get("project_code")),
            ("机号", order.get("serial_no")),
        ],
        "columns": columns,
        "rows": rows,
        "total_quantity": sum((_as_decimal(row.get("quantity")) for row in rows), Decimal("0")),
        "total_amount": None,
        "remark": order.get("remark"),
        "signatures": ["制单", "审核", "仓库", "财务"],
        "print_time": datetime.now(),
        "back_url": back_url,
    }
    doc["partner_name"] = order.get("partner_name")
    doc["project_code"] = order.get("project_code")
    doc["serial_no"] = order.get("serial_no")
    document_type = "subcontract_issue" if kind == "issue" else "subcontract_receive"
    template_grid = build_template_grid_for_document(document_type, doc, _safe_one)
    return render_template("document_print.html", doc=doc, template_grid=template_grid)


def _update_subcontract_status(order_id, action):
    order = _subcontract_summary(order_id)
    if not order:
        flash("委外订单不存在。", "warning")
        return redirect("/subcontract")
    status = (order.get("status") or "").strip()
    if action == "release":
        if status in {"completed", "已完成", "closed", "已关闭", "cancelled", "已作废", "void"}:
            flash("已完成、已关闭或已作废的委外订单不能下达。", "warning")
        else:
            _execute_db(
                "UPDATE subcontract_orders SET status=%s, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                ("已下达", order_id),
            )
            _log_action("下达委外订单", order.get("order_no"))
            flash("委外订单已下达，可安排发料。", "success")
    elif action == "close":
        if _as_decimal(order.get("open_qty")) > 0:
            flash("委外未回数量大于 0，不能关闭；请先收货、报废或处理短收。", "warning")
        elif _as_decimal(order.get("payable_balance")) > 0:
            flash("委外应付余额未清，不能关闭；请先核对应付。", "warning")
        else:
            _execute_db(
                "UPDATE subcontract_orders SET status=%s, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                ("已关闭", order_id),
            )
            _log_action("关闭委外订单", order.get("order_no"))
            flash("委外订单已关闭。", "success")
    elif action == "void":
        if _as_decimal(order.get("issued_qty")) > 0 or _as_decimal(order.get("received_qty")) > 0:
            flash("已有发料或收货记录的委外订单不能作废。", "warning")
        else:
            _execute_db(
                "UPDATE subcontract_orders SET status=%s, updated_at=CURRENT_TIMESTAMP WHERE id=%s",
                ("已作废", order_id),
            )
            _execute_db(
                """
                UPDATE supplier_payables
                SET status='已作废', balance=0
                WHERE doc_type='subcontract_order' AND (doc_id=%s OR doc_no=%s)
                """,
                (order_id, order.get("order_no")),
            )
            _log_action("作废委外订单", order.get("order_no"))
            flash("委外订单已作废，关联应付已关闭。", "success")
    return redirect(f"/subcontract/{order_id}")


