def _detail_value(row, *keys):
    for key in keys:
        value = (row or {}).get(key)
        if value not in (None, ""):
            return value
    return "-"


def _controlled_detail_menu(list_url, print_url=None, source_url=None, readonly=False):
    actions = [
        {"label": "返回列表", "type": "link", "href": list_url},
        {"label": "刷新", "type": "link", "href": request.path},
    ]
    if print_url:
        actions.append({"label": "打印", "type": "link", "href": print_url})
    tools = []
    if source_url:
        tools.append({"label": "上查来源单", "type": "link", "href": source_url})
    tools.append({"label": "关联库存流水", "type": "link", "href": f"/transactions?keyword={request.view_args.get('id') or ''}"})
    if readonly:
        tools.append({"label": "只读边界说明", "type": "disabled"})
    actions.append({"label": "工具", "type": "dropdown", "items": tools})
    actions.append({"label": "更多", "type": "dropdown", "icon": "bi-three-dots", "items": [
        {"label": "复制", "type": "button", "event": "global-copy-document"},
        {"type": "divider"},
        {"label": "返回首页", "type": "link", "href": "/"},
    ]})
    return actions


