def _pick_line_expr(table_cols, column, alias, fallback="NULL"):
    return f"pli.{column} AS {alias}" if column in table_cols else f"{fallback} AS {alias}"


def _pick_snapshot_expr(table_cols, column, fallback, alias):
    if column in table_cols:
        return f"COALESCE(NULLIF(pli.{column}, ''), {fallback}) AS {alias}"
    return f"{fallback} AS {alias}"


def _render_work_order_requisition_print(pick_id):
    row = _safe_one(
        """
        SELECT pl.*, wo.wo_no, wo.project_code, wo.serial_no, wo.status AS work_order_status,
               p.code AS product_code, p.name AS product_name
        FROM pick_lists pl
        LEFT JOIN work_orders wo ON wo.id=pl.work_order_id
        LEFT JOIN products p ON p.id=wo.product_id
        WHERE pl.id=%s
        """,
        (pick_id,),
    )
    if not row:
        return render_template("simple_detail.html", title="工单领料打印", row=None, back_url="/requisition")

    item_cols = {col.get("column_name") for col in _table_columns("pick_list_items")} if _has_table("pick_list_items") else set()
    lines = []
    if item_cols:
        pick_filter = []
        params = []
        if "pick_list_id" in item_cols:
            pick_filter.append("pli.pick_list_id=%s")
            params.append(pick_id)
        if "pick_id" in item_cols:
            pick_filter.append("pli.pick_id=%s")
            params.append(pick_id)
        where_sql = " OR ".join(pick_filter) or "1=0"
        warehouse_join = "LEFT JOIN warehouses w ON w.id=pli.warehouse_id" if "warehouse_id" in item_cols else ""
        location_join = "LEFT JOIN locations l ON l.id=pli.location_id" if "location_id" in item_cols else ""
        warehouse_expr = "COALESCE(w.name, '') AS warehouse_name" if "warehouse_id" in item_cols else "'' AS warehouse_name"
        location_expr = "COALESCE(NULLIF(l.code, ''), l.name, '') AS location_name" if "location_id" in item_cols else "'' AS location_name"
        if {"line_serial_no", "serial_no"}.issubset(item_cols):
            line_serial_expr = "COALESCE(NULLIF(pli.line_serial_no, ''), NULLIF(pli.serial_no, ''), wo.serial_no) AS line_serial_no"
        elif "line_serial_no" in item_cols:
            line_serial_expr = "COALESCE(NULLIF(pli.line_serial_no, ''), wo.serial_no) AS line_serial_no"
        elif "serial_no" in item_cols:
            line_serial_expr = "COALESCE(NULLIF(pli.serial_no, ''), wo.serial_no) AS line_serial_no"
        else:
            line_serial_expr = "wo.serial_no AS line_serial_no"
        lines = _safe_rows(
            f"""
            SELECT pli.id,
                   {_pick_snapshot_expr(item_cols, "material_code", "p.code", "material_code")},
                   {_pick_snapshot_expr(item_cols, "material_name", "p.name", "material_name")},
                   {_pick_snapshot_expr(item_cols, "material_spec", "p.specification", "specification")},
                   {_pick_snapshot_expr(item_cols, "material_unit", "p.unit", "unit")},
                   {_pick_line_expr(item_cols, "quantity", "quantity", "0")},
                   {_pick_line_expr(item_cols, "lot_no", "lot_no", "''")},
                   {line_serial_expr},
                   {warehouse_expr},
                   {location_expr},
                   {_pick_line_expr(item_cols, "remark", "remark", "''")}
            FROM pick_list_items pli
            LEFT JOIN pick_lists pl ON pl.id=%s
            LEFT JOIN work_orders wo ON wo.id=pl.work_order_id
            LEFT JOIN products p ON p.id=pli.product_id
            {warehouse_join}
            {location_join}
            WHERE {where_sql}
            ORDER BY pli.id
            LIMIT 300
            """,
            (pick_id, *params),
        )

    requisition = dict(row)
    requisition["doc_no"] = _detail_value(row, "pick_no", "req_no", "doc_no", "id")
    total_quantity = sum((_as_decimal(line.get("quantity")) for line in lines), Decimal("0"))
    doc = {
        "title": "生产领料申请单",
        "subtitle": "机床 ERP 单据打印",
        "number": requisition.get("doc_no"),
        "number_label": "领料单号",
        "date": _detail_value(row, "pick_date", "created_at"),
        "date_label": "领料日期",
        "status_label": row.get("status") or "未定",
        "project_code": row.get("project_code"),
        "serial_no": row.get("serial_no"),
        "info": [
            ("来源工单", row.get("wo_no") or row.get("work_order_id")),
            ("项目号", row.get("project_code")),
            ("机号", row.get("serial_no")),
            ("生产物料", " / ".join(str(v) for v in [row.get("product_code"), row.get("product_name")] if v)),
            ("用途", row.get("purpose")),
            ("备注", row.get("remark")),
        ],
        "columns": [
            ("product_code", "物料编码", ""),
            ("product_name", "物料名称", ""),
            ("specification", "规格型号", ""),
            ("unit", "单位", "center"),
            ("quantity", "数量", "right"),
            ("lot_no", "批号", ""),
            ("line_serial_no", "机号", ""),
            ("warehouse_name", "仓库", ""),
            ("location_name", "库位", ""),
            ("remark", "备注", ""),
        ],
        "rows": [
            {
                "product_code": line.get("material_code"),
                "product_name": line.get("material_name"),
                "specification": line.get("specification"),
                "unit": line.get("unit"),
                "quantity": line.get("quantity"),
                "lot_no": line.get("lot_no"),
                "line_serial_no": line.get("line_serial_no"),
                "warehouse_name": line.get("warehouse_name"),
                "location_name": line.get("location_name"),
                "remark": line.get("remark"),
            }
            for line in lines
        ],
        "total_quantity": total_quantity,
        "total_amount": None,
        "remark": row.get("remark"),
        "signatures": ["制单", "生产", "仓库", "复核"],
        "print_time": datetime.now(),
        "back_url": f"/requisition/{pick_id}",
    }
    template_grid = build_template_grid_for_document("work_order_requisition", doc, _safe_one)
    return render_template("document_print.html", doc=doc, template_grid=template_grid)


def _ensure_production_schedule_schema():
    for statement in (
        "CREATE TABLE IF NOT EXISTS production_schedules (id SERIAL PRIMARY KEY)",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS schedule_no VARCHAR(120)",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS work_order_id INTEGER",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS work_order_process_id INTEGER",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS work_center_id INTEGER",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS planned_start_date DATE",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS planned_end_date DATE",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS actual_start_date DATE",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS actual_end_date DATE",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS responsible_person VARCHAR(120)",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS blocked_reason TEXT",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS next_action TEXT",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS downstream_impact TEXT",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS dispatch_status VARCHAR(80) DEFAULT '待派工'",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS dispatched_to VARCHAR(120)",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS dispatched_at TIMESTAMP",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS status VARCHAR(80) DEFAULT '计划'",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS remark TEXT",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP",
        "ALTER TABLE production_schedules ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP",
    ):
        _execute_db(statement)
    _execute_db("ALTER TABLE production_schedules ALTER COLUMN status SET DEFAULT 'scheduled'")
    _execute_db(
        """
        UPDATE production_schedules
        SET status = CASE
            WHEN status IN ('计划', '待派工') THEN 'scheduled'
            WHEN status IN ('已派工', 'started', 'in_progress') THEN 'dispatched'
            WHEN status='已完成' THEN 'completed'
            WHEN status IN ('延期/受阻', '延期', '受阻', 'delayed') THEN 'rescheduled'
            WHEN status IN ('暂停', 'paused') THEN 'paused'
            WHEN status='已取消' THEN 'cancelled'
            ELSE status
        END
        WHERE status IN ('计划', '待派工', '已派工', 'started', '执行中', 'in_progress',
                         '已完成', '延期/受阻', '延期', '受阻', 'delayed', '暂停', 'paused', '已取消')
        """
    )


def _render_production_schedule_list(back_url="/production-schedules"):
    _ensure_production_schedule_schema()
    keyword = request.args.get("keyword", "").strip()
    keyword_sql = ""
    params = []
    if keyword:
        keyword_sql = """
          AND (ps.schedule_no ILIKE %s OR wo.wo_no ILIKE %s OR wo.project_code ILIKE %s
               OR wo.serial_no ILIKE %s OR wc.name ILIKE %s)
        """
        params.extend([f"%{keyword}%"] * 5)
    rows = _safe_rows(
        f"""
        SELECT ps.*, wo.wo_no, wo.project_code, wo.serial_no,
               wc.code AS work_center_code, wc.name AS work_center_name,
               COALESCE(ps.next_action, '派工或报工') AS next_step,
               '生产计划' AS owner_role,
               ps.blocked_reason,
               ps.downstream_impact,
               'dispatch' AS dispatch_action,
               'report' AS report_action
        FROM production_schedules ps
        LEFT JOIN work_orders wo ON wo.id=ps.work_order_id
        LEFT JOIN work_centers wc ON wc.id=ps.work_center_id
        WHERE 1=1 {keyword_sql}
        ORDER BY COALESCE(ps.planned_start_date, CURRENT_DATE) DESC, ps.id DESC
        LIMIT 300
        """,
        tuple(params),
    )
    columns = [
        {"key": "schedule_no", "label": "排程单号"},
        {"key": "wo_no", "label": "来源工单"},
        {"key": "project_code", "label": "项目号"},
        {"key": "serial_no", "label": "机号"},
        {"key": "work_center_name", "label": "工作中心"},
        {"key": "planned_start_date", "label": "计划开始"},
        {"key": "planned_end_date", "label": "计划完成"},
        {"key": "dispatch_status", "label": "派工状态"},
        {"key": "responsible_person", "label": "负责人"},
        {"key": "blocked_reason", "label": "阻塞原因"},
        {"key": "next_step", "label": "下一步"},
        {"key": "dispatch_action", "label": "派工"},
        {"key": "report_action", "label": "报工"},
    ]
    return render_template(
        "simple_list.html",
        title="生产排程",
        subtitle="只读排程列表；派工和报工从详情或工序报工单执行。",
        rows=rows,
        columns=columns,
        detail_base="/production-schedules",
        add_url=None,
    )


