def _work_center_bool(value):
    return str(value or "").strip() in {"1", "true", "True", "on", "enabled", "启用"}


def _work_center_form_state(center_id=None):
    if not center_id:
        return {"code": "", "name": "", "description": "", "location": "", "responsible_person": "", "is_active": True}
    row = _safe_one(
        "SELECT id, code, name, description, location, responsible_person, is_active FROM work_centers WHERE id=%s",
        (center_id,),
    )
    return dict(row) if row else None


def _render_work_center_list():
    keyword = (request.args.get("keyword") or request.args.get("q") or request.args.get("search") or "").strip()
    status = (request.args.get("status") or "").strip()
    where_parts = ["TRUE"]
    params = []
    if keyword:
        where_parts.append(
            """
            (
                code ILIKE %s OR name ILIKE %s OR COALESCE(description, '') ILIKE %s
                OR COALESCE(location, '') ILIKE %s OR COALESCE(responsible_person, '') ILIKE %s
            )
            """
        )
        params.extend([f"%{keyword}%"] * 5)
    if status == "enabled":
        where_parts.append("COALESCE(is_active, FALSE)=TRUE")
    elif status == "disabled":
        where_parts.append("COALESCE(is_active, FALSE)=FALSE")
    rows = _safe_rows(
        f"""
        SELECT id, code, name, description, location, responsible_person, is_active
        FROM work_centers
        WHERE {" AND ".join(where_parts)}
        ORDER BY CASE WHEN COALESCE(is_active, FALSE) THEN 0 ELSE 1 END, code NULLS LAST, id DESC
        LIMIT 100
        """,
        tuple(params),
    )
    display_rows = []
    for row in rows:
        item = dict(row)
        item["status_display"] = "启用" if item.get("is_active") else "停用"
        item["status_class"] = "success" if item.get("is_active") else "secondary"
        item["owner_display"] = item.get("responsible_person") or "-"
        item["next_action"] = "可被工艺路线、排程和报工引用" if item.get("is_active") else "停用中心仅保留历史引用"
        display_rows.append(item)
    return render_template(
        "work_center_list.html",
        title="工作中心",
        subtitle="技术主数据页：用于工艺路线归类、责任识别和工程标准引用，不做生产排程、不计算产能负荷。",
        rows=display_rows,
        filters={"keyword": keyword, "status": status},
    )


def _render_work_center_detail(work_center_id, back_url="/work-centers"):
    row = _safe_one(
        """
        SELECT id, code, name, description, location, responsible_person, is_active, created_at
        FROM work_centers
        WHERE id=%s
        """,
        (work_center_id,),
    )
    routing_refs = _safe_rows(
        """
        SELECT pr.id, pr.routing_no, pr.name AS routing_name, ro.operation_no, ro.operation_name
        FROM routing_operations ro
        JOIN production_routings pr ON pr.id=ro.routing_id
        WHERE ro.work_center_id=%s
        ORDER BY pr.id DESC, ro.sequence
        LIMIT 50
        """,
        (work_center_id,),
    )
    schedule_refs = _safe_rows(
        """
        SELECT ps.id, ps.schedule_no, ps.status, ps.planned_start_date, ps.planned_end_date, wo.wo_no
        FROM production_schedules ps
        LEFT JOIN work_orders wo ON wo.id=ps.work_order_id
        WHERE ps.work_center_id=%s
        ORDER BY COALESCE(ps.planned_start_date, ps.start_date, CURRENT_DATE) DESC, ps.id DESC
        LIMIT 50
        """,
        (work_center_id,),
    ) if _has_table("production_schedules") else []
    return render_template(
        "work_center_detail.html",
        center=row,
        routing_refs=routing_refs,
        schedule_refs=schedule_refs,
        back_url=back_url,
    )


def _render_work_center_form(center_id=None, form_state=None, errors=None):
    center = _safe_one("SELECT id, code, name FROM work_centers WHERE id=%s", (center_id,)) if center_id else None
    if center_id and not center:
        flash("工作中心不存在。", "warning")
        return redirect("/work-centers")
    if form_state is None:
        form_state = _work_center_form_state(center_id)
    return render_template(
        "work_center_form.html",
        mode="edit" if center_id else "new",
        center=center,
        form_state=form_state,
        form_errors=errors or [],
    )


def _save_work_center(center_id=None):
    form_state = {
        "code": (request.form.get("code") or "").strip(),
        "name": (request.form.get("name") or "").strip(),
        "description": (request.form.get("description") or "").strip(),
        "location": (request.form.get("location") or "").strip(),
        "responsible_person": (request.form.get("responsible_person") or "").strip(),
        "is_active": _work_center_bool(request.form.get("is_active")),
    }
    errors = []
    if not form_state["code"]:
        errors.append("中心编码不能为空。")
    if not form_state["name"]:
        errors.append("工作中心名称不能为空。")
    duplicate = _safe_one(
        "SELECT id FROM work_centers WHERE code=%s AND (%s IS NULL OR id<>%s) LIMIT 1",
        (form_state["code"], center_id, center_id),
    )
    if duplicate:
        errors.append("中心编码已存在。")
    if errors:
        return _render_work_center_form(center_id, form_state, errors)
    if center_id:
        _execute_db(
            """
            UPDATE work_centers
            SET code=%s, name=%s, description=%s, location=%s, responsible_person=%s, is_active=%s
            WHERE id=%s
            """,
            (
                form_state["code"],
                form_state["name"],
                form_state["description"],
                form_state["location"],
                form_state["responsible_person"],
                form_state["is_active"],
                center_id,
            ),
        )
        saved_id = center_id
    else:
        created = _execute_and_return(
            """
            INSERT INTO work_centers (code, name, description, location, responsible_person, is_active)
            VALUES (%s,%s,%s,%s,%s,%s)
            RETURNING id
            """,
            (
                form_state["code"],
                form_state["name"],
                form_state["description"],
                form_state["location"],
                form_state["responsible_person"],
                form_state["is_active"],
            ),
        )
        saved_id = created.get("id") if isinstance(created, dict) else created
    _log_action("保存工作中心", form_state["code"], "技术主数据维护")
    flash("工作中心已保存。", "success")
    return redirect(f"/work-centers/{saved_id}")


def _delete_work_center(center_id):
    row = _safe_one("SELECT id, code FROM work_centers WHERE id=%s", (center_id,))
    if not row:
        flash("工作中心不存在。", "warning")
        return redirect("/work-centers")
    checks = [("routing_operations", "work_center_id"), ("production_schedules", "work_center_id"), ("operation_reports", "work_center_id")]
    referenced = 0
    for table, column in checks:
        if _has_table(table) and _has_column(table, column):
            count_row = _safe_one(f"SELECT COUNT(*) AS value FROM {table} WHERE {column}=%s", (center_id,))
            referenced += int((count_row or {}).get("value") or 0)
    if referenced:
        flash("该工作中心已被工艺路线、排程或报工引用，不能删除；如不再使用请改为停用。", "warning")
        return redirect(f"/work-centers/{center_id}")
    _execute_db("DELETE FROM work_centers WHERE id=%s", (center_id,))
    _log_action("删除工作中心", row.get("code"), "未被下游记录引用")
    flash("工作中心已删除。", "success")
    return redirect("/work-centers")


def _production_schedule_next_no():
    prefix = f"PS{datetime.now():%Y%m%d}"
    row = _safe_one(
        "SELECT schedule_no FROM production_schedules WHERE schedule_no LIKE %s ORDER BY schedule_no DESC LIMIT 1",
        (f"{prefix}%",),
    )
    if not row or not row.get("schedule_no"):
        return f"{prefix}001"
    suffix = str(row.get("schedule_no") or "").replace(prefix, "", 1)
    try:
        return f"{prefix}{int(suffix or '0') + 1:03d}"
    except ValueError:
        return f"{prefix}{datetime.now():%H%M%S}"


def _production_schedule_options():
    scope_clause, scope_params = _data_scope_filter(
        {"project": "project_code", "serial": "serial_no"}
    )
    work_orders = _safe_rows(
        f"""
        SELECT id, wo_no, project_code, serial_no, status
        FROM work_orders
        WHERE COALESCE(status, '') NOT IN ('已关闭', '已作废', 'closed', 'voided')
          {scope_clause}
        ORDER BY id DESC
        LIMIT 300
        """,
        scope_params,
    )
    work_centers = _safe_rows(
        """
        SELECT id, code, name
        FROM work_centers
        WHERE COALESCE(is_active, TRUE)=TRUE
        ORDER BY code NULLS LAST, name NULLS LAST, id DESC
        LIMIT 300
        """
    )
    return work_orders, work_centers


def _production_schedule_status_label(value):
    return {
        "scheduled": "计划",
        "dispatched": "已派工",
        "rescheduled": "改期",
        "paused": "暂停",
        "completed": "已完成",
        "cancelled": "已取消",
    }.get(str(value or "").strip(), value or "-")


def _production_schedule_status_key(value):
    text = str(value or "").strip()
    allowed = {"scheduled", "dispatched", "rescheduled", "paused", "completed", "cancelled"}
    mapping = {
        "计划": "scheduled",
        "待派工": "scheduled",
        "已派工": "dispatched",
        "执行中": "dispatched",
        "已完成": "completed",
        "延期/受阻": "rescheduled",
        "延期": "rescheduled",
        "改期": "rescheduled",
        "受阻": "paused",
        "暂停": "paused",
        "started": "dispatched",
        "in_progress": "dispatched",
        "delayed": "rescheduled",
        "已取消": "cancelled",
    }
    mapped = mapping.get(text, text or "scheduled")
    return mapped if mapped in allowed else "scheduled"


def _production_schedule_form_state(schedule_id=None):
    if not schedule_id:
        today = datetime.now().date().isoformat()
        return {
            "schedule_no": _production_schedule_next_no(),
            "work_order_id": "",
            "work_center_id": "",
            "planned_start_date": today,
            "planned_end_date": today,
            "quantity": "0",
            "dispatch_status": "待派工",
            "status": "scheduled",
            "responsible_person": "",
            "blocked_reason": "",
            "next_action": "",
            "downstream_impact": "",
            "remark": "",
        }
    row = _safe_one(
        """
        SELECT id, schedule_no, work_order_id, work_center_id,
               COALESCE(planned_start_date, start_date) AS planned_start_date,
               COALESCE(planned_end_date, end_date) AS planned_end_date,
               quantity, dispatch_status, status, responsible_person, blocked_reason,
               next_action, downstream_impact, remark
        FROM production_schedules
        WHERE id=%s
        """,
        (schedule_id,),
    )
    return dict(row) if row else None


def _detect_schedule_conflicts(work_center_id, planned_start, planned_end, exclude_id=None):
    """D-2: Detect overlapping schedules on the same work center.

    Returns a list of conflict dicts with schedule_no, work_order_no,
    planned_start, planned_end, and status.
    """
    if not work_center_id or not planned_start or not planned_end:
        return []
    rows = _safe_rows(
        """
        SELECT ps.id, ps.schedule_no, ps.planned_start_date, ps.planned_end_date,
               ps.status, ps.dispatch_status, wo.wo_no
        FROM production_schedules ps
        LEFT JOIN work_orders wo ON wo.id = ps.work_order_id
        WHERE ps.work_center_id = %s
          AND COALESCE(ps.status, '') NOT IN ('cancelled', '已取消')
          AND ps.planned_start_date IS NOT NULL
          AND ps.planned_end_date IS NOT NULL
          AND ps.planned_start_date <= %s
          AND ps.planned_end_date >= %s
          AND (%s IS NULL OR ps.id <> %s)
        ORDER BY ps.planned_start_date
        """,
        (work_center_id, planned_end, planned_start, exclude_id, exclude_id),
    )
    conflicts = []
    for row in rows or []:
        conflicts.append(
            {
                "schedule_no": row.get("schedule_no"),
                "wo_no": row.get("wo_no") or "",
                "planned_start": row.get("planned_start_date"),
                "planned_end": row.get("planned_end_date"),
                "status": row.get("status") or "",
                "dispatch_status": row.get("dispatch_status") or "",
            }
        )
    return conflicts


def _render_production_schedule_list(back_url="/production-schedules"):
    _ensure_production_schedule_schema()
    keyword = (request.args.get("keyword") or "").strip()
    status_filter = (request.args.get("status") or "").strip()
    keyword_sql = ""
    params = []
    if keyword:
        keyword_sql = """
          AND (ps.schedule_no ILIKE %s OR wo.wo_no ILIKE %s OR COALESCE(wo.project_code, '') ILIKE %s
               OR COALESCE(wo.serial_no, '') ILIKE %s OR COALESCE(wc.name, '') ILIKE %s)
        """
        params.extend([f"%{keyword}%"] * 5)
    status_sql = ""
    if status_filter == "blocked":
        status_sql = " AND COALESCE(ps.blocked_reason, '') <> ''"
    elif status_filter:
        status_sql = " AND (COALESCE(ps.status, '') = %s OR COALESCE(ps.dispatch_status, '') = %s)"
        params.extend([status_filter, status_filter])
    rows = _safe_rows(
        f"""
        SELECT ps.*, wo.wo_no, wo.project_code, wo.serial_no,
               wc.code AS work_center_code, wc.name AS work_center_name,
               COALESCE(ps.planned_start_date, ps.start_date) AS planned_start,
               COALESCE(ps.planned_end_date, ps.end_date) AS planned_end
        FROM production_schedules ps
        LEFT JOIN work_orders wo ON wo.id=ps.work_order_id
        LEFT JOIN work_centers wc ON wc.id=ps.work_center_id
        WHERE 1=1 {keyword_sql} {status_sql}
        ORDER BY COALESCE(ps.planned_start_date, ps.start_date, CURRENT_DATE) DESC, ps.id DESC
        LIMIT 300
        """,
        tuple(params),
    )
    display_rows = []
    for row in rows:
        item = dict(row)
        item["status_display"] = _production_schedule_status_label(item.get("status"))
        # D-2: detect scheduling conflicts (same work center, overlapping dates)
        wc_id = item.get("work_center_id")
        p_start = item.get("planned_start") or item.get("planned_start_date") or item.get("start_date")
        p_end = item.get("planned_end") or item.get("planned_end_date") or item.get("end_date")
        if wc_id and p_start and p_end and item.get("status") not in ("cancelled", "已取消"):
            conflicts = _detect_schedule_conflicts(wc_id, p_start, p_end, exclude_id=item.get("id"))
            if conflicts:
                item["conflict_count"] = len(conflicts)
                item["conflict_warning"] = "工作中心排程冲突：与 {} 等 {} 条排程日期重叠".format(
                    conflicts[0].get("schedule_no") or "",
                    len(conflicts),
                )
                item["conflicts"] = conflicts
            else:
                item["conflict_count"] = 0
                item["conflict_warning"] = ""
        else:
            item["conflict_count"] = 0
            item["conflict_warning"] = ""
        display_rows.append(item)
    conflict_total = sum(1 for r in display_rows if r.get("conflict_count", 0) > 0)
    return render_template(
        "production_schedule_list.html",
        title="生产排程",
        subtitle="生产计划列表：维护工单计划日期、工作中心、责任人、派工状态和堵点，不替代工序报工或库存入库。",
        rows=display_rows,
        filters={"keyword": keyword, "status": status_filter},
        back_url=back_url,
        conflict_total=conflict_total,
    )


