def _save_production_schedule(schedule_id=None):
    _ensure_production_schedule_schema()
    form_state = {
        "schedule_no": (request.form.get("schedule_no") or "").strip(),
        "work_order_id": (request.form.get("work_order_id") or "").strip(),
        "work_center_id": (request.form.get("work_center_id") or "").strip(),
        "planned_start_date": (request.form.get("planned_start_date") or "").strip(),
        "planned_end_date": (request.form.get("planned_end_date") or "").strip(),
        "quantity": (request.form.get("quantity") or "0").strip(),
        "dispatch_status": (request.form.get("dispatch_status") or "待派工").strip(),
        "status": _production_schedule_status_key(request.form.get("status") or "scheduled"),
        "responsible_person": (request.form.get("responsible_person") or "").strip(),
        "blocked_reason": (request.form.get("blocked_reason") or "").strip(),
        "next_action": (request.form.get("next_action") or "").strip(),
        "downstream_impact": (request.form.get("downstream_impact") or "").strip(),
        "remark": (request.form.get("remark") or "").strip(),
    }
    if not form_state["schedule_no"]:
        form_state["schedule_no"] = _production_schedule_next_no()
    errors = []
    if not form_state["planned_start_date"]:
        errors.append("计划开始日期不能为空。")
    if not form_state["planned_end_date"]:
        errors.append("计划完成日期不能为空。")
    duplicate = _safe_one(
        "SELECT id FROM production_schedules WHERE schedule_no=%s AND (%s IS NULL OR id<>%s) LIMIT 1",
        (form_state["schedule_no"], schedule_id, schedule_id),
    )
    if duplicate:
        errors.append("排程单号已存在。")
    if errors:
        return _render_production_schedule_form(schedule_id, form_state, errors)
    work_order_id = _routing_int_clean(form_state["work_order_id"], 0) or None
    work_center_id = _routing_int_clean(form_state["work_center_id"], 0) or None
    quantity = _routing_decimal_clean(form_state["quantity"]) or Decimal("0")
    if schedule_id:
        _execute_db(
            """
            UPDATE production_schedules
            SET schedule_no=%s, work_order_id=%s, work_center_id=%s,
                planned_start_date=%s, planned_end_date=%s, start_date=%s, end_date=%s,
                quantity=%s, dispatch_status=%s, status=%s, responsible_person=%s,
                blocked_reason=%s, next_action=%s, downstream_impact=%s, remark=%s,
                updated_at=CURRENT_TIMESTAMP
            WHERE id=%s
            """,
            (
                form_state["schedule_no"],
                work_order_id,
                work_center_id,
                form_state["planned_start_date"],
                form_state["planned_end_date"],
                form_state["planned_start_date"],
                form_state["planned_end_date"],
                quantity,
                form_state["dispatch_status"],
                form_state["status"],
                form_state["responsible_person"],
                form_state["blocked_reason"],
                form_state["next_action"],
                form_state["downstream_impact"],
                form_state["remark"],
                schedule_id,
            ),
        )
        saved_id = schedule_id
    else:
        created = _execute_and_return(
            """
            INSERT INTO production_schedules
                (schedule_no, work_order_id, work_center_id, planned_start_date, planned_end_date,
                 start_date, end_date, quantity, dispatch_status, status, responsible_person,
                 blocked_reason, next_action, downstream_impact, remark)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            RETURNING id
            """,
            (
                form_state["schedule_no"],
                work_order_id,
                work_center_id,
                form_state["planned_start_date"],
                form_state["planned_end_date"],
                form_state["planned_start_date"],
                form_state["planned_end_date"],
                quantity,
                form_state["dispatch_status"],
                form_state["status"],
                form_state["responsible_person"],
                form_state["blocked_reason"],
                form_state["next_action"],
                form_state["downstream_impact"],
                form_state["remark"],
            ),
        )
        saved_id = created.get("id") if isinstance(created, dict) else created
    _log_action("保存生产排程", form_state["schedule_no"], "生产计划维护")
    flash("生产排程已保存。", "success")
    # D-2: flash conflict warning if the saved schedule overlaps with others
    if work_center_id and form_state["planned_start_date"] and form_state["planned_end_date"]:
        conflicts = _detect_schedule_conflicts(
            work_center_id,
            form_state["planned_start_date"],
            form_state["planned_end_date"],
            exclude_id=saved_id,
        )
        if conflicts:
            conflict_desc = "、".join(
                f"{c.get('schedule_no') or ''}({c.get('wo_no') or '无工单'})" for c in conflicts[:3]
            )
            flash(
                "排程冲突预警：工作中心在此日期范围内已有 {} 条排程（{}），请核实产能。".format(
                    len(conflicts), conflict_desc
                ),
                "warning",
            )
    if request.form.get("after_save") == "new":
        return redirect("/production-schedules/new")
    return redirect(f"/production-schedules/{saved_id}")


def _delete_production_schedule(schedule_id):
    row = _safe_one("SELECT id, schedule_no FROM production_schedules WHERE id=%s", (schedule_id,))
    if not row:
        flash("生产排程不存在。", "warning")
        return redirect("/production-schedules")
    _execute_db("DELETE FROM production_schedules WHERE id=%s", (schedule_id,))
    _log_action("删除生产排程", row.get("schedule_no"), "生产计划维护")
    flash("生产排程已删除。", "success")
    return redirect("/production-schedules")


def _dispatch_production_schedule(schedule_id):
    _ensure_production_schedule_schema()
    row = _safe_one("SELECT id, schedule_no FROM production_schedules WHERE id=%s", (schedule_id,))
    if not row:
        flash("生产排程不存在。", "warning")
        return redirect("/production-schedules")
    planned_start_date = (request.form.get("planned_start_date") or "").strip() or None
    planned_end_date = (request.form.get("planned_end_date") or "").strip() or None
    work_center_id = _routing_int_clean(request.form.get("work_center_id"), 0) or None
    responsible_person = (request.form.get("responsible_person") or "").strip()
    dispatch_status = (request.form.get("dispatch_status") or "待派工").strip()
    blocked_reason = (request.form.get("blocked_reason") or "").strip()
    next_action = (request.form.get("next_action") or "").strip()
    downstream_impact = (request.form.get("downstream_impact") or "").strip()
    remark = (request.form.get("remark") or "").strip()
    status = _production_schedule_status_key(dispatch_status)
    _execute_db(
        """
        UPDATE production_schedules
        SET planned_start_date=%s, planned_end_date=%s, start_date=%s, end_date=%s,
            work_center_id=%s, responsible_person=%s, dispatch_status=%s, status=%s,
            blocked_reason=%s, next_action=%s, downstream_impact=%s, remark=%s,
            dispatched_to=%s, dispatched_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP
        WHERE id=%s
        """,
        (
            planned_start_date,
            planned_end_date,
            planned_start_date,
            planned_end_date,
            work_center_id,
            responsible_person,
            dispatch_status,
            status,
            blocked_reason,
            next_action,
            downstream_impact,
            remark,
            responsible_person,
            schedule_id,
        ),
    )
    _log_action("更新生产排程派工", row.get("schedule_no"), "同步计划日期和派工状态")
    flash("生产排程派工信息已保存。", "success")
    return redirect(f"/production-schedules/{schedule_id}")


