INVENTORY_STATUS_PENDING = "待过账"
INVENTORY_STATUS_POSTED = "已过账"
INVENTORY_STATUS_CLOSED = "已关闭"
INVENTORY_STATUS_CANCELLED = "已取消"
INVENTORY_PENDING_STATUSES = {INVENTORY_STATUS_PENDING, "待审核", "草稿", ""}


def _inventory_initial_status():
    return INVENTORY_STATUS_PENDING


def _inventory_cancel_allowed(status):
    return (status or "") in INVENTORY_PENDING_STATUSES


def _inventory_location_requirement_error(warehouse_id, location_id, warehouse_label="仓库"):
    if not warehouse_id:
        return f"请选择{warehouse_label}。"
    warehouse = _safe_one("SELECT name FROM warehouses WHERE id=%s", (warehouse_id,)) or {}
    warehouse_name = warehouse.get("name") or str(warehouse_id)
    count_row = _safe_one(
        """
        SELECT COUNT(*) AS count
        FROM locations
        WHERE warehouse_id=%s AND COALESCE(is_active, TRUE)=TRUE
        """,
        (warehouse_id,),
    ) or {}
    if _as_int(count_row.get("count")) <= 0:
        # 该仓库未启用库位（locations 表无记录）：库位字段灰显、非必填，允许保存。
        return ""
    if not location_id:
        return f"请选择{warehouse_label}{warehouse_name}的库位。"
    location = _safe_one(
        """
        SELECT id
        FROM locations
        WHERE id=%s AND warehouse_id=%s AND COALESCE(is_active, TRUE)=TRUE
        """,
        (location_id, warehouse_id),
    )
    if not location:
        return f"所选库位不属于{warehouse_label}{warehouse_name}或已停用。"
    return ""


def _warehouse_has_locations(warehouse_id):
    """该仓库是否启用库位：locations 表存在启用记录即为启用。

    用于行级保存路径：未启用库位时把行级 location_id 同步清零，避免脏值。
    """
    if not warehouse_id:
        return False
    count_row = _safe_one(
        """
        SELECT COUNT(*) AS count
        FROM locations
        WHERE warehouse_id=%s AND COALESCE(is_active, TRUE)=TRUE
        """,
        (warehouse_id,),
    ) or {}
    return _as_int(count_row.get("count")) > 0


def _require_inventory_location_or_redirect(warehouse_id, location_id, back_url, warehouse_label="仓库"):
    error = _inventory_location_requirement_error(warehouse_id, location_id, warehouse_label)
    if error:
        flash(error, "warning")
        return redirect(back_url)
    return None


def _validate_inventory_location_or_raise(warehouse_id, location_id, warehouse_label="仓库"):
    error = _inventory_location_requirement_error(warehouse_id, location_id, warehouse_label)
    if error:
        raise ValueError(error)


def _normalize_inventory_location_id(warehouse_id, location_id):
    if location_id and not _warehouse_has_locations(warehouse_id):
        return None
    return location_id or None


def _apply_inventory_movement(product_id, quantity, unit_cost, tx_type, reference_no, remark="", warehouse_id=None, location_id=None, lot_no="", serial_no="", tx_date=None, project_code="", query_one=None, execute_db_fn=None):
    # Ensure atomicity: if no transaction context is provided, wrap in a transaction
    # so that inventory_balances, legacy inventory, stock_transactions, and batch_tracking
    # are all committed together or rolled back together.
    if execute_db_fn is None:
        def _tx_op(cursor):
            if cursor is not None:
                _qdb, _edb, _ = cursor_db_helpers(cursor)
                _q1 = lambda sql, params=None: _qdb(sql, params, one=True)
            else:
                _q1, _edb = _safe_one, _execute_db
            _apply_inventory_movement(
                product_id, quantity, unit_cost, tx_type, reference_no, remark,
                warehouse_id, location_id, lot_no, serial_no, tx_date, project_code,
                query_one=_q1, execute_db_fn=_edb,
            )
        return _run_registry_transaction(_tx_op)

    query_one = query_one or _safe_one
    execute_db_fn = execute_db_fn or _execute_db
    qty = _as_decimal(quantity)
    cost = _as_decimal(unit_cost)
    if not product_id or qty == 0:
        raise ValueError("请选择物料并输入有效数量。")
    warehouse_id = warehouse_id or _ensure_default_warehouse_id()
    location_id = _normalize_inventory_location_id(warehouse_id, location_id)
    product_error = _inactive_master_error("products", product_id, "物料")
    if product_error:
        raise ValueError(product_error)
    warehouse_error = _inactive_master_error("warehouses", warehouse_id, "仓库")
    if warehouse_error:
        raise ValueError(warehouse_error)
    if location_id:
        location_error = _inactive_master_error("locations", location_id, "库位")
        if location_error:
            raise ValueError(location_error)
    tx_date = tx_date or datetime.now().date().isoformat()
    location_label = ""
    if location_id:
        loc = _safe_one("SELECT code, name FROM locations WHERE id=%s", (location_id,))
        if loc:
            location_label = loc.get("code") or loc.get("name") or ""

    balance = query_one(
        """
        SELECT id, quantity, unit_cost
        FROM inventory_balances
        WHERE product_id=%s AND COALESCE(warehouse_id,0)=COALESCE(%s,0)
          AND COALESCE(location_id,0)=COALESCE(%s,0)
          AND COALESCE(lot_no,'')=COALESCE(%s,'')
          AND COALESCE(serial_no,'')=COALESCE(%s,'')
          AND COALESCE(project_code,'')=COALESCE(%s,'')
        ORDER BY id
        LIMIT 1
        FOR UPDATE
        """,
        (product_id, warehouse_id, location_id, lot_no, serial_no, project_code),
    )
    if qty > 0:
        if balance:
            old_qty = _as_decimal(balance.get("quantity"))
            old_cost = _as_decimal(balance.get("unit_cost"))
            new_qty = old_qty + qty
            new_cost = ((old_qty * old_cost) + (qty * cost)) / new_qty if new_qty > 0 else cost
            execute_db_fn(
                "UPDATE inventory_balances SET quantity=%s, unit_cost=%s, updated_at=NOW() WHERE id=%s",
                (new_qty, new_cost, balance.get("id")),
            )
        else:
            execute_db_fn(
                """
                INSERT INTO inventory_balances
                    (product_id, warehouse_id, location_id, lot_no, serial_no, project_code, quantity, locked_qty, unit_cost, updated_at)
                VALUES (%s,%s,%s,%s,%s,%s,%s,0,%s,NOW())
                """,
                (product_id, warehouse_id, location_id, lot_no, serial_no, project_code, qty, cost),
            )
        inv = query_one("SELECT id, quantity, unit_cost FROM inventory WHERE product_id=%s LIMIT 1 FOR UPDATE", (product_id,))
        if inv:
            old_qty = _as_decimal(inv.get("quantity"))
            old_cost = _as_decimal(inv.get("unit_cost"))
            new_qty = old_qty + qty
            new_cost = ((old_qty * old_cost) + (qty * cost)) / new_qty if new_qty > 0 else cost
            execute_db_fn("UPDATE inventory SET quantity=%s, unit_cost=%s WHERE id=%s", (new_qty, new_cost, inv.get("id")))
        else:
            execute_db_fn(
                "INSERT INTO inventory (product_id, quantity, unit_cost, location, reorder_level) VALUES (%s,%s,%s,%s,0)",
                (product_id, qty, cost, location_label),
            )
    else:
        abs_qty = -qty
        if serial_no or project_code:
            current_qty = _as_decimal(balance.get("quantity")) if balance else Decimal("0")
            if current_qty < abs_qty:
                common_balance = query_one(
                    """
                    SELECT id, quantity, unit_cost
                    FROM inventory_balances
                    WHERE product_id=%s AND COALESCE(warehouse_id,0)=COALESCE(%s,0)
                      AND COALESCE(location_id,0)=COALESCE(%s,0)
                      AND COALESCE(lot_no,'')=COALESCE(%s,'')
                      AND COALESCE(serial_no,'')=''
                      AND COALESCE(project_code,'')=''
                    ORDER BY id
                    LIMIT 1
                    FOR UPDATE
                    """,
                    (product_id, warehouse_id, location_id, lot_no),
                )
                if common_balance and _as_decimal(common_balance.get("quantity")) >= abs_qty:
                    serial_no = ""
                    project_code = ""
                    balance = common_balance
        if balance:
            current_qty = _as_decimal(balance.get("quantity"))
            if current_qty - abs_qty < 0:
                raise ValueError(
                    f"库存不足：物料 {product_id} 当前库存 {current_qty}，不能出库 {abs_qty}。"
                )
            execute_db_fn(
                "UPDATE inventory_balances SET quantity=COALESCE(quantity,0)-%s, updated_at=NOW() WHERE id=%s",
                (abs_qty, balance.get("id")),
            )
        else:
            raise ValueError(f"库存不足：物料 {product_id} 无库存记录，不能出库 {abs_qty}。")
        if False:
            raise ValueError(
                f"库存不足：物料 {product_id} 无库存记录，不能出库 {abs_qty}。"
            )
        inv = query_one("SELECT id FROM inventory WHERE product_id=%s LIMIT 1 FOR UPDATE", (product_id,))
        if inv:
            execute_db_fn("UPDATE inventory SET quantity=COALESCE(quantity,0)-%s WHERE id=%s", (abs_qty, inv.get("id")))
        else:
            execute_db_fn(
                "INSERT INTO inventory (product_id, quantity, unit_cost, location, reorder_level) VALUES (%s,0,%s,%s,0)",
                (product_id, cost, location_label),
            )
        if False:
            raise ValueError(
                f"库存不足：物料 {product_id} 无库存记录，不能出库 {abs_qty}。"
            )

    execute_db_fn(
        """
        INSERT INTO stock_transactions
            (transaction_date, transaction_type, product_id, quantity, unit_cost, reference_no,
             lot_no, serial_no, project_code, location, remark, warehouse_id, location_id)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        """,
        (tx_date, tx_type, product_id, qty, cost, reference_no, lot_no, serial_no, project_code, location_label, remark, warehouse_id, location_id),
    )

    # Sync batch_tracking from inventory_balances to prevent consistency audit failures.
    # _apply_inventory_movement bypasses inventory_service.inventory_inbound/outbound,
    # so we must sync batch_tracking here as well.
    _balance_row = query_one(
        """
        SELECT COALESCE(SUM(quantity),0) AS quantity,
               CASE WHEN COALESCE(SUM(quantity),0) <> 0
                   THEN COALESCE(SUM(quantity * COALESCE(unit_cost,0)) / NULLIF(SUM(quantity),0),0)
                   ELSE COALESCE(MAX(unit_cost),0)
               END AS unit_cost
        FROM inventory_balances
        WHERE product_id=%s
          AND warehouse_id IS NOT DISTINCT FROM %s
          AND location_id IS NOT DISTINCT FROM %s
          AND COALESCE(project_code,'')=%s
          AND COALESCE(lot_no,'')=%s
          AND COALESCE(serial_no,'')=%s
        """,
        (product_id, warehouse_id, location_id, project_code or "", lot_no or "", serial_no or ""),
    ) or {}
    _bt_qty = _as_decimal(_balance_row.get("quantity"))
    _bt_cost = _as_decimal(_balance_row.get("unit_cost"))
    _existing_bt = query_one(
        """
        SELECT id FROM batch_tracking
        WHERE product_id=%s
          AND warehouse_id IS NOT DISTINCT FROM %s
          AND location_id IS NOT DISTINCT FROM %s
          AND COALESCE(project_code,'')=%s
          AND COALESCE(lot_no,'')=%s
          AND COALESCE(serial_no,'')=%s
        ORDER BY id LIMIT 1
        FOR UPDATE
        """,
        (product_id, warehouse_id, location_id, project_code or "", lot_no or "", serial_no or ""),
    )
    if _existing_bt:
        execute_db_fn(
            """
            UPDATE batch_tracking
            SET quantity_available=%s,
                unit_cost=%s,
                quantity_in=CASE WHEN %s > 0 THEN COALESCE(quantity_in,0) + %s ELSE COALESCE(quantity_in,0) END,
                quantity_out=CASE WHEN %s < 0 THEN COALESCE(quantity_out,0) + (-%s) ELSE COALESCE(quantity_out,0) END,
                updated_at=NOW()
            WHERE id=%s
            """,
            (_bt_qty, _bt_cost, qty, qty, qty, qty, _existing_bt["id"]),
        )
    else:
        execute_db_fn(
            """
            INSERT INTO batch_tracking
                (lot_no, product_id, warehouse_id, location_id, serial_no, project_code,
                 quantity_in, quantity_out, quantity_available, unit_cost, source_order_no,
                 status, created_at, updated_at)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,'derived',NOW(),NOW())
            """,
            (
                lot_no or "", product_id, warehouse_id, location_id,
                serial_no or None, project_code or None,
                qty if qty > 0 else Decimal("0"),
                -qty if qty < 0 else Decimal("0"),
                _bt_qty, _bt_cost, reference_no or "inventory_movement_sync",
            ),
        )


