def _project_engineering_readiness(order):
    if not order:
        return {
            "ready": False,
            "blocked_reason": "缺少销售订单",
            "next_action": "选择销售订单后重新检查工程准备",
            "owner_role": "销售/计划",
        }
    order_id = order.get("id")
    project_code = order.get("project_code")
    serial_no = order.get("serial_no")
    confirmation = _safe_one(
        """
        SELECT etc.id, etc.confirm_no, etc.status, etc.confirmed_at,
               etc.bom_id, etc.routing_id, etc.work_center_id,
               etc.drawing_no, etc.drawing_version, etc.owner,
               b.bom_no, b.status AS bom_status,
               COALESCE(bom_items.item_count, 0) AS bom_item_count,
               released_drawing.id AS released_drawing_id
        FROM engineering_technical_confirmations etc
        LEFT JOIN boms b ON b.id=etc.bom_id
        LEFT JOIN LATERAL (
            SELECT COUNT(*) AS item_count
            FROM bom_items bi
            WHERE bi.bom_id=etc.bom_id
        ) bom_items ON TRUE
        LEFT JOIN LATERAL (
            SELECT d.id
            FROM engineering_drawings d
            WHERE d.drawing_no=etc.drawing_no
              AND d.version=etc.drawing_version
              AND d.status='released'
              AND (d.effective_date IS NULL OR d.effective_date <= CURRENT_DATE)
              AND (d.obsolete_date IS NULL OR d.obsolete_date > CURRENT_DATE)
            ORDER BY d.effective_date DESC NULLS LAST, d.released_date DESC NULLS LAST, d.id DESC
            LIMIT 1
        ) released_drawing ON TRUE
        WHERE etc.sales_order_id=%s
           OR (%s IS NOT NULL AND etc.project_code=%s)
           OR (%s IS NOT NULL AND etc.serial_no=%s)
        ORDER BY etc.confirmed_at DESC NULLS LAST, etc.id DESC
        LIMIT 1
        """,
        (order_id, project_code, project_code, serial_no, serial_no),
    )
    blockers = []
    if not confirmation:
        blockers.append("缺少技术确认单")
    else:
        confirmed = bool(
            confirmation.get("confirmed_at")
            or (confirmation.get("status") or "").strip() in {"已确认", "confirmed", "released"}
        )
        if not confirmed:
            blockers.append("技术确认未确认")
        if not confirmation.get("bom_id"):
            blockers.append("缺少BOM")
        elif not confirmation.get("bom_item_count"):
            blockers.append("BOM无明细")
        if not confirmation.get("drawing_no") or not confirmation.get("drawing_version"):
            blockers.append("缺少图纸版本")
        elif not confirmation.get("released_drawing_id"):
            blockers.append("图纸未发布")
        if not confirmation.get("routing_id"):
            blockers.append("缺少工艺路线")
        if not confirmation.get("work_center_id"):
            blockers.append("缺少工作中心")

    return {
        "ready": not blockers,
        "blocked_reason": "；".join(blockers),
        "next_action": "生成采购申请" if not blockers else "先补齐技术确认、BOM、图纸和工艺路线",
        "owner_role": "采购" if not blockers else "技术/工艺",
    }


def _create_purchase_requisition_from_suggestions():
    keyword = (request.form.get("keyword") or request.args.get("keyword") or "").strip()
    suggestions_url = url_for("purchase_suggestions", keyword=keyword) if keyword else url_for("purchase_suggestions")
    selected_keys = {key.strip() for key in request.form.getlist("suggestion_key") if key.strip()}
    if not selected_keys:
        flash("请先勾选要生成采购申请的采购建议行，系统不会再默认全量生成。", "warning")
        return redirect(suggestions_url)

    candidate_rows = [
        row
        for row in _purchase_suggestion_rows(300, keyword=keyword)
        if _as_decimal(row.get("suggestion_qty")) > 0
        and f"{row.get('product_id')}|{row.get('project_code') or '-'}|{row.get('serial_no') or '-'}" in selected_keys
    ]
    blocked_engineering = [row for row in candidate_rows if not row.get("engineering_ready")]
    if blocked_engineering:
        first = blocked_engineering[0]
        flash(
            "工程准备未就绪，不能生成采购申请；请先补齐技术确认、BOM、图纸和工艺路线，再回到采购建议复核。"
            f" 阻塞项目/机号：{first.get('project_code') or '-'} / {first.get('serial_no') or '-'}。",
            "warning",
        )
        return redirect(suggestions_url)

    rows = [row for row in candidate_rows if row.get("engineering_ready")]
    if not rows:
        flash("当前没有可生成采购申请的采购建议。", "info")
        return redirect(suggestions_url)

    req_no = _next_daily_doc_no("PR", "purchase_requisitions", "req_no")
    first = rows[0]
    req = _execute_and_return(
        """
        INSERT INTO purchase_requisitions
            (req_no, req_date, department, purpose, status, remark, project_code, serial_no)
        VALUES
            (%s, CURRENT_DATE, %s, %s, %s, %s, %s, %s)
        RETURNING id, req_no
        """,
        (
            req_no,
            "采购部",
            "MRP缺料生成采购申请",
            "待提交",
            "由采购建议自动生成，来源为当前 MRP 缺料扣减采购申请和采购未到后的缺口。",
            None if first.get("project_code") == "-" else first.get("project_code"),
            None if first.get("serial_no") == "-" else first.get("serial_no"),
        ),
    )
    req_id = req.get("id")
    _execute_db("UPDATE purchase_requisitions SET approval_status='draft' WHERE id=%s", (req_id,))
    created = 0
    for row in rows:
        qty = _as_decimal(row.get("suggestion_qty"))
        unit_price = _as_decimal(row.get("unit_price"))
        _execute_db(
            """
            INSERT INTO purchase_requisition_items
                (req_id, product_id, quantity, unit_price, amount, need_date, suggested_supplier_id, remark, project_code, serial_no)
            VALUES
                (%s, %s, %s, %s, %s, %s, NULLIF(%s, 0), %s, %s, %s)
            """,
            (
                req_id,
                row.get("product_id"),
                qty,
                unit_price,
                qty * unit_price,
                row.get("need_date"),
                row.get("suggested_supplier_id") or 0,
                f"MRP缺料建议：项目 {row.get('project_code') or '-'} / 机号 {row.get('serial_no') or '-'}",
                None if row.get("project_code") == "-" else row.get("project_code"),
                None if row.get("serial_no") == "-" else row.get("serial_no"),
            ),
        )
        created += 1
    _log_action("生成采购申请", req_no, f"由采购建议生成 {created} 行")
    flash(f"已生成采购申请 {req_no}，共 {created} 行。", "success")
    return redirect(f"/purchase_request/{req_id}")


def _create_purchase_requisition_from_project_shortage(order_id):
    order = _safe_one(
        """
        SELECT id, order_no, project_code, serial_no, cost_object_id
        FROM sales_orders
        WHERE id=%s
        """,
        (order_id,),
    )
    if not order:
        flash("销售订单不存在，无法生成采购申请。", "warning")
        return redirect("/projects")

    readiness = _project_engineering_readiness(order)
    if not readiness.get("ready"):
        flash(
            f"工程准备未就绪，不能生成采购申请；阻塞原因：{readiness.get('blocked_reason') or '技术资料未就绪'}；"
            f"下一步：{readiness.get('next_action') or '先补齐技术资料'}。",
            "warning",
        )
        return redirect(f"/project_kit/{order_id}")

    kit_rows = _project_kit_rows(
        order_id,
        order.get("project_code"),
        order.get("serial_no"),
        order.get("cost_object_id"),
    )
    shortage_rows = [row for row in kit_rows if _as_decimal(row.get("shortage_qty")) > 0]
    if not shortage_rows:
        flash("当前项目没有需要采购的齐套缺口。", "info")
        return redirect(f"/project_kit/{order_id}")

    req_no = _next_daily_doc_no("PR", "purchase_requisitions", "req_no")
    req = _execute_and_return(
        """
        INSERT INTO purchase_requisitions
            (req_no, req_date, department, purpose, status, remark, project_code, serial_no)
        VALUES
            (%s, CURRENT_DATE, %s, %s, %s, %s, %s, %s)
        RETURNING id, req_no
        """,
        (
            req_no,
            "采购部",
            "项目缺料生成采购申请",
            "待提交",
            f"项目齐套缺口自动生成，来源销售订单 {order.get('order_no') or order_id}",
            order.get("project_code"),
            order.get("serial_no"),
        ),
    )
    req_id = req.get("id")
    _execute_db("UPDATE purchase_requisitions SET approval_status='draft' WHERE id=%s", (req_id,))
    created = 0
    for row in shortage_rows:
        qty = _as_decimal(row.get("shortage_qty"))
        price_row = _safe_one(
            """
            SELECT COALESCE(sp.supplier_id, 0) AS supplier_id,
                   COALESCE(sp.unit_price, p.standard_price, 0) AS unit_price
            FROM products p
            LEFT JOIN LATERAL (
                SELECT supplier_id, unit_price
                FROM supplier_prices
                WHERE product_id=p.id AND COALESCE(is_active, TRUE)=TRUE
                ORDER BY COALESCE(is_primary, FALSE) DESC, effective_date DESC NULLS LAST, id DESC
                LIMIT 1
            ) sp ON TRUE
            WHERE p.id=%s
            """,
            (row.get("product_id"),),
        ) or {}
        unit_price = _as_decimal(price_row.get("unit_price"))
        _execute_db(
            """
            INSERT INTO purchase_requisition_items
                (req_id, product_id, quantity, unit_price, amount, need_date, suggested_supplier_id, remark, project_code, serial_no)
            VALUES
                (%s, %s, %s, %s, %s, CURRENT_DATE, NULLIF(%s, 0), %s, %s, %s)
            """,
            (
                req_id,
                row.get("product_id"),
                qty,
                unit_price,
                qty * unit_price,
                price_row.get("supplier_id") or 0,
                f"项目缺料建议：父项 {row.get('parent_name') or '-'} / BOM {row.get('bom_no') or '-'}",
                order.get("project_code"),
                order.get("serial_no"),
            ),
        )
        created += 1

    _log_action("项目缺料生成采购申请", req_no, f"来源销售订单 {order.get('order_no') or order_id}，生成 {created} 行")
    flash(f"已生成项目缺料采购申请 {req_no}，共 {created} 行。", "success")
    return redirect(f"/purchase_request/{req_id}")


