def _create_purchase_requisition_from_form():
    payload = request.get_json(silent=True) or {}
    items = payload.get("items") or []
    project_code = _short_text(payload.get("project_code"), 120)
    serial_no = _short_text(payload.get("serial_no"), 120)
    project_serial_error = _require_project_serial_json(project_code, serial_no)
    if project_serial_error:
        return project_serial_error
    valid_items = []
    for item in items:
        product_id = _as_int(item.get("material_id"))
        material_code = (item.get("material_code") or "").strip()
        product = None
        if product_id:
            product = _safe_one("SELECT id, standard_price, code, name, specification, unit FROM products WHERE id=%s", (product_id,))
        elif material_code:
            product = _safe_one("SELECT id, standard_price, code, name, specification, unit FROM products WHERE code=%s", (material_code,))
        if not product:
            continue
        quantity = _as_decimal(item.get("quantity"))
        if quantity <= 0:
            continue
        unit_price = _as_decimal(item.get("estimated_price"), product.get("standard_price") or "0")
        # 明细行级 project_code/serial_no 优先，回退到表头值
        line_project_code = _short_text(item.get("project_code"), 120) or project_code
        line_serial_no = _short_text(item.get("serial_no"), 120) or serial_no
        valid_items.append(
            {
                "product_id": product.get("id"),
                "quantity": quantity,
                "unit_price": unit_price,
                "supplier_id": _as_int(item.get("supplier_id")) or None,
                "warehouse_id": _as_int(item.get("warehouse_id")) or None,
                "location_id": _as_int(item.get("location_id")) or None,
                "lot_no": _short_text(item.get("lot_no"), 120),
                "source_line_no": _short_text(item.get("source_line_no"), 80),
                "material_code": (item.get("material_code") or product.get("code") or "").strip(),
                "material_name": (item.get("material_name") or product.get("name") or "").strip(),
                "material_spec": (item.get("spec") or product.get("specification") or "").strip(),
                "material_unit": (item.get("unit") or product.get("unit") or "").strip(),
                "project_code": line_project_code,
                "serial_no": line_serial_no,
                "expected_delivery_date": (item.get("expected_delivery_date") or payload.get("expected_date") or "").strip() or None,
            }
        )
    if not valid_items:
        return jsonify({"status": "error", "msg": "请至少录入一条有效物料明细。"}), 400

    req_no = (payload.get("request_no") or "").strip() or _next_daily_doc_no("PR", "purchase_requisitions", "req_no")
    req_date = (payload.get("date") or datetime.now().strftime("%Y-%m-%d")).strip()
    department = _short_text(payload.get("department"), 120)
    purpose = _short_text(payload.get("reason") or payload.get("purpose"), 500)
    remark = _short_text(payload.get("remark"), 1000)
    applicant = _short_text(payload.get("applicant"), 120)
    urgency = _short_text(payload.get("urgency"), 30) or "normal"
    req = _execute_and_return(
        """
        INSERT INTO purchase_requisitions
            (req_no, req_date, department, requester_id, purpose, status, remark,
             project_code, serial_no, applicant, urgency)
        VALUES
            (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
        RETURNING id, req_no
        """,
        (req_no, req_date, department, session.get("user_id"), purpose, "待提交", remark,
         project_code, serial_no, applicant, urgency),
    )
    req_id = _returned_id(req)
    _execute_db("UPDATE purchase_requisitions SET approval_status='draft' WHERE id=%s", (req_id,))
    for item in valid_items:
        amount = item["quantity"] * item["unit_price"]
        _execute_db(
            """
            INSERT INTO purchase_requisition_items
                (req_id, product_id, quantity, unit_price, amount, need_date, suggested_supplier_id,
                 project_code, serial_no,
                 warehouse_id, location_id, lot_no, source_line_no,
                 material_code, material_name, material_spec, material_unit)
            VALUES
                (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
            """,
            (
                req_id,
                item["product_id"],
                item["quantity"],
                item["unit_price"],
                amount,
                item["expected_delivery_date"],
                item["supplier_id"],
                item["project_code"],
                item["serial_no"],
                item["warehouse_id"],
                item["location_id"],
                item["lot_no"],
                item["source_line_no"],
                item["material_code"],
                item["material_name"],
                item["material_spec"],
                item["material_unit"],
            ),
        )
    _save_document_custom_payload("purchase_request", req_id, payload.get("custom_fields_json"))
    _log_action("新增采购申请", req_no, f"lines={len(valid_items)}")
    return jsonify({"status": "success", "id": req_id, "request_no": req_no})


