def _purchase_requisition_status_action(req_id, action):
    status_map = {
        "submit": ("已提交", {"待提交", "草稿", "pending", "draft", ""}, "提交"),
        "approve": ("已审核", {"已提交", "待审批", "待审核", "submitted"}, "审核"),
        "reject": ("已驳回", {"已提交", "待审批", "待审核", "submitted"}, "驳回"),
        "revert": ("已提交", {"已审核", "approved"}, "反审核"),
        "close": ("已关闭", {"已审核", "已生成采购订单", "approved", "completed"}, "关闭"),
        "void": ("已作废", {"待提交", "草稿", "已提交", "待审批", "待审核", "已驳回", "pending", "draft", "submitted"}, "作废"),
    }
    target = status_map.get(action)
    if not target:
        flash("不支持的采购申请操作。", "warning")
        return redirect(f"/purchase_request/{req_id}")
    new_status, allowed_statuses, action_label = target
    req = _safe_one("SELECT id, req_no, status, approval_status FROM purchase_requisitions WHERE id=%s", (req_id,))
    if not req:
        flash("采购申请不存在。", "warning")
        return redirect("/purchase_request")
    current_status = (req.get("status") or "").strip()
    if current_status not in allowed_statuses:
        flash(f"当前状态不能{action_label}。", "warning")
        return redirect(f"/purchase_request/{req_id}")
    if action in {"close", "void"}:
        linked = _safe_one(
            """
            SELECT COUNT(*) AS count
            FROM purchase_requisition_items
            WHERE req_id=%s AND po_order_id IS NOT NULL
            """,
            (req_id,),
        )
        if action == "void" and (linked or {}).get("count", 0):
            flash("已下推采购订单的采购申请不能作废。", "warning")
            return redirect(f"/purchase_request/{req_id}")
    _execute_db("UPDATE purchase_requisitions SET status=%s WHERE id=%s", (new_status, req_id))
    approval_status_map = {
        "submit": "submitted",
        "approve": "approved",
        "reject": "rejected",
        "revert": "submitted",
    }
    if action in approval_status_map:
        _execute_db(
            "UPDATE purchase_requisitions SET approval_status=%s WHERE id=%s",
            (approval_status_map[action], req_id),
        )
    _log_action(f"{action_label}采购申请", req.get("req_no") or str(req_id), f"{current_status}->{new_status}")
    flash(f"采购申请已{action_label}。", "success")
    return redirect(f"/purchase_request/{req_id}")


def _create_purchase_order_from_requisition(req_id):
    req = _safe_one("SELECT * FROM purchase_requisitions WHERE id=%s", (req_id,))
    if not req:
        flash("采购申请不存在，无法生成采购订单。", "warning")
        return redirect("/purchase_request")
    if (req.get("approval_status") or "").strip() != "approved":
        flash("Purchase requisition must be approved before creating purchase orders.", "warning")
        return redirect(f"/purchase_request/{req_id}")
    selected_quantities = {}
    if request.is_json:
        payload = request.get_json(silent=True) or {}
        selected_rows = payload.get("items") or []
        for row in payload.get("items") or []:
            item_id = _as_int(row.get("purchase_request_item_id"))
            qty = _as_decimal(row.get("quantity"))
            if item_id and qty > 0:
                selected_quantities[item_id] = qty
        if not selected_quantities:
            return jsonify({"status": "error", "msg": "请选择要下推的采购申请明细。"}), 400
    items = _safe_rows(
        """
        SELECT pri.*, COALESCE(pri.suggested_supplier_id, 0) AS supplier_id,
               COALESCE(pri.unit_price, p.standard_price, 0) AS price,
               p.default_tax_rate,
               GREATEST(COALESCE(pri.quantity,0)-COALESCE(po_items.ordered_qty,0),0) AS remaining_qty
        FROM purchase_requisition_items pri
        LEFT JOIN products p ON p.id=pri.product_id
        LEFT JOIN LATERAL (
            SELECT COALESCE(SUM(poi.quantity), 0) AS ordered_qty
            FROM purchase_order_items poi
            WHERE poi.source_line_no=CONCAT('PRITEM-', pri.id::text)
        ) po_items ON TRUE
        WHERE pri.req_id=%s
        ORDER BY pri.suggested_supplier_id NULLS LAST, pri.id
        """,
        (req_id,),
    )
    if selected_quantities:
        items = [item for item in items if item.get("id") in selected_quantities]
    for item in items:
        remaining_qty = _as_decimal(item.get("remaining_qty"))
        if selected_quantities:
            remaining_qty = min(remaining_qty, selected_quantities.get(item.get("id"), Decimal("0")))
        item["push_qty"] = remaining_qty
    items = [item for item in items if _as_decimal(item.get("push_qty")) > 0]
    if not items:
        flash("采购申请没有可下推的未下推明细。", "warning")
        return redirect(f"/purchase_request/{req_id}")

    groups = {}
    for item in items:
        supplier_id = item.get("supplier_id") or 0
        group_key = (
            supplier_id,
            item.get("cost_object_id"),
            item.get("project_code"),
            item.get("serial_no"),
        )
        groups.setdefault(group_key, []).append(item)
    created_orders = []
    for (supplier_id, cost_object_id, project_code, serial_no), group_items in groups.items():
        order_no = _next_daily_doc_no("PO", "purchase_orders", "order_no")
        total_amount = sum((_as_decimal(item.get("push_qty")) * _as_decimal(item.get("price")) for item in group_items), Decimal("0"))
        tax_amount = sum((
            _as_decimal(item.get("push_qty")) * _as_decimal(item.get("price")) * _as_decimal(item.get("default_tax_rate"), "13") / Decimal("100")
            for item in group_items
        ), Decimal("0"))
        po = _execute_and_return(
            """
            INSERT INTO purchase_orders
                (order_no, order_date, supplier_id, status, remark, total_amount, received_amount,
                 expected_date, tax_amount, amount_with_tax, cost_object_id, project_code, serial_no, created_by)
            VALUES
                (%s, CURRENT_DATE, %s, %s, %s, %s, 0, %s, %s, %s, %s, %s, %s, %s)
            RETURNING id, order_no
            """,
            (
                order_no,
                supplier_id or None,
                "待提交",
                f"由采购申请生成 {req.get('req_no')}",
                total_amount,
                min((item.get("need_date") for item in group_items if item.get("need_date")), default=None),
                tax_amount,
                total_amount + tax_amount,
                cost_object_id or req.get("cost_object_id"),
                project_code or req.get("project_code"),
                serial_no or req.get("serial_no"),
                session.get("user_id"),
            ),
        )
        if supplier_id:
            follow_up_date = min((item.get("need_date") for item in group_items if item.get("need_date")), default=None)
            payable_amount = total_amount + tax_amount
            upsert_purchase_order_payable(
                _execute_db,
                supplier_id=supplier_id,
                payable_no=_next_doc_no("AP", "supplier_payables", "payable_no"),
                doc_id=po.get("id"),
                doc_no=po.get("order_no"),
                doc_date=datetime.now().date().isoformat(),
                amount=payable_amount,
                balance=payable_amount,
                unpaid_status="未付款",
                paid_status="已付款",
                finance_remark=f"由采购申请 {req.get('req_no')} 自动生成应付。",
                next_follow_up_date=follow_up_date,
            )
        for item in group_items:
            qty = _as_decimal(item.get("push_qty"))
            price = _as_decimal(item.get("price"))
            item_tax_rate = _as_decimal(item.get("default_tax_rate"), "13")
            amount = qty * price
            item_tax = amount * item_tax_rate / Decimal("100")
            _execute_db(
                """
            INSERT INTO purchase_order_items
                (order_id, product_id, quantity, received_qty, unit_price, amount, remark,
                 tax_rate, tax_amount, amount_with_tax, source_supplier_id, source_line_no,
                 expected_date)
            VALUES
                (%s, %s, %s, 0, %s, %s, %s, %s, %s, %s, %s, %s, %s)
            """,
            (
                po.get("id"),
                    item.get("product_id"),
                    qty,
                    price,
                    amount,
                    f"由采购申请生成 {req.get('req_no')}",
                    item_tax_rate,
                item_tax,
                amount + item_tax,
                supplier_id or None,
                f"PRITEM-{item.get('id')}",
                item.get("need_date") or None,
            ),
        )
            _execute_db(
                "UPDATE purchase_requisition_items SET po_order_id=%s WHERE id=%s",
                (po.get("id"), item.get("id")),
            )
        created_orders.append(po.get("order_no"))

    if created_orders:
        _execute_db("UPDATE purchase_requisitions SET status=%s WHERE id=%s", ("已生成采购订单", req_id))
        _log_action("采购申请生成采购订单", req.get("req_no"), ", ".join(created_orders))
        if request.is_json:
            first_order = _safe_one(
                "SELECT id FROM purchase_orders WHERE order_no=%s ORDER BY id DESC LIMIT 1",
                (created_orders[0],),
            )
            return jsonify({
                "status": "success",
                "msg": f"已生成采购订单：{', '.join(created_orders)}",
                "id": first_order.get("id") if first_order else None,
                "redirect_url": f"/purchase_order/{first_order.get('id')}" if first_order else f"/purchase_request/{req_id}",
            })
        flash(f"已生成采购订单：{', '.join(created_orders)}", "success")
    return redirect(f"/purchase_request/{req_id}")


