def _shipment_status_action(shipment_id, action):
    if action in {"confirm", "audit"}:
        return _post_sales_shipment(shipment_id)
    if action == "unaudit":
        return _unaudit_sales_shipment(shipment_id)
    status_map = {"confirm": "已确认", "close": "已关闭", "void": "已作废"}
    action_text = {"confirm": "确认", "close": "关闭", "void": "作废"}.get(action)
    new_status = status_map.get(action)
    if not new_status:
        flash("不支持的销售发货单操作。", "warning")
        return redirect(f"/shipments/{shipment_id}")
    shipment = _safe_one("SELECT id, shipment_no, status FROM sales_shipments WHERE id=%s", (shipment_id,))
    if not shipment:
        flash("销售发货单不存在。", "warning")
        return redirect("/shipments")
    current_status = shipment.get("status") or ""
    if action == "confirm" and current_status in {"已发货", "已确认", "已关闭", "已作废", "void", "closed", "cancelled"}:
        flash("销售发货单当前状态不需要确认。", "info")
        return redirect(f"/shipments/{shipment_id}")
    if action in {"close", "void"} and current_status in {"已关闭", "已作废", "void", "closed", "cancelled"}:
        flash("销售发货单已结束，不能重复操作。", "warning")
        return redirect(f"/shipments/{shipment_id}")
    # H-01 修复：confirm 仅做状态流转。库存扣减在生成出库单时已完成（inventory_posted=TRUE 标记）。
    # 若单据未标记 inventory_posted（手工创建路径），此处仅更新状态，不重复扣库。
    _execute_db("UPDATE sales_shipments SET status=%s WHERE id=%s", (new_status, shipment_id))
    _log_action(f"{action_text}销售发货", shipment.get("shipment_no") or str(shipment_id), f"{current_status}->{new_status}")
    flash(f"销售发货单已{action_text}。", "success")
    return redirect(f"/shipments/{shipment_id}")


def _sales_order_shipping_status(order_id):
    row = _safe_one(
        """
        SELECT status,
               COALESCE(SUM(COALESCE(soi.quantity,0)),0) AS ordered_qty,
               COALESCE(SUM(COALESCE(soi.shipped_qty,0)),0) AS shipped_qty
        FROM sales_orders so
        LEFT JOIN sales_order_items soi ON soi.order_id=so.id
        WHERE so.id=%s
        GROUP BY so.id
        """,
        (order_id,),
    ) or {}
    current_status = (row.get("status") or "").strip()
    if current_status in {"已关闭", "已作废", "closed", "voided"}:
        return current_status
    ordered_qty = _as_decimal(row.get("ordered_qty"))
    shipped_qty = _as_decimal(row.get("shipped_qty"))
    if shipped_qty <= 0:
        return "已审核"
    if ordered_qty > 0 and shipped_qty >= ordered_qty:
        return "已发货"
    return "部分发货"


def _post_sales_shipment(shipment_id):
    shipment = _safe_one(
        """
        SELECT ss.*, so.order_no, so.customer_id AS order_customer_id,
               so.cost_object_id AS order_cost_object_id
        FROM sales_shipments ss
        LEFT JOIN sales_orders so ON so.id=ss.order_id
        WHERE ss.id=%s
        """,
        (shipment_id,),
    )
    if not shipment:
        flash("销售发货单不存在。", "warning")
        return redirect("/shipments")
    status = (shipment.get("status") or "").strip()
    if status in {"已关闭", "已作废", "void", "closed", "cancelled", "已取消"}:
        flash("销售发货单已结束，不能审核。", "warning")
        return redirect(f"/shipments/{shipment_id}")
    if shipment.get("inventory_posted") or status in {"已发货", "已确认", "confirmed"}:
        flash("销售发货单已审核过账。", "info")
        return redirect(f"/shipments/{shipment_id}")
    lines = _safe_rows(
        """
        SELECT *
        FROM sales_shipment_items
        WHERE shipment_id=%s
        ORDER BY id
        """,
        (shipment_id,),
    )
    if not lines:
        flash("销售发货单没有明细，不能审核。", "warning")
        return redirect(f"/shipments/{shipment_id}")

    def _shipment_stock_dimensions(line, qty):
        warehouse_id = line.get("warehouse_id") or shipment.get("warehouse_id")
        location_id = line.get("location_id")
        lot_no = line.get("lot_no") or ""
        serial_no = shipment.get("serial_no") or ""
        project_code = shipment.get("project_code") or ""
        exact_qty = _inventory_available_qty(line.get("product_id"), warehouse_id, location_id, lot_no, serial_no, project_code)
        if exact_qty >= qty or (not serial_no and not project_code):
            return serial_no, project_code
        common_qty = _inventory_available_qty(line.get("product_id"), warehouse_id, location_id, lot_no, "", "")
        if common_qty >= qty:
            return "", ""
        return serial_no, project_code

    def operation(_cursor):
        for line in lines:
            qty = _as_decimal(line.get("quantity"))
            if qty <= 0:
                continue
            unit_cost = _as_decimal(line.get("unit_price") or line.get("unit_cost"))
            stock_serial_no, stock_project_code = _shipment_stock_dimensions(line, qty)
            _execute_db(
                "UPDATE sales_order_items SET shipped_qty=COALESCE(shipped_qty,0)+%s WHERE id=%s",
                (qty, line.get("order_item_id")),
            )
            _apply_inventory_movement(
                product_id=line.get("product_id"),
                quantity=-qty,
                unit_cost=unit_cost,
                tx_type="销售出库",
                reference_no=shipment.get("shipment_no"),
                remark=shipment.get("remark") or "销售发货审核过账",
                warehouse_id=line.get("warehouse_id") or shipment.get("warehouse_id"),
                location_id=line.get("location_id"),
                lot_no=line.get("lot_no") or "",
                serial_no=stock_serial_no,
                project_code=stock_project_code,
                tx_date=shipment.get("shipment_date"),
                query_one=_safe_one,
                execute_db_fn=_execute_db,
            )
            st_row = _safe_one(
                "SELECT id FROM stock_transactions WHERE reference_no=%s AND product_id=%s ORDER BY id DESC LIMIT 1",
                (shipment.get("shipment_no"), line.get("product_id")),
            ) or {}
            st_id = st_row.get("id")
            if st_id:
                try:
                    create_trace_link(
                        _safe_one,
                        _execute_db,
                        execute_and_return=_execute_and_return,
                        source_doc_type="sales_shipment",
                        source_doc_id=shipment_id,
                        source_doc_no=shipment.get("shipment_no"),
                        target_doc_type="stock_transaction",
                        target_doc_id=st_id,
                        link_type="posts_to",
                        link_strength="soft",
                        project_code=shipment.get("project_code"),
                        serial_no=shipment.get("serial_no"),
                        created_by=session.get("user_id"),
                        created_event="sales_shipment_inventory",
                    )
                except Exception:
                    current_app.logger.exception("Sales shipment traceability link failed for shipment_no=%s", shipment.get("shipment_no"))
        _execute_db(
            """
            UPDATE sales_orders
            SET shipped_amount=COALESCE(shipped_amount,0)+%s,
                status=%s
            WHERE id=%s
            """,
            (
                _as_decimal(shipment.get("shipped_amount")),
                _sales_order_shipping_status(shipment.get("order_id")),
                shipment.get("order_id"),
            ),
        )
        _execute_db(
            "UPDATE sales_shipments SET status='已发货', inventory_posted=TRUE WHERE id=%s",
            (shipment_id,),
        )

    _run_registry_transaction(operation)
    order_for_service = dict(shipment)
    order_for_service["id"] = shipment.get("order_id")
    order_for_service["order_no"] = shipment.get("order_no")
    order_for_service["customer_id"] = shipment.get("order_customer_id") or shipment.get("customer_id")
    order_for_service["cost_object_id"] = shipment.get("order_cost_object_id") or shipment.get("cost_object_id")
    service_lines = [(line, _as_decimal(line.get("quantity"))) for line in lines]
    service_card = _ensure_service_card_for_shipment(order_for_service, service_lines, shipment.get("shipment_date"), shipment.get("shipment_no"))
    service_card_text = "，并生成/更新设备服务档案" if service_card else ""
    _log_action("审核销售发货", shipment.get("shipment_no") or str(shipment_id), "审核即过账")
    flash(f"销售发货单已审核过账{service_card_text}。", "success")
    return redirect(f"/shipments/{shipment_id}")


def _unaudit_sales_shipment(shipment_id):
    shipment = _safe_one("SELECT * FROM sales_shipments WHERE id=%s", (shipment_id,))
    if not shipment:
        flash("销售发货单不存在。", "warning")
        return redirect("/shipments")
    if not shipment.get("inventory_posted") and (shipment.get("status") or "").strip() not in {"已发货", "已确认", "confirmed"}:
        flash("只有已审核过账的销售发货单可以反审。", "warning")
        return redirect(f"/shipments/{shipment_id}")
    if (shipment.get("status") or "").strip() in {"已关闭", "已作废", "void", "closed", "cancelled", "已取消"}:
        flash("销售发货单已结束，不能反审。", "warning")
        return redirect(f"/shipments/{shipment_id}")
    lines = _safe_rows("SELECT * FROM sales_shipment_items WHERE shipment_id=%s ORDER BY id", (shipment_id,))
    if not lines:
        flash("销售发货单没有明细，不能反审。", "warning")
        return redirect(f"/shipments/{shipment_id}")

    def operation(_cursor):
        for line in lines:
            qty = _as_decimal(line.get("quantity"))
            if qty <= 0:
                continue
            unit_cost = _as_decimal(line.get("unit_price") or line.get("unit_cost"))
            posted_tx = _safe_one(
                """
                SELECT serial_no, project_code
                FROM stock_transactions
                WHERE reference_no=%s AND product_id=%s AND quantity<0
                ORDER BY id DESC
                LIMIT 1
                """,
                (shipment.get("shipment_no"), line.get("product_id")),
            ) or {}
            _apply_inventory_movement(
                product_id=line.get("product_id"),
                quantity=qty,
                unit_cost=unit_cost,
                tx_type="销售出库反审",
                reference_no=shipment.get("shipment_no"),
                remark=shipment.get("remark") or "销售发货反审回滚",
                warehouse_id=line.get("warehouse_id") or shipment.get("warehouse_id"),
                location_id=line.get("location_id"),
                lot_no=line.get("lot_no") or "",
                serial_no=posted_tx.get("serial_no") or "",
                project_code=posted_tx.get("project_code") or "",
                tx_date=shipment.get("shipment_date"),
                query_one=_safe_one,
                execute_db_fn=_execute_db,
            )
            _execute_db(
                "UPDATE sales_order_items SET shipped_qty=GREATEST(COALESCE(shipped_qty,0)-%s,0) WHERE id=%s",
                (qty, line.get("order_item_id")),
            )
        _execute_db(
            """
            UPDATE sales_orders
            SET shipped_amount=GREATEST(COALESCE(shipped_amount,0)-%s,0),
                status=%s
            WHERE id=%s
            """,
            (
                _as_decimal(shipment.get("shipped_amount")),
                _sales_order_shipping_status(shipment.get("order_id")),
                shipment.get("order_id"),
            ),
        )
        _execute_db(
            "UPDATE sales_shipments SET status='待审核', inventory_posted=FALSE WHERE id=%s",
            (shipment_id,),
        )

    _run_registry_transaction(operation)
    _log_action("反审销售发货", shipment.get("shipment_no") or str(shipment_id), "回滚库存和订单发货数量")
    flash("销售发货单已反审，库存和销售订单已发数量已回滚。", "success")
    return redirect(f"/shipments/{shipment_id}")


def _delete_sales_shipment_draft(shipment_id):
    shipment = _safe_one("SELECT id, shipment_no, status, inventory_posted FROM sales_shipments WHERE id=%s", (shipment_id,))
    if not shipment:
        flash("销售发货单不存在或已删除。", "warning")
        return redirect("/shipments")
    status = (shipment.get("status") or "").strip()
    if shipment.get("inventory_posted") or status in {"已发货", "已确认", "confirmed", "已过账"}:
        flash("已过账销售发货单不能直接删除，请先反审。", "warning")
        return redirect(f"/shipments/{shipment_id}")
    if status in {"已关闭", "已作废", "void", "closed", "cancelled", "已取消"}:
        flash("已关闭或已作废销售发货单不能删除。", "warning")
        return redirect(f"/shipments/{shipment_id}")
    shipment_no = shipment.get("shipment_no") or str(shipment_id)
    if _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s OR source_doc_no=%s LIMIT 1", (shipment_no, shipment_no)):
        flash("该销售发货单已有库存流水，不能直接删除，请先反审。", "warning")
        return redirect(f"/shipments/{shipment_id}")

    def operation(_cursor):
        _execute_db("DELETE FROM sales_shipment_items WHERE shipment_id=%s", (shipment_id,))
        _execute_db("DELETE FROM sales_shipments WHERE id=%s", (shipment_id,))

    _run_registry_transaction(operation)
    _log_action("删除销售发货单草稿", shipment_no)
    flash(f"销售发货单 {shipment_no} 已删除。", "success")
    return redirect("/shipments")


def _create_purchase_receipt_from_order(order_id):
    if request.is_json:
        payload = request.get_json(silent=True) or {}
    else:
        payload = request.form.to_dict(flat=False)

    def payload_value(key, default=None):
        value = payload.get(key, default)
        if isinstance(value, list):
            return value[0] if value else default
        return value

    save_action = (payload_value("save_action", "save") or "save").strip()
    if save_action == "unaudit":
        flash("反审请在已入库采购入库单详情页执行。", "warning")
        return redirect("/purchase_receipts")

    order = _safe_one(
        """
        SELECT po.*, s.name AS supplier_name
        FROM purchase_orders po
        LEFT JOIN suppliers s ON s.id=po.supplier_id
        WHERE po.id=%s
        """,
        (order_id,),
    )
    if not order:
        return jsonify({"ok": False, "error": "采购订单不存在。"}), 404
    if (order.get("status") or "").strip() not in PURCHASE_RECEIVE_READY_STATUSES:
        if request.is_json:
            return jsonify({"ok": False, "error": "采购订单必须已审核/待收货/部分收货才能生成采购入库。"}), 400
        flash("采购订单必须已审核/待收货/部分收货才能生成采购入库。", "warning")
        return redirect(f"/purchase_order/{order_id}")

    warehouse_id = _as_int(payload_value("warehouse_id")) or _as_int(order.get("warehouse_id"))
    if warehouse_id and not _active_master_exists("warehouses", warehouse_id):
        if request.is_json:
            return jsonify({"ok": False, "error": "收货仓库不存在或已停用。"}), 400
        flash("收货仓库不存在或已停用。", "warning")
        return redirect(f"/purchase_order/{order_id}")

    receipt_date = payload_value("receipt_date") or datetime.now().date().isoformat()
    remark = payload_value("remark") or f"由采购订单 {order.get('order_no')} 生成入库"
    raw_items = payload.get("items") or []
    if not raw_items and payload.get("item_id[]"):
        item_ids = payload.get("item_id[]") or []
        quantities = payload.get("quantity[]") or []
        raw_items = [
            {"item_id": item_id, "quantity": quantities[idx] if idx < len(quantities) else 0}
            for idx, item_id in enumerate(item_ids)
        ]
    if isinstance(raw_items, dict):
        raw_items = list(raw_items.values())
    if not raw_items and not request.is_json:
        item_ids = request.form.getlist("item_id[]")
        quantities = request.form.getlist("quantity[]")
        raw_items = [
            {"item_id": item_id, "quantity": quantities[idx] if idx < len(quantities) else "0"}
            for idx, item_id in enumerate(item_ids)
        ]
    if not raw_items and not request.is_json:
        item_ids = request.form.getlist("order_item_id[]")
        quantities = request.form.getlist("quantity[]")
        lot_nos = request.form.getlist("lot_no[]")
        warehouse_ids = request.form.getlist("warehouse_id[]")
        location_ids = request.form.getlist("location_id[]")
        raw_items = []
        for idx, item_id in enumerate(item_ids):
            raw_items.append({
                "item_id": item_id,
                "quantity": quantities[idx] if idx < len(quantities) else "0",
                "lot_no": lot_nos[idx] if idx < len(lot_nos) else "",
                "warehouse_id": warehouse_ids[idx] if idx < len(warehouse_ids) else "",
                "location_id": location_ids[idx] if idx < len(location_ids) else "",
            })

    receipt_no = _form_text("receipt_no") or _next_doc_no("PIR", "purchase_receipts", "receipt_no")
    conn = deps["get_db"]()
    receipt_id = None
    try:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT po.*, s.name AS supplier_name
                FROM purchase_orders po
                LEFT JOIN suppliers s ON s.id=po.supplier_id
                WHERE po.id=%s
                FOR UPDATE OF po
                """,
                (order_id,),
            )
            order = cur.fetchone()
            if not order:
                raise ValueError("采购订单不存在。")
            if (order.get("status") or "").strip() not in PURCHASE_RECEIVE_READY_STATUSES:
                raise ValueError("采购订单必须已审核/待收货/部分收货才能生成采购入库。")
            cur.execute(
                """
                SELECT poi.*, p.default_warehouse_id, p.default_location
                FROM purchase_order_items poi
                LEFT JOIN products p ON p.id=poi.product_id
                WHERE poi.order_id=%s
                ORDER BY poi.id
                FOR UPDATE OF poi
                """,
                (order_id,),
            )
            order_items = cur.fetchall()
            item_map = {str(row["id"]): row for row in order_items}
            selected = []
            if raw_items:
                for item in raw_items:
                    item_id = str(item.get("item_id") or item.get("order_item_id") or item.get("id") or "")
                    row = item_map.get(item_id)
                    if not row:
                        continue
                    pending_qty = _as_decimal(row.get("quantity")) - _as_decimal(row.get("received_qty"))
                    requested_qty = _as_decimal(item.get("quantity"))
                    if requested_qty <= 0:
                        continue
                    if requested_qty > pending_qty:
                        raise ValueError(f"明细 {item_id} 收货数量不能大于未收数量。")
                    selected.append((
                        row,
                        requested_qty,
                        item.get("lot_no") or row.get("lot_no") or "",
                        _as_int(item.get("warehouse_id")) or _as_int(row.get("warehouse_id")) or _as_int(row.get("default_warehouse_id")) or warehouse_id,
                        _as_int(item.get("location_id")) or _as_int(row.get("location_id")) or _as_int(row.get("default_location")),
                    ))
            else:
                for row in order_items:
                    pending_qty = _as_decimal(row.get("quantity")) - _as_decimal(row.get("received_qty"))
                    if pending_qty > 0:
                        selected.append((
                            row,
                            pending_qty,
                            row.get("lot_no") or "",
                            _as_int(row.get("warehouse_id")) or _as_int(row.get("default_warehouse_id")) or warehouse_id,
                            _as_int(row.get("location_id")) or _as_int(row.get("default_location")),
                        ))
            if not selected:
                raise ValueError("没有可入库的明细。")
            receipt_warehouse_id = warehouse_id or selected[0][3]
            if not receipt_warehouse_id:
                raise ValueError("请选择收货仓库。")
            if not _active_master_exists("warehouses", receipt_warehouse_id):
                raise ValueError("收货仓库不存在或已停用。")

            cur.execute(
                """
                INSERT INTO purchase_receipts
                    (receipt_no, order_id, receipt_date, warehouse_id, operator_id, status, remark, cost_object_id, project_code, serial_no)
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                RETURNING id
                """,
                (
                    receipt_no,
                    order_id,
                    receipt_date,
                    receipt_warehouse_id,
                    session.get("user_id"),
                    INVENTORY_STATUS_PENDING,
                    remark,
                    order.get("cost_object_id"),
                    order.get("project_code"),
                    order.get("serial_no"),
                ),
            )
            receipt_row = cur.fetchone()
            if not receipt_row:
                raise RuntimeError("采购收货单插入失败")
            receipt_id = receipt_row["id"] if isinstance(receipt_row, dict) else receipt_row[0]
            query_db_fn, execute_db_fn, execute_and_return_fn = cursor_db_helpers(cur)
            create_trace_link(
                query_db_fn,
                execute_db_fn,
                execute_and_return=execute_and_return_fn,
                source_doc_type="purchase_order",
                source_doc_id=order_id,
                source_doc_no=order.get("order_no"),
                target_doc_type="purchase_receipt",
                target_doc_id=receipt_id,
                target_doc_no=receipt_no,
                link_type="source_of",
                link_strength="hard",
                project_code=order.get("project_code"),
                serial_no=order.get("serial_no"),
                created_by=session.get("user_id"),
                created_event="create_purchase_receipt",
            )
            total_received_amount = Decimal("0")
            for row, qty, lot_no, line_warehouse_id, location_id in selected:
                # 仓库未启用库位时清空库位避免脏值（表头/行级回退可能带入历史库位）
                if location_id and not _warehouse_has_locations(line_warehouse_id):
                    location_id = 0
                product_id = row.get("product_id")
                if not product_id:
                    raise ValueError("采购订单明细缺少物料，不能入库。")
                product_error = _inactive_master_error("products", product_id, "物料")
                if product_error:
                    raise ValueError(product_error)
                warehouse_error = _inactive_master_error("warehouses", line_warehouse_id, "收货仓库")
                if warehouse_error:
                    raise ValueError(warehouse_error)
                if location_id:
                    location_error = _inventory_location_requirement_error(line_warehouse_id, location_id, "收货仓库")
                    if location_error:
                        raise ValueError(location_error)
                unit_cost = _as_decimal(row.get("unit_price"))
                tax_rate = _as_decimal(row.get("tax_rate"))
                amount = qty * unit_cost
                tax_amount = amount * tax_rate / Decimal("100")
                amount_with_tax = amount + tax_amount
                total_received_amount += amount_with_tax
                cur.execute(
                    """
                    INSERT INTO purchase_receipt_items
                        (receipt_id, order_item_id, product_id, quantity, unit_cost, lot_no, warehouse_id, location_id,
                         tax_rate, tax_amount, amount_with_tax, price_source, price_source_label,
                         supplier_item_code_snapshot, lead_time_days_snapshot, source_supplier_id)
                    VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                    """,
                    (
                        receipt_id,
                        row.get("id"),
                        product_id,
                        qty,
                        unit_cost,
                        lot_no,
                        line_warehouse_id,
                        location_id,
                        tax_rate,
                        tax_amount,
                        amount_with_tax,
                        row.get("price_source"),
                        row.get("price_source_label"),
                        row.get("supplier_item_code_snapshot"),
                        row.get("lead_time_days_snapshot"),
                        row.get("source_supplier_id"),
                    ),
                )
                continue
                cur.execute(
                    "UPDATE purchase_order_items SET received_qty=COALESCE(received_qty,0)+%s WHERE id=%s",
                    (qty, row.get("id")),
                )
                cur.execute("SELECT code, name FROM locations WHERE id=%s", (location_id,)) if location_id else None
                loc = cur.fetchone() if location_id else None
                location_label = (loc.get("code") or loc.get("name") or "") if loc else ""
                project_code = order.get("project_code") or ""
                serial_no = order.get("serial_no") or ""
                cur.execute(
                    """
                    SELECT id, quantity, unit_cost
                    FROM inventory_balances
                    WHERE product_id=%s AND COALESCE(warehouse_id,0)=COALESCE(%s,0)
                      AND COALESCE(location_id,0)=COALESCE(%s,0)
                      AND COALESCE(lot_no,'')=COALESCE(%s,'')
                      AND COALESCE(serial_no,'')=COALESCE(%s,'')
                      AND COALESCE(project_code,'')=COALESCE(%s,'')
                    ORDER BY id
                    LIMIT 1
                    FOR UPDATE
                    """,
                    (product_id, line_warehouse_id, location_id, lot_no, serial_no, project_code),
                )
                balance = cur.fetchone()
                if balance:
                    old_qty = _as_decimal(balance.get("quantity"))
                    old_cost = _as_decimal(balance.get("unit_cost"))
                    new_qty = old_qty + qty
                    new_cost = ((old_qty * old_cost) + (qty * unit_cost)) / new_qty if new_qty > 0 else unit_cost
                    cur.execute(
                        "UPDATE inventory_balances SET quantity=%s, unit_cost=%s, updated_at=NOW() WHERE id=%s",
                        (new_qty, new_cost, balance.get("id")),
                    )
                else:
                    cur.execute(
                        """
                        INSERT INTO inventory_balances
                            (product_id, warehouse_id, location_id, lot_no, serial_no, project_code, quantity, locked_qty, unit_cost, updated_at)
                        VALUES (%s,%s,%s,%s,%s,%s,%s,0,%s,NOW())
                        """,
                        (product_id, line_warehouse_id, location_id, lot_no, serial_no, project_code, qty, unit_cost),
                    )
                cur.execute("SELECT id, quantity, unit_cost FROM inventory WHERE product_id=%s LIMIT 1 FOR UPDATE", (product_id,))
                inv = cur.fetchone()
                if inv:
                    old_qty = _as_decimal(inv.get("quantity"))
                    old_cost = _as_decimal(inv.get("unit_cost"))
                    new_qty = old_qty + qty
                    new_cost = ((old_qty * old_cost) + (qty * unit_cost)) / new_qty if new_qty > 0 else unit_cost
                    cur.execute("UPDATE inventory SET quantity=%s, unit_cost=%s WHERE id=%s", (new_qty, new_cost, inv.get("id")))
                else:
                    cur.execute(
                        "INSERT INTO inventory (product_id, quantity, unit_cost, location, reorder_level) VALUES (%s,%s,%s,%s,0)",
                        (product_id, qty, unit_cost, location_label),
                    )
                cur.execute(
                    """
                    INSERT INTO stock_transactions
                        (transaction_date, transaction_type, product_id, quantity, unit_cost, reference_no,
                         lot_no, serial_no, project_code, location, remark, warehouse_id, location_id)
                    VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                    """,
                    (receipt_date, "采购入库", product_id, qty, unit_cost, receipt_no, lot_no, serial_no, project_code, location_label, remark, line_warehouse_id, location_id),
                )
                # Sync batch_tracking from inventory_balances to prevent consistency audit failures.
                # This path directly modifies inventory_balances (bypassing _apply_inventory_movement),
                # so batch_tracking must be synced here as well. Without this, every purchase receipt
                # creates an inventory_balances row without a matching batch_tracking row, causing
                # the audit to fail. This is the root cause of recurring batch_tracking inconsistency.
                cur.execute(
                    """
                    SELECT COALESCE(SUM(quantity),0) AS quantity,
                           CASE WHEN COALESCE(SUM(quantity),0) <> 0
                               THEN COALESCE(SUM(quantity * COALESCE(unit_cost,0)) / NULLIF(SUM(quantity),0),0)
                               ELSE COALESCE(MAX(unit_cost),0)
                           END AS unit_cost
                    FROM inventory_balances
                    WHERE product_id=%s
                      AND warehouse_id IS NOT DISTINCT FROM %s
                      AND location_id IS NOT DISTINCT FROM %s
                      AND COALESCE(project_code,'')=%s
                      AND COALESCE(lot_no,'')=%s
                      AND COALESCE(serial_no,'')=%s
                    """,
                    (product_id, line_warehouse_id, location_id, project_code or "", lot_no or "", serial_no or ""),
                )
                _bt_balance = cur.fetchone() or {}
                _bt_qty = _as_decimal(_bt_balance.get("quantity"))
                _bt_cost = _as_decimal(_bt_balance.get("unit_cost"))
                cur.execute(
                    """
                    SELECT id FROM batch_tracking
                    WHERE product_id=%s
                      AND warehouse_id IS NOT DISTINCT FROM %s
                      AND location_id IS NOT DISTINCT FROM %s
                      AND COALESCE(project_code,'')=%s
                      AND COALESCE(lot_no,'')=%s
                      AND COALESCE(serial_no,'')=%s
                    ORDER BY id LIMIT 1
                    FOR UPDATE
                    """,
                    (product_id, line_warehouse_id, location_id, project_code or "", lot_no or "", serial_no or ""),
                )
                _existing_bt = cur.fetchone()
                if _existing_bt:
                    cur.execute(
                        """
                        UPDATE batch_tracking
                        SET quantity_available=%s,
                            unit_cost=%s,
                            quantity_in=CASE WHEN %s > 0 THEN COALESCE(quantity_in,0) + %s ELSE COALESCE(quantity_in,0) END,
                            quantity_out=CASE WHEN %s < 0 THEN COALESCE(quantity_out,0) + (-%s) ELSE COALESCE(quantity_out,0) END,
                            updated_at=NOW()
                        WHERE id=%s
                        """,
                        (_bt_qty, _bt_cost, qty, qty, qty, qty, _existing_bt["id"]),
                    )
                else:
                    cur.execute(
                        """
                        INSERT INTO batch_tracking
                            (lot_no, product_id, warehouse_id, location_id, serial_no, project_code,
                             quantity_in, quantity_out, quantity_available, unit_cost, source_order_no,
                             status, created_at, updated_at)
                        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,'derived',NOW(),NOW())
                        """,
                        (
                            lot_no or "", product_id, line_warehouse_id, location_id,
                            serial_no or None, project_code or None,
                            qty if qty > 0 else Decimal("0"),
                            -qty if qty < 0 else Decimal("0"),
                            _bt_qty, _bt_cost, receipt_no or "purchase_receipt_sync",
                        ),
                    )
                # Link the purchase receipt to the inventory movement for traceability.
                st_row = cur.execute(
                    "SELECT id FROM stock_transactions WHERE reference_no=%s AND product_id=%s ORDER BY id DESC LIMIT 1",
                    (receipt_no, product_id),
                )
                st_id = None
                st_fetch = cur.fetchone() if st_row is not None else None
                if st_fetch:
                    st_id = st_fetch.get("id") if isinstance(st_fetch, dict) else st_fetch[0]
                if st_id:
                    try:
                        create_trace_link(
                            query_db_fn,
                            execute_db_fn,
                            execute_and_return=execute_and_return_fn,
                            source_doc_type="purchase_receipt",
                            source_doc_id=receipt_id,
                            source_doc_no=receipt_no,
                            target_doc_type="stock_transaction",
                            target_doc_id=st_id,
                            link_type="posts_to",
                            link_strength="soft",
                            project_code=project_code,
                            serial_no=serial_no,
                            created_by=session.get("user_id"),
                            created_event="purchase_receipt_inventory",
                        )
                    except Exception:
                        current_app.logger.exception("Purchase receipt traceability link failed for receipt_no=%s", receipt_no)

            pass
        conn.commit()
    except ValueError as exc:
        conn.rollback()
        if request.is_json:
            return jsonify({"ok": False, "error": str(exc)}), 400
        flash(str(exc), "warning")
        return redirect(f"/purchase_order/{order_id}")
    except Exception:
        conn.rollback()
        raise

    _log_action("采购入库", receipt_no, f"由采购订单 {order.get('order_no')} 生成")
    if request.is_json:
        return jsonify({"ok": True, "id": receipt_id, "receipt_no": receipt_no, "url": f"/purchase_receipts/{receipt_id}"})
    flash(f"已生成采购入库单 {receipt_no}。", "success")
    if save_action == "save_new":
        return redirect("/purchase_receipts/new")
    return redirect(f"/purchase_receipts/{receipt_id}")


def _unaudit_purchase_receipt(receipt_id):
    receipt = _safe_one("SELECT * FROM purchase_receipts WHERE id=%s", (receipt_id,))
    if not receipt:
        return redirect("/purchase_receipts")
    receipt_no = receipt.get("receipt_no")
    if not receipt_no:
        flash("采购入库单缺少单据编号，反审已停止。", "warning")
        return redirect(f"/purchase_receipts/{receipt_id}")

    def operation(cursor):
        query_one, query_rows, execute_db, _ = _registry_transaction_callables(cursor)
        fresh = query_one("SELECT * FROM purchase_receipts WHERE id=%s FOR UPDATE", (receipt_id,))
        if not fresh:
            raise ValueError("Purchase receipt not found.")
        lines = query_rows(
            """
            SELECT id, order_item_id, quantity, amount_with_tax
            FROM purchase_receipt_items
            WHERE receipt_id=%s
            ORDER BY id
            """,
            (receipt_id,),
        )
        if not lines:
            raise ValueError("Purchase receipt has no lines.")
        receipt_amount = sum((_as_decimal(line.get("amount_with_tax")) for line in lines), Decimal("0"))
        reversed_count = _reverse_stock_transactions_for_reference(
            receipt_no,
            query_rows=query_rows,
            query_one=query_one,
            execute_db_fn=execute_db,
        )
        for line in lines:
            order_item_id = line.get("order_item_id")
            if not order_item_id:
                continue
            qty = _as_decimal(line.get("quantity"))
            execute_db(
                """
                UPDATE purchase_order_items
                SET received_qty=GREATEST(COALESCE(received_qty,0)-%s,0)
                WHERE id=%s
                """,
                (qty, order_item_id),
            )
        if fresh.get("order_id"):
            pending = query_one(
                """
                SELECT COALESCE(SUM(GREATEST(COALESCE(quantity,0)-COALESCE(received_qty,0),0)),0) AS pending_qty,
                       COALESCE(SUM(COALESCE(received_qty,0)),0) AS received_qty
                FROM purchase_order_items
                WHERE order_id=%s
                """,
                (fresh.get("order_id"),),
            ) or {}
            if _as_decimal(pending.get("received_qty")) <= 0:
                order_status = "已审核"
            elif _as_decimal(pending.get("pending_qty")) > 0:
                order_status = "部分收货"
            else:
                order_status = "已收货"
            execute_db(
                """
                UPDATE purchase_orders
                SET status=%s,
                    received_amount=GREATEST(COALESCE(received_amount,0)-COALESCE(%s,0),0)
                WHERE id=%s
                """,
                (order_status, receipt_amount, fresh.get("order_id")),
            )
        execute_db(
            """
            UPDATE purchase_receipts
            SET status=%s
            WHERE id=%s
            """,
            (INVENTORY_STATUS_PENDING, receipt_id),
        )
        return reversed_count

    try:
        reversed_count = _run_registry_transaction(operation)
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(f"/purchase_receipts/{receipt_id}")
    _log_action("purchase_receipt_reverse_audit", receipt_no)
    flash(f"反审完成，已回滚 {reversed_count} 条库存流水。", "success")
    return redirect(f"/purchase_receipts/{receipt_id}")


def _delete_purchase_receipt_draft(receipt_id):
    receipt = _safe_one("SELECT * FROM purchase_receipts WHERE id=%s", (receipt_id,))
    if not receipt:
        flash("采购入库单不存在或已删除。", "warning")
        return redirect("/purchase_receipts")
    receipt_no = receipt.get("receipt_no")
    status = (receipt.get("status") or "").strip()
    if status in {INVENTORY_STATUS_POSTED, "已收货", "posted", "audited"}:
        flash("已过账采购入库单不能直接删除，请先反审。", "warning")
        return redirect(f"/purchase_receipts/{receipt_id}")
    if receipt_no:
        tx_count = _safe_one(
            "SELECT COUNT(*) AS count FROM stock_transactions WHERE reference_no=%s",
            (receipt_no,),
        ) or {}
        if _as_int(tx_count.get("count")) > 0:
            flash("该采购入库单已有库存流水，不能直接删除，请先反审。", "warning")
            return redirect(f"/purchase_receipts/{receipt_id}")

    def operation(cursor):
        query_one, _query_rows, execute_db, _ = _registry_transaction_callables(cursor)
        fresh = query_one("SELECT id, receipt_no, status FROM purchase_receipts WHERE id=%s FOR UPDATE", (receipt_id,))
        if not fresh:
            raise ValueError("采购入库单不存在或已删除。")
        fresh_status = (fresh.get("status") or "").strip()
        if fresh_status in {INVENTORY_STATUS_POSTED, "已收货", "posted", "audited"}:
            raise ValueError("已过账采购入库单不能直接删除，请先反审。")
        fresh_no = fresh.get("receipt_no")
        if fresh_no:
            tx = query_one("SELECT COUNT(*) AS count FROM stock_transactions WHERE reference_no=%s", (fresh_no,)) or {}
            if _as_int(tx.get("count")) > 0:
                raise ValueError("该采购入库单已有库存流水，不能直接删除，请先反审。")
        execute_db("DELETE FROM purchase_receipt_items WHERE receipt_id=%s", (receipt_id,))
        execute_db("DELETE FROM purchase_receipts WHERE id=%s", (receipt_id,))
        return fresh_no

    try:
        deleted_no = _run_registry_transaction(operation)
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(f"/purchase_receipts/{receipt_id}")
    _log_action("删除采购入库单草稿", deleted_no or str(receipt_id))
    flash(f"采购入库单 {deleted_no or receipt_id} 已删除。", "success")
    return redirect("/purchase_receipts")


def _create_sales_shipment_from_order(order_id):
    if request.is_json:
        payload = request.get_json(silent=True) or {}
    else:
        payload = request.form.to_dict(flat=False)

    def payload_value(key, default=None):
        value = payload.get(key, default)
        if isinstance(value, list):
            return value[0] if value else default
        return value

    save_action = (payload_value("save_action", "save") or "save").strip()
    if save_action == "unaudit":
        flash("反审请在已审核过账的销售发货单详情页执行。", "warning")
        return redirect("/shipments/new")

    order = _safe_one(
        """
        SELECT so.*, c.name AS customer_name
        FROM sales_orders so
        LEFT JOIN customers c ON c.id=so.customer_id
        WHERE so.id=%s
        """,
        (order_id,),
    )
    if not order:
        flash("销售订单不存在。", "warning")
        return redirect("/sales")
    if order.get("status") != "已审核":
        flash("销售订单必须已审核才能生成销售出库。", "warning")
        return redirect(f"/sales/{order_id}")
    project_serial_error = _require_project_serial_values_or_redirect(
        order.get("project_code"),
        order.get("serial_no"),
        f"/sales/{order_id}",
    )
    if project_serial_error:
        return project_serial_error

    order_items = _safe_rows(
        """
        SELECT soi.*, p.default_location
        FROM sales_order_items soi
        LEFT JOIN products p ON p.id=soi.product_id
        WHERE soi.order_id=%s
        ORDER BY soi.id
        FOR UPDATE OF soi
        """,
        (order_id,),
    )
    raw_items = payload.get("items") or []
    if isinstance(raw_items, dict):
        raw_items = list(raw_items.values())
    item_map = {str(row.get("id")): row for row in order_items}
    selected = []
    if raw_items:
        for item in raw_items:
            item_id = str(item.get("item_id") or item.get("order_item_id") or item.get("sales_order_item_id") or item.get("id") or "")
            row = item_map.get(item_id)
            if not row:
                continue
            pending_qty = _as_decimal(row.get("quantity")) - _as_decimal(row.get("shipped_qty"))
            requested_qty = _as_decimal(item.get("quantity"))
            if requested_qty <= 0:
                continue
            if requested_qty > pending_qty:
                if request.is_json:
                    return jsonify({"ok": False, "error": f"明细 {item_id} 发货数量不能大于未发数量。"}), 400
                flash(f"明细 {item_id} 发货数量不能大于未发数量。", "warning")
                return redirect(f"/sales/{order_id}")
            selected.append((row, requested_qty))
    elif request.is_json:
        return jsonify({"ok": False, "error": "请选择要下推的销售订单明细。"}), 400
    else:
        for row in order_items:
            pending_qty = _as_decimal(row.get("quantity")) - _as_decimal(row.get("shipped_qty"))
            if pending_qty > 0:
                selected.append((row, pending_qty))
    if not selected:
        if request.is_json:
            return jsonify({"ok": False, "error": "没有可发货的明细。"}), 400
        flash("没有可出库的明细。", "warning")
        return redirect(f"/sales/{order_id}")

    shipment_date = (payload_value("shipment_date") or datetime.now().date().isoformat()).strip()
    warehouse_id = _as_int(payload_value("warehouse_id")) or order.get("warehouse_id")
    remark = _form_text("remark") or f"由销售订单 {order.get('order_no')} 生成出库"
    if payload_value("remark"):
        remark = payload_value("remark")
    shipment_no = _next_doc_no("SS", "sales_shipments", "shipment_no")
    shipment = _execute_and_return(
        """
        INSERT INTO sales_shipments
            (shipment_no, order_id, shipment_date, warehouse_id, operator_id, status,
             remark, cost_object_id, project_code, serial_no, customer_id, source_type,
             source_no, shipped_amount, tax_amount, amount_with_tax)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        RETURNING id
        """,
        (
            shipment_no,
            order_id,
            shipment_date,
            warehouse_id,
            session.get("user_id"),
            "待审核",
            remark,
            order.get("cost_object_id"),
            order.get("project_code"),
            order.get("serial_no"),
            order.get("customer_id"),
            "sales_order",
            order.get("order_no"),
            0,
            0,
            0,
        ),
    )
    shipment_id = shipment["id"]
    create_trace_link(
        _safe_one,
        _execute_db,
        execute_and_return=_execute_and_return,
        source_doc_type="sales_order",
        source_doc_id=order_id,
        source_doc_no=order.get("order_no"),
        target_doc_type="sales_shipment",
        target_doc_id=shipment_id,
        target_doc_no=shipment_no,
        link_type="source_of",
        link_strength="hard",
        project_code=order.get("project_code"),
        serial_no=order.get("serial_no"),
        created_by=session.get("user_id"),
        created_event="create_sales_shipment",
    )
    shipped_amount = Decimal("0")
    shipment_tax_amount = Decimal("0")
    shipment_amount_with_tax = Decimal("0")
    for row, qty in selected:
        unit_price = _as_decimal(row.get("unit_price"))
        tax_rate = _as_decimal(row.get("tax_rate"))
        amount = qty * unit_price
        tax_amount = amount * tax_rate / Decimal("100")
        amount_with_tax = amount + tax_amount
        shipped_amount += amount
        shipment_tax_amount += tax_amount
        shipment_amount_with_tax += amount_with_tax
        # 仓库未启用库位时清空库位避免脏值（销售订单明细可能携带历史库位）
        line_location_id = _as_int(row.get("location_id"))
        if line_location_id and not _warehouse_has_locations(warehouse_id):
            line_location_id = 0
        _execute_db(
            """
            INSERT INTO sales_shipment_items
                (shipment_id, order_item_id, product_id, quantity, unit_cost, lot_no,
                 warehouse_id, location_id, tax_rate, tax_amount, amount_with_tax, unit_price, amount)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """,
            (
                shipment_id,
                row.get("id"),
                row.get("product_id"),
                qty,
                unit_price,
                row.get("lot_no") or "",
                warehouse_id,
                line_location_id,
                tax_rate,
                tax_amount,
                amount_with_tax,
                unit_price,
                amount,
            ),
        )
    _execute_db(
        """
        UPDATE sales_shipments
        SET shipped_amount=%s, tax_amount=%s, amount_with_tax=%s, inventory_posted=FALSE
        WHERE id=%s
        """,
        (shipped_amount, shipment_tax_amount, shipment_amount_with_tax, shipment_id),
    )
    _log_action("新增销售发货单", shipment_no, f"由销售订单 {order.get('order_no')} 生成")
    flash(f"已保存销售发货单 {shipment_no}，审核后过账。", "success")
    if request.is_json:
        return jsonify({
            "ok": True,
            "id": shipment_id,
            "shipment_no": shipment_no,
            "url": f"/shipments/{shipment_id}",
            "msg": f"已生成销售发货单 {shipment_no}。",
        })
    if save_action == "save_new":
        return redirect("/shipments/new")
    return redirect(f"/shipments/{shipment_id}")


def _ensure_service_card_for_shipment(order, shipped_lines, shipment_date, shipment_no):
    serial_no = (order.get("serial_no") or "").strip()
    if not serial_no:
        return None
    product_id = None
    if shipped_lines:
        product_id = shipped_lines[0][0].get("product_id")
    machine_model = None
    if product_id:
        product = _safe_one("SELECT code, name, specification FROM products WHERE id=%s", (product_id,))
        if product:
            machine_model = " / ".join(str(part) for part in [product.get("code"), product.get("name"), product.get("specification")] if part)
    customer = _safe_one("SELECT address, contact_person, phone FROM customers WHERE id=%s", (order.get("customer_id"),)) if order.get("customer_id") else None
    install_address = (customer or {}).get("address") or ""
    existing = _safe_one(
        """
        SELECT id
        FROM machine_service_cards
        WHERE sales_order_id=%s AND serial_no=%s
        ORDER BY id DESC
        LIMIT 1
        """,
        (order.get("id"), serial_no),
    )
    if existing:
        _execute_db(
            """
            UPDATE machine_service_cards
            SET customer_id=COALESCE(customer_id,%s),
                product_id=COALESCE(product_id,%s),
                project_code=COALESCE(NULLIF(project_code,''),%s),
                cost_object_id=COALESCE(cost_object_id,%s),
                machine_model=COALESCE(NULLIF(machine_model,''),%s),
                install_date=COALESCE(install_date,%s),
                installation_date=COALESCE(installation_date,%s),
                status=CASE WHEN COALESCE(status,'') IN ('','新建') THEN '待安装' ELSE status END,
                remark=COALESCE(NULLIF(remark,''),%s)
            WHERE id=%s
            """,
            (
                order.get("customer_id"),
                product_id,
                order.get("project_code"),
                order.get("cost_object_id"),
                machine_model,
                shipment_date,
                shipment_date,
                f"由销售发货 {shipment_no} 更新服务档案",
                existing.get("id"),
            ),
        )
        _log_action("更新服务档案", serial_no, f"由销售发货 {shipment_no} 更新")
        return existing
    card_no = _next_doc_no("SC", "machine_service_cards", "card_no")
    card = _execute_and_return(
        """
        INSERT INTO machine_service_cards
            (card_no, sales_order_id, cost_object_id, customer_id, product_id, serial_no,
             project_code, machine_model, install_date, installation_date, status, install_address, remark)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        ON CONFLICT (sales_order_id, serial_no) WHERE sales_order_id IS NOT NULL AND serial_no IS NOT NULL
        DO UPDATE SET customer_id=EXCLUDED.customer_id,
            product_id=EXCLUDED.product_id,
            project_code=EXCLUDED.project_code,
            cost_object_id=EXCLUDED.cost_object_id,
            machine_model=COALESCE(machine_service_cards.machine_model,EXCLUDED.machine_model),
            install_date=COALESCE(machine_service_cards.install_date,EXCLUDED.install_date),
            installation_date=COALESCE(machine_service_cards.installation_date,EXCLUDED.installation_date),
            status=CASE WHEN COALESCE(machine_service_cards.status,'') IN ('','新建') THEN '待安装' ELSE machine_service_cards.status END,
            remark=EXCLUDED.remark
        RETURNING id
        """,
        (
            card_no,
            order.get("id"),
            order.get("cost_object_id"),
            order.get("customer_id"),
            product_id,
            serial_no,
            order.get("project_code"),
            machine_model,
            shipment_date,
            shipment_date,
            "待安装",
            install_address,
            f"由销售发货 {shipment_no} 自动生成服务档案",
        ),
    )
    _log_action("生成服务档案", serial_no, f"由销售发货 {shipment_no} 生成")
    return card


def _create_customer_receipt_for_order(order_id):
    order = _safe_one("SELECT * FROM sales_orders WHERE id=%s", (order_id,))
    if not order:
        flash("销售订单不存在。", "warning")
        return redirect("/sales")
    amount = _form_decimal("amount")
    if amount <= 0:
        flash("收款金额必须大于 0。", "warning")
        return redirect(f"/sales/{order_id}")

    receipt_no = _next_doc_no("CR", "customer_receipts", "receipt_no")
    receipt_date = _form_text("receipt_date", datetime.now().date().isoformat())
    receipt = _execute_and_return(
        """
        INSERT INTO customer_receipts
            (receipt_no, receipt_date, customer_id, amount, payment_method, bank_account,
             remark, created_by, source_type, source_id, source_no, receipt_kind,
             fund_direction, status, unapplied_amount)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,'customer_receipt','in',%s,%s)
        RETURNING id
        """,
        (
            receipt_no,
            receipt_date,
            order.get("customer_id"),
            amount,
            _form_text("payment_method", "银行转账"),
            _form_text("bank_account"),
            _form_text("remark") or f"销售订单 {order.get('order_no')} 收款",
            session.get("user_id"),
            "sales_order",
            order_id,
            order.get("order_no"),
            "confirmed",
            amount,
        ),
    )
    receipt_id = receipt.get("id") if receipt else None

    remaining = amount
    total_applied = Decimal("0")
    first_source = None
    receivables = _safe_rows(
        """
        SELECT id, source_no, source_type, source_id, balance, cost_object_id, project_code, serial_no
        FROM customer_receivables
        WHERE customer_id=%s
          AND (
            source_id=%s OR source_no=%s
            OR (%s IS NOT NULL AND cost_object_id=%s)
            OR (%s <> '' AND project_code=%s)
            OR (%s <> '' AND serial_no=%s)
          )
          AND COALESCE(balance,0) > 0
        ORDER BY due_date NULLS LAST, id
        """,
        (
            order.get("customer_id"),
            order_id,
            order.get("order_no"),
            order.get("cost_object_id"),
            order.get("cost_object_id"),
            order.get("project_code") or "",
            order.get("project_code") or "",
            order.get("serial_no") or "",
            order.get("serial_no") or "",
        ),
    )
    for row in receivables:
        if remaining <= 0:
            break
        balance = _as_decimal(row.get("balance"))
        applied = min(remaining, balance)
        new_balance = balance - applied
        new_status = "已收款" if new_balance <= 0 else "部分收款"
        _execute_db(
            """
            UPDATE customer_receivables
            SET received_amount=COALESCE(received_amount,0)+%s,
                balance=GREATEST(COALESCE(balance,0)-%s,0),
                status=%s
            WHERE id=%s
            """,
            (applied, applied, new_status, row.get("id")),
        )
        if receipt_id:
            _execute_db(
                """
                INSERT INTO customer_receipt_settlements (receipt_id, receivable_id, applied_amount)
                VALUES (%s,%s,%s)
                ON CONFLICT (receipt_id, receivable_id)
                DO UPDATE SET applied_amount=EXCLUDED.applied_amount
                """,
                (receipt_id, row.get("id"), applied),
            )
            create_trace_link(
                _safe_one,
                _execute_db,
                execute_and_return=_execute_and_return,
                source_doc_type="customer_receivable",
                source_doc_id=row.get("id"),
                source_doc_no=row.get("source_no"),
                target_doc_type="customer_receipt",
                target_doc_id=receipt_id,
                target_doc_no=receipt_no,
                link_type="settles",
                link_strength="hard",
                project_code=row.get("project_code") or order.get("project_code"),
                serial_no=row.get("serial_no") or order.get("serial_no"),
                created_by=session.get("user_id"),
                created_event="create_customer_receipt",
            )
        total_applied += applied
        if first_source is None:
            first_source = row
        remaining -= applied
    if receipt_id:
        _execute_db(
            """
            UPDATE customer_receipts
            SET cost_object_id=%s,
                project_code=%s,
                serial_no=%s,
                unapplied_amount=%s
            WHERE id=%s
            """,
            (
                first_source.get("cost_object_id") if first_source else order.get("cost_object_id"),
                (first_source.get("project_code") if first_source else None) or order.get("project_code"),
                (first_source.get("serial_no") if first_source else None) or order.get("serial_no"),
                max(amount - total_applied, Decimal("0")),
                receipt_id,
            ),
        )

    _log_action("客户收款", receipt_no, f"销售订单 {order.get('order_no')} 收款")
    flash(f"已生成客户收款单 {receipt_no}。", "success")
    return redirect(f"/sales/{order_id}")


def _create_supplier_payment_for_order(order_id):
    order = _safe_one("SELECT * FROM purchase_orders WHERE id=%s", (order_id,))
    if not order:
        flash("采购订单不存在。", "warning")
        return redirect("/purchase_order")
    amount = _form_decimal("amount")
    if amount <= 0:
        flash("付款金额必须大于 0。", "warning")
        return redirect(f"/purchase_order/{order_id}")

    payment_no = _next_doc_no("SP", "supplier_payments", "payment_no")
    payment_date = _form_text("payment_date", datetime.now().date().isoformat())
    payment = _execute_and_return(
        """
        INSERT INTO supplier_payments
            (payment_no, payment_date, supplier_id, amount, payment_method, bank_account,
             operator_id, remark, source_type, source_id, source_no, payable_id,
             payment_kind, fund_direction, status, unapplied_amount)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,NULL,'supplier_payment','out',%s,%s)
        RETURNING id
        """,
        (
            payment_no,
            payment_date,
            order.get("supplier_id"),
            amount,
            _form_text("payment_method", "银行转账"),
            _form_text("bank_account"),
            session.get("user_id"),
            _form_text("remark") or f"采购订单 {order.get('order_no')} 付款",
            "purchase_order",
            order_id,
            order.get("order_no"),
            "已确认",
            amount,
        ),
    )
    payment_id = payment.get("id") if payment else None

    remaining = amount
    total_applied = Decimal("0")
    first_source = None
    payables = _safe_rows(
        """
        SELECT id, doc_no, doc_type, doc_id, balance, cost_object_id, project_code, serial_no
        FROM supplier_payables
        WHERE supplier_id=%s
          AND (
            doc_id=%s OR doc_no=%s
          )
          AND COALESCE(balance,0) > 0
        ORDER BY next_follow_up_date NULLS LAST, id
        """,
        (order.get("supplier_id"), order_id, order.get("order_no")),
    )
    for row in payables:
        if remaining <= 0:
            break
        balance = _as_decimal(row.get("balance"))
        applied = min(remaining, balance)
        new_balance = balance - applied
        apply_supplier_payment_to_payable(
            _execute_db,
            payable_id=row.get("id"),
            applied_amount=applied,
            paid_status="已付款",
            partial_status="部分付款",
            new_balance=new_balance,
        )
        if payment_id:
            _execute_db(
                """
                INSERT INTO supplier_payment_settlements (payment_id, payable_id, applied_amount)
                VALUES (%s,%s,%s)
                ON CONFLICT (payment_id, payable_id)
                DO UPDATE SET applied_amount=EXCLUDED.applied_amount
                """,
                (payment_id, row.get("id"), applied),
            )
            create_trace_link(
                _safe_one,
                _execute_db,
                execute_and_return=_execute_and_return,
                source_doc_type="supplier_payable",
                source_doc_id=row.get("id"),
                source_doc_no=row.get("doc_no"),
                target_doc_type="supplier_payment",
                target_doc_id=payment_id,
                target_doc_no=payment_no,
                link_type="settles",
                link_strength="hard",
                project_code=row.get("project_code") or order.get("project_code"),
                serial_no=row.get("serial_no") or order.get("serial_no"),
                created_by=session.get("user_id"),
                created_event="create_supplier_payment",
            )
        total_applied += applied
        if first_source is None:
            first_source = row
        remaining -= applied
    if payment_id:
        _execute_db(
            """
            UPDATE supplier_payments
            SET payable_id=%s,
                cost_object_id=%s,
                project_code=%s,
                serial_no=%s,
                unapplied_amount=%s
            WHERE id=%s
            """,
            (
                first_source.get("id") if first_source else None,
                first_source.get("cost_object_id") if first_source else None,
                (first_source.get("project_code") if first_source else None) or order.get("project_code"),
                (first_source.get("serial_no") if first_source else None) or order.get("serial_no"),
                max(amount - total_applied, Decimal("0")),
                payment_id,
            ),
        )

    _log_action("供应商付款", payment_no, f"采购订单 {order.get('order_no')} 付款")
    flash(f"已生成供应商付款单 {payment_no}。", "success")
    return redirect(f"/purchase_order/{order_id}")


def _render_material_form(product_id=None):
    return render_material_form_adapter(product_id, _safe_one, _safe_rows)


def _material_category_for_code(category_id=None, category_text=""):
    row = None
    if category_id:
        row = _safe_one(
            "SELECT id, code, name FROM product_categories WHERE id=%s LIMIT 1",
            (category_id,),
        )
    if not row and category_text:
        row = _safe_one(
            """
            SELECT id, code, name
            FROM product_categories
            WHERE code=%s OR name=%s
            ORDER BY id
            LIMIT 1
            """,
            (category_text, category_text),
        )
    return row or {}


def _next_material_code(category_id=None, category_text=""):
    rule = _load_code_rule("material:products.code", "material:default")
    category = _material_category_for_code(category_id, category_text)
    prefix = str(category.get("code") or (rule or {}).get("prefix") or "MAT").strip().upper()
    prefix = "".join(ch for ch in prefix if ch.isalnum()) or "MAT"
    separator = str((rule or {}).get("separator") or "")
    sequence_length = int((rule or {}).get("sequence_length") or 4)
    base = f"{prefix}{separator}" if separator else prefix
    rows = _safe_rows(
        "SELECT code FROM products WHERE code LIKE %s ORDER BY code DESC LIMIT 50",
        (f"{base}%",),
    )
    next_number = 1
    for row in rows or []:
        suffix = str(row.get("code") or "").replace(base, "", 1)
        if suffix.isdigit():
            next_number = max(next_number, int(suffix) + 1)
    return f"{base}{next_number:0{sequence_length}d}"


def _material_code_exists(code, exclude_product_id=None):
    if exclude_product_id:
        row = _safe_one("SELECT id FROM products WHERE code=%s AND id<>%s LIMIT 1", (code, exclude_product_id))
    else:
        row = _safe_one("SELECT id FROM products WHERE code=%s LIMIT 1", (code,))
    return bool(row)


def _active_master_row(table, row_id, label_expr="name"):
    if not row_id:
        return None
    return _safe_one(
        f"""
        SELECT id, {label_expr} AS name
        FROM {table}
        WHERE id=%s
          AND COALESCE(status, '启用') NOT IN ('停用','disabled','inactive')
        LIMIT 1
        """,
        (row_id,),
    )


def _active_location_row(location_id):
    if not location_id:
        return None
    return _safe_one(
        """
        SELECT id, warehouse_id, code || ' / ' || name AS name
        FROM locations
        WHERE id=%s
          AND COALESCE(is_active, TRUE)=TRUE
          AND COALESCE(status, '启用') NOT IN ('停用','disabled','inactive')
        LIMIT 1
        """,
        (location_id,),
    )


def _save_material(product_id=None):
    code = _form_text("code")
    name = _form_text("name")
    category_id = _form_int("category_id")
    category_text = _form_text("category")
    category_row = _material_category_for_code(category_id, category_text)
    if category_row:
        category_id = category_row.get("id")
        category_text = category_text or category_row.get("name") or ""
    if product_id and not code:
        flash("物料编码必填。", "warning")
        return redirect(request.path)
    if not name:
        flash("物料编码和名称必填。", "warning")
        return redirect(request.path)
    if not code:
        code = _next_material_code(category_id, category_text)
    if _material_code_exists(code, product_id):
        flash(f"物料编码 {code} 已存在。", "warning")
        return redirect(request.path)
    default_supplier_name = _form_text("default_supplier_name")
    default_supplier_id = _form_int("default_supplier_id")
    default_warehouse = _form_text("default_warehouse")
    default_warehouse_id = _form_int("default_warehouse_id")
    default_location = _form_text("default_location")
    default_location_id = _form_int("default_location_id")
    if default_supplier_id:
        supplier_row = _active_master_row("suppliers", default_supplier_id)
        if not supplier_row:
            flash("默认供应商已停用或不存在。", "warning")
            return redirect(request.path)
        default_supplier_name = default_supplier_name or supplier_row.get("name") or ""
    if default_warehouse_id:
        warehouse_row = _active_master_row("warehouses", default_warehouse_id)
