def _upload_material_attachment(product_id):
    product = _safe_one("SELECT code FROM products WHERE id=%s", (product_id,))
    if not product:
        flash("物料不存在。", "warning")
        return redirect("/material")
    file = request.files.get("file")
    if not file or not file.filename:
        flash("请选择要上传的附件。", "warning")
        return redirect(f"/material/{product_id}")
    safe_name, original_name = _validate_attachment_upload(file)
    if not safe_name:
        flash("附件类型不允许上传。", "warning")
        return redirect(f"/material/{product_id}")
    MATERIAL_UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
    stored_name = f"{product_id}_{datetime.now():%Y%m%d%H%M%S%f}_{safe_name}"
    target = MATERIAL_UPLOAD_DIR / stored_name
    file.save(target)
    relative_path = f"uploads/materials/{stored_name}"
    content_type = file.mimetype or ""
    attachment_type = "image" if content_type.startswith("image/") else "file"
    _ensure_attachment_table()
    _execute_db(
        """
        INSERT INTO document_attachments
            (subject_type, subject_id, file_name, stored_path, content_type, file_size,
             attachment_type, remark, uploaded_by)
        VALUES ('product',%s,%s,%s,%s,%s,%s,%s,%s)
        """,
        (
            product_id,
            original_name,
            relative_path,
            content_type,
            target.stat().st_size if target.exists() else None,
            attachment_type,
            _form_text("remark"),
            session.get("user_id"),
        ),
    )
    _log_action("上传物料附件", product.get("code"), original_name)
    flash("物料附件已上传。", "success")
    return redirect(f"/material/{product_id}")


def _delete_material_attachment(product_id, attachment_id):
    _ensure_attachment_table()
    row = _safe_one(
        """
        SELECT *
        FROM document_attachments
        WHERE id=%s AND subject_type='product' AND subject_id=%s
        """,
        (attachment_id, product_id),
    )
    if not row:
        flash("附件不存在或已删除。", "warning")
        return redirect(f"/material/{product_id}")
    stored_path = row.get("stored_path") or ""
    target = (ROOT_DIR / "static" / stored_path).resolve()
    upload_root = MATERIAL_UPLOAD_DIR.resolve()
    if str(target).startswith(str(upload_root)) and target.exists():
        target.unlink()
    _execute_db("DELETE FROM document_attachments WHERE id=%s", (attachment_id,))
    _log_action("删除物料附件", str(product_id), row.get("file_name") or "")
    flash("物料附件已删除。", "success")
    return redirect(f"/material/{product_id}")


def _upload_document_attachment(kind, order_id):
    config = _document_subject(kind)
    if not config:
        flash("不支持的单据类型。", "warning")
        return redirect("/")
    owner_select = ", created_by" if "created_by" in _columns(config["table"]) else ""
    order = _safe_one(
        f"SELECT id, {config['doc_no_field']} AS doc_no{owner_select} FROM {config['table']} WHERE id=%s",
        (order_id,),
    )
    if not order:
        flash(f"{config['label']}不存在。", "warning")
        return redirect(config["url_prefix"])
    if not _document_attachment_access_allowed(config, order):
        return "Forbidden", 403
    file = request.files.get("file")
    if not file or not file.filename:
        flash("请选择要上传的附件。", "warning")
        return redirect(f"{config['url_prefix']}/{order_id}")
    safe_name, original_name = _validate_attachment_upload(file)
    if not safe_name:
        flash("附件类型不允许上传。", "warning")
        return redirect(f"{config['url_prefix']}/{order_id}")
    DOCUMENT_UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
    stored_name = f"{config['subject_type']}_{order_id}_{datetime.now():%Y%m%d%H%M%S%f}_{safe_name}"
    target = DOCUMENT_UPLOAD_DIR / stored_name
    file.save(target)
    relative_path = f"uploads/documents/{stored_name}"
    content_type = file.mimetype or ""
    attachment_type = "image" if content_type.startswith("image/") else "file"
    _ensure_attachment_table()
    _execute_db(
        """
        INSERT INTO document_attachments
            (subject_type, subject_id, file_name, stored_path, content_type, file_size,
             attachment_type, remark, uploaded_by)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)
        """,
        (
            config["subject_type"],
            order_id,
            original_name,
            relative_path,
            content_type,
            target.stat().st_size if target.exists() else None,
            attachment_type,
            _form_text("remark"),
            session.get("user_id"),
        ),
    )
    _log_action(f"上传{config['label']}附件", order.get("doc_no") or str(order_id), original_name)
    flash(f"{config['label']}附件已上传。", "success")
    return redirect(f"{config['url_prefix']}/{order_id}")


