NOTE_WRITE_ROLE_MAP = {
    "sales": {"sales"},
    "receivable": {"sales", "finance"},
    "service_order": {"sales", "service"},
    "purchase": {"purchase"},
    "payable": {"purchase", "finance"},
    "inventory_adjustment": {"warehouse"},
    "inventory_transfer": {"warehouse"},
    "inventory_check": {"warehouse"},
    "work_order": {"production"},
}


def _can_write_document_note(kind):
    role = str(session.get("role") or "").strip().lower()
    if role in {"admin", "manager"}:
        return True
    allowed = NOTE_WRITE_ROLE_MAP.get(kind)
    return allowed is None or role in allowed


def _add_document_note(kind, order_id):
    if not _can_write_document_note(kind):
        abort(403)
    config = _document_subject(kind)
    if not config:
        flash("不支持的单据类型。", "warning")
        return redirect("/")
    order = _safe_one(
        f"SELECT id, {config['doc_no_field']} AS doc_no FROM {config['table']} WHERE id=%s",
        (order_id,),
    )
    if not order:
        flash(f"{config['label']}不存在。", "warning")
        return redirect(config["url_prefix"])
    note = _form_text("note")
    if not note:
        flash("请输入备注内容。", "warning")
        return redirect(f"{config['url_prefix']}/{order_id}")
    _log_action(f"{config['label']}备注", order.get("doc_no") or str(order_id), note)
    flash("备注已保存。", "success")
    return redirect(f"{config['url_prefix']}/{order_id}")


