def _save_category(kind, category_id=None):
    config = CATEGORY_TYPES.get(kind)
    if not config:
        flash("不支持的分类类型。", "warning")
        return redirect("/master-data")
    table = config["table"]
    name = _form_text("name")
    if not name:
        flash("分类名称必填。", "warning")
        return redirect(request.path)
    parent_id = _form_int("parent_id")
    if category_id and parent_id == category_id:
        flash("上级分类不能选择自己。", "warning")
        return redirect(request.path)
    values = (_form_text("code"), name, parent_id, _form_text("remark"))
    if category_id:
        _execute_db(
            f"UPDATE {table} SET code=%s, name=%s, parent_id=%s, remark=%s WHERE id=%s",
            values + (category_id,),
        )
        _log_action(f"更新{config['title']}", name)
        flash(f"{config['title']}已更新。", "success")
        return redirect(f"/categories/{kind}/{category_id}")
    row = _execute_and_return(
        f"INSERT INTO {table} (code, name, parent_id, remark) VALUES (%s,%s,%s,%s) RETURNING id",
        values,
    )
    _log_action(f"新增{config['title']}", name)
    flash(f"{config['title']}已新增。", "success")
    new_id = row.get("id") if isinstance(row, dict) else (row[0] if row else None)
    return redirect(f"/categories/{kind}/{new_id}")


def _order_form_items():
    items = []
    product_ids = request.form.getlist("product_id[]")
    if product_ids:
        quantities = request.form.getlist("quantity[]")
        unit_prices = request.form.getlist("unit_price[]")
        tax_rates = request.form.getlist("tax_rate[]")
        lot_nos = request.form.getlist("lot_no[]")
        source_line_nos = request.form.getlist("source_line_no[]")
        expected_dates = request.form.getlist("expected_date[]")
        for idx, product_id_value in enumerate(product_ids):
            product_id = _as_int(product_id_value)
            qty = _as_decimal(quantities[idx] if idx < len(quantities) else "0")
            unit_price = _as_decimal(unit_prices[idx] if idx < len(unit_prices) else "0")
            tax_rate = _as_decimal(tax_rates[idx] if idx < len(tax_rates) else "13", "13")
            if not product_id or qty <= 0:
                continue
            if unit_price < 0:
                continue
            amount = qty * unit_price
            tax_amount = amount * tax_rate / Decimal("100")
            items.append(
                {
                    "product_id": product_id,
                    "quantity": qty,
                    "unit_price": unit_price,
                    "amount": amount,
                    "lot_no": lot_nos[idx] if idx < len(lot_nos) else "",
                    "tax_rate": tax_rate,
                    "tax_amount": tax_amount,
                    "amount_with_tax": amount + tax_amount,
                    "source_line_no": source_line_nos[idx] if idx < len(source_line_nos) else "",
                    "expected_date": expected_dates[idx] if idx < len(expected_dates) else "",
                }
            )
    else:
        for suffix in ["", "2"]:
            product_id = _form_int(f"product_id{suffix}")
            qty = _form_decimal(f"quantity{suffix}")
            unit_price = _form_decimal(f"unit_price{suffix}")
            tax_rate = _form_decimal(f"tax_rate{suffix}", "13")
            if not product_id:
                continue
            if qty <= 0:
                continue
            if unit_price < 0:
                continue
            amount = qty * unit_price
            tax_amount = amount * tax_rate / Decimal("100")
            items.append(
                {
                    "product_id": product_id,
                    "quantity": qty,
                    "unit_price": unit_price,
                    "amount": amount,
                    "lot_no": _form_text(f"lot_no{suffix}"),
                    "tax_rate": tax_rate,
                    "tax_amount": tax_amount,
                    "amount_with_tax": amount + tax_amount,
                    "source_line_no": _form_text(f"source_line_no{suffix}"),
                    "expected_date": _form_text(f"expected_date{suffix}"),
                }
            )
    return items


def _document_reference_errors(kind, partner_id=None, warehouse_id=None, items=None):
    errors = []
    if kind == "sales":
        error = _inactive_master_error("customers", partner_id, "客户")
        if error:
            errors.append(error)
    elif kind == "purchase" and partner_id:
        error = _inactive_master_error("suppliers", partner_id, "供应商")
        if error:
            errors.append(error)
    if warehouse_id:
        error = _inactive_master_error("warehouses", warehouse_id, "仓库")
        if error:
            errors.append(error)
    seen_products = set()
    for item in items or []:
        product_id = item.get("product_id")
        if not product_id or product_id in seen_products:
            continue
        seen_products.add(product_id)
        error = _inactive_master_error("products", product_id, f"物料 {product_id}")
        if error:
            errors.append(error)
    return errors


def _block_document_reference_errors(kind, partner_id=None, warehouse_id=None, items=None, redirect_url="/"):
    errors = _document_reference_errors(kind, partner_id, warehouse_id, items)
    if not errors:
        return None
    flash("单据引用资料校验未通过：" + "；".join(errors[:5]), "warning")
    return redirect(redirect_url)


ORDER_EDITABLE_STATUSES = {
    "",
    "draft",
    "pending",
    "submitted",
    "待提交",
    "已提交",
}


ORDER_NON_EDITABLE_STATUS_KEYWORDS = (
    "审核",
    "发货",
    "收货",
    "关闭",
    "作废",
    "audited",
    "approved",
    "closed",
    "void",
    "cancel",
    "shipped",
    "received",
    "completed",
)


def _order_line_match_key(row):
    return (
        str(row.get("source_line_no") or "").strip(),
        str(row.get("product_id") or "").strip(),
        str(row.get("lot_no") or "").strip(),
    )


def _order_line_fallback_key(row):
    return (
        str(row.get("product_id") or "").strip(),
        str(row.get("lot_no") or "").strip(),
    )


def _prepare_order_edit_lines(*, kind, order, items):
    status = str(order.get("status") or "").strip()
    back_url = f"/sales/{order.get('id')}/edit" if kind == "sales" else f"/purchase_order/{order.get('id')}/edit"
    label = "销售订单" if kind == "sales" else "采购订单"
    item_table = "sales_order_items" if kind == "sales" else "purchase_order_items"
    exec_field = "shipped_qty" if kind == "sales" else "received_qty"
    exec_label = "已发货数量" if kind == "sales" else "已收货数量"

    old_rows = _safe_rows(f"SELECT * FROM {item_table} WHERE order_id=%s ORDER BY id", (order.get("id"),))
    if kind == "purchase":
        downstream_refs = _safe_one(
            """
            SELECT COUNT(*) AS count
            FROM purchase_receipt_items pri
            JOIN purchase_receipts pr ON pr.id=pri.receipt_id
            WHERE pri.order_item_id IN (SELECT id FROM purchase_order_items WHERE order_id=%s)
              AND COALESCE(pr.status,'') NOT IN ('已作废','void','voided','cancelled','canceled')
            """,
            (order.get("id"),),
        ) or {}
        if _as_int(downstream_refs.get("count")) > 0:
            flash("采购订单已有下游入库明细引用，不能通过编辑删除重建明细。", "warning")
            return None, redirect(back_url)
    if status not in ORDER_EDITABLE_STATUSES or any(keyword in status.lower() for keyword in ORDER_NON_EDITABLE_STATUS_KEYWORDS):
        flash(f"{label}当前状态为 {status or '-'}，不能普通编辑保存。", "warning")
        return None, redirect(back_url)

    old_by_full = {}
    old_by_fallback = {}
    for row in old_rows:
        old_by_full.setdefault(_order_line_match_key(row), []).append(row)
        old_by_fallback.setdefault(_order_line_fallback_key(row), []).append(row)

    prepared = []
    matched_old_ids = set()
    for item in items:
        candidates = old_by_full.get(_order_line_match_key(item)) or old_by_fallback.get(_order_line_fallback_key(item)) or []
        old = next((row for row in candidates if row.get("id") not in matched_old_ids), None)
        executed = _as_decimal(old.get(exec_field)) if old else Decimal("0")
        if old:
            matched_old_ids.add(old.get("id"))
        if executed > item["quantity"]:
            flash(f"{label}明细数量不能低于{exec_label}：物料 {item.get('product_id')} 已执行 {executed}。", "warning")
            return None, redirect(back_url)
        merged = dict(item)
        merged[exec_field] = executed
        for field in (
            "source_line_no",
            "line_project_code",
            "line_serial_no",
            "material_code",
            "material_name",
            "material_spec",
            "material_unit",
            "expected_date",
        ):
            if not merged.get(field) and old and old.get(field):
                merged[field] = old.get(field)
        prepared.append(merged)

    deleted_executed = [
        row for row in old_rows
        if row.get("id") not in matched_old_ids and _as_decimal(row.get(exec_field)) > 0
    ]
    if deleted_executed:
        row = deleted_executed[0]
        flash(f"{label}已执行明细不能删除：物料 {row.get('product_id')} {exec_label} {_as_decimal(row.get(exec_field))}。", "warning")
        return None, redirect(back_url)
    return prepared, None


def _ensure_document_custom_field_table():
    _execute_db(
        """
        CREATE TABLE IF NOT EXISTS document_custom_field_values (
            id SERIAL PRIMARY KEY,
            document_type VARCHAR(50) NOT NULL,
            document_id INTEGER NOT NULL,
            payload JSONB NOT NULL DEFAULT '{}'::jsonb,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            UNIQUE(document_type, document_id)
        )
        """
    )


def _order_custom_payload(raw=None):
    if raw is None:
        raw = request.form.get("custom_fields_json")
    raw = (raw or "").strip()
    if not raw:
        return {}
    try:
        payload = json.loads(raw)
    except Exception:
        return {}
    if not isinstance(payload, dict):
        return {}
    fields = payload.get("fields") if isinstance(payload.get("fields"), list) else []
    rows = payload.get("rows") if isinstance(payload.get("rows"), list) else []
    clean_fields = []
    for field in fields[:50]:
        if not isinstance(field, dict):
            continue
        key = str(field.get("key") or "").strip()[:80]
        label = str(field.get("label") or "").strip()[:120]
        if key and label:
            clean_fields.append({"key": key, "label": label})
    clean_keys = {field["key"] for field in clean_fields}
    clean_rows = []
    for idx, row in enumerate(rows[:500]):
        values = row.get("values") if isinstance(row, dict) and isinstance(row.get("values"), dict) else {}
        clean_values = {}
        for key in clean_keys:
            clean_values[key] = str(values.get(key) or "")[:1000]
        clean_rows.append({"row": idx + 1, "values": clean_values})
    return {"fields": clean_fields, "rows": clean_rows} if clean_fields else {}


def _save_document_custom_payload(document_type, document_id, raw=None, execute_db_fn=None):
    payload = _order_custom_payload(raw)
    execute_db = execute_db_fn or _execute_db
    if execute_db_fn is None:
        _ensure_document_custom_field_table()
    execute_db(
        """
        INSERT INTO document_custom_field_values (document_type, document_id, payload, updated_at)
        VALUES (%s,%s,%s::jsonb,CURRENT_TIMESTAMP)
        ON CONFLICT (document_type, document_id)
        DO UPDATE SET payload=EXCLUDED.payload, updated_at=CURRENT_TIMESTAMP
        """,
        (document_type, document_id, json.dumps(payload, ensure_ascii=False)),
    )


def _load_document_custom_payload(document_type, document_id):
    if not document_id:
        return {}
    try:
        _ensure_document_custom_field_table()
        row = _safe_one(
            "SELECT payload FROM document_custom_field_values WHERE document_type=%s AND document_id=%s",
            (document_type, document_id),
        )
    except Exception:
        return {}
    if not row:
        return {}
    payload = row.get("payload")
    return payload if isinstance(payload, dict) else {}


