def _save_subcontract_order():
    project_serial_error = _require_project_serial_or_redirect("/subcontract/new")
    if project_serial_error:
        return project_serial_error
    supplier_id = _form_int("supplier_id")
    if not supplier_id:
        flash("请选择委外商。", "warning")
        return redirect("/subcontract/new")
    supplier_error = _inactive_master_error("suppliers", supplier_id, "委外商")
    if supplier_error:
        flash(supplier_error, "warning")
        return redirect("/subcontract/new")
    product_ids = request.form.getlist("product_id[]") or request.form.getlist("product_id")
    quantities = request.form.getlist("quantity[]") or request.form.getlist("quantity")
    unit_prices = request.form.getlist("unit_price[]") or request.form.getlist("unit_price")
    process_names = request.form.getlist("process_name[]") or request.form.getlist("process_name")
    warehouses = request.form.getlist("warehouse[]")
    locations = request.form.getlist("location[]")
    lot_nos = request.form.getlist("lot_no[]")
    source_line_nos = request.form.getlist("source_line_no[]")
    line_project_codes = request.form.getlist("line_project_code[]")
    line_serial_nos = request.form.getlist("line_serial_no[]")
    first_line = None
    all_lines = []
    for index, product_id in enumerate(product_ids):
        product_id = _as_int(product_id)
        quantity = _as_decimal(quantities[index] if index < len(quantities) else "0")
        unit_price = _as_decimal(unit_prices[index] if index < len(unit_prices) else "0")
        process_name = (process_names[index] if index < len(process_names) else "").strip()
        if not product_id and quantity <= 0 and not process_name:
            continue
        if not product_id:
            flash("委外明细必须选择物料。", "warning")
            return redirect("/subcontract/new")
        product_error = _inactive_master_error("products", product_id, "委外物料")
        if product_error:
            flash(product_error, "warning")
            return redirect("/subcontract/new")
        if quantity <= 0:
            flash("委外数量必须大于 0。", "warning")
            return redirect("/subcontract/new")
        line = {
            "product_id": product_id,
            "quantity": quantity,
            "unit_price": unit_price,
            "process_name": process_name,
            "warehouse": warehouses[index] if index < len(warehouses) else "",
            "location": locations[index] if index < len(locations) else "",
            "lot_no": lot_nos[index] if index < len(lot_nos) else "",
            "source_line_no": source_line_nos[index] if index < len(source_line_nos) else "",
            "line_project_code": line_project_codes[index] if index < len(line_project_codes) else "",
            "line_serial_no": line_serial_nos[index] if index < len(line_serial_nos) else "",
        }
        all_lines.append(line)
        if first_line is None:
            first_line = line
    if not first_line:
        flash("请至少录入一条委外明细。", "warning")
        return redirect("/subcontract/new")
    quantity = first_line["quantity"]
    unit_price = first_line["unit_price"]
    total_amount = quantity * unit_price
    product_snapshot = _inventory_product_snapshot(first_line["product_id"])
    order_no = _next_doc_no("OS", "subcontract_orders", "order_no")
    project_code = _form_text("project_code")
    serial_no = _form_text("serial_no")
    work_order_scope_clause, work_order_scope_params = _data_scope_filter(
        {"project": "project_code", "serial": "serial_no"}
    )
    parent_work_order = _safe_one(
        f"""
        SELECT id
        FROM work_orders
        WHERE (
              (%s <> '' AND project_code=%s)
           OR (%s <> '' AND serial_no=%s)
        )
          {work_order_scope_clause}
        ORDER BY id DESC
        LIMIT 1
        """,
        (project_code, project_code, serial_no, serial_no, *work_order_scope_params),
    )
    new_order = _execute_and_return(
        """
        INSERT INTO subcontract_orders
            (order_no, order_date, supplier_id, product_id, quantity, unit_price,
              total_amount, project_code, serial_no, status, remark, updated_at,
              parent_work_order_id, required_date, arrival_status, shortage_qty, received_qty,
              process_name, warehouse, location, lot_no, source_line_no, line_project_code,
              line_serial_no, material_code, material_name, material_spec, material_unit)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,CURRENT_TIMESTAMP,%s,%s,%s,%s,0,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        RETURNING id
        """,
        (
            order_no,
            _form_text("order_date", datetime.now().date().isoformat()),
            supplier_id,
            first_line["product_id"],
            quantity,
            unit_price,
            total_amount,
            project_code,
            serial_no,
            "draft",
            _form_text("remark") or first_line["process_name"],
            parent_work_order.get("id") if parent_work_order else None,
            _form_text("required_date") or _form_text("deadline") or None,
            "未发料",
            quantity,
            first_line["process_name"],
            first_line["warehouse"],
            first_line["location"],
            first_line["lot_no"],
            first_line["source_line_no"],
            first_line["line_project_code"] or project_code,
            first_line["line_serial_no"] or serial_no,
            product_snapshot["material_code"],
            product_snapshot["material_name"],
            product_snapshot["material_spec"],
            product_snapshot["material_unit"],
        ),
    )
    order_id = new_order["id"]
    for seq, line in enumerate(all_lines, start=1):
        line_snapshot = _inventory_product_snapshot(line["product_id"])
        _execute_db(
            """
            INSERT INTO subcontract_items
                (order_id, product_id, required_quantity, unit_price, amount, sequence,
                 process_name, warehouse, location, lot_no, source_line_no,
                 line_project_code, line_serial_no,
                 material_code, material_name, material_spec, material_unit, remark)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """,
            (order_id, line["product_id"], line["quantity"], line["unit_price"],
             line["quantity"] * line["unit_price"], seq,
             line["process_name"], line["warehouse"], line["location"], line["lot_no"],
             line["source_line_no"], line["line_project_code"] or project_code,
             line["line_serial_no"] or serial_no,
             line_snapshot["material_code"], line_snapshot["material_name"],
             line_snapshot["material_spec"], line_snapshot["material_unit"],
             line["process_name"]),
        )
    _execute_db(
        """
        INSERT INTO supplier_payables
            (supplier_id, payable_no, doc_type, doc_id, doc_no, doc_date, amount, paid_amount, balance, status, finance_remark, next_follow_up_date)
        VALUES (%s,%s,'subcontract_order',%s,%s,%s,%s,0,%s,'未付款',%s,%s)
        ON CONFLICT (doc_type, doc_id) WHERE doc_type IS NOT NULL AND doc_id IS NOT NULL
        DO UPDATE SET supplier_id=EXCLUDED.supplier_id, doc_no=EXCLUDED.doc_no,
            doc_date=EXCLUDED.doc_date, amount=EXCLUDED.amount,
            balance=GREATEST(EXCLUDED.amount-COALESCE(supplier_payables.paid_amount,0),0),
            status=CASE WHEN GREATEST(EXCLUDED.amount-COALESCE(supplier_payables.paid_amount,0),0)=0 THEN '已付款' ELSE supplier_payables.status END,
            finance_remark=EXCLUDED.finance_remark, next_follow_up_date=EXCLUDED.next_follow_up_date
        """,
        (
            supplier_id,
            _next_doc_no("AP", "supplier_payables", "payable_no"),
            order_id,
            order_no,
            _form_text("order_date", datetime.now().date().isoformat()),
            total_amount,
            total_amount,
            "由委外订单自动生成应付。",
            _form_text("required_date") or _form_text("deadline") or None,
        ),
    )
    _log_action("新增委外订单", order_no)
    if parent_work_order and parent_work_order.get("id"):
        try:
            create_trace_link(
                _safe_one,
                _execute_db,
                source_doc_type="work_order",
                source_doc_id=parent_work_order["id"],
                target_doc_type="subcontract_order",
                target_doc_id=order_id,
                link_type="source_of",
            )
        except Exception:
            current_app.logger.warning("Failed to create subcontract order trace link", exc_info=True)
    flash(f"已新增委外订单 {order_no}，并生成委外应付。", "success")
    return redirect("/subcontract")


