def _edit_subcontract_order(order_id):
    order = _safe_one("SELECT * FROM subcontract_orders WHERE id=%s", (order_id,))
    if not order:
        flash("委外订单不存在。", "warning")
        return redirect("/subcontract")
    downstream = _safe_one(
        """
        SELECT 1 AS has_downstream
        WHERE EXISTS (SELECT 1 FROM subcontract_issue_orders WHERE subcontract_order_id=%s AND COALESCE(status,'') NOT IN ('已作废','void','voided','cancelled','已取消'))
           OR EXISTS (SELECT 1 FROM subcontract_receive_orders WHERE subcontract_order_id=%s AND COALESCE(status,'') NOT IN ('已作废','void','voided','cancelled','已取消'))
        """,
        (order_id, order_id),
    )
    if downstream or not _document_can_edit_status(order.get("status"), {"", "draft", "pending", "新建", "草稿"}):
        flash("委外订单已下推发料/收货、已关闭或已作废，不能普通编辑。", "warning")
        return redirect(f"/subcontract/{order_id}")
    supplier_id = _form_int("supplier_id")
    line = _first_form_line("product_id[]", "quantity[]", True)
    if not supplier_id or not line:
        flash("请选择加工厂商并录入有效委外明细。", "warning")
        return redirect(f"/subcontract/{order_id}/edit")
    supplier_error = _inactive_master_error("suppliers", supplier_id, "委外商")
    if supplier_error:
        flash(supplier_error, "warning")
        return redirect(f"/subcontract/{order_id}/edit")
    product_error = _inactive_master_error("products", line["product_id"], "委外物料")
    if product_error:
        flash(product_error, "warning")
        return redirect(f"/subcontract/{order_id}/edit")
    project_code = _form_text("project_code")
    serial_no = _form_text("serial_no")
    project_serial_error = _require_project_serial_values_or_redirect(project_code, serial_no, f"/subcontract/{order_id}/edit")
    if project_serial_error:
        return project_serial_error
    unit_price = line["unit_cost"]
    total_amount = line["quantity"] * unit_price
    product_snapshot = _inventory_product_snapshot(line["product_id"])
    _execute_db(
        """
        UPDATE subcontract_orders
        SET order_date=%s, supplier_id=%s, product_id=%s, quantity=%s, unit_price=%s,
            total_amount=%s, project_code=%s, serial_no=%s, remark=%s,
            required_date=%s, shortage_qty=%s, process_name=%s, warehouse=%s,
            location=%s, lot_no=%s, source_line_no=%s, line_project_code=%s,
            line_serial_no=%s, material_code=%s, material_name=%s,
            material_spec=%s, material_unit=%s, updated_at=CURRENT_TIMESTAMP
        WHERE id=%s
        """,
        (
            _form_text("order_date", datetime.now().date().isoformat()),
            supplier_id,
            line["product_id"],
            line["quantity"],
            unit_price,
            total_amount,
            project_code,
            serial_no,
            _form_text("remark"),
            _form_text("required_date") or None,
            line["quantity"],
            _form_list_value("process_name[]", line.get("index", 0)),
            line.get("warehouse") or "",
            line.get("location") or "",
            line.get("lot_no") or "",
            line.get("source_line_no") or "",
            line.get("project_code") or project_code,
            line.get("serial_no") or serial_no,
            product_snapshot["material_code"],
            product_snapshot["material_name"],
            product_snapshot["material_spec"],
            product_snapshot["material_unit"],
            order_id,
        ),
    )
    _execute_db(
        """
        UPDATE supplier_payables
        SET supplier_id=%s, doc_date=%s, amount=%s,
            balance=GREATEST(%s-COALESCE(paid_amount,0),0),
            finance_remark=%s, next_follow_up_date=%s
        WHERE doc_type='subcontract_order' AND doc_id=%s
        """,
        (supplier_id, _form_text("order_date", datetime.now().date().isoformat()), total_amount, total_amount, "由委外订单编辑同步。", _form_text("required_date") or None, order_id),
    )
    _log_action("编辑委外订单", order.get("order_no") or str(order_id))
    flash("委外订单已保存。", "success")
    return redirect(f"/subcontract/{order_id}")


