def _save_work_order():
    project_serial_error = _require_project_serial_or_redirect("/work-orders/new")
    if project_serial_error:
        return project_serial_error
    product_id = _form_int("product_id")
    if not product_id:
        flash("请选择生产物料。", "warning")
        return redirect("/work-orders/new")
    product_error = _inactive_master_error("products", product_id, "生产物料")
    if product_error:
        flash(product_error, "warning")
        return redirect("/work-orders/new")
    wo_no = _next_doc_no("WO", "work_orders", "wo_no")

    def _operation(cur):
        cur.execute(
            """
            INSERT INTO work_orders
                (wo_no, wo_date, product_id, bom_id, warehouse_id, location_id, quantity, status,
                 lot_no, unit_cost, amount, material_code, material_name, material_spec, material_unit,
                 source_line_no, line_project_code, line_serial_no,
                 production_stage, status_changed_at, status_changed_by, responsible_person,
                 priority, production_type, planned_start_date, planned_end_date, project_code, serial_no, remark)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,CURRENT_TIMESTAMP,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            RETURNING id
            """,
            (
                wo_no,
                _form_text("wo_date", datetime.now().date().isoformat()),
                product_id,
                _form_int("bom_id"),
                _form_int("warehouse_id"),
                _form_int("location_id"),
                _form_decimal("quantity", "0"),
                "创建",
                _form_text("lot_no"),
                _form_decimal("unit_cost", "0"),
                _form_decimal("quantity", "0") * _form_decimal("unit_cost", "0"),
                _form_text("material_code_display"),
                _form_text("material_name_display"),
                _form_text("specification_display"),
                _form_text("unit_display"),
                _form_text("source_line_no"),
                _form_text("line_project_code") or _form_text("project_code"),
                _form_text("line_serial_no") or _form_text("serial_no"),
                "创建",
                session.get("user_id"),
                _form_text("responsible_person"),
                _form_text("priority", "普通"),
                _form_text("production_type") or "整机生产",
                _form_text("planned_start_date") or None,
                _form_text("planned_end_date") or None,
                _form_text("project_code"),
                _form_text("serial_no"),
                _form_text("remark"),
            ),
        )
        row = cur.fetchone()
        new_order_id = row.get("id") if row else None
        if new_order_id:
            cur.execute(
                """
                INSERT INTO work_order_status_logs (work_order_id, to_status, to_stage, changed_by, remark)
                VALUES (%s, %s, %s, %s, %s)
                """,
                (new_order_id, "创建", "创建", session.get("user_id"), "新建工单"),
            )
        return new_order_id

    new_order_id = current_app.extensions["run_in_transaction"](_operation)
    if new_order_id:
        try:
            create_work_order_execution_snapshot(
                _safe_one,
                _safe_rows,
                _execute_db,
                _execute_and_return,
                new_order_id,
                snapshot_by=session.get("user_id"),
            )
        except Exception:
            current_app.logger.exception("Failed to create work order execution snapshot for %s", new_order_id)
    _log_action("新增生产工单", wo_no)
    flash(f"已新增生产工单 {wo_no}。", "success")
    return redirect("/work-orders")


def _work_order_edit_row(work_order_id):
    return _safe_one(
        """
        SELECT wo.*, p.code AS product_code, p.name AS product_name, p.specification AS product_specification, p.unit AS product_unit
        FROM work_orders wo
        LEFT JOIN products p ON p.id=wo.product_id
        WHERE wo.id=%s
        """,
        (work_order_id,),
    )


def _work_order_edit_blockers(work_order_id, order):
    blockers = []
    if not _status_allows_edit(order.get("status")):
        blockers.append("当前工单状态不允许普通编辑")
    material = _safe_one(
        """
        SELECT COUNT(*) AS line_count,
               COALESCE(SUM(COALESCE(issued_qty,0)),0) AS issued_qty,
               COALESCE(SUM(COALESCE(returned_qty,0)),0) AS returned_qty
        FROM wo_material_items
        WHERE wo_id=%s
        """,
        (work_order_id,),
    ) or {}
    if _as_int(material.get("line_count")) > 0:
        blockers.append("已生成工单用料需求")
    if _as_decimal(material.get("issued_qty")) > 0 or _as_decimal(material.get("returned_qty")) > 0:
        blockers.append("已发生生产领料或退料")
    checks = [
        ("pick_lists", "work_order_id", "已存在生产领退料单"),
        ("production_completion_orders", "work_order_id", "已存在完工入库单"),
        ("wo_complete_items", "wo_id", "已存在工单完工明细"),
        ("operation_reports", "work_order_id", "已存在工序报工单"),
    ]
    for table, column, label in checks:
        row = _safe_one(f"SELECT COUNT(*) AS count FROM {table} WHERE {column}=%s", (work_order_id,)) or {}
        if _as_int(row.get("count")) > 0:
            blockers.append(label)
    quality = _safe_one(
        "SELECT COUNT(*) AS count FROM quality_inspection_records WHERE source_document_type='work_order' AND source_document_id=%s",
        (work_order_id,),
    ) or {}
    if _as_int(quality.get("count")) > 0:
        blockers.append("已存在质量检验记录")
    return blockers


def _render_work_order_edit(work_order_id):
    _require_work_order_scope(work_order_id, action="edit")
    order = _work_order_edit_row(work_order_id)
    if not order:
        flash("生产工单不存在。", "warning")
        return redirect("/work-orders")
    blockers = _work_order_edit_blockers(work_order_id, order)
    if blockers:
        flash("当前生产工单不能普通编辑：" + "；".join(blockers), "warning")
        return redirect(f"/work-orders/{work_order_id}")
    return _render_work_order_form(order=order, mode="edit", post_url=f"/work-orders/{work_order_id}/edit")


def _save_work_order_edit(work_order_id):
    _require_work_order_scope(work_order_id, action="edit")
    order = _work_order_edit_row(work_order_id)
    if not order:
        flash("生产工单不存在。", "warning")
        return redirect("/work-orders")
    blockers = _work_order_edit_blockers(work_order_id, order)
    if blockers:
        flash("当前生产工单不能普通编辑：" + "；".join(blockers), "warning")
        return redirect(f"/work-orders/{work_order_id}")
    product_id = _form_int("product_id")
    if not product_id:
        flash("请选择生产物料。", "warning")
        return redirect(f"/work-orders/{work_order_id}/edit")
    product_error = _inactive_master_error("products", product_id, "生产物料")
    if product_error:
        flash(product_error, "warning")
        return redirect(f"/work-orders/{work_order_id}/edit")
    quantity = _form_decimal("quantity", "0")
    unit_cost = _form_decimal("unit_cost", "0")
    updated = _execute_and_return(
        """
        UPDATE work_orders
        SET wo_date=%s, product_id=%s, bom_id=%s, warehouse_id=%s, location_id=%s,
            quantity=%s, lot_no=%s, unit_cost=%s, amount=%s,
            material_code=%s, material_name=%s, material_spec=%s, material_unit=%s,
            source_line_no=%s, line_project_code=%s, line_serial_no=%s,
            responsible_person=%s, priority=%s, production_type=%s,
            planned_start_date=%s, planned_end_date=%s, project_code=%s, serial_no=%s, remark=%s,
            row_version=COALESCE(row_version,1)+1
        WHERE id=%s
          AND COALESCE(row_version,1)=%s
        RETURNING id
        """,
        (
            _form_text("wo_date", datetime.now().date().isoformat()),
            product_id,
            _form_int("bom_id"),
            _form_int("warehouse_id"),
            _form_int("location_id"),
            quantity,
            _form_text("lot_no"),
            unit_cost,
            quantity * unit_cost,
            _form_text("material_code_display"),
            _form_text("material_name_display"),
            _form_text("specification_display"),
            _form_text("unit_display"),
            _form_text("source_line_no"),
            _form_text("line_project_code") or _form_text("project_code"),
            _form_text("line_serial_no") or _form_text("serial_no"),
            _form_text("responsible_person"),
            _form_text("priority", "普通"),
            _form_text("production_type") or "整机生产",
            _form_text("planned_start_date") or None,
            _form_text("planned_end_date") or None,
            _form_text("project_code"),
            _form_text("serial_no"),
            _form_text("remark"),
            work_order_id,
            _submitted_row_version(order),
        ),
    )
    if not updated:
        return "Document version conflict", 409
    _log_action("编辑生产工单", order.get("wo_no"), f"id={work_order_id}")
    flash(f"生产工单 {order.get('wo_no')} 已保存修改。", "success")
    return redirect(f"/work-orders/{work_order_id}")


def _transfer_form_items():
    items = []
    product_ids = request.form.getlist("product_id[]")
    if product_ids:
        quantities = request.form.getlist("quantity[]")
        unit_costs = request.form.getlist("unit_cost[]")
        lot_nos = request.form.getlist("lot_no[]")
        serial_nos = request.form.getlist("serial_no[]")
        from_location_ids = request.form.getlist("from_location_id[]")
        to_location_ids = request.form.getlist("to_location_id[]")
        from_warehouse_ids = request.form.getlist("from_warehouse_id[]")
        to_warehouse_ids = request.form.getlist("to_warehouse_id[]")
        line_project_codes = request.form.getlist("line_project_code[]")
        source_line_nos = request.form.getlist("source_line_no[]")
        remarks = request.form.getlist("remark[]")
        for idx, product_id_value in enumerate(product_ids):
            product_id = _as_int(product_id_value)
            qty = _as_decimal(quantities[idx] if idx < len(quantities) else "0")
            if not product_id or qty <= 0:
                continue
            items.append(
                {
                    "product_id": product_id,
                    "quantity": qty,
                    "unit_cost": _as_decimal(unit_costs[idx] if idx < len(unit_costs) else "0"),
                    "amount": qty * _as_decimal(unit_costs[idx] if idx < len(unit_costs) else "0"),
                    "lot_no": lot_nos[idx] if idx < len(lot_nos) else "",
                    "serial_no": serial_nos[idx] if idx < len(serial_nos) else "",
                    "from_location_id": _as_int(from_location_ids[idx]) if idx < len(from_location_ids) else 0,
                    "to_location_id": _as_int(to_location_ids[idx]) if idx < len(to_location_ids) else 0,
                    "from_warehouse_id": _as_int(from_warehouse_ids[idx]) if idx < len(from_warehouse_ids) else 0,
                    "to_warehouse_id": _as_int(to_warehouse_ids[idx]) if idx < len(to_warehouse_ids) else 0,
                    "line_project_code": _short_text(line_project_codes[idx], 120) if idx < len(line_project_codes) else "",
                    "source_line_no": _short_text(source_line_nos[idx], 80) if idx < len(source_line_nos) else "",
                    "remark": remarks[idx] if idx < len(remarks) else "",
                }
            )
    else:
        product_id = _form_int("product_id")
        qty = _form_decimal("quantity")
        if product_id and qty > 0:
            items.append(
                {
                    "product_id": product_id,
                    "quantity": qty,
                    "unit_cost": _form_decimal("unit_cost"),
                    "amount": qty * _form_decimal("unit_cost"),
                    "lot_no": _form_text("lot_no"),
                    "serial_no": _form_text("serial_no"),
                    "from_location_id": _form_int("from_location_id"),
                    "to_location_id": _form_int("to_location_id"),
                    "line_project_code": _short_text(_form_text("line_project_code"), 120),
                    "source_line_no": _short_text(_form_text("source_line_no"), 80),
                    "remark": _form_text("remark"),
                }
            )
    return items


def _create_inventory_transfer():
    from_warehouse_id = _form_int("from_warehouse_id")
    to_warehouse_id = _form_int("to_warehouse_id")
    project_code = _form_text("project_code")
    project_header_error = _require_project_serial_values_or_redirect(project_code, "pending-line-check", "/transfers/new")
    if project_header_error:
        return project_header_error
    items = _transfer_form_items()
    if not from_warehouse_id or not to_warehouse_id or not items:
        flash("请选择调出仓库、调入仓库，并录入至少一条有效明细。", "warning")
        return redirect("/transfers/new")
    if from_warehouse_id == to_warehouse_id and (_form_int("from_location_id") or 0) == (_form_int("to_location_id") or 0):
        flash("调出和调入的仓库库位不能完全相同。", "warning")
        return redirect("/transfers/new")
    _ensure_transfer_item_table()
    transfer_no = _next_doc_no("TR", "transfer_orders", "transfer_no")
    transfer_date = _form_text("transfer_date", datetime.now().date().isoformat())
    remark = _form_text("remark")
    transfer = _execute_and_return(
        """
        INSERT INTO transfer_orders
            (transfer_no, transfer_date, from_warehouse_id, to_warehouse_id, project_code, status, remark, created_by, completed_at)
        VALUES (%s,%s,%s,%s,%s,'已完成',%s,%s,NOW())
        RETURNING id
        """,
        (transfer_no, transfer_date, from_warehouse_id, to_warehouse_id, project_code, remark, session.get("user_id")),
    )
    transfer_id = transfer["id"]
    from_location_id = _form_int("from_location_id")
    to_location_id = _form_int("to_location_id")
    for item in items:
        project_serial_error = _require_project_serial_values_or_redirect(project_code, item["serial_no"], "/transfers/new")
        if project_serial_error:
            return project_serial_error
        _execute_db(
            """
            INSERT INTO transfer_order_items
                (transfer_id, product_id, quantity, lot_no, serial_no, unit_cost, remark)
            VALUES (%s,%s,%s,%s,%s,%s,%s)
            """,
            (transfer_id, item["product_id"], item["quantity"], item["lot_no"], item["serial_no"], item["unit_cost"], remark),
        )
        _apply_inventory_movement(
            product_id=item["product_id"],
            quantity=-item["quantity"],
            unit_cost=item["unit_cost"],
            tx_type="调拨出库",
            reference_no=transfer_no,
            remark=remark,
            warehouse_id=from_warehouse_id,
            location_id=from_location_id,
            lot_no=item["lot_no"],
            serial_no=item["serial_no"],
            project_code=project_code,
            tx_date=transfer_date,
        )
        _apply_inventory_movement(
            product_id=item["product_id"],
            quantity=item["quantity"],
            unit_cost=item["unit_cost"],
            tx_type="调拨入库",
            reference_no=transfer_no,
            remark=remark,
            warehouse_id=to_warehouse_id,
            location_id=to_location_id,
            lot_no=item["lot_no"],
            serial_no=item["serial_no"],
            project_code=project_code,
            tx_date=transfer_date,
        )
    _log_action("库存调拨", transfer_no)
    flash(f"已生成库存调拨单 {transfer_no}。", "success")
    _save_document_custom_payload("inventory_transfer", transfer_id)
    return redirect(f"/transfers/{transfer_id}")


def _ensure_inventory_check_item_table():
    _execute_db(
        """
        CREATE TABLE IF NOT EXISTS inventory_check_order_items (
            id SERIAL PRIMARY KEY,
            check_id INTEGER NOT NULL REFERENCES inventory_check_orders(id) ON DELETE CASCADE,
            product_id INTEGER NOT NULL,
            book_qty NUMERIC(14,3) NOT NULL DEFAULT 0,
            actual_qty NUMERIC(14,3) NOT NULL DEFAULT 0,
            diff_qty NUMERIC(14,3) NOT NULL DEFAULT 0,
            lot_no VARCHAR(100),
            serial_no VARCHAR(100),
            unit_cost NUMERIC(14,2) DEFAULT 0
        )
        """
    )
    _execute_db("ALTER TABLE inventory_check_order_items ALTER COLUMN book_qty TYPE NUMERIC(14,3)")
    _execute_db("ALTER TABLE inventory_check_order_items ALTER COLUMN actual_qty TYPE NUMERIC(14,3)")
    _execute_db("ALTER TABLE inventory_check_order_items ALTER COLUMN diff_qty TYPE NUMERIC(14,3)")
    _execute_db("ALTER TABLE inventory_check_order_items ALTER COLUMN unit_cost TYPE NUMERIC(14,2)")
    _execute_db("ALTER TABLE inventory_check_order_items ADD COLUMN IF NOT EXISTS amount NUMERIC(14,2) DEFAULT 0")
    _execute_db("ALTER TABLE inventory_check_order_items ALTER COLUMN amount TYPE NUMERIC(14,2)")
    _execute_db("ALTER TABLE inventory_check_order_items ADD COLUMN IF NOT EXISTS warehouse_id INTEGER")
    _execute_db("ALTER TABLE inventory_check_order_items ADD COLUMN IF NOT EXISTS location_id INTEGER")
    _execute_db("ALTER TABLE inventory_check_order_items ADD COLUMN IF NOT EXISTS line_warehouse_id INTEGER")
    _execute_db("ALTER TABLE inventory_check_order_items ADD COLUMN IF NOT EXISTS line_location_id INTEGER")
    _execute_db(
        """
        UPDATE inventory_check_order_items
        SET line_warehouse_id=warehouse_id
        WHERE line_warehouse_id IS NULL
          AND warehouse_id IS NOT NULL
        """
    )
    _execute_db(
        """
        UPDATE inventory_check_order_items
        SET line_location_id=location_id
        WHERE line_location_id IS NULL
          AND location_id IS NOT NULL
        """
    )


