def _render_return_detail(table, record_id, back_url, title, partner_join, partner_label, direction_label):
    order = _safe_one(
        f"""
        SELECT r.*, p.code AS product_code, p.name AS product_name, p.specification, p.unit,
               w.name AS warehouse_name, l.code AS location_code, l.name AS location_name,
               {partner_join['name_expr']} AS partner_name
        FROM {table} r
        LEFT JOIN products p ON p.id=r.product_id
        LEFT JOIN warehouses w ON w.id=r.warehouse_id
        LEFT JOIN locations l ON l.id=r.location_id
        {partner_join['join_sql']}
        WHERE r.id=%s
        """,
        (record_id,),
    )
    if not order:
        return render_template("simple_detail.html", title=title, row=None, back_url=back_url, labels={})
    doc_no = order.get("return_no") or str(record_id)
    doc_kind = "sales_return" if table == "sales_returns" else "purchase_return"
    transactions = _safe_rows(
        """
        SELECT st.*, p.code AS product_code, p.name AS product_name,
               w.name AS warehouse_name, l.code AS location_code
        FROM stock_transactions st
        LEFT JOIN products p ON p.id=st.product_id
        LEFT JOIN warehouses w ON w.id=st.warehouse_id
        LEFT JOIN locations l ON l.id=st.location_id
        WHERE st.reference_no=%s
        ORDER BY st.id DESC
        LIMIT 80
        """,
        (doc_no,),
    )
    return render_template(
        "inventory_return_detail.html",
        title=title,
        order=order,
        transactions=transactions,
        back_url=back_url,
        post_url=f"{back_url}/{record_id}/post",
        partner_label=partner_label,
        direction_label=direction_label,
        print_url=f"{back_url}/{record_id}/print",
        action_prefix=back_url,
        doc_kind=doc_kind,
        attachments=_document_attachments(doc_kind, record_id),
        activity_logs=_document_activity_logs(doc_kind, order),
    )


