def _ensure_inventory_return_columns(table):
    if not _has_table(table):
        return
    for ddl in (
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS product_id INTEGER",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS quantity NUMERIC(14, 3) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS unit_cost NUMERIC(14, 4) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS warehouse_id INTEGER",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS location_id INTEGER",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS lot_no VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS serial_no VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS project_code VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS posted_at TIMESTAMP",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS posted_by INTEGER",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS cancelled_at TIMESTAMP",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS cancelled_by INTEGER",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS closed_at TIMESTAMP",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS closed_by INTEGER",
    ):
        _execute_db(ddl)


def _post_inventory_return(table, record_id, kind):
    _ensure_inventory_return_columns(table)
    back_url = "/sales-returns" if kind == "sales" else "/purchase-returns"
    order = _safe_one(f"SELECT * FROM {table} WHERE id=%s", (record_id,))
    if not order:
        return redirect(back_url)
    status = order.get("status") or ""
    if status in {"已取消", "cancelled", "canceled"}:
        flash("已取消的退货单不能过账。", "warning")
        return redirect(f"{back_url}/{record_id}")
    if status == INVENTORY_STATUS_POSTED:
        flash("退货单已过账，不能重复过账。", "info")
        return redirect(f"{back_url}/{record_id}")
    if status not in INVENTORY_PENDING_STATUSES:
        flash(f"退货单状态为 {status or '-'}，不能过账。", "warning")
        return redirect(f"{back_url}/{record_id}")
    return_no = order.get("return_no") or f"RET-{record_id}"
    try:
        _validate_inventory_location_or_raise(order.get("warehouse_id"), order.get("location_id"), "退货仓库")
        qty = _as_decimal(order.get("quantity"))
        move_qty = qty if kind == "sales" else -qty
        tx_type = "销售退货入库" if kind == "sales" else "采购退货出库"
        _apply_inventory_movement(order.get("product_id"), move_qty, order.get("unit_cost"), tx_type, return_no, order.get("remark") or "", order.get("warehouse_id"), order.get("location_id"), order.get("lot_no") or "", order.get("serial_no") or "", order.get("return_date") or datetime.now().date().isoformat(), order.get("project_code") or "")
        _execute_db(f"UPDATE {table} SET status='已过账', posted_at=NOW(), posted_by=%s WHERE id=%s", (session.get("user_id"), record_id))
    except ValueError as exc:
        flash(str(exc), "warning")
    return redirect(f"{back_url}/{record_id}")


def _unaudit_inventory_return(table, record_id, kind):
    _ensure_inventory_return_columns(table)
    back_url = "/sales-returns" if kind == "sales" else "/purchase-returns"
    order = _safe_one(f"SELECT * FROM {table} WHERE id=%s", (record_id,))
    if not order:
        return redirect(back_url)
    status = order.get("status") or ""
    if status != INVENTORY_STATUS_POSTED:
        flash("只有已过账的退货单可以反审。", "warning")
        return redirect(f"{back_url}/{record_id}")
    return_no = order.get("return_no") or f"RET-{record_id}"
    tx_type = "销售退货入库" if kind == "sales" else "采购退货出库"

    def operation(cursor):
        query_one, query_rows, execute_db, _ = _registry_transaction_callables(cursor)
        fresh = query_one(f"SELECT status FROM {table} WHERE id=%s FOR UPDATE", (record_id,))
        if not fresh or fresh.get("status") != INVENTORY_STATUS_POSTED:
            raise ValueError("退货单状态已变化，反审中止。")
        tx_rows = query_rows(
            """
            SELECT id, product_id, quantity, unit_cost, warehouse_id, location_id,
                   lot_no, serial_no, project_code
            FROM stock_transactions
            WHERE reference_no=%s AND transaction_type=%s
            ORDER BY id
            """,
            (return_no, tx_type),
        )
        if not tx_rows:
            raise ValueError("未找到该退货单对应的库存流水，无法反审。")
        for tx in tx_rows:
            _reverse_inventory_movement_balance(
                product_id=tx.get("product_id"),
                signed_qty=_as_decimal(tx.get("quantity")),
                unit_cost=_as_decimal(tx.get("unit_cost")),
                warehouse_id=tx.get("warehouse_id"),
                location_id=tx.get("location_id"),
                lot_no=tx.get("lot_no") or "",
                serial_no=tx.get("serial_no") or "",
                project_code=tx.get("project_code") or "",
                query_one=query_one,
                execute_db_fn=execute_db,
            )
            execute_db("DELETE FROM stock_transactions WHERE id=%s", (tx.get("id"),))
        execute_db(
            f"""
            UPDATE {table}
            SET status=%s, posted_at=NULL, posted_by=NULL
            WHERE id=%s
            """,
            (INVENTORY_STATUS_PENDING, record_id),
        )
        return len(tx_rows)

    try:
        reversed_count = _run_registry_transaction(operation)
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(f"{back_url}/{record_id}")
    _log_action("反审销售退货单" if kind == "sales" else "反审采购退货单", return_no)
    flash(f"退货单已反审，已回滚 {reversed_count} 条库存流水。", "success")
    return redirect(f"{back_url}/{record_id}")


def _cancel_inventory_return(table, record_id, kind):
    _ensure_inventory_return_columns(table)
    back_url = "/sales-returns" if kind == "sales" else "/purchase-returns"
    order = _safe_one(f"SELECT * FROM {table} WHERE id=%s", (record_id,))
    if not order:
        return redirect(back_url)
    if not _inventory_cancel_allowed(order.get("status")):
        flash("只有待过账的退货单可以取消。", "warning")
        return redirect(f"{back_url}/{record_id}")
    _execute_db(f"UPDATE {table} SET status='已取消', cancelled_at=NOW(), cancelled_by=%s WHERE id=%s", (session.get("user_id"), record_id))
    return redirect(f"{back_url}/{record_id}")


def _close_inventory_return(table, record_id, kind):
    _ensure_inventory_return_columns(table)
    back_url = "/sales-returns" if kind == "sales" else "/purchase-returns"
    order = _safe_one(f"SELECT * FROM {table} WHERE id=%s", (record_id,))
    if not order:
        return redirect(back_url)
    if order.get("status") != "已过账":
        flash("只有已过账的退货单可以关闭。", "warning")
        return redirect(f"{back_url}/{record_id}")
    _execute_db(f"UPDATE {table} SET status='已关闭', closed_at=NOW(), closed_by=%s WHERE id=%s", (session.get("user_id"), record_id))
    return redirect(f"{back_url}/{record_id}")


def _delete_inventory_return_draft(table, record_id, kind):
    _ensure_inventory_return_columns(table)
    back_url = "/sales-returns" if kind == "sales" else "/purchase-returns"
    order = _safe_one(f"SELECT id, return_no, status FROM {table} WHERE id=%s", (record_id,))
    if not order:
        flash("退货单不存在或已删除。", "warning")
        return redirect(back_url)
    status = (order.get("status") or "").strip()
    if status == INVENTORY_STATUS_POSTED:
        flash("已过账退货单不能直接删除，请先反审。", "warning")
        return redirect(f"{back_url}/{record_id}")
    if status in {"已关闭", "已取消", "已作废", "void", "closed", "cancelled"}:
        flash("已关闭、已取消或已作废退货单不能删除。", "warning")
        return redirect(f"{back_url}/{record_id}")
    return_no = order.get("return_no") or str(record_id)
    if _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s OR source_doc_no=%s LIMIT 1", (return_no, return_no)):
        flash("该退货单已有库存流水，不能直接删除，请先反审。", "warning")
        return redirect(f"{back_url}/{record_id}")
    _execute_db(f"DELETE FROM {table} WHERE id=%s", (record_id,))
    _log_action("删除销售退货单草稿" if kind == "sales" else "删除采购退货单草稿", return_no)
    flash(f"退货单 {return_no} 已删除。", "success")
    return redirect(back_url)


def _generic_entry_options():
    sales_return_sources = _safe_rows(
        """
        SELECT ss.shipment_no AS source_no,
               COALESCE(ss.source_no, so.order_no, '') AS source_order_no,
               COALESCE(ss.customer_id, so.customer_id) AS customer_id,
               COALESCE(ss.project_code, so.project_code, '') AS project_code,
               COALESCE(ss.serial_no, so.serial_no, '') AS serial_no,
               COALESCE(c.name, '') AS customer_name
        FROM sales_shipments ss
        LEFT JOIN sales_orders so ON so.id=ss.order_id
        LEFT JOIN customers c ON c.id=COALESCE(ss.customer_id, so.customer_id)
        WHERE COALESCE(ss.status, '') NOT IN ('已作废', 'voided', 'cancelled', 'canceled')
        ORDER BY ss.id DESC
        LIMIT 300
        """
    ) if _has_table("sales_shipments") else []
    sales_return_orders = _safe_rows(
        """
        SELECT so.order_no AS source_order_no,
               so.customer_id,
               COALESCE(so.project_code, '') AS project_code,
               COALESCE(so.serial_no, '') AS serial_no,
               COALESCE(c.name, '') AS customer_name
        FROM sales_orders so
        LEFT JOIN customers c ON c.id=so.customer_id
        WHERE COALESCE(so.status, '') NOT IN ('已作废', 'voided', 'cancelled', 'canceled')
        ORDER BY so.id DESC
        LIMIT 300
        """
    ) if _has_table("sales_orders") else []
    purchase_return_sources = _safe_rows(
        """
        SELECT pr.receipt_no AS source_no,
               COALESCE(po.order_no, '') AS source_order_no,
               po.supplier_id,
               COALESCE(pr.project_code, po.project_code, '') AS project_code,
               COALESCE(pr.serial_no, po.serial_no, '') AS serial_no,
               COALESCE(s.name, '') AS supplier_name,
               pri.product_id,
               COALESCE(p.name, poi.material_name, '') AS product_name,
               COALESCE(p.specification, poi.material_spec, '') AS specification,
               COALESCE(p.unit, poi.material_unit, '') AS unit,
               COALESCE(pri.quantity, 0) AS quantity,
               COALESCE(pri.unit_cost, poi.unit_price, p.last_purchase_cost, p.current_cost, p.standard_price, 0) AS unit_cost,
               COALESCE(pri.tax_rate, poi.tax_rate, p.default_tax_rate, 13) AS tax_rate,
               COALESCE(pri.warehouse_id, pr.warehouse_id, po.warehouse_id) AS warehouse_id,
               pri.location_id,
               COALESCE(pri.lot_no, poi.lot_no, '') AS lot_no
        FROM purchase_receipts pr
        LEFT JOIN purchase_orders po ON po.id=pr.order_id
        LEFT JOIN suppliers s ON s.id=po.supplier_id
        LEFT JOIN LATERAL (
            SELECT *
            FROM purchase_receipt_items item
            WHERE item.receipt_id=pr.id
            ORDER BY item.id
            LIMIT 1
        ) pri ON TRUE
        LEFT JOIN purchase_order_items poi ON poi.id=pri.order_item_id
        LEFT JOIN products p ON p.id=COALESCE(pri.product_id, poi.product_id)
        WHERE COALESCE(pr.status, '') NOT IN ('已作废', 'voided', 'cancelled', 'canceled')
        ORDER BY pr.id DESC
        LIMIT 300
        """
    ) if _has_table("purchase_receipts") and _has_table("purchase_receipt_items") else []
    purchase_return_orders = _safe_rows(
        """
        SELECT po.order_no AS source_order_no,
               latest_receipt.receipt_no AS source_no,
               po.supplier_id,
               COALESCE(po.project_code, '') AS project_code,
               COALESCE(po.serial_no, '') AS serial_no,
               COALESCE(s.name, '') AS supplier_name,
               poi.product_id,
               COALESCE(p.name, poi.material_name, '') AS product_name,
               COALESCE(p.specification, poi.material_spec, '') AS specification,
               COALESCE(p.unit, poi.material_unit, '') AS unit,
               COALESCE(poi.received_qty, poi.quantity, 0) AS quantity,
               COALESCE(poi.unit_price, p.last_purchase_cost, p.current_cost, p.standard_price, 0) AS unit_cost,
               COALESCE(poi.tax_rate, p.default_tax_rate, 13) AS tax_rate,
               COALESCE(latest_receipt.warehouse_id, po.warehouse_id) AS warehouse_id,
               COALESCE(latest_receipt.location_id, poi.location_id) AS location_id,
               COALESCE(latest_receipt.lot_no, poi.lot_no, '') AS lot_no
        FROM purchase_orders po
        LEFT JOIN suppliers s ON s.id=po.supplier_id
        LEFT JOIN LATERAL (
            SELECT *
            FROM purchase_order_items item
            WHERE item.order_id=po.id
            ORDER BY item.id
            LIMIT 1
        ) poi ON TRUE
        LEFT JOIN products p ON p.id=poi.product_id
        LEFT JOIN LATERAL (
            SELECT pr.receipt_no, COALESCE(pri.warehouse_id, pr.warehouse_id) AS warehouse_id,
                   pri.location_id, pri.lot_no
            FROM purchase_receipts pr
            LEFT JOIN purchase_receipt_items pri ON pri.receipt_id=pr.id
            WHERE pr.order_id=po.id
            ORDER BY pr.id DESC, pri.id
            LIMIT 1
        ) latest_receipt ON TRUE
        WHERE COALESCE(po.status, '') NOT IN ('已关闭', '已作废', 'voided', 'cancelled', 'canceled')
        ORDER BY po.id DESC
        LIMIT 300
        """
    ) if _has_table("purchase_orders") and _has_table("purchase_order_items") else []
    return {
        "customers": _filter_clean_rows(_safe_rows("SELECT id, name FROM customers ORDER BY id DESC LIMIT 1000"), "name"),
        "suppliers": _supplier_options(),
        "products": _inventory_document_product_options(),
        "warehouses": _warehouse_options(),
        "locations": _filter_clean_rows(_safe_rows("SELECT id, warehouse_id, code, name FROM locations WHERE COALESCE(is_active, TRUE)=TRUE ORDER BY code LIMIT 1000"), "code", "name"),
        "sales_return_sources": sales_return_sources,
        "sales_return_orders": sales_return_orders,
        "purchase_return_sources": purchase_return_sources,
        "purchase_return_orders": purchase_return_orders,
    }


def _render_purchase_receipt_entry():
    g.toolbar_extras = []
    orders = _safe_rows(
        """
        SELECT po.id, po.order_no, po.order_date, po.warehouse_id, s.name AS partner_name, po.project_code, po.serial_no,
               COALESCE(SUM(GREATEST(COALESCE(poi.quantity,0)-COALESCE(poi.received_qty,0),0)),0) AS pending_qty
        FROM purchase_orders po
        LEFT JOIN suppliers s ON s.id=po.supplier_id
        LEFT JOIN purchase_order_items poi ON poi.order_id=po.id
        WHERE COALESCE(po.status,'') = ANY(%s)
        GROUP BY po.id, s.name
        HAVING COALESCE(SUM(GREATEST(COALESCE(poi.quantity,0)-COALESCE(poi.received_qty,0),0)),0) > 0
        ORDER BY po.id DESC
        LIMIT 200
        """,
        (list(PURCHASE_RECEIVE_READY_STATUSES),),
    )
    requested_order_id = _as_int(request.args.get("purchase_order_id"))
    selected_order = next((order for order in orders if _as_int(order.get("id")) == requested_order_id), None) if requested_order_id else None
    selected_order_id = _as_int(selected_order.get("id")) if selected_order else None
    items = []
    if selected_order_id:
        items = _safe_rows(
            """
            SELECT poi.id, poi.product_id, poi.quantity, COALESCE(poi.received_qty,0) AS received_qty,
                   GREATEST(COALESCE(poi.quantity,0)-COALESCE(poi.received_qty,0),0) AS pending_qty,
                   poi.unit_price, poi.lot_no, poi.expected_date,
                   COALESCE(p.code, poi.material_code, '') AS product_code,
                   COALESCE(p.name, poi.material_name, '') AS product_name,
                   COALESCE(p.specification, poi.material_spec, '') AS specification,
                   COALESCE(p.unit, poi.material_unit, '') AS unit,
                   p.default_warehouse_id, p.default_location_id
            FROM purchase_order_items poi
            LEFT JOIN products p ON p.id=poi.product_id
            WHERE poi.order_id=%s
              AND GREATEST(COALESCE(poi.quantity,0)-COALESCE(poi.received_qty,0),0) > 0
            ORDER BY poi.id
            """,
            (selected_order_id,),
        )
    return render_template(
        "purchase_receipt_form.html",
        receipt_no=_next_doc_no("PIR", "purchase_receipts", "receipt_no"),
        orders=orders,
        selected_order=selected_order,
        items=items,
        warehouses=_warehouse_options(),
        locations=_filter_clean_rows(_safe_rows("SELECT id, warehouse_id, code, name FROM locations WHERE COALESCE(is_active, TRUE)=TRUE ORDER BY code LIMIT 1000"), "code", "name"),
    )


def _sales_shipment_source_lines(order_id):
    if not order_id:
        return []
    return _safe_rows(
        """
        SELECT soi.id, soi.product_id,
               COALESCE(p.code, soi.material_code, '') AS product_code,
               COALESCE(p.name, soi.material_name, '') AS product_name,
               COALESCE(p.specification, soi.material_spec, '') AS specification,
               COALESCE(p.unit, soi.material_unit, '') AS unit,
               COALESCE(soi.quantity, 0) AS quantity,
               COALESCE(soi.shipped_qty, 0) AS shipped_qty,
               GREATEST(COALESCE(soi.quantity,0)-COALESCE(soi.shipped_qty,0),0) AS pending_qty,
               COALESCE(soi.unit_price, 0) AS unit_price,
               COALESCE(soi.tax_rate, 0) AS tax_rate,
               COALESCE(soi.lot_no, '') AS lot_no,
               COALESCE(soi.source_line_no, '') AS source_line_no,
               COALESCE(soi.line_project_code, so.project_code, '') AS line_project_code,
               COALESCE(soi.line_serial_no, so.serial_no, '') AS line_serial_no
        FROM sales_order_items soi
        JOIN sales_orders so ON so.id=soi.order_id
        LEFT JOIN products p ON p.id=soi.product_id
        WHERE soi.order_id=%s
          AND GREATEST(COALESCE(soi.quantity,0)-COALESCE(soi.shipped_qty,0),0) > 0
        ORDER BY soi.id
        """,
        (order_id,),
    )


def _render_source_order_entry(kind):
    if kind == "shipment":
        g.toolbar_extras = []
        orders = _safe_rows(
            """
            SELECT so.id, so.order_no, so.order_date, so.warehouse_id, c.name AS partner_name, so.project_code, so.serial_no,
                   COALESCE(SUM(GREATEST(COALESCE(soi.quantity,0)-COALESCE(soi.shipped_qty,0),0)),0) AS pending_qty
            FROM sales_orders so
            LEFT JOIN customers c ON c.id=so.customer_id
            LEFT JOIN sales_order_items soi ON soi.order_id=so.id
            WHERE COALESCE(so.status,'') NOT IN ('已关闭','已作废','closed','voided')
            GROUP BY so.id, c.name
            HAVING COALESCE(SUM(GREATEST(COALESCE(soi.quantity,0)-COALESCE(soi.shipped_qty,0),0)),0) > 0
            ORDER BY so.id DESC
            LIMIT 200
            """
        )
        selected_order_id = _as_int(request.args.get("sales_order_id")) or (orders[0].get("id") if orders else None)
        selected_order = next((row for row in orders if row.get("id") == selected_order_id), None)
        return render_template(
            "source_order_entry.html",
            kind="shipment",
            title="新增销售发货单",
            list_url="/shipments",
            post_url="/shipments/new",
            source_label="来源销售订单",
            source_field="sales_order_id",
            orders=orders,
            selected_source_id=selected_order_id,
            selected_order=selected_order,
            items=_sales_shipment_source_lines(selected_order_id),
            warehouses=_warehouse_options(),
            date_field="shipment_date",
            date_label="发货日期",
            hide_footer_actions=True,
        )
    orders = _safe_rows(
        """
        SELECT po.id, po.order_no, po.order_date, s.name AS partner_name, po.project_code, po.serial_no,
               COALESCE(SUM(GREATEST(COALESCE(poi.quantity,0)-COALESCE(poi.received_qty,0),0)),0) AS pending_qty
        FROM purchase_orders po
        LEFT JOIN suppliers s ON s.id=po.supplier_id
        LEFT JOIN purchase_order_items poi ON poi.order_id=po.id
        WHERE COALESCE(po.status,'') NOT IN ('已关闭','已作废','closed','voided')
        GROUP BY po.id, s.name
        HAVING COALESCE(SUM(GREATEST(COALESCE(poi.quantity,0)-COALESCE(poi.received_qty,0),0)),0) > 0
        ORDER BY po.id DESC
        LIMIT 200
        """
    )
    return render_template("source_order_entry.html", title="新增采购入库单", list_url="/purchase_receipts", post_url="/purchase_receipts/new", source_label="来源采购订单", source_field="purchase_order_id", orders=orders, date_field="receipt_date", date_label="收货日期")


