def _save_supplier_quote_edit(quote_id):
    quote = _supplier_quote_row(quote_id)
    if not quote:
        flash("供应商报价不存在。", "warning")
        return redirect("/supplier-quotes")
    if not _status_allows_edit(quote.get("status")):
        flash("当前状态不允许编辑供应商报价。", "warning")
        return redirect(f"/supplier-quotes/{quote_id}")
    supplier_id = _form_int("supplier_id")
    product_id = _form_int("product_id")
    quantity = _form_decimal("quantity", "0")
    unit_price = _form_decimal("unit_price", "0")
    tax_rate = _form_decimal("tax_rate", "13")
    if not supplier_id or not product_id or quantity <= 0:
        flash("请填写供应商、物料名称和有效数量。", "warning")
        return redirect(f"/supplier-quotes/{quote_id}/edit")
    product = _safe_one("SELECT name, specification, unit FROM products WHERE id=%s", (product_id,)) or {}
    amount = quantity * unit_price
    tax_amount = amount * tax_rate / Decimal("100")
    amount_with_tax = amount + tax_amount
    def operation(_cursor):
        _execute_db(
            """
            UPDATE supplier_quotes
            SET quote_date=%s, supplier_id=%s, source_no=%s, project_code=%s, serial_no=%s,
                valid_from=%s, valid_to=%s, valid_until=%s, total_amount=%s, tax_amount=%s,
                amount_with_tax=%s, remark=%s, updated_at=NOW()
            WHERE id=%s
            """,
            (
                _form_text("doc_date", datetime.now().date().isoformat()),
                supplier_id,
                _form_text("source_no"),
                _form_text("project_code"),
                _form_text("serial_no"),
                _form_text("doc_date", datetime.now().date().isoformat()),
                _form_text("valid_until") or None,
                _form_text("valid_until") or None,
                amount,
                tax_amount,
                amount_with_tax,
                _form_text("remark"),
                quote_id,
            ),
        )
        _execute_db("DELETE FROM supplier_quote_items WHERE quote_id=%s", (quote_id,))
        _execute_db(
            """
            INSERT INTO supplier_quote_items
                (quote_id, line_no, product_id, item_name, specification, unit, quantity,
                 unit_price, tax_rate, amount, tax_amount, amount_with_tax, remark)
            VALUES (%s,1,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """,
            (quote_id, product_id, product.get("name") or "", product.get("specification") or "", product.get("unit") or "", quantity, unit_price, tax_rate, amount, tax_amount, amount_with_tax, _form_text("line_remark")),
        )

    _run_registry_transaction(operation)
    _log_action("更新供应商报价", quote.get("quote_no") or str(quote_id))
    flash("供应商报价已更新。", "success")
    return redirect(f"/supplier-quotes/{quote_id}")


def _return_row(table, record_id):
    _ensure_inventory_return_columns(table)
    for ddl in (
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS source_no VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS source_order_no VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS return_date DATE DEFAULT CURRENT_DATE",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS total_amount NUMERIC(14,2) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS amount_with_tax NUMERIC(14,2) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS tax_rate NUMERIC(8,2) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS unit_price NUMERIC(14,4) DEFAULT 0",
    ):
        _execute_db(ddl)
    return _safe_one(
        f"""
        SELECT r.*, p.name AS product_name, p.specification, p.unit
        FROM {table} r
        LEFT JOIN products p ON p.id=r.product_id
        WHERE r.id=%s
        """,
        (record_id,),
    )


