def _save_source_document_edit(kind, record_id):
    is_shipment = kind == "shipment"
    table = "sales_shipments" if is_shipment else "purchase_receipts"
    list_url = "/shipments" if is_shipment else "/purchase_receipts"
    date_col = "shipment_date" if is_shipment else "receipt_date"
    doc_col = "shipment_no" if is_shipment else "receipt_no"
    row = _safe_one(f"SELECT id, {doc_col}, status FROM {table} WHERE id=%s", (record_id,))
    if not row:
        flash("单据不存在。", "warning")
        return redirect(list_url)
    save_action = (_form_text("save_action") or "").strip()
    if is_shipment and save_action == "unaudit":
        return _unaudit_sales_shipment(record_id)
    if not _status_allows_edit(row.get("status"), {"", "草稿", "待提交", "待审核", "draft", "pending", "unposted"}):
        flash("当前单据已形成库存或下游影响，不允许普通编辑。", "warning")
        return redirect(f"{list_url}/{record_id}")
    _execute_db(
        f"UPDATE {table} SET {date_col}=%s, remark=%s WHERE id=%s",
        (_form_text(date_col, datetime.now().date().isoformat()), _form_text("remark"), record_id),
    )
    _log_action("更新销售发货单" if is_shipment else "更新采购入库单", row.get(doc_col) or str(record_id))
    if is_shipment and save_action in {"audit", "post", "confirm"}:
        return _post_sales_shipment(record_id)
    flash("单据已更新。", "success")
    return redirect(f"{list_url}/{record_id}")


def _save_quotation_entry():
    customer_id = _form_int("customer_id")
    product_id = _form_int("product_id")
    quantity = _form_decimal("quantity", "0")
    unit_price = _form_decimal("unit_price", "0")
    tax_rate = _form_decimal("tax_rate", "13")
    if not customer_id or not product_id or quantity <= 0:
        flash("请填写客户、物料名称和有效数量。", "warning")
        return redirect("/quotations/new")
    product = _safe_one("SELECT code, name, specification, unit FROM products WHERE id=%s", (product_id,)) or {}
    amount = quantity * unit_price
    tax_amount = amount * tax_rate / Decimal("100")
    amount_with_tax = amount + tax_amount
    quote_no = _next_doc_no("QT", "quotation_headers", "quote_no")
    quote = _execute_and_return(
        """
        INSERT INTO quotation_headers
            (quote_no, quote_date, customer_id, valid_until, status, project_code, serial_no,
             source_no, machine_type, remark, total_amount, tax_amount, amount_with_tax, created_by)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        RETURNING id
        """,
        (quote_no, _form_text("doc_date", datetime.now().date().isoformat()), customer_id, _form_text("valid_until") or None, "草稿", _form_text("project_code"), _form_text("serial_no"), _form_text("source_no"), _form_text("machine_type"), _form_text("remark"), amount, tax_amount, amount_with_tax, session.get("user_id")),
    )
    quote_id = quote.get("id")
    _execute_db(
        """
        INSERT INTO quotation_items
            (quotation_id, line_no, item_type, product_id, item_name, specification, quantity,
             unit, unit_price, tax_rate, amount, tax_amount, amount_with_tax, remark)
        VALUES (%s,1,'main',%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        """,
        (quote_id, product_id, product.get("name") or "", product.get("specification") or "", quantity, product.get("unit") or "", unit_price, tax_rate, amount, tax_amount, amount_with_tax, _form_text("line_remark")),
    )
    _log_action("新增报价单", quote_no)
    flash(f"已新增报价单 {quote_no}。", "success")
    return redirect(f"/quotations/{quote_id}")


