def _save_supplier_quote_entry():
    _ensure_supplier_quote_tables()
    supplier_id = _form_int("supplier_id")
    product_id = _form_int("product_id")
    quantity = _form_decimal("quantity", "0")
    unit_price = _form_decimal("unit_price", "0")
    tax_rate = _form_decimal("tax_rate", "13")
    if not supplier_id or not product_id or quantity <= 0:
        flash("请填写供应商、物料名称和有效数量。", "warning")
        return redirect("/supplier-quotes/new")
    product = _safe_one("SELECT code, name, specification, unit FROM products WHERE id=%s", (product_id,)) or {}
    amount = quantity * unit_price
    tax_amount = amount * tax_rate / Decimal("100")
    amount_with_tax = amount + tax_amount
    quote_no = _next_doc_no("SQ", "supplier_quotes", "quote_no")
    quote = _execute_and_return(
        """
        INSERT INTO supplier_quotes
            (quote_no, quote_date, supplier_id, product_id, unit_price, tax_rate, source_no,
             project_code, serial_no, valid_from, valid_to, valid_until, status, total_amount,
             tax_amount, amount_with_tax, remark, created_by, updated_at)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,'草稿',%s,%s,%s,%s,%s,NOW())
        RETURNING id
        """,
        (
            quote_no,
            _form_text("doc_date", datetime.now().date().isoformat()),
            supplier_id,
            product_id,
            unit_price,
            tax_rate,
            _form_text("source_no"),
            _form_text("project_code"),
            _form_text("serial_no"),
            _form_text("doc_date", datetime.now().date().isoformat()),
            _form_text("valid_until") or None,
            _form_text("valid_until") or None,
            amount,
            tax_amount,
            amount_with_tax,
            _form_text("remark"),
            session.get("user_id"),
        ),
    )
    quote_id = quote.get("id")
    _execute_db(
        """
        INSERT INTO supplier_quote_items
            (quote_id, line_no, product_id, item_name, specification, unit, quantity,
             unit_price, tax_rate, amount, tax_amount, amount_with_tax, remark)
        VALUES (%s,1,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        """,
        (
            quote_id,
            product_id,
            product.get("name") or "",
            product.get("specification") or "",
            product.get("unit") or "",
            quantity,
            unit_price,
            tax_rate,
            amount,
            tax_amount,
            amount_with_tax,
            _form_text("line_remark"),
        ),
    )
    _log_action("新增供应商报价", quote_no)
    flash(f"已新增供应商报价 {quote_no}。", "success")
    return redirect(f"/supplier-quotes/{quote_id}")


def _quotation_status_value(value):
    aliases = {
        "draft": "草稿",
        "submitted": "已提交",
        "audited": "已审核",
        "closed": "已关闭",
        "voided": "已作废",
        "converted": "已转订单",
    }
    raw = str(value or "").strip()
    lowered = raw.lower()
    if "草" in raw:
        return "草稿"
    if "提交" in raw:
        return "已提交"
    if "审核" in raw or "审" in raw:
        return "已审核"
    if "关闭" in raw:
        return "已关闭"
    if "作废" in raw:
        return "已作废"
    if "转订单" in raw:
        return "已转订单"
    return aliases.get(lowered, raw)


def _quotation_header(quote_id):
    return _safe_one(
        """
        SELECT qh.*, c.name AS customer_name, c.contact_person, c.phone AS customer_phone
        FROM quotation_headers qh
        LEFT JOIN customers c ON c.id=qh.customer_id
        WHERE qh.id=%s
        """,
        (quote_id,),
    )


def _quotation_items(quote_id):
    return _safe_rows(
        """
        SELECT qi.*, p.code AS product_code, p.name AS product_name,
               COALESCE(qi.specification, p.specification) AS specification,
               COALESCE(qi.unit, p.unit) AS unit
        FROM quotation_items qi
        LEFT JOIN products p ON p.id=qi.product_id
        WHERE qi.quotation_id=%s
        ORDER BY COALESCE(qi.line_no, qi.id), qi.id
        """,
        (quote_id,),
    )


def _render_quotation_detail(quote_id, back_url="/quotations"):
    quote = _quotation_header(quote_id)
    if not quote:
        return render_template("simple_detail.html", title="报价单不存在", row=None, back_url=back_url, labels={})
    quote["status"] = _quotation_status_value(quote.get("status"))
    return render_template(
        "quotation_detail.html",
        title="报价单详情",
        quotation=quote,
        items=_quotation_items(quote_id),
        attachments=_document_attachments("quotation", quote_id),
        activity_logs=_document_activity_logs("quotation", quote),
        back_url=back_url,
    )


