def _save_return_entry(kind):
    is_sales = kind == "sales"
    table = "sales_returns" if is_sales else "purchase_returns"
    back_url = "/sales-returns/new" if is_sales else "/purchase-returns/new"
    list_url = "/sales-returns" if is_sales else "/purchase-returns"
    save_action = _form_text("save_action", "save")
    if save_action == "unaudit":
        flash("新单据尚未过账，不能反审。请先打开已过账的退货单详情页执行反审。", "warning")
        return redirect(back_url)
    partner_field = "customer_id" if is_sales else "supplier_id"
    partner_id = _form_int(partner_field)
    warehouse_id = _form_int("warehouse_id")
    if not partner_id or not warehouse_id:
        flash("请填写往来单位和退货入库仓库。", "warning")
        return redirect(back_url)
    _ensure_inventory_return_columns(table)
    for ddl in (
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS source_no VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS source_order_no VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS return_date DATE DEFAULT CURRENT_DATE",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS total_amount NUMERIC(14,2) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS amount_with_tax NUMERIC(14,2) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS tax_rate NUMERIC(8,2) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS unit_price NUMERIC(14,4) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS line_no INTEGER",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS parent_id INTEGER",
    ):
        _execute_db(ddl)
    # Collect multi-line items (array) or fallback to single line
    product_ids = request.form.getlist("product_id[]")
    if not product_ids:
        single_pid = _form_int("product_id")
        if single_pid:
            product_ids = [str(single_pid)]
    quantities = request.form.getlist("quantity[]") or [request.form.get("quantity", "0")]
    unit_costs = request.form.getlist("unit_cost[]") or [request.form.get("unit_cost", "0")]
    tax_rates = request.form.getlist("tax_rate[]") or [request.form.get("tax_rate", "13")]
    lot_nos = request.form.getlist("lot_no[]") or [request.form.get("lot_no", "")]
    serial_nos = request.form.getlist("serial_no[]") or [request.form.get("serial_no", "")]
    location_ids = request.form.getlist("location_id[]") or [request.form.get("location_id", "0")]
    source_line_nos = request.form.getlist("source_line_no[]") or [""]
    line_project_codes = request.form.getlist("line_project_code[]") or [""]
    remarks = request.form.getlist("remark[]") or [request.form.get("remark", "")]
    items = []
    for idx, pid_value in enumerate(product_ids):
        product_id = _as_int(pid_value)
        quantity = _as_decimal(quantities[idx] if idx < len(quantities) else "0")
        if not product_id or quantity <= 0:
            continue
        items.append({
            "product_id": product_id,
            "quantity": quantity,
            "unit_cost": _as_decimal(unit_costs[idx] if idx < len(unit_costs) else "0"),
            "tax_rate": _as_decimal(tax_rates[idx] if idx < len(tax_rates) else "13"),
            "lot_no": lot_nos[idx] if idx < len(lot_nos) else "",
            "serial_no": serial_nos[idx] if idx < len(serial_nos) else "",
            "location_id": _as_int(location_ids[idx]) if idx < len(location_ids) else 0,
            "source_line_no": source_line_nos[idx] if idx < len(source_line_nos) else "",
            "line_project_code": line_project_codes[idx] if idx < len(line_project_codes) else "",
            "remark": remarks[idx] if idx < len(remarks) else "",
        })
    if not items:
        flash("请填写至少一行有效的物料名称和退货数量。", "warning")
        return redirect(back_url)
    header_project_code = _form_text("project_code")
    header_serial_no = _form_text("serial_no")
    header_remark = _form_text("remark")
    total_amount = Decimal("0")
    first_row = None
    for seq, item in enumerate(items, start=1):
        item_project_code = item["line_project_code"] or header_project_code
        item_serial_no = item["serial_no"] or header_serial_no
        amount = item["quantity"] * item["unit_cost"] * (Decimal("1") + item["tax_rate"] / Decimal("100"))
        total_amount += amount
        return_no = _next_doc_no("SR" if is_sales else "PR", table, "return_no") if seq == 1 else f"{first_row['return_no']}-{seq}"
        row = _execute_and_return(
            f"""
            INSERT INTO {table}
                (return_no, return_date, {partner_field}, source_no, source_order_no, product_id,
                 quantity, unit_price, tax_rate, amount_with_tax, total_amount, unit_cost,
                 warehouse_id, location_id, lot_no, serial_no, project_code, status, remark,
                 line_no, parent_id)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            RETURNING id, return_no
            """,
            (return_no, _form_text("doc_date", datetime.now().date().isoformat()), partner_id, _form_text("source_no"), _form_text("source_order_no"), item["product_id"], item["quantity"], item["unit_cost"], item["tax_rate"], amount, amount, item["unit_cost"], warehouse_id, item["location_id"], item["lot_no"], item_serial_no, item_project_code, INVENTORY_STATUS_PENDING, item["remark"] or header_remark, seq, first_row["id"] if first_row else None),
        )
        if first_row is None:
            first_row = row
    _log_action("新增销售退货单" if is_sales else "新增采购退货单", first_row["return_no"])
    flash(f"已新增退货单 {first_row['return_no']}（共 {len(items)} 行），请在详情页确认过账。", "success")
    return redirect(f"{list_url}/{first_row.get('id')}")


def _ensure_invoice_table(kind):
    table = "sales_invoices" if kind == "sales" else "purchase_invoices"
    partner_col = "customer_id" if kind == "sales" else "supplier_id"
    _execute_db(f"CREATE TABLE IF NOT EXISTS {table} (id SERIAL PRIMARY KEY)")
    for ddl in (
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS invoice_no VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS {partner_col} INTEGER",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS source_type VARCHAR(80)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS source_id INTEGER",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS source_no VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS invoice_date DATE DEFAULT CURRENT_DATE",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS amount NUMERIC(14,2) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS tax_amount NUMERIC(14,2) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS amount_with_tax NUMERIC(14,2) DEFAULT 0",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS project_code VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS serial_no VARCHAR(120)",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS status VARCHAR(80) DEFAULT 'draft'",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS remark TEXT",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS created_by INTEGER",
        f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP",
    ):
        _execute_db(ddl)
    return table, partner_col


def _save_invoice_entry(kind):
    table, partner_col = _ensure_invoice_table(kind)
    partner_id = _form_int(partner_col)
    if not partner_id:
        flash("请选择往来单位。", "warning")
        return redirect("/sales-invoices/new" if kind == "sales" else "/purchase-invoices/new")
    amount = _form_decimal("amount", "0")
    tax_amount = _form_decimal("tax_amount", "0")
    invoice_no = _form_text("invoice_no") or _next_doc_no("SI" if kind == "sales" else "PI", table, "invoice_no")
    row = _execute_and_return(
        f"""
        INSERT INTO {table}
            (invoice_no, {partner_col}, source_type, source_no, invoice_date, amount,
             tax_amount, amount_with_tax, project_code, serial_no, status, remark, created_by)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        RETURNING id
        """,
        (invoice_no, partner_id, _form_text("source_type"), _form_text("source_no"), _form_text("doc_date", datetime.now().date().isoformat()), amount, tax_amount, _form_decimal("amount_with_tax", str(amount + tax_amount)), _form_text("project_code"), _form_text("serial_no"), _form_text("status", "已登记"), _form_text("remark"), session.get("user_id")),
    )
    _log_action("新增销售发票登记" if kind == "sales" else "新增采购发票登记", invoice_no)
    flash(f"已登记发票 {invoice_no}。", "success")
    return redirect(("/sales-invoices" if kind == "sales" else "/purchase-invoices") + f"/{row.get('id')}")


def _invoice_meta(kind):
    if kind == "sales":
        return {
            "table": "sales_invoices",
            "partner_col": "customer_id",
            "partner_table": "customers",
            "partner_label": "客户",
            "title": "销售发票登记明细",
            "list_url": "/sales-invoices",
            "doc_kind": "sales_invoice",
            "link_label": "应收",
            "link_url": "/receivables",
        }
    return {
        "table": "purchase_invoices",
        "partner_col": "supplier_id",
        "partner_table": "suppliers",
        "partner_label": "供应商",
        "title": "采购发票登记明细",
        "list_url": "/purchase-invoices",
        "doc_kind": "purchase_invoice",
        "link_label": "应付",
        "link_url": "/payables",
    }


def _invoice_row(kind, invoice_id):
    meta = _invoice_meta(kind)
    _ensure_invoice_table(kind)
    return _safe_one(
        f"""
        SELECT i.*, i.{meta['partner_col']} AS partner_id, p.name AS partner_name
        FROM {meta['table']} i
        LEFT JOIN {meta['partner_table']} p ON p.id=i.{meta['partner_col']}
        WHERE i.id=%s
        """,
        (invoice_id,),
    )


def _invoice_linked_doc(kind, invoice):
    if kind == "sales":
        row = _safe_one(
            """
            SELECT id, source_no, status, balance
            FROM customer_receivables
            WHERE source_type='sales_invoice' AND source_id=%s
            """,
            (invoice.get("id"),),
        )
        if row:
            row["url"] = f"/receivables/{row.get('id')}"
        return row
    row = _safe_one(
        """
        SELECT id, doc_no AS source_no, status, balance
        FROM supplier_payables
        WHERE doc_type='purchase_invoice' AND doc_id=%s
        """,
        (invoice.get("id"),),
    )
    if row:
        row["url"] = f"/payables/{row.get('id')}"
    return row


def _render_invoice_detail(kind, invoice_id, back_url=None):
    meta = _invoice_meta(kind)
    invoice = _invoice_row(kind, invoice_id)
    linked_doc = _invoice_linked_doc(kind, invoice) if invoice else None
    linked_status = "未联动"
    if linked_doc:
        linked_status = f"{linked_doc.get('status') or '已生成'}，余额 {linked_doc.get('balance') or 0}"
    return render_template(
        "invoice_detail.html",
        title=meta["title"],
        invoice=invoice,
        partner_label=meta["partner_label"],
        list_url=back_url or meta["list_url"],
        action_base=f"{meta['list_url']}/{invoice_id}",
        print_url=f"{meta['list_url']}/{invoice_id}/print",
        attachments=_document_attachments(meta["doc_kind"], invoice_id) if invoice else [],
        activities=_document_activity_logs(meta["doc_kind"], invoice) if invoice else [],
        linked_doc=linked_doc,
        linked_status=linked_status,
        link_label=meta["link_label"],
        link_url=meta["link_url"],
    )


