def _confirm_invoice(kind, invoice_id):
    invoice = _invoice_row(kind, invoice_id)
    meta = _invoice_meta(kind)
    if not invoice:
        flash("发票登记不存在。", "warning")
        return redirect(meta["list_url"])
    if invoice.get("status") in {"已作废", "已红冲"}:
        flash("已作废或已红冲的发票登记不能确认。", "warning")
        return redirect(f"{meta['list_url']}/{invoice_id}")
    amount_with_tax = _as_decimal(invoice.get("amount_with_tax"))
    remark = f"发票登记 {invoice.get('invoice_no')}，来源单 {invoice.get('source_no') or '-'}；财务二期自动生成应收应付。"

    # 获取当前用户ID用于审核记录
    from flask import session
    current_user_id = session.get("user_id")

    if kind == "sales":
        # 查找现有应收单
        existing = _safe_one("SELECT id, received_amount FROM customer_receivables WHERE source_type='sales_invoice' AND source_id=%s", (invoice_id,))
        receivable_id = None

        if existing:
            # 更新现有应收单，增加 invoice_id 字段
            _execute_db(
                """
                UPDATE customer_receivables
                SET customer_id=%s, source_no=%s, receivable_date=%s, total_amount=%s,
                    balance=GREATEST(%s-COALESCE(received_amount,0),0),
                    status=CASE WHEN GREATEST(%s-COALESCE(received_amount,0),0)=0 THEN '已收款' ELSE '未收款' END,
                    remark=%s, project_code=%s, serial_no=%s, invoice_id=%s
                WHERE id=%s
                """,
                (invoice.get("customer_id"), invoice.get("invoice_no"), invoice.get("invoice_date"),
                 amount_with_tax, amount_with_tax, amount_with_tax, remark,
                 invoice.get("project_code"), invoice.get("serial_no"), invoice_id, existing.get("id")),
            )
            receivable_id = existing.get("id")
        else:
            # 创建新应收单，包含 invoice_id 字段
            receivable_no = _next_doc_no("AR", "customer_receivables", "receivable_no")
            receivable_id = _execute_and_return(
                """
                INSERT INTO customer_receivables
                    (receivable_no, customer_id, source_type, source_id, source_no, receivable_date, total_amount,
                     received_amount, balance, status, remark, project_code, serial_no, invoice_id)
                VALUES (%s,%s,'sales_invoice',%s,%s,%s,%s,0,%s,%s,%s,%s,%s,%s)
                RETURNING id
                """,
                (receivable_no, invoice.get("customer_id"), invoice_id, invoice.get("invoice_no"),
                 invoice.get("invoice_date"), amount_with_tax, amount_with_tax, "未收款",
                 remark, invoice.get("project_code"), invoice.get("serial_no"), invoice_id),
            ).get("id")

        # 插入发票与应收单关联记录（如果不存在）
        if receivable_id:
            _execute_db(
                """
                INSERT INTO sales_invoice_receivables (invoice_id, receivable_id, allocated_amount)
                VALUES (%s, %s, %s)
                ON CONFLICT (invoice_id, receivable_id) DO UPDATE
                SET allocated_amount = EXCLUDED.allocated_amount
                """,
                (invoice_id, receivable_id, amount_with_tax),
            )
            create_trace_link(
                _safe_one,
                _execute_db,
                execute_and_return=_execute_and_return,
                source_doc_type="sales_invoice",
                source_doc_id=invoice_id,
                source_doc_no=invoice.get("invoice_no"),
                target_doc_type="customer_receivable",
                target_doc_id=receivable_id,
                target_doc_no=invoice.get("invoice_no"),
                link_type="source_of",
                link_strength="hard",
                project_code=invoice.get("project_code"),
                serial_no=invoice.get("serial_no"),
                created_by=current_user_id,
                created_event="confirm_sales_invoice",
            )

        # 更新销售发票，记录关联的应收单ID、审核人和审核时间
        _execute_db(
            """
            UPDATE sales_invoices
            SET status='已确认', receivable_id=%s, approved_by=%s, approved_at=CURRENT_TIMESTAMP,
                invoice_status=CASE WHEN invoice_status='draft' THEN 'issued' ELSE invoice_status END
            WHERE id=%s
            """,
            (receivable_id, current_user_id, invoice_id),
        )
    else:
        # 采购发票：使用现有的 upsert 函数生成应付单
        payable_result = upsert_purchase_invoice_payable(
            _execute_db,
            supplier_id=invoice.get("supplier_id"),
            payable_no=_next_doc_no("AP", "supplier_payables", "payable_no"),
            doc_id=invoice_id,
            doc_no=invoice.get("invoice_no"),
            doc_date=invoice.get("invoice_date"),
            amount=amount_with_tax,
            balance=amount_with_tax,
            status="未付款",
            paid_status="已付款",
            unpaid_status="未付款",
            finance_remark=remark,
            project_code=invoice.get("project_code"),
            serial_no=invoice.get("serial_no"),
        )

        # 获取应付单ID（假设 upsert 函数返回或可查询）
        payable = _safe_one(
            """
            SELECT id, doc_no
            FROM supplier_payables
            WHERE (source_type='purchase_invoice' AND source_id=%s)
               OR (doc_type='purchase_invoice' AND doc_id=%s)
            ORDER BY id DESC
            LIMIT 1
            """,
            (invoice_id, invoice_id),
        )
        payable_id = payable.get("id") if payable else None

        # 插入发票与应付单关联记录（如果应付单存在）
        if payable_id:
            _execute_db(
                """
                INSERT INTO purchase_invoice_payables (invoice_id, payable_id, allocated_amount)
                VALUES (%s, %s, %s)
                ON CONFLICT (invoice_id, payable_id) DO UPDATE
                SET allocated_amount = EXCLUDED.allocated_amount
                """,
                (invoice_id, payable_id, amount_with_tax),
            )

            # 更新应付单的 invoice_id 字段
            _execute_db(
                "UPDATE supplier_payables SET invoice_id=%s WHERE id=%s",
                (invoice_id, payable_id),
            )
            create_trace_link(
                _safe_one,
                _execute_db,
                execute_and_return=_execute_and_return,
                source_doc_type="purchase_invoice",
                source_doc_id=invoice_id,
                source_doc_no=invoice.get("invoice_no"),
                target_doc_type="supplier_payable",
                target_doc_id=payable_id,
                target_doc_no=payable.get("doc_no") or invoice.get("invoice_no"),
                link_type="source_of",
                link_strength="hard",
                project_code=invoice.get("project_code"),
                serial_no=invoice.get("serial_no"),
                created_by=current_user_id,
                created_event="confirm_purchase_invoice",
            )

        # 更新采购发票，记录关联的应付单ID、审核人和审核时间
        _execute_db(
            """
            UPDATE purchase_invoices
            SET status='已确认', payable_id=%s, approved_by=%s, approved_at=CURRENT_TIMESTAMP,
                invoice_status=CASE WHEN invoice_status='draft' THEN 'issued' ELSE invoice_status END
            WHERE id=%s
            """,
            (payable_id, current_user_id, invoice_id),
        )

    _log_action(f"确认{meta['title']}", invoice.get("invoice_no"), remark)
    flash(f"{meta['title']}已确认，并已自动生成{meta['link_label']}登记。", "success")
    return redirect(f"{meta['list_url']}/{invoice_id}")


def _finish_invoice(kind, invoice_id, status):
    meta = _invoice_meta(kind)
    invoice = _invoice_row(kind, invoice_id)
    if not invoice:
        flash("发票登记不存在。", "warning")
        return redirect(meta["list_url"])
    remark = _form_text("remark") or ("发票作废" if status == "已作废" else "发票红冲")
    _execute_db(f"UPDATE {meta['table']} SET status=%s, remark=COALESCE(NULLIF(%s, ''), remark) WHERE id=%s", (status, remark, invoice_id))
    if kind == "sales":
        _execute_db("UPDATE customer_receivables SET status=%s, balance=0, remark=COALESCE(remark,'') || %s WHERE source_type='sales_invoice' AND source_id=%s", (status, f"\n{remark}", invoice_id))
    else:
        finish_purchase_invoice_payable(_execute_db, doc_id=invoice_id, status=status, remark=f"\n{remark}")
    _log_action(f"{status}{meta['title']}", invoice.get("invoice_no"), remark)
    flash(f"{meta['title']}已{status.replace('已', '')}，相关{meta['link_label']}登记已标记结束。", "success")
    return redirect(f"{meta['list_url']}/{invoice_id}")


