def _wants_json_response():
    return bool(
        request.is_json
        or request.headers.get("X-Requested-With") == "XMLHttpRequest"
        or "application/json" in (request.headers.get("Accept") or "")
    )


def _document_action_response(ok, message, redirect_url, status_code=200, **extra):
    if _wants_json_response():
        payload = {"ok": ok, "status": "success" if ok else "error", "msg": message, "redirect_url": redirect_url}
        payload.update(extra)
        return jsonify(payload), status_code
    flash(message, "success" if ok else "warning")
    return redirect(redirect_url)


def _document_status_action(kind, order_id, status):
    if kind == "sales":
        table = "sales_orders"
        redirect_url = f"/sales/{order_id}"
        list_url = "/sales"
        label = "销售订单"
    else:
        table = "purchase_orders"
        redirect_url = f"/purchase_order/{order_id}"
        list_url = "/purchase_order"
        label = "采购订单"
    order = _safe_one(f"SELECT order_no, status FROM {table} WHERE id=%s", (order_id,))
    if not order:
        flash(f"{label}不存在。", "warning")
        return redirect(list_url)
    current_status = (order.get("status") or "").strip()
    if current_status == status:
        flash(f"{label}当前已经是{status}，无需重复操作。", "info")
        return redirect(redirect_url)
    status_allowed = {
        "已提交": {"", "待提交", "草稿", "draft", "pending"},
        "已审核": {"已提交", "submitted"},
    }.get(status)
    if status_allowed is not None and current_status not in status_allowed:
        flash(f"{label}当前状态为 {current_status or '-'}，不能执行该操作。", "warning")
        return redirect(redirect_url)
    item_table = "sales_order_items" if kind == "sales" else "purchase_order_items"
    partner_field = "customer_id" if kind == "sales" else "supplier_id"
    order_refs = _safe_one(f"SELECT {partner_field}, warehouse_id FROM {table} WHERE id=%s", (order_id,)) or {}
    item_refs = _safe_rows(f"SELECT product_id FROM {item_table} WHERE order_id=%s", (order_id,))
    reference_error = _block_document_reference_errors(
        kind,
        partner_id=order_refs.get(partner_field),
        warehouse_id=order_refs.get("warehouse_id"),
        items=item_refs,
        redirect_url=redirect_url,
    )
    if reference_error:
        return reference_error
    if kind == "purchase" and status == "已审核":
        order_check = _safe_one("SELECT supplier_id, created_by FROM purchase_orders WHERE id=%s", (order_id,))
        if not (order_check or {}).get("supplier_id"):
            flash("采购订单审核前必须指定供应商；草稿保存允许暂不填写供应商。", "warning")
            return redirect(redirect_url)
        if not _system_option_enabled("business_allow_self_audit", "1") and (order_check or {}).get("created_by") == session.get("user_id"):
            flash("不允许审核自己创建的采购订单。", "warning")
            return redirect(redirect_url)
    if kind == "sales" and status == "已审核" and os.environ.get("SALES_SELF_AUDIT_BLOCK", "0") == "1":
        order_check = _safe_one("SELECT created_by FROM sales_orders WHERE id=%s", (order_id,))
        if (order_check or {}).get("created_by") == session.get("user_id"):
            flash("不允许审核自己创建的销售订单。", "warning")
            return redirect(redirect_url)
    _execute_db(f"UPDATE {table} SET status=%s WHERE id=%s", (status, order_id))
    _log_action(f"{status}{label}", order.get("order_no") or str(order_id))
    action_label = status[1:] if status.startswith("已") else status
    flash(f"{label}已{action_label}。", "success")
    return redirect(redirect_url)


def _order_downstream_execution(kind, order_id):
    if kind == "sales":
        item_table = "sales_order_items"
        exec_field = "shipped_qty"
        downstream_table = "sales_shipments"
    else:
        item_table = "purchase_order_items"
        exec_field = "received_qty"
        downstream_table = "purchase_receipts"
    qty_row = _safe_one(
        f"SELECT COALESCE(SUM(COALESCE({exec_field},0)),0) AS qty FROM {item_table} WHERE order_id=%s",
        (order_id,),
    ) or {}
    doc_row = _safe_one(
        f"""
        SELECT COUNT(*) AS count
        FROM {downstream_table}
        WHERE order_id=%s
          AND COALESCE(status,'') NOT IN ('已作废','void','voided','cancelled','canceled')
        """,
        (order_id,),
    ) or {}
    return _as_decimal(qty_row.get("qty")), _as_int(doc_row.get("count"))


def _document_lifecycle_action(kind, order_id, action):
    if kind == "sales":
        table = "sales_orders"
        redirect_url = f"/sales/{order_id}"
        list_url = "/sales"
        label = "销售订单"
    else:
        table = "purchase_orders"
        redirect_url = f"/purchase_order/{order_id}"
        list_url = "/purchase_order"
        label = "采购订单"
    done_status = {"unaudit": "已提交", "close": "已关闭", "void": "已作废", "reopen": None}.get(action)
    if action not in {"unaudit", "close", "void", "reopen"}:
        return _document_action_response(False, "不支持的单据操作。", list_url, 400)
    order = _safe_one(f"SELECT order_no, status FROM {table} WHERE id=%s", (order_id,))
    if not order:
        return _document_action_response(False, f"{label}不存在。", list_url, 404)
    current_status = (order.get("status") or "").strip()
    terminal_statuses = {"已关闭", "已作废", "void", "voided", "closed", "cancelled", "canceled"}
    void_statuses = {"已作废", "void", "voided", "cancelled", "canceled"}
    executed_qty, downstream_count = _order_downstream_execution(kind, order_id)
    if action == "reopen":
        if current_status not in {"已关闭", "closed"}:
            return _document_action_response(False, f"{label}只有已关闭状态才能重新打开。", redirect_url, 400)
        if kind == "purchase":
            qty_row = _safe_one(
                """
                SELECT COALESCE(SUM(COALESCE(quantity,0)),0) AS qty,
                       COALESCE(SUM(COALESCE(received_qty,0)),0) AS received_qty,
                       COALESCE(SUM(GREATEST(COALESCE(quantity,0)-COALESCE(received_qty,0),0)),0) AS pending_qty
                FROM purchase_order_items
                WHERE order_id=%s
                """,
                (order_id,),
            ) or {}
            pending_qty = _as_decimal(qty_row.get("pending_qty"))
            received_qty = _as_decimal(qty_row.get("received_qty"))
            done_status = "已收货" if pending_qty <= 0 else ("部分收货" if received_qty > 0 else "待收货")
        else:
            done_status = "已审核"
    elif current_status in terminal_statuses:
        return _document_action_response(False, f"{label}已经关闭或作废，不能继续执行该操作。", redirect_url, 400)
    if action == "unaudit" and current_status != "已审核":
        return _document_action_response(False, f"{label}当前状态不允许反审。", redirect_url, 400)
    if action in {"unaudit", "void"} and (executed_qty > 0 or downstream_count > 0):
        return _document_action_response(False, f"{label}已有下游收发货或库存影响，不能反审或作废。", redirect_url, 400)
    if action == "close" and current_status not in {"已审核", "已审批", "待收货", "部分发货", "已发货", "部分收货", "已收货", "approved", "partial"}:
        return _document_action_response(False, f"{label}当前状态不允许关闭。", redirect_url, 400)
    if action == "void" and current_status in {"部分发货", "已发货", "部分收货", "已收货", "已关闭"}:
        return _document_action_response(False, f"{label}已有出入库或已关闭的单据不能作废。", redirect_url, 400)
    if kind == "purchase" and action == "void":
        payable = _safe_one(
            """
            SELECT COALESCE(SUM(COALESCE(paid_amount,0)),0) AS paid_amount,
                   COALESCE(SUM(COALESCE(balance,0)),0) AS balance
            FROM supplier_payables
            WHERE doc_type='purchase_order' AND doc_id=%s
            """,
            (order_id,),
        ) or {}
        if _as_decimal(payable.get("paid_amount")) > 0:
            return _document_action_response(False, "采购订单已有付款记录，不能直接作废，请先做付款冲销/反核销。", redirect_url, 400)
    _execute_db(f"UPDATE {table} SET status=%s WHERE id=%s", (done_status, order_id))
    if kind == "purchase" and action == "void":
        void_purchase_order_payable(
            _execute_db,
            doc_id=order_id,
            status="已作废",
            remark=f"\n采购订单 {order.get('order_no') or order_id} 已作废，应付同步清零。",
        )
    action_text = {"unaudit": "反审", "close": "关闭", "void": "作废", "reopen": "重新打开"}[action]
    _log_action(f"{action_text}{label}", order.get("order_no") or str(order_id), f"{current_status}->{done_status}")
    return _document_action_response(True, f"{label}已{action_text}。", redirect_url, status=done_status)

def _copy_document(kind, order_id):
    if kind == "sales":
        order = _safe_one("SELECT * FROM sales_orders WHERE id=%s", (order_id,))
        if not order:
            flash("销售订单不存在。", "warning")
            return redirect("/sales")
        new_no = _next_doc_no("SO", "sales_orders", "order_no")
        new_order = _execute_and_return(
            """
            INSERT INTO sales_orders
                (order_no, order_date, customer_id, status, remark, total_amount, shipped_amount,
                 warehouse_id, delivery_date, tax_amount, amount_with_tax, project_code, serial_no, created_by)
            VALUES (%s,%s,%s,%s,%s,%s,0,%s,%s,%s,%s,%s,%s,%s)
            RETURNING id
            """,
            (
                new_no,
                datetime.now().date().isoformat(),
                order.get("customer_id"),
                "待提交",
                f"复制自 {order.get('order_no')} {order.get('remark') or ''}".strip(),
                order.get("total_amount"),
                order.get("warehouse_id"),
                order.get("delivery_date"),
                order.get("tax_amount"),
                order.get("amount_with_tax"),
                order.get("project_code"),
                order.get("serial_no"),
                session.get("user_id"),
            ),
        )
        new_id = new_order["id"]
        items = _safe_rows("SELECT * FROM sales_order_items WHERE order_id=%s ORDER BY id", (order_id,))
        for item in items:
            _execute_db(
                """
                INSERT INTO sales_order_items
                    (order_id, product_id, quantity, shipped_qty, unit_price, amount, lot_no, tax_rate, tax_amount, amount_with_tax)
                VALUES (%s,%s,%s,0,%s,%s,%s,%s,%s,%s)
                """,
                (
                    new_id,
                    item.get("product_id"),
                    item.get("quantity"),
                    item.get("unit_price"),
                    item.get("amount"),
                    item.get("lot_no"),
                    item.get("tax_rate"),
                    item.get("tax_amount"),
                    item.get("amount_with_tax"),
                ),
            )
        receivable_no = _next_doc_no("AR", "customer_receivables", "receivable_no")
        _execute_db(
            """
            INSERT INTO customer_receivables
                (receivable_no, customer_id, source_type, source_id, source_no, receivable_date, total_amount,
                 received_amount, balance, status, due_date, remark, project_code, serial_no)
            VALUES (%s,%s,'sales_order',%s,%s,%s,%s,0,%s,%s,%s,%s,%s,%s)
            """,
            (
                receivable_no,
                order.get("customer_id"),
                new_id,
                new_no,
                datetime.now().date().isoformat(),
                order.get("amount_with_tax"),
                order.get("amount_with_tax"),
                "未收款",
                order.get("delivery_date"),
                f"复制销售订单 {order.get('order_no')}",
                order.get("project_code"),
                order.get("serial_no"),
            ),
        )
        _log_action("复制销售订单", f"{order.get('order_no')} -> {new_no}")
        return _document_action_response(True, f"已复制销售订单 {new_no}。", f"/sales/{new_id}", id=new_id, order_no=new_no)
    order = _safe_one("SELECT * FROM purchase_orders WHERE id=%s", (order_id,))
    if not order:
        return _document_action_response(False, "采购订单不存在。", "/purchase_order", 404)
    new_no = _next_doc_no("PO", "purchase_orders", "order_no")
    new_order = _execute_and_return(
        """
        INSERT INTO purchase_orders
            (order_no, order_date, supplier_id, status, remark, total_amount, received_amount,
             warehouse_id, expected_date, tax_amount, amount_with_tax, project_code, serial_no, created_by)
        VALUES (%s,%s,%s,%s,%s,%s,0,%s,%s,%s,%s,%s,%s,%s)
        RETURNING id
        """,
        (
            new_no,
            datetime.now().date().isoformat(),
            order.get("supplier_id"),
            "待提交",
            f"复制自 {order.get('order_no')} {order.get('remark') or ''}".strip(),
            order.get("total_amount"),
            order.get("warehouse_id"),
            order.get("expected_date"),
            order.get("tax_amount"),
            order.get("amount_with_tax"),
            order.get("project_code"),
            order.get("serial_no"),
            session.get("user_id"),
        ),
    )
    new_id = new_order["id"]
    items = _safe_rows("SELECT * FROM purchase_order_items WHERE order_id=%s ORDER BY id", (order_id,))
    for item in items:
        _execute_db(
            """
            INSERT INTO purchase_order_items
                (order_id, product_id, quantity, received_qty, unit_price, amount, lot_no,
                 tax_rate, tax_amount, amount_with_tax, expected_date)
            VALUES (%s,%s,%s,0,%s,%s,%s,%s,%s,%s,%s)
            """,
            (
                new_id,
                item.get("product_id"),
                item.get("quantity"),
                item.get("unit_price"),
                item.get("amount"),
                item.get("lot_no"),
                item.get("tax_rate"),
                item.get("tax_amount"),
                item.get("amount_with_tax"),
                item.get("expected_date"),
            ),
        )
    insert_purchase_order_payable(
        _execute_db,
        supplier_id=order.get("supplier_id"),
        payable_no=_next_doc_no("AP", "supplier_payables", "payable_no"),
        doc_id=new_id,
        doc_no=new_no,
        doc_date=datetime.now().date().isoformat(),
        amount=order.get("amount_with_tax"),
        balance=order.get("amount_with_tax"),
        status="未付款",
        finance_remark=f"复制采购订单 {order.get('order_no')}",
        next_follow_up_date=order.get("expected_date"),
    )
    _log_action("复制采购订单", f"{order.get('order_no')} -> {new_no}")
    return _document_action_response(True, f"已复制采购订单 {new_no}。", f"/purchase_order/{new_id}", id=new_id, order_no=new_no)

