def _supplier_quote_status_key(status):
    value = str(status or "").strip().lower()
    if value in {"草稿", "draft", "pending", ""}:
        return "draft"
    if value in {"已提交", "submitted"}:
        return "submitted"
    if value in {"已审核", "已确认", "audited", "confirmed", "approved"}:
        return "audited"
    if value in {"已关闭", "closed"}:
        return "closed"
    if value in {"已作废", "void", "voided", "cancelled", "canceled"}:
        return "void"
    return value


def _supplier_quote_status_label(status):
    labels = {
        "draft": "草稿",
        "submitted": "已提交",
        "audited": "已审核",
        "closed": "已关闭",
        "void": "已作废",
    }
    return labels.get(_supplier_quote_status_key(status), status or "草稿")


