def _supplier_quote_status_action(quote_id, action):
    _ensure_supplier_quote_tables()
    transitions = {
        "submit": ("已提交", {"draft"}, "提交"),
        "audit": ("已审核", {"submitted"}, "审核"),
        "confirm": ("已审核", {"submitted"}, "确认"),
        "close": ("已关闭", {"audited"}, "关闭"),
        "void": ("已作废", {"draft", "submitted"}, "作废"),
    }
    config = transitions.get(action)
    if not config:
        flash("不支持的供应商报价操作。", "warning")
        return redirect(f"/supplier-quotes/{quote_id}")
    quote = _safe_one("SELECT id, quote_no, supplier_id, status FROM supplier_quotes WHERE id=%s", (quote_id,))
    if not quote:
        flash("供应商报价不存在。", "warning")
        return redirect("/supplier-quotes")
    next_status, allowed, action_label = config
    current_key = _supplier_quote_status_key(quote.get("status"))
    if current_key not in allowed:
        flash(f"供应商报价当前状态不允许{action_label}。", "warning")
        return redirect(f"/supplier-quotes/{quote_id}")
    if action in {"audit", "confirm"} and not quote.get("supplier_id"):
        flash("审核/确认供应商报价前必须指定供应商。", "warning")
        return redirect(f"/supplier-quotes/{quote_id}")
    user_id = session.get("user_id")
    if action == "submit":
        _execute_db("UPDATE supplier_quotes SET status=%s, submitted_by=%s, submitted_at=NOW(), updated_at=NOW() WHERE id=%s", (next_status, user_id, quote_id))
    elif action in {"audit", "confirm"}:
        _execute_db("UPDATE supplier_quotes SET status=%s, audited_by=%s, audited_at=NOW(), updated_at=NOW() WHERE id=%s", (next_status, user_id, quote_id))
    elif action == "close":
        _execute_db("UPDATE supplier_quotes SET status=%s, closed_by=%s, closed_at=NOW(), updated_at=NOW() WHERE id=%s", (next_status, user_id, quote_id))
    else:
        _execute_db("UPDATE supplier_quotes SET status=%s, voided_by=%s, voided_at=NOW(), updated_at=NOW() WHERE id=%s", (next_status, user_id, quote_id))
    _log_action(f"{action_label}供应商报价", quote.get("quote_no") or str(quote_id), f"{quote.get('status')}->{next_status}")
    flash(f"供应商报价已{action_label}。", "success")
    return redirect(f"/supplier-quotes/{quote_id}")


def _copy_supplier_quote_document(quote_id):
    _ensure_supplier_quote_tables()
    quote = _safe_one("SELECT * FROM supplier_quotes WHERE id=%s", (quote_id,))
    if not quote:
        flash("供应商报价不存在，不能复制。", "warning")
        return redirect("/supplier-quotes")
    lines = _safe_rows("SELECT * FROM supplier_quote_items WHERE quote_id=%s ORDER BY id", (quote_id,))
    if not lines:
        flash("原供应商报价没有明细，不能复制。", "warning")
        return redirect(f"/supplier-quotes/{quote_id}")
    new_no = _next_doc_no("SQ", "supplier_quotes", "quote_no")

    def operation(cursor):
        _query_one, _query_rows, execute_db, execute_return = _registry_transaction_callables(cursor)
        new_quote = _insert_copied_row(
            "supplier_quotes",
            quote,
            overrides={
                "quote_no": new_no,
                "quote_date": datetime.now().date().isoformat(),
                "status": "草稿",
                "created_at": _COPY_NOW,
                "updated_at": _COPY_NOW,
                "created_by": session.get("user_id") or quote.get("created_by"),
            },
            exclude=_document_copy_excluded_fields(),
            execute_return_fn=execute_return,
        )
        new_id = new_quote.get("id")
        for line in lines:
            _insert_copied_row(
                "supplier_quote_items",
                line,
                overrides={"quote_id": new_id},
                exclude={"id", "quote_id"},
                returning=None,
                execute_fn=execute_db,
            )
        return new_id

    new_id = _run_registry_transaction(operation)
    _log_action("复制供应商报价", f"{quote.get('quote_no')} -> {new_no}")
    flash(f"已复制为新草稿单据 {new_no}，请检查后提交。", "success")
    return redirect(f"/supplier-quotes/{new_id}")


