def _issue_work_order_materials(work_order_id, _tx=False):
    if not _tx:
        _require_work_order_scope(work_order_id, action="operate")
        return _run_registry_transaction(lambda cursor: _issue_work_order_materials(work_order_id, _tx=True))
    order = _safe_one(
        """
        SELECT wo.*, p.code AS product_code, p.name AS product_name
        FROM work_orders wo
        LEFT JOIN products p ON p.id=wo.product_id
        WHERE wo.id=%s
        """,
        (work_order_id,),
    )
    if not order:
        flash("工单不存在。", "warning")
        return redirect("/work-orders")
    rows = _safe_rows(
        """
        SELECT mi.*, p.code AS product_code, p.name AS product_name
        FROM wo_material_items mi
        LEFT JOIN products p ON p.id=mi.product_id
        WHERE mi.wo_id=%s
        ORDER BY mi.id
        """,
        (work_order_id,),
    )
    issue_date = _form_text("issue_date", datetime.now().date().isoformat())
    warehouse_id = _form_int("warehouse_id") or order.get("warehouse_id")
    remark = _form_text("remark", f"工单领料 {order.get('wo_no')}")
    requested_item_id = _form_int("material_item_id")
    requested_qty = _form_decimal("issue_quantity")
    posted = Decimal("0")
    for row in rows:
        pending_qty, issue_error = issue_quantity_for_row(row, requested_item_id, requested_qty)
        if issue_error == "quantity_required":
            flash("领料数量必须大于 0。", "warning")
            return redirect(f"/work-orders/{work_order_id}")
        if issue_error == "quantity_over_pending":
            flash("领料数量不能大于待领数量。", "warning")
            return redirect(f"/work-orders/{work_order_id}")
        if pending_qty is None:
            continue
        stock_error, available_qty = validate_issue_stock(row, pending_qty, warehouse_id, _safe_one)
        if stock_error == "stock_shortage":
            flash(f"库存不足：{row.get('product_code') or row.get('product_id')}，可用 {available_qty}，需要 {pending_qty}。", "warning")
            return redirect(f"/work-orders/{work_order_id}")
        unit_cost = resolve_unit_cost(row.get("unit_cost"), row.get("product_id"), warehouse_id, _safe_one)
        _apply_inventory_movement(
            product_id=row.get("product_id"),
            quantity=-pending_qty,
            unit_cost=unit_cost,
            tx_type="工单领料",
            reference_no=order.get("wo_no"),
            remark=remark,
            warehouse_id=warehouse_id,
            location_id=row.get("location_id") or order.get("location_id"),
            lot_no=_form_text("lot_no"),
            serial_no=order.get("serial_no"),
            tx_date=issue_date,
            project_code=row.get("line_project_code") or order.get("project_code") or "",
        )
        _execute_db(
            "UPDATE wo_material_items SET issued_qty=COALESCE(issued_qty,0)+%s, unit_cost=COALESCE(NULLIF(unit_cost,0),%s) WHERE id=%s",
            (pending_qty, unit_cost, row.get("id")),
        )
        posted += pending_qty
    if posted <= 0:
        flash("没有可领用的物料。", "warning")
    else:
        _execute_db(
            "UPDATE work_orders SET status=CASE WHEN COALESCE(status,'') IN ('待提交','已提交','') THEN '生产中' ELSE status END, actual_start_date=COALESCE(actual_start_date,%s) WHERE id=%s",
            (issue_date, work_order_id),
        )
        _set_work_order_stage(work_order_id, "投产", "工单领料后投产")
        _set_work_order_stage(work_order_id, "加工", "材料已领用，进入加工")
        _sync_work_order_cost_quiet(work_order_id, source_type="工单领料", source_no=order.get("wo_no"), remark="工单直接领料后同步成本")
        _log_action("工单领料", order.get("wo_no"), f"issued_qty={posted}")
        flash(f"工单 {order.get('wo_no')} 已领料 {posted}。", "success")
    return redirect(f"/work-orders/{work_order_id}")


def _return_work_order_materials(work_order_id, _tx=False):
    if not _tx:
        _require_work_order_scope(work_order_id, action="operate")
        return _run_registry_transaction(lambda cursor: _return_work_order_materials(work_order_id, _tx=True))
    order = _safe_one(
        """
        SELECT wo.*, p.code AS product_code, p.name AS product_name
        FROM work_orders wo
        LEFT JOIN products p ON p.id=wo.product_id
        WHERE wo.id=%s
        """,
        (work_order_id,),
    )
    if not order:
        flash("工单不存在。", "warning")
        return redirect("/work-orders")
    if (order.get("status") or "") in {"已关闭", "已完工", "已作废"}:
        flash("工单已关闭、已完工或已作废，不能执行该操作。", "warning")
        return redirect(f"/work-orders/{work_order_id}")

    return_qty = _form_decimal("quantity")
    item_id = _form_int("material_item_id")
    if return_qty <= 0:
        flash("数量必须大于 0。", "warning")
        return redirect(f"/work-orders/{work_order_id}")
    item = _safe_one(
        """
        SELECT mi.*, p.code AS product_code, p.name AS product_name
        FROM wo_material_items mi
        LEFT JOIN products p ON p.id=mi.product_id
        WHERE mi.id=%s AND mi.wo_id=%s
        """,
        (item_id, work_order_id),
    )
    if not item:
        flash("工单物料明细不存在。", "warning")
        return redirect(f"/work-orders/{work_order_id}")
    return_qty, return_error = validate_return_quantity(item, return_qty)
    if return_error == "quantity_required":
        flash("数量必须大于 0。", "warning")
        return redirect(f"/work-orders/{work_order_id}")
    if return_error == "quantity_over_returnable":
        flash("退料数量不能大于可退数量。", "warning")
        return redirect(f"/work-orders/{work_order_id}")

    return_date = _form_text("return_date", datetime.now().date().isoformat())
    warehouse_id = _form_int("warehouse_id") or order.get("warehouse_id")
    unit_cost = resolve_unit_cost(item.get("unit_cost"), item.get("product_id"), warehouse_id, _safe_one)
    remark = _form_text("remark", f"工单退料 {order.get('wo_no')}")
    _apply_inventory_movement(
        product_id=item.get("product_id"),
        quantity=return_qty,
        unit_cost=unit_cost,
        tx_type="工单退料",
        reference_no=order.get("wo_no"),
        remark=remark,
        warehouse_id=warehouse_id,
        lot_no=_form_text("lot_no"),
        serial_no=order.get("serial_no"),
        tx_date=return_date,
    )
    _execute_db(
        "UPDATE wo_material_items SET returned_qty=COALESCE(returned_qty,0)+%s WHERE id=%s",
        (return_qty, item_id),
    )
    _sync_work_order_cost_quiet(work_order_id, source_type="工单退料", source_no=order.get("wo_no"), remark="工单直接退料后同步成本")
    _log_action("工单退料", order.get("wo_no"), f"{item.get('product_code') or item.get('product_id')} qty={return_qty}")
    flash(f"工单 {order.get('wo_no')} 已退料 {return_qty}。", "success")
    return redirect(f"/work-orders/{work_order_id}")

def _generate_work_order_material_requirements_from_bom(work_order_id, _tx=False):
    if not _tx:
        _require_work_order_scope(work_order_id, action="operate")
        return _run_registry_transaction(lambda cursor: _generate_work_order_material_requirements_from_bom(work_order_id, _tx=True))
    order = _safe_one("SELECT * FROM work_orders WHERE id=%s", (work_order_id,))
    if not order:
        flash("工单不存在。", "warning")
        return redirect("/work-orders")
    if (order.get("status") or "") in {"已关闭", "已完工", "已作废"}:
        flash("工单已关闭、已完工或已作废，不能生成BOM领料需求。", "warning")
        return redirect(f"/work-orders/{work_order_id}")
    if not order.get("bom_id"):
        flash("工单未选择BOM，未生成领料需求。", "warning")
        return redirect(f"/work-orders/{work_order_id}")

    snapshot = latest_work_order_execution_snapshot(_safe_one, work_order_id)
    bom_rows = bom_requirement_rows_from_snapshot(snapshot)
    if not bom_rows:
        try:
            create_work_order_execution_snapshot(
                _safe_one,
                _safe_rows,
                _execute_db,
                _execute_and_return,
                work_order_id,
                snapshot_by=session.get("user_id"),
            )
            snapshot = latest_work_order_execution_snapshot(_safe_one, work_order_id)
            bom_rows = bom_requirement_rows_from_snapshot(snapshot)
        except Exception:
            current_app.logger.exception("Failed to create work order execution snapshot before BOM requirement generation for %s", work_order_id)
    if not bom_rows:
        bom_rows = _safe_rows(
            """
            SELECT bi.id AS bom_item_id, bi.product_id,
                   COALESCE(bi.quantity, 0) AS base_qty,
                   COALESCE(bi.loss_rate, 0) AS loss_rate,
                   COALESCE(bi.unit, p.unit, '') AS material_unit,
                   bi.remark,
                   p.code AS material_code, p.name AS material_name, p.specification AS material_spec,
                   p.standard_price
            FROM bom_items bi
            LEFT JOIN products p ON p.id=bi.product_id
            WHERE bi.bom_id=%s
            ORDER BY bi.id
            """,
            (order.get("bom_id"),),
        )
    existing_rows = _safe_rows(
        """
        SELECT source_line_no
        FROM wo_material_items
        WHERE wo_id=%s
          AND source_line_no LIKE 'BOM-%%'
        """,
        (work_order_id,),
    )
    existing_source_lines = {row.get("source_line_no") for row in existing_rows if row.get("source_line_no")}
    generation_summary = summarize_bom_requirement_generation(order, bom_rows, existing_source_lines)
    if not generation_summary["can_generate"]:
        flash(generation_summary["reason"], "warning")
        return redirect(f"/work-orders/{work_order_id}")

    created = 0
    for row in bom_rows:
        if f"BOM-{row.get('bom_item_id')}" in existing_source_lines:
            continue
        line = build_bom_requirement_line(row, order, _safe_one)
        if not line:
            continue
        _execute_db(
            """
            INSERT INTO wo_material_items
                (wo_id, product_id, required_qty, issued_qty, returned_qty, unit_cost, amount, remark,
                 warehouse_id, location_id, source_line_no, line_project_code, line_serial_no,
                 material_code, material_name, material_spec, material_unit)
            VALUES
                (%s, %s, %s, 0, 0, %s, %s, %s,
                 %s, %s, %s, %s, %s,
                 %s, %s, %s, %s)
            """,
            (
                work_order_id,
                line["product_id"],
                line["required_qty"],
                line["unit_cost"],
                line["amount"],
                line["remark"],
                line["warehouse_id"],
                line["location_id"],
                line["source_line_no"],
                line["line_project_code"],
                line["line_serial_no"],
                line["material_code"],
                line["material_name"],
                line["material_spec"],
                line["material_unit"],
            ),
        )
        created += 1
    if not created:
        flash(generation_summary["reason"], "warning")
    else:
        skipped = generation_summary["skipped_count"]
        invalid = generation_summary["invalid_count"]
        _log_action("工单按BOM生成领料需求", order.get("wo_no"), f"bom_id={order.get('bom_id')} lines={created} skipped={skipped} invalid={invalid}")
        suffix_parts = []
        if skipped:
            suffix_parts.append(f"已跳过已有来源行 {skipped} 行")
        if invalid:
            suffix_parts.append(f"已忽略无效BOM行 {invalid} 行")
        suffix = f"（{'; '.join(suffix_parts)}）" if suffix_parts else ""
        flash(f"工单 {order.get('wo_no')} 已按BOM生成 {created} 行领料需求，未扣减库存。{suffix}", "success")
    return redirect(f"/work-orders/{work_order_id}")


def _add_work_order_material_requirement(work_order_id, _tx=False):
    if not _tx:
        _require_work_order_scope(work_order_id, action="operate")
