def _complete_work_order(work_order_id, _tx=False):
    if not _tx:
        _require_work_order_scope(work_order_id, action="operate")
        return _run_registry_transaction(lambda cursor: _complete_work_order(work_order_id, _tx=True))
    order = _safe_one(
        """
        SELECT wo.*, p.standard_price, p.unit AS product_unit
        FROM work_orders wo
        LEFT JOIN products p ON p.id=wo.product_id
        WHERE wo.id=%s
        """,
        (work_order_id,),
    )
    if not order:
        flash("工单不存在。", "warning")
        return redirect("/work-orders")
    completed = _safe_one("SELECT COALESCE(SUM(qty),0) AS qty FROM wo_complete_items WHERE wo_id=%s", (work_order_id,)) or {}
    default_qty = _as_decimal(order.get("quantity")) - _as_decimal(completed.get("qty"))
    qty = _form_decimal("quantity", str(default_qty if default_qty > 0 else 0))
    if qty <= 0:
        flash("完工数量必须大于 0。", "warning")
        return redirect(f"/work-orders/{work_order_id}")
    complete_date = _form_text("complete_date", datetime.now().date().isoformat())
    warehouse_id = _form_int("warehouse_id") or order.get("warehouse_id")
    unit_cost = _form_decimal("unit_cost")
    if unit_cost == 0:
        cost = _safe_one("SELECT total_cost FROM work_order_costs WHERE work_order_id=%s ORDER BY id DESC LIMIT 1", (work_order_id,)) or {}
        if _as_decimal(order.get("quantity")) > 0:
            unit_cost = _as_decimal(cost.get("total_cost")) / _as_decimal(order.get("quantity"))
        if unit_cost == 0:
            unit_cost = _as_decimal(order.get("standard_price"))
    _execute_db(
        """
        INSERT INTO wo_complete_items
            (wo_id, complete_date, qty, lot_no, unit_cost, product_id, serial_no, warehouse_id, location_id)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)
        """,
        (
            work_order_id,
            complete_date,
            qty,
            _form_text("lot_no"),
            unit_cost,
            order.get("product_id"),
            _form_text("serial_no") or order.get("serial_no"),
            warehouse_id,
            _form_int("location_id"),
        ),
    )
    _apply_inventory_movement(
        product_id=order.get("product_id"),
        quantity=qty,
        unit_cost=unit_cost,
        tx_type="工单完工入库",
        reference_no=order.get("wo_no"),
        remark=_form_text("remark", "工单完工入库"),
        warehouse_id=warehouse_id,
        location_id=_form_int("location_id"),
        lot_no=_form_text("lot_no"),
        serial_no=_form_text("serial_no") or order.get("serial_no"),
        tx_date=complete_date,
    )
    new_completed = _as_decimal(completed.get("qty")) + qty
    target_qty = _as_decimal(order.get("quantity"))
    status = "已完工" if target_qty > 0 and new_completed >= target_qty else "部分完工"
    _execute_db(
        "UPDATE work_orders SET status=%s, actual_end_date=CASE WHEN %s='已完工' THEN %s ELSE actual_end_date END WHERE id=%s",
        (status, status, complete_date, work_order_id),
    )
    _set_work_order_stage(work_order_id, "装配", "完工入库前确认装配完成")
    _set_work_order_stage(work_order_id, "调试", "完工入库前确认调试完成")
    if status == "已完工":
        _set_work_order_stage(work_order_id, "入库", "完工入库")
    _sync_work_order_cost_quiet(work_order_id, source_type="工单完工入库", source_no=order.get("wo_no"), remark="工单直接完工后同步成本")
    # P0 集成：工单完工入库后自动归集成本
    try:
        _p0_run_cost_calculation(
            _safe_one,
            _safe_rows,
            _execute_db,
            _execute_and_return,
            project_code=order.get("project_code"),
            serial_no=order.get("serial_no"),
            work_order_id=work_order_id,
            created_by=session.get("user_id"),
        )
    except Exception:
        current_app.logger.warning("Failed to create work order completion trace link", exc_info=True)
    _log_action("工单完工入库", order.get("wo_no"), f"complete_qty={qty}")
    flash(f"工单 {order.get('wo_no')} 已完工入库 {qty}。", "success")
    return redirect(f"/work-orders/{work_order_id}")


def _record_work_order_quality(work_order_id):
    _require_work_order_scope(work_order_id, action="operate")
    order = _safe_one(
        """
        SELECT id, wo_no, product_id, quantity, status, cost_object_id, project_code, serial_no
        FROM work_orders
        WHERE id=%s
        """,
        (work_order_id,),
    )
    if not order:
        flash("工单不存在。", "warning")
        return redirect("/work-orders")
    if (order.get("status") or "") in {"已关闭", "已作废"}:
        flash("工单已关闭或已作废，不能登记质检。", "warning")
        return redirect(f"/work-orders/{work_order_id}")

    inspection_no = _next_daily_doc_no("QI", "quality_inspection_records", "inspection_no")
    sample_size = int(_form_decimal("sample_size", str(order.get("quantity") or 1)) or 0)
    passed_qty = int(_form_decimal("passed_quantity", str(sample_size)) or 0)
    failed_qty = int(_form_decimal("failed_quantity", "0") or 0)
    if sample_size <= 0:
        flash("抽样数量必须大于 0。", "warning")
        return redirect(f"/work-orders/{work_order_id}")
    if passed_qty + failed_qty > sample_size:
        flash("合格数量和不合格数量之和不能大于抽样数量。", "warning")
        return redirect(f"/work-orders/{work_order_id}")
    result = _form_text("inspection_result") or ("fail" if failed_qty else "pass")
    if result in {"合格", "pass", "passed"}:
        result = "pass"
    elif result in {"不合格", "fail", "failed", "ng"}:
        result = "fail"
    elif result in {"让步接收", "conditional_pass"}:
        result = "conditional_pass"
    inspection_type = _form_text("inspection_type", "final")
    if inspection_type in {"终检", "final"}:
        inspection_type = "final"
    elif inspection_type in {"过程检", "in_process"}:
        inspection_type = "in_process"
    _execute_db(
        """
        INSERT INTO quality_inspection_records
            (inspection_no, product_id, inspection_type, inspection_date, sample_size,
             passed_quantity, failed_quantity, inspection_result, defect_description,
             corrective_action, status, cost_object_id, project_code, serial_no,
             source_document_type, source_document_id)
        VALUES
            (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, 'work_order', %s)
        """,
        (
            inspection_no,
            order.get("product_id"),
            inspection_type,
            _form_text("inspection_date", datetime.now().date().isoformat()),
            sample_size,
            passed_qty,
            failed_qty,
            result,
            _form_text("defect_description"),
            _form_text("corrective_action"),
            "completed",
            order.get("cost_object_id"),
            order.get("project_code"),
            order.get("serial_no"),
            work_order_id,
        ),
    )
    _log_action("工单质检", inspection_no, f"工单 {order.get('wo_no')}, result={result}")
    flash(f"已登记质检单 {inspection_no}。", "success")
    return redirect(f"/work-orders/{work_order_id}")


