def _service_order_or_redirect(order_id):
    service = _safe_one("SELECT * FROM machine_service_orders WHERE id=%s", (order_id,))
    if not service:
        flash("服务单不存在。", "warning")
        return None
    if str(service.get("status") or "") in {"已关闭", "已完成", "已作废", "closed", "completed", "cancelled"}:
        flash("服务单已关闭、已完成或已作废，不能继续处理。", "warning")
        return None
    if _project_serial_required() and (not (service.get("project_code") or "").strip() or not (service.get("serial_no") or "").strip()):
        flash("系统已启用强制项目号/机号，服务单必须关联项目号和机号后才能继续流转。", "warning")
        return None
    return service


def _service_order_close_blocker(service):
    order_id = service.get("id")
    open_rma = _safe_one(
        """
        SELECT id, rma_no
        FROM machine_service_rmas
        WHERE order_id=%s
          AND COALESCE(status,'') NOT IN ('已关闭','已完成','closed','completed','cancelled')
        ORDER BY id DESC
        LIMIT 1
        """,
        (order_id,),
    )
    if open_rma:
        return f"存在未关闭RMA {open_rma.get('rma_no') or open_rma.get('id')}，请先完成RMA诊断、索赔或关闭。"
    visit = _safe_one("SELECT id FROM machine_service_return_visits WHERE order_id=%s LIMIT 1", (order_id,))
    if not visit:
        return "服务单缺少客户回访记录，请先登记回访后再关闭。"
    if _as_decimal(service.get("billable_amount")) > 0 and str(service.get("settlement_status") or "") not in {
        "已结算",
        "已生成应收",
        "已收款",
        "closed",
        "completed",
    }:
        return "服务单存在未结算可收费金额，请先登记结算状态或生成应收。"
    return ""


def _rma_close_blocker(rma, close_reason):
    claim_amount = _as_decimal(rma.get("supplier_claim_amount"))
    recovered_amount = _as_decimal(rma.get("supplier_recovered_amount"))
    if claim_amount > recovered_amount and not close_reason:
        return "供应商索赔未追回，必须填写关闭原因后才能关闭RMA。"
    return ""


def _service_part_issue_stock_error(product_id, quantity, warehouse_id, location_id, lot_no, service):
    if not product_id or quantity <= 0:
        return ""
    actual_warehouse_id = warehouse_id or _ensure_default_warehouse_id()
    product_error = _inactive_master_error("products", product_id, "物料")
    if product_error:
        return product_error
    warehouse_error = _inactive_master_error("warehouses", actual_warehouse_id, "仓库")
    if warehouse_error:
        return warehouse_error
    if location_id:
        location_error = _inactive_master_error("locations", location_id, "库位")
        if location_error:
            return location_error
    available_qty = _inventory_available_qty(
        product_id,
        actual_warehouse_id,
        location_id,
        lot_no,
        service.get("serial_no") or "",
        service.get("project_code") or "",
    )
    if available_qty < quantity:
        return f"库存不足：物料 {product_id} 可用 {available_qty}，需要 {quantity}。"
    return ""


def _dispatch_service_order(order_id):
    service = _service_order_or_redirect(order_id)
    if not service:
        return redirect(f"/service-orders/{order_id}")
    dispatch_no = _next_daily_doc_no("SD", "machine_service_dispatches", "dispatch_no")
    dispatch_date = _form_text("dispatch_date", datetime.now().date().isoformat())
    planned_service_date = _form_text("planned_service_date", dispatch_date)
    assigned_employee_id = _form_int("assigned_employee_id")
    task_summary = _form_text("task_summary") or service.get("issue_summary") or "售后服务派工"
    remark = _form_text("remark")
    _execute_db(
        """
        INSERT INTO machine_service_dispatches (
            dispatch_no, project_id, order_id, wo_id, service_card_id, dispatch_date,
            planned_service_date, assigned_employee_id, support_employee_id, status,
            work_hours, travel_hours, labor_amount, travel_amount, task_summary, remark
        )
        VALUES (%s, NULL, %s, %s, %s, %s, %s, %s, NULL, %s, 0, 0, 0, 0, %s, %s)
        """,
        (
            dispatch_no,
            order_id,
            service.get("wo_id") or 0,
            service.get("service_card_id"),
            dispatch_date,
            planned_service_date,
            assigned_employee_id,
            "已派工",
            task_summary,
            remark,
        ),
    )
    _execute_db("UPDATE machine_service_orders SET status=%s WHERE id=%s", ("已派工", order_id))
    _sync_service_order_flow(order_id, "已派工")
    _log_action("服务派工", service.get("order_no") or str(order_id), f"{dispatch_no} {task_summary}")
    flash(f"服务单已派工：{dispatch_no}。", "success")
    return redirect(f"/service-orders/{order_id}")


def _handle_service_order(order_id):
    service = _service_order_or_redirect(order_id)
    if not service:
        return redirect(f"/service-orders/{order_id}")
    check_item = _form_text("check_item", "现场检查")
    result = _form_text("result", "已完成")
    solution = _form_text("solution") or service.get("solution")
    fault_cause = _form_text("fault_cause") or service.get("fault_cause")
    prevention_action = _form_text("prevention_action") or service.get("prevention_action")
    execution_note = _form_text("execution_note")
    labor_cost = _form_decimal("labor_cost", service.get("labor_cost") or "0")
    travel_cost = _form_decimal("travel_cost", service.get("travel_cost") or "0")
    parts_cost = _form_decimal("parts_cost", service.get("parts_cost") or "0")
    total_cost = labor_cost + travel_cost + parts_cost
    _execute_db(
        """
        INSERT INTO machine_service_order_checklists (
            order_id, wo_id, service_card_id, check_item, result, remark, created_by
        )
        VALUES (%s, %s, %s, %s, %s, %s, %s)
        """,
        (
            order_id,
            service.get("wo_id") or None,
            service.get("service_card_id"),
            check_item,
            result,
            execution_note,
            session.get("user_id"),
        ),
    )
    _execute_db(
        """
        UPDATE machine_service_orders
        SET status=%s, solution=%s, fault_cause=%s, prevention_action=%s,
            execution_note=%s, labor_cost=%s, travel_cost=%s, parts_cost=%s,
            total_cost=%s, checkout_at=COALESCE(checkout_at, NOW())
        WHERE id=%s
        """,
        ("处理中", solution, fault_cause, prevention_action, execution_note, labor_cost, travel_cost, parts_cost, total_cost, order_id),
    )
    _sync_service_order_flow(order_id, "处理中")
    _execute_db(
        """
        INSERT INTO machine_service_logs (
            service_card_id, service_date, service_type, performed_by, status,
            issue_summary, solution, remark
        )
        VALUES (%s, %s, %s, %s, %s, %s, %s, %s)
        """,
        (
            service.get("service_card_id"),
            datetime.now().date().isoformat(),
            service.get("service_type") or "售后服务",
            service.get("performed_by"),
            "处理中",
            service.get("issue_summary"),
            solution,
            execution_note,
        ),
    )
    _log_action("服务处理", service.get("order_no") or str(order_id), check_item)
    flash("服务处理已记录。", "success")
    return redirect(f"/service-orders/{order_id}")


def _issue_service_order_part(order_id):
    service = _service_order_or_redirect(order_id)
    if not service:
        return redirect(f"/service-orders/{order_id}")
    product_ids = request.form.getlist("product_id[]")
    if product_ids:
        quantities = request.form.getlist("quantity[]")
        unit_costs = request.form.getlist("unit_cost[]")
        lot_nos = request.form.getlist("lot_no[]")
        remarks = request.form.getlist("remark[]")
        source_line_nos = request.form.getlist("source_line_no[]")
        line_warehouse_ids = request.form.getlist("line_warehouse_id[]")
        line_location_ids = request.form.getlist("line_location_id[]")
        warehouse_id = _form_int("warehouse_id")
        location_id = _form_int("location_id")
        created = 0
        total_amount = Decimal("0")
        stock_requirements = {}
        for idx, product_id_value in enumerate(product_ids):
            product_id = _as_int(product_id_value)
            quantity = _as_decimal(quantities[idx] if idx < len(quantities) else "0")
            if not product_id or quantity <= 0:
                continue
            line_warehouse_id = _as_int(line_warehouse_ids[idx]) if idx < len(line_warehouse_ids) else 0
            line_location_id = _as_int(line_location_ids[idx]) if idx < len(line_location_ids) else 0
            actual_warehouse_id = line_warehouse_id or warehouse_id or _ensure_default_warehouse_id()
            actual_location_id = line_location_id or location_id
            lot_no = lot_nos[idx] if idx < len(lot_nos) else ""
            key = (product_id, actual_warehouse_id, actual_location_id, lot_no)
            stock_requirements[key] = stock_requirements.get(key, Decimal("0")) + quantity
        for product_id, actual_warehouse_id, actual_location_id, lot_no in stock_requirements:
            stock_error = _service_part_issue_stock_error(
                product_id,
                stock_requirements[(product_id, actual_warehouse_id, actual_location_id, lot_no)],
                actual_warehouse_id,
                actual_location_id,
                lot_no,
                service,
            )
            if stock_error:
                flash(stock_error, "warning")
                return redirect(f"/service-orders/{order_id}")
        for idx, product_id_value in enumerate(product_ids):
            product_id = _as_int(product_id_value)
            quantity = _as_decimal(quantities[idx] if idx < len(quantities) else "0")
            if not product_id or quantity <= 0:
                continue
            unit_cost = _as_decimal(unit_costs[idx] if idx < len(unit_costs) else "0")
            if unit_cost <= 0:
                product = _safe_one("SELECT standard_price FROM products WHERE id=%s", (product_id,))
                unit_cost = _as_decimal(product.get("standard_price")) if product else Decimal("0")
            lot_no = lot_nos[idx] if idx < len(lot_nos) else ""
            remark = remarks[idx] if idx < len(remarks) else _form_text("remark")
            line_warehouse_id = _as_int(line_warehouse_ids[idx]) if idx < len(line_warehouse_ids) else 0
            line_location_id = _as_int(line_location_ids[idx]) if idx < len(line_location_ids) else 0
            actual_warehouse_id = line_warehouse_id or warehouse_id
            actual_location_id = line_location_id or location_id
            source_line_no = source_line_nos[idx] if idx < len(source_line_nos) else ""
            snapshot = _inventory_product_snapshot(product_id)
            amount = quantity * unit_cost
            total_amount += amount
            _execute_db(
                """
                INSERT INTO machine_service_order_items (
                    order_id, product_id, quantity, unit_cost, amount, warehouse_id, location_id,
                    lot_no, serial_no, project_code, source_line_no,
                    material_code, material_name, material_spec, material_unit, spec, unit, remark
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
                """,
                (
                    order_id,
                    product_id,
                    quantity,
                    unit_cost,
                    amount,
                    actual_warehouse_id,
                    actual_location_id,
                    lot_no,
                    service.get("serial_no") or "",
                    service.get("project_code") or "",
                    source_line_no,
                    snapshot["material_code"],
                    snapshot["material_name"],
                    snapshot["material_spec"],
                    snapshot["material_unit"],
                    snapshot["material_spec"],
                    snapshot["material_unit"],
                    remark,
                ),
            )
            _apply_inventory_movement(
                product_id,
                -quantity,
                unit_cost,
                "售后备件出库",
                service.get("order_no") or str(order_id),
                remark,
                warehouse_id=actual_warehouse_id,
                location_id=actual_location_id,
                lot_no=lot_no,
                serial_no=service.get("serial_no") or "",
                project_code=service.get("project_code") or "",
            )
            created += 1
        if not created:
            flash("请录入有效的备件出库明细。", "warning")
            return redirect(f"/service-orders/{order_id}")
        service_cost = _safe_one(
            """
            SELECT COALESCE(SUM(amount),0) AS parts_cost
            FROM machine_service_order_items
            WHERE order_id=%s
            """,
            (order_id,),
        )
        parts_cost = _as_decimal(service_cost.get("parts_cost")) if service_cost else total_amount
        total_cost = _as_decimal(service.get("labor_cost")) + _as_decimal(service.get("travel_cost")) + parts_cost
        _execute_db(
            """
            UPDATE machine_service_orders
            SET parts_cost=%s, total_cost=%s,
                status=CASE WHEN status IN ('已派工','待处理') THEN '处理中' ELSE status END
            WHERE id=%s
            """,
            (parts_cost, total_cost, order_id),
        )
        _sync_service_order_flow(order_id, "处理中")
        _save_document_custom_payload("service_order_part", order_id)
        _log_action("售后备件出库", service.get("order_no") or str(order_id), f"lines={created}")
        flash(f"已出库售后备件 {created} 行。", "success")
        return redirect(f"/service-orders/{order_id}")
    product_id = _form_int("product_id")
    quantity = _form_decimal("quantity")
    unit_cost = _form_decimal("unit_cost")
    warehouse_id = _form_int("warehouse_id")
    location_id = _form_int("location_id")
    lot_no = _form_text("lot_no")
    source_line_no = _form_text("source_line_no")
    remark = _form_text("remark")
    if not product_id or quantity <= 0:
        flash("请录入有效的备件出库明细。", "warning")
        return redirect(f"/service-orders/{order_id}")
    stock_error = _service_part_issue_stock_error(product_id, quantity, warehouse_id, location_id, lot_no, service)
    if stock_error:
        flash(stock_error, "warning")
        return redirect(f"/service-orders/{order_id}")
    if unit_cost <= 0:
        product = _safe_one("SELECT standard_price FROM products WHERE id=%s", (product_id,))
        unit_cost = _as_decimal(product.get("standard_price")) if product else Decimal("0")
    snapshot = _inventory_product_snapshot(product_id)
    amount = quantity * unit_cost
    _execute_db(
        """
        INSERT INTO machine_service_order_items (
            order_id, product_id, quantity, unit_cost, amount, warehouse_id, location_id,
            lot_no, serial_no, project_code, source_line_no,
            material_code, material_name, material_spec, material_unit, spec, unit, remark
        )
        VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
        """,
        (
            order_id,
            product_id,
            quantity,
            unit_cost,
            amount,
            warehouse_id,
            location_id,
            lot_no,
            service.get("serial_no") or "",
            service.get("project_code") or "",
            source_line_no,
            snapshot["material_code"],
            snapshot["material_name"],
            snapshot["material_spec"],
            snapshot["material_unit"],
            snapshot["material_spec"],
            snapshot["material_unit"],
            remark,
        ),
    )
    _apply_inventory_movement(
        product_id,
        -quantity,
        unit_cost,
        "售后备件出库",
        service.get("order_no") or str(order_id),
        remark,
        warehouse_id=warehouse_id,
        location_id=location_id,
        lot_no=lot_no,
        serial_no=service.get("serial_no") or "",
        project_code=service.get("project_code") or "",
    )
    service_cost = _safe_one(
        """
        SELECT COALESCE(SUM(amount),0) AS parts_cost
        FROM machine_service_order_items
        WHERE order_id=%s
        """,
        (order_id,),
    )
    parts_cost = _as_decimal(service_cost.get("parts_cost")) if service_cost else amount
    total_cost = _as_decimal(service.get("labor_cost")) + _as_decimal(service.get("travel_cost")) + parts_cost
    _execute_db(
        """
        UPDATE machine_service_orders
        SET parts_cost=%s, total_cost=%s,
            status=CASE WHEN status IN ('已派工','待处理') THEN '处理中' ELSE status END
        WHERE id=%s
        """,
        (parts_cost, total_cost, order_id),
    )
    _sync_service_order_flow(order_id, "处理中")
    _log_action("售后备件出库", service.get("order_no") or str(order_id), f"{product_id} x {quantity}")
    flash(f"已出库售后备件 {quantity}。", "success")
    return redirect(f"/service-orders/{order_id}")


def _create_rma_from_service_order(order_id):
    service = _service_order_or_redirect(order_id)
    if not service:
        return redirect(f"/service-orders/{order_id}")
    existing = _safe_one(
        """
        SELECT id, rma_no
        FROM machine_service_rmas
        WHERE order_id=%s AND COALESCE(status,'') NOT IN (%s,%s,'closed','completed','cancelled')
        ORDER BY id DESC LIMIT 1
        """,
        (order_id, "已关闭", "已完成"),
    )
    if existing:
        flash(f"已存在 RMA {existing.get('rma_no')}。", "info")
        return redirect(f"/service-rmas/{existing.get('id')}")
    rma_no = _next_daily_doc_no("RMA", "machine_service_rmas", "rma_no")
    rma_date = _form_text("rma_date", datetime.now().date().isoformat())
    warranty_scope = _short_text(_form_text("warranty_scope", "保内"), 20)
    responsibility_type = _short_text(_form_text("responsibility_type", "保内"), 20)
    return_factory_required = _form_bool("return_factory_required", True)
    fault_summary = _form_text("fault_summary") or service.get("issue_summary") or ""
    diagnosis = _form_text("diagnosis")
    remark = _form_text("remark")
    rma_item = _safe_one(
        """
        SELECT product_id, quantity, unit_cost, amount, warehouse_id, location_id, lot_no,
               source_line_no, material_code, material_name, material_spec, material_unit
        FROM machine_service_order_items
        WHERE order_id=%s
        ORDER BY id DESC
        LIMIT 1
        """,
        (order_id,),
    ) or {}
    new_rma = _execute_and_return(
        """
        INSERT INTO machine_service_rmas (
            rma_no, order_id, service_card_id, wo_id, rma_date,
            warranty_scope, responsibility_type, return_factory_required,
            status, internal_claim_amount, supplier_claim_amount,
            supplier_recovered_amount, claim_status, claim_note,
            fault_summary, diagnosis, remark, created_by,
            sales_order_id, cost_object_id, project_code, serial_no,
            product_id, quantity, unit_cost, amount, warehouse_id, location_id,
            lot_no, source_line_no, material_code, material_name, material_spec,
            material_unit, line_project_code, line_serial_no
        )
        VALUES (%s, %s, %s, %s, %s, %s, %s, %s,
                %s, 0, 0, 0, %s, %s,
                %s, %s, %s, %s, %s, %s, %s, %s,
                %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
        RETURNING id
        """,
        (
            rma_no,
            order_id,
            service.get("service_card_id"),
            service.get("wo_id"),
            rma_date,
            warranty_scope,
            responsibility_type,
            return_factory_required,
            "待处理",
            "未索赔",
            "",
            fault_summary,
            diagnosis,
            remark,
            session.get("user_id"),
            service.get("sales_order_id"),
            service.get("cost_object_id"),
            service.get("project_code"),
            service.get("serial_no"),
            rma_item.get("product_id"),
            _as_decimal(rma_item.get("quantity")),
            _as_decimal(rma_item.get("unit_cost")),
            _as_decimal(rma_item.get("amount")),
            rma_item.get("warehouse_id"),
            rma_item.get("location_id"),
            rma_item.get("lot_no") or "",
            rma_item.get("source_line_no") or "",
            rma_item.get("material_code") or "",
            rma_item.get("material_name") or "",
            rma_item.get("material_spec") or "",
            rma_item.get("material_unit") or "",
            service.get("project_code") or "",
            service.get("serial_no") or "",
        ),
    )
    rma_id = _returned_id(new_rma)
    _sync_rma_flow(rma_id, "待处理")
    _execute_db(
        """
        UPDATE machine_service_orders
        SET status=CASE WHEN status IN (%s,%s,'open') THEN %s ELSE status END
        WHERE id=%s
        """,
        ("已派工", "处理中", "RMA处理中", order_id),
    )
    _sync_service_order_flow(order_id, "RMA处理中")
    _log_action("生成 RMA", service.get("order_no") or str(order_id), rma_no)
    flash(f"已生成 RMA {rma_no}。", "success")
    return redirect(f"/service-rmas/{rma_id}")


