def _inventory_product_snapshot(product_id):
    row = _safe_one(
        "SELECT code, name, specification, unit FROM products WHERE id=%s",
        (product_id,),
    ) or {}
    return {
        "material_code": row.get("code") or "",
        "material_name": row.get("name") or "",
        "material_spec": row.get("specification") or "",
        "material_unit": row.get("unit") or "",
    }


def _inventory_available_qty(product_id, warehouse_id=None, location_id=None, lot_no="", serial_no="", project_code=""):
    row = _safe_one(
        """
        SELECT COALESCE(SUM(quantity),0) AS available_qty
        FROM inventory_balances
        WHERE product_id=%s
          AND (%s IS NULL OR warehouse_id=%s)
          AND (%s IS NULL OR location_id=%s)
          AND COALESCE(lot_no,'')=COALESCE(%s,'')
          AND COALESCE(serial_no,'')=COALESCE(%s,'')
          AND COALESCE(project_code,'')=COALESCE(%s,'')
        """,
        (product_id, warehouse_id, warehouse_id, location_id, location_id, lot_no, serial_no, project_code),
    ) or {}
    return _as_decimal(row.get("available_qty"))


def _inventory_movement_can_audit(lines, direction):
    if direction != "out":
        return True, ""
    for line in lines or []:
        product_id = line.get("product_id")
        qty = _as_decimal(line.get("quantity"))
        if not product_id or qty <= 0:
            continue
        available_qty = _inventory_available_qty(
            product_id,
            line.get("line_warehouse_id"),
            line.get("line_location_id"),
            line.get("lot_no") or "",
            line.get("serial_no") or "",
            line.get("project_code") or "",
        )
        if available_qty < qty:
            return False, f"库存不足：物料 {product_id} 可用 {available_qty}，需要 {qty}。"
    return True, ""


def _form_list_value(name, index, default=""):
    values = request.form.getlist(name)
    if index < len(values):
        return (values[index] or "").strip()
    return default


def _document_can_edit_status(status, pending_statuses=None):
    normalized = (status or "").strip()
    allowed = pending_statuses or {"", "draft", "pending", "新建", "草稿", "待过账", "待审核", "待派工", "待处理", "未索赔", "待收货", "待发料"}
    blocked = {"已审核", "audited", "已过账", "posted", "已关闭", "closed", "已完成", "completed", "已作废", "void", "voided", "cancelled", "已取消"}
    return normalized not in blocked and normalized in allowed


def _block_edit_if_inventory_posted(table, record_id, doc_no_field=None, source_type=None, return_url="/inventory"):
    order = _safe_one(f"SELECT * FROM {table} WHERE id=%s", (record_id,))
    if not order:
        flash("单据不存在。", "warning")
        return None
    if not _document_can_edit_status(order.get("status"), INVENTORY_PENDING_STATUSES):
        flash("单据已审核、已过账、已关闭、已作废或已取消，不能普通编辑。", "warning")
        return None
    if doc_no_field:
        doc_no = order.get(doc_no_field)
        if doc_no:
            tx = _safe_one(
                "SELECT id FROM stock_transactions WHERE reference_no=%s AND (%s IS NULL OR source_type=%s) LIMIT 1",
                (doc_no, source_type, source_type),
            )
            if tx:
                flash("单据已有库存流水，不能普通编辑。", "warning")
                return None
    return order


def _first_form_line(product_field="product_id[]", quantity_field="quantity[]", min_positive=True):
    product_ids = request.form.getlist(product_field)
    quantities = request.form.getlist(quantity_field)
    unit_costs = request.form.getlist("unit_cost[]") or request.form.getlist("unit_price[]")
    lot_nos = request.form.getlist("lot_no[]")
    serial_nos = request.form.getlist("serial_no[]")
    source_line_nos = request.form.getlist("source_line_no[]")
    project_codes = request.form.getlist("line_project_code[]")
    warehouses = request.form.getlist("warehouse[]")
    locations = request.form.getlist("location[]")
    remarks = request.form.getlist("remark[]")
    for idx, product_id_value in enumerate(product_ids):
        product_id = _as_int(product_id_value)
        quantity = _as_decimal(quantities[idx] if idx < len(quantities) else "0")
        if not product_id:
            continue
        if min_positive and quantity <= 0:
            continue
        if not min_positive and quantity == 0:
            continue
        return {
            "index": idx,
            "product_id": product_id,
            "quantity": quantity,
            "unit_cost": _as_decimal(unit_costs[idx] if idx < len(unit_costs) else "0"),
            "lot_no": lot_nos[idx] if idx < len(lot_nos) else "",
            "serial_no": serial_nos[idx] if idx < len(serial_nos) else "",
            "source_line_no": source_line_nos[idx] if idx < len(source_line_nos) else "",
            "project_code": project_codes[idx] if idx < len(project_codes) else "",
            "warehouse": warehouses[idx] if idx < len(warehouses) else "",
            "location": locations[idx] if idx < len(locations) else "",
            "remark": remarks[idx] if idx < len(remarks) else "",
        }
    return None


def _inventory_form_lines(quantity_field="quantity"):
    rows = []
    product_ids = request.form.getlist("product_id[]")
    quantities = request.form.getlist(f"{quantity_field}[]") or request.form.getlist("line_quantity[]")
    for idx, product_id_value in enumerate(product_ids):
        product_id = _as_int(product_id_value)
        quantity = _as_decimal(quantities[idx] if idx < len(quantities) else "0")
        if not product_id or quantity == 0:
            continue
        rows.append({
            "product_id": product_id,
            "quantity": quantity,
            "unit_cost": _as_decimal(_form_list_value("unit_cost[]", idx, "0")),
            "amount": quantity * _as_decimal(_form_list_value("unit_cost[]", idx, "0")),
            "lot_no": _form_list_value("lot_no[]", idx),
            "serial_no": _form_list_value("serial_no[]", idx),
            "project_code": _form_list_value("line_project_code[]", idx),
            "source_line_no": _form_list_value("source_line_no[]", idx),
            "warehouse_id": _as_int(_form_list_value("line_warehouse_id[]", idx, "0")),
            "location_id": _as_int(_form_list_value("line_location_id[]", idx, "0")),
            "remark": _form_list_value("remark[]", idx),
        })
    return rows


def _ensure_stock_transaction_movement_columns():
    if not _has_table("stock_transactions"):
        return
    for ddl in (
        "ALTER TABLE stock_transactions ADD COLUMN IF NOT EXISTS source_type VARCHAR(80)",
        "ALTER TABLE stock_transactions ADD COLUMN IF NOT EXISTS source_doc_type VARCHAR(80)",
        "ALTER TABLE stock_transactions ADD COLUMN IF NOT EXISTS source_doc_no VARCHAR(120)",
        "ALTER TABLE stock_transactions ADD COLUMN IF NOT EXISTS source_line_no VARCHAR(80)",
        "ALTER TABLE stock_transactions ADD COLUMN IF NOT EXISTS usage_reason VARCHAR(240)",
        "ALTER TABLE stock_transactions ADD COLUMN IF NOT EXISTS amount NUMERIC(14,2) DEFAULT 0",
    ):
        _execute_db(ddl)


def _create_inventory_movement(direction):
    _ensure_stock_transaction_movement_columns()
    _ensure_inventory_movement_document_columns()
    return_type = (request.args.get("return_type") or "").strip()
    if return_type == "sales_return":
        tx_type = "销售退货入库"
        movement_kind = "sales_return"
    elif return_type == "purchase_return":
        tx_type = "采购退货出库"
        movement_kind = "purchase_return"
    else:
        tx_type = "其他入库" if direction == "in" else "其他出库"
        movement_kind = "other_inbound" if direction == "in" else "other_outbound"
    document_type = "other_inbound" if direction == "in" else "other_outbound"
    back_url = "/inventory/inbound" if direction == "in" else "/inventory/outbound"
    detail_url = f"{back_url}/{{doc_no}}"
    # Save writes only the header and lines. Audit posts inventory.
    use_draft_flow = True
    project_code = _form_text("project_code")
    project_header_error = _require_project_serial_values_or_redirect(project_code, "pending-line-check", back_url)
    if project_header_error:
        return project_header_error
    reference_no = _form_text("reference_no") or _next_doc_no("OI" if direction == "in" else "OO", "inventory_movement_documents", "doc_no")
    tx_date = _form_text("tx_date") or datetime.now().date().isoformat()
    remark = _form_text("remark")
    save_action = _form_text("save_action", "save")
    if save_action == "unaudit":
        flash("反审请在已审核单据详情页执行。", "warning")
        return redirect(back_url)
    product_ids = request.form.getlist("product_id[]") or [str(_form_int("product_id") or "")]
    quantities = request.form.getlist("quantity[]") or [str(_form_decimal("quantity"))]
    unit_costs = request.form.getlist("unit_cost[]") or [str(_form_decimal("unit_cost"))]
    lot_nos = request.form.getlist("lot_no[]") or [_form_text("lot_no")]
    serial_nos = request.form.getlist("serial_no[]") or [_form_text("serial_no")]
    line_warehouse_ids = request.form.getlist("line_warehouse_id[]")
    line_location_ids = request.form.getlist("line_location_id[]")
    warehouse_id = _as_int(line_warehouse_ids[0]) if line_warehouse_ids else _form_int("warehouse_id")
    header_location_id = _as_int(line_location_ids[0]) if line_location_ids else _form_int("location_id")
    if header_location_id and not _warehouse_has_locations(warehouse_id):
        header_location_id = 0
    header_location_error = _require_inventory_location_or_redirect(warehouse_id, header_location_id, back_url, "仓库")
    if header_location_error:
        return header_location_error
    # Insert the document header first so line rows can reference it. For return-type
    # variants the header is created with status='posted' immediately; for regular
    # other_inbound/other_outbound it starts as 'draft' and is promoted to 'posted'
    # by _audit_inventory_movement.
    initial_status = "draft" if use_draft_flow else "posted"
    _execute_db(
        """
        INSERT INTO inventory_movement_documents
            (doc_no, direction, movement_kind, transaction_type, tx_date,
             warehouse_id, location_id, project_code, remark, status,
             approval_status, created_at, updated_at)
        VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, 'not_required', NOW(), NOW())
        """,
        (reference_no, direction, movement_kind, tx_type, tx_date,
         warehouse_id, header_location_id, project_code, remark, initial_status),
    )
    header_row = _safe_one("SELECT id FROM inventory_movement_documents WHERE doc_no=%s", (reference_no,))
    doc_id = header_row.get("id") if header_row else None
    created = 0
    try:
        for idx, product_id_value in enumerate(product_ids):
            product_id = _as_int(product_id_value)
            entered_qty = _as_decimal(quantities[idx] if idx < len(quantities) else "0")
            if not product_id or entered_qty <= 0:
                continue
            line_warehouse_id = _as_int(_form_list_value("line_warehouse_id[]", idx, "0"))
            location_id = _as_int(_form_list_value("line_location_id[]", idx, "0"))
            line_location_error = _require_inventory_location_or_redirect(line_warehouse_id, location_id, back_url, "仓库")
            if line_location_error:
                _rollback_inventory_movement_draft(doc_id)
                return line_location_error
            line_project_code = _form_list_value("line_project_code[]", idx) or project_code
            unit_cost = _as_decimal(unit_costs[idx] if idx < len(unit_costs) else "0")
            cost = unit_cost
            qty = -entered_qty if direction == "out" else entered_qty
            amount = abs(qty) * cost
            usage_reason = _form_list_value("usage_reason[]", idx) or _form_list_value("line_usage[]", idx) or remark
            if direction == "out" and not use_draft_flow and not usage_reason:
                raise ValueError("其他出库每行必须填写用途/原因。")
            lot_no = lot_nos[idx] if idx < len(lot_nos) else ""
            serial_no = serial_nos[idx] if idx < len(serial_nos) else ""
            project_serial_error = _require_project_serial_values_or_redirect(line_project_code, serial_no, back_url)
            if project_serial_error:
                _rollback_inventory_movement_draft(doc_id)
                return project_serial_error
            if direction == "out" and not use_draft_flow:
                available_qty = _inventory_available_qty(product_id, line_warehouse_id, location_id, lot_no, serial_no, line_project_code)
                if available_qty < entered_qty:
                    raise ValueError(f"库存不足，可用 {available_qty}，需要 {entered_qty}。")
            # Persist the line in inventory_movement_lines. For draft flow this is
            # the only write; for return-type variants the audit step happens
            # inline below via _apply_inventory_movement.
            _execute_db(
                """
                INSERT INTO inventory_movement_lines
                    (doc_id, line_no, product_id, quantity, unit_cost, amount,
                     lot_no, serial_no, line_project_code, line_warehouse_id,
                     line_location_id, usage_reason, source_doc_no, source_line_no,
                     created_at)
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, NOW())
                """,
                (doc_id, idx + 1, product_id, entered_qty, unit_cost, amount,
                 lot_no, serial_no, line_project_code, line_warehouse_id, location_id,
                 usage_reason, _form_list_value("source_doc_no[]", idx),
                 _form_list_value("source_line_no[]", idx)),
            )
            if not use_draft_flow:
                _apply_inventory_movement(product_id, qty, unit_cost, tx_type, reference_no, usage_reason, line_warehouse_id, location_id, lot_no, serial_no, tx_date, line_project_code)
                _execute_db(
                    """
                    UPDATE stock_transactions
                    SET source_doc_type=%s, source_doc_no=%s, source_line_no=%s, usage_reason=%s, amount=%s
                    WHERE id=(SELECT id FROM stock_transactions WHERE reference_no=%s ORDER BY id DESC LIMIT 1)
                    """,
                    (document_type, reference_no, _form_list_value("source_line_no[]", idx), usage_reason, amount, reference_no),
                )
            created += 1
    except ValueError as exc:
        _rollback_inventory_movement_draft(doc_id)
        flash(str(exc), "warning")
        return redirect(back_url)
    if not created:
        _rollback_inventory_movement_draft(doc_id)
        flash("请录入至少一条有效明细，数量必须大于 0。", "warning")
        return redirect(back_url)
    if not use_draft_flow:
        first_transaction = _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s ORDER BY id LIMIT 1", (reference_no,))
        if first_transaction:
            _save_document_custom_payload(document_type, first_transaction.get("id"))
    _log_action(f"{tx_type}{'草稿保存' if use_draft_flow else '已过账'}", reference_no)
    if use_draft_flow:
        if save_action == "save_new":
            flash(f"{tx_type}已保存为草稿，共 {created} 行。", "success")
            return redirect(f"{back_url}/new")
        flash(f"{tx_type}已保存为草稿，共 {created} 行。请在详情页审核后过账。", "success")
        return redirect(detail_url.format(doc_no=reference_no))
    flash(f"{tx_type}已过账，共 {created} 行。", "success")
    return redirect("/inventory/detail")


def _ensure_inventory_movement_document_columns():
    """Idempotent no-op placeholder kept next to the create function so future
    schema additions on inventory_movement_documents / inventory_movement_lines
    have an obvious extension point. Schema is created by
    services/schema_migrations.py migration 20260628_001."""
    return None


def _rollback_inventory_movement_draft(doc_id):
    """Delete a half-saved draft document (header + lines via cascade) when
    validation fails mid-creation. Safe to call with doc_id=None or already
    deleted rows."""
    if not doc_id:
        return
    _execute_db("DELETE FROM inventory_movement_documents WHERE id=%s", (doc_id,))


def _audit_inventory_movement(doc_no):
    """Promote a draft inventory_movement_documents row to 'posted' by applying
    every line to stock_transactions and inventory_balances atomically. Used by
    the 详情页「审核」button on /inventory/inbound/<doc_no>/audit."""
    header = _safe_one(
        """
        SELECT id, direction, movement_kind, transaction_type, tx_date,
               warehouse_id, location_id, project_code, remark
        FROM inventory_movement_documents
        WHERE doc_no=%s
        """,
        (doc_no,),
    )
    if not header:
        flash("未找到该单据。", "warning")
        return redirect("/inventory/inbound")
    detail_base = "/inventory/outbound" if header.get("direction") == "out" else "/inventory/inbound"
    if header.get("status") not in (None, "", "draft", "待过账", "草稿"):
        flash(f"单据当前状态为「{header.get('status')}」，不能审核。", "warning")
        return redirect(f"{detail_base}/{doc_no}")
    lines = _safe_rows(
        """
        SELECT product_id, quantity, unit_cost, lot_no, serial_no,
               line_project_code, line_warehouse_id, line_location_id,
               usage_reason, source_doc_no, source_line_no
        FROM inventory_movement_lines
        WHERE doc_id=%s
        ORDER BY line_no
        """,
        (header.get("id"),),
    )
    if not lines:
        flash("单据没有明细行，无法审核。", "warning")
        return redirect(f"{detail_base}/{doc_no}")
    direction = header.get("direction")
    tx_type = header.get("transaction_type")
    reference_no = doc_no
    tx_date = header.get("tx_date")
    document_type = header.get("movement_kind") or ("other_inbound" if direction == "in" else "other_outbound")

    def operation(cursor):
        query_db, execute_db, _ = cursor_db_helpers(cursor)
        query_one = lambda sql, params=None: query_db(sql, params, one=True)
        # Re-read header FOR UPDATE to prevent concurrent audits.
        fresh = query_one(
            "SELECT status FROM inventory_movement_documents WHERE id=%s FOR UPDATE",
            (header.get("id"),),
        )
        if not fresh or fresh.get("status") not in (None, "", "draft", "待过账", "草稿"):
            raise ValueError("单据状态已变更，审核中止。")
        posted = 0
        for line in lines:
            product_id = line.get("product_id")
            entered_qty = _as_decimal(line.get("quantity"))
            if not product_id or entered_qty <= 0:
                continue
            qty = -entered_qty if direction == "out" else entered_qty
            unit_cost = _as_decimal(line.get("unit_cost"))
            usage_reason = line.get("usage_reason") or header.get("remark")
            line_warehouse_id = line.get("line_warehouse_id") or header.get("warehouse_id")
            location_id = line.get("line_location_id") or header.get("location_id")
            lot_no = line.get("lot_no") or ""
            serial_no = line.get("serial_no") or ""
            line_project_code = line.get("line_project_code") or header.get("project_code")
            if direction == "out":
                available_qty = _inventory_available_qty(product_id, line_warehouse_id, location_id, lot_no, serial_no, line_project_code)
                if available_qty < entered_qty:
                    raise ValueError(f"库存不足，可用 {available_qty}，需要 {entered_qty}。")
            _apply_inventory_movement(
                product_id, qty, unit_cost, tx_type, reference_no, usage_reason,
                line_warehouse_id, location_id, lot_no, serial_no, tx_date,
                line_project_code,
                query_one=query_one, execute_db_fn=execute_db,
            )
            execute_db(
                """
                UPDATE stock_transactions
                SET source_doc_type=%s, source_doc_no=%s, source_line_no=%s,
                    usage_reason=%s, amount=%s
                WHERE id=(SELECT id FROM stock_transactions
                          WHERE reference_no=%s ORDER BY id DESC LIMIT 1)
                """,
                (document_type, reference_no, line.get("source_line_no"),
                 usage_reason, abs(qty) * unit_cost, reference_no),
            )
            posted += 1
        if not posted:
            raise ValueError("没有可过账的明细行。")
        execute_db(
            """
            UPDATE inventory_movement_documents
            SET status='posted', audited_at=NOW(), audited_by=%s, updated_at=NOW()
            WHERE id=%s
            """,
            (session.get("user_id"), header.get("id")),
        )
        return posted

    try:
        posted_count = _run_registry_transaction(operation)
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(f"{detail_base}/{doc_no}")
    first_transaction = _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s ORDER BY id LIMIT 1", (reference_no,))
    if first_transaction:
        _save_document_custom_payload(document_type, first_transaction.get("id"))
    _log_action(f"{tx_type}审核过账", reference_no)
    flash(f"{tx_type}已审核过账，共 {posted_count} 行。", "success")
    return redirect(f"{detail_base}/{doc_no}")


def _unaudit_inventory_movement(doc_no):
    """Reverse a posted inventory_movement_documents row back to 'draft' by
    deleting the stock_transactions rows that were created at audit time and
    reversing the inventory_balances effect. Used by the 详情页「反审」button.
    Guarded by a downstream-impact check: if any later stock_transactions row
    references the same product/warehouse/lot/serial/project bucket, the unaudit
    is refused to avoid corrupting balances."""
    header = _safe_one(
        """
        SELECT id, direction, movement_kind, transaction_type, tx_date,
               warehouse_id, location_id, project_code, status
        FROM inventory_movement_documents
        WHERE doc_no=%s
        """,
        (doc_no,),
    )
    if not header:
        flash("未找到该单据。", "warning")
        return redirect("/inventory/inbound")
    detail_base = "/inventory/outbound" if header.get("direction") == "out" else "/inventory/inbound"
    if header.get("status") != "posted":
        flash(f"单据当前状态为「{header.get('status')}」，不能反审。", "warning")
        return redirect(f"{detail_base}/{doc_no}")
    doc_id = header.get("id")
    # Lock header to prevent concurrent unaudit/audit.
    fresh = _safe_one("SELECT status FROM inventory_movement_documents WHERE id=%s FOR UPDATE", (doc_id,))
    if not fresh or fresh.get("status") != "posted":
        flash("单据状态已变更，反审中止。", "warning")
        return redirect(f"{detail_base}/{doc_no}")
    # Load the stock_transactions rows that this audit produced. They are the
    # rows with matching reference_no and transaction_type that were created
    # at audit time.
    tx_rows = _safe_rows(
        """
        SELECT id, product_id, quantity, unit_cost, warehouse_id, location_id,
               lot_no, serial_no, project_code
        FROM stock_transactions
        WHERE reference_no=%s AND transaction_type=%s
        ORDER BY id
        """,
        (doc_no, header.get("transaction_type")),
    )
    if not tx_rows:
        flash("未找到该单据对应的库存流水，无法反审。", "warning")
        return redirect(f"{detail_base}/{doc_no}")

    def operation(cursor):
        query_db, execute_db, _ = cursor_db_helpers(cursor)
        query_one = lambda sql, params=None: query_db(sql, params, one=True)
        # Reverse every stock_transactions row against inventory_balances and
        # the legacy inventory table, then delete the rows themselves.
        for tx in tx_rows:
            later = query_one(
                """
                SELECT id, reference_no, transaction_type
                FROM stock_transactions
                WHERE id > %s
                  AND NOT (reference_no=%s AND transaction_type=%s)
                  AND product_id=%s
                  AND COALESCE(warehouse_id,0)=COALESCE(%s,0)
                  AND COALESCE(location_id,0)=COALESCE(%s,0)
                  AND COALESCE(lot_no,'')=COALESCE(%s,'')
                  AND COALESCE(serial_no,'')=COALESCE(%s,'')
                  AND COALESCE(project_code,'')=COALESCE(%s,'')
                ORDER BY id
                LIMIT 1
                """,
                (
                    tx.get("id"),
                    doc_no,
                    header.get("transaction_type"),
                    tx.get("product_id"),
                    tx.get("warehouse_id"),
                    tx.get("location_id"),
                    tx.get("lot_no") or "",
                    tx.get("serial_no") or "",
                    tx.get("project_code") or "",
                ),
            )
            if later:
                raise ValueError(
                    f"无法反审：该单据库存已被后续流水 {later.get('reference_no') or later.get('id')} 使用，请先处理后续单据。"
                )
            _reverse_inventory_movement_balance(
                product_id=tx.get("product_id"),
                signed_qty=_as_decimal(tx.get("quantity")),
                unit_cost=_as_decimal(tx.get("unit_cost")),
                warehouse_id=tx.get("warehouse_id"),
                location_id=tx.get("location_id"),
                lot_no=tx.get("lot_no") or "",
                serial_no=tx.get("serial_no") or "",
                project_code=tx.get("project_code") or "",
                query_one=query_one,
                execute_db_fn=execute_db,
            )
            execute_db("DELETE FROM stock_transactions WHERE id=%s", (tx.get("id"),))
        execute_db(
            """
            UPDATE inventory_movement_documents
            SET status='draft', audited_at=NULL, audited_by=NULL, updated_at=NOW()
            WHERE id=%s
            """,
            (doc_id,),
        )
        return True

    try:
        _run_registry_transaction(operation)
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(f"{detail_base}/{doc_no}")
    _log_action(f"{header.get('transaction_type')}反审回滚", doc_no)
    flash(f"{header.get('transaction_type')}已反审，库存已回滚到草稿状态。", "success")
    return redirect(f"{detail_base}/{doc_no}")


def _delete_inventory_movement_draft(doc_no):
    header = _safe_one(
        """
        SELECT id, direction, transaction_type, status
        FROM inventory_movement_documents
        WHERE doc_no=%s
        """,
        (doc_no,),
    )
    detail_base = "/inventory/outbound"
    if header and header.get("direction") != "out":
        detail_base = "/inventory/inbound"
    list_url = detail_base
    if not header:
        flash("未找到该单据。", "warning")
        return redirect("/inventory/inbound")
    if (header.get("status") or "").strip() == "posted":
        flash("已过账单据不能直接删除，请先反审。", "warning")
        return redirect(f"{detail_base}/{doc_no}")
    tx_count = _safe_one(
        "SELECT COUNT(*) AS count FROM stock_transactions WHERE reference_no=%s AND transaction_type=%s",
        (doc_no, header.get("transaction_type")),
    )
    if (tx_count or {}).get("count"):
        flash("该单据仍有关联库存流水，不能删除。", "warning")
        return redirect(f"{detail_base}/{doc_no}")
    _execute_db("DELETE FROM inventory_movement_documents WHERE id=%s", (header.get("id"),))
    _log_action(f"{header.get('transaction_type')}删除草稿", doc_no)
    flash(f"{header.get('transaction_type')}草稿已删除。", "success")
    return redirect(list_url)



def _inventory_copy_clean_text(value):
    text = str(value or "").strip()
    if not text or text.count("?") >= 3 or chr(0xFFFD) in text:
        return ""
    return text


def _copy_inventory_movement_document(doc_no):
    header = _safe_one(
        """
        SELECT id, direction, movement_kind, transaction_type, warehouse_id,
               location_id, project_code, remark
        FROM inventory_movement_documents
        WHERE doc_no=%s
        """,
        (doc_no,),
    )
    if not header:
        flash("未找到该单据。", "warning")
        return redirect("/inventory/inbound")
    direction = header.get("direction")
    detail_base = "/inventory/outbound" if direction == "out" else "/inventory/inbound"
    movement_kind = header.get("movement_kind")
    expected_kind = "other_outbound" if direction == "out" else "other_inbound"
    if movement_kind != expected_kind:
        flash("只有其他入库/其他出库单支持复制。", "warning")
        return redirect(f"{detail_base}/{doc_no}")
    lines = _safe_rows(
        """
        SELECT line_no, product_id, quantity, unit_cost, amount, lot_no, serial_no,
               line_project_code, line_warehouse_id, line_location_id,
               usage_reason, source_doc_no, source_line_no
        FROM inventory_movement_lines
        WHERE doc_id=%s
        ORDER BY line_no
        """,
        (header.get("id"),),
    )
    if not lines:
        flash("原单没有明细，不能复制。", "warning")
        return redirect(f"{detail_base}/{doc_no}")

    prefix = "OO" if direction == "out" else "OI"
    new_doc_no = _next_doc_no(prefix, "inventory_movement_documents", "doc_no")
    tx_date = datetime.now().date().isoformat()
    remark = _inventory_copy_clean_text(header.get("remark"))

    def operation(cursor):
        _query_one, _query_rows, execute_db, execute_and_return = _registry_transaction_callables(cursor)
        new_header = execute_and_return(
            """
            INSERT INTO inventory_movement_documents
                (doc_no, direction, movement_kind, transaction_type, tx_date,
                 warehouse_id, location_id, project_code, remark, status,
                 approval_status, created_at, updated_at)
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, 'draft',
                    'not_required', NOW(), NOW())
            RETURNING id
            """,
            (
                new_doc_no,
                direction,
                movement_kind,
                header.get("transaction_type"),
                tx_date,
                header.get("warehouse_id"),
                header.get("location_id"),
                header.get("project_code"),
                remark,
            ),
        )
        new_doc_id = new_header.get("id")
        for idx, line in enumerate(lines, start=1):
            execute_db(
                """
                INSERT INTO inventory_movement_lines
                    (doc_id, line_no, product_id, quantity, unit_cost, amount,
                     lot_no, serial_no, line_project_code, line_warehouse_id,
                     line_location_id, usage_reason, source_doc_no, source_line_no,
                     created_at)
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, NOW())
                """,
                (
                    new_doc_id,
                    idx,
                    line.get("product_id"),
                    line.get("quantity"),
                    line.get("unit_cost"),
                    line.get("amount"),
                    line.get("lot_no"),
                    line.get("serial_no"),
                    line.get("line_project_code"),
                    line.get("line_warehouse_id"),
                    line.get("line_location_id"),
                    _inventory_copy_clean_text(line.get("usage_reason")),
                    line.get("source_doc_no"),
                    line.get("source_line_no"),
                ),
            )
        return new_doc_no

    new_reference_no = _run_registry_transaction(operation)
    _log_action(f"{header.get('transaction_type')}复制单据", f"{doc_no} -> {new_reference_no}")
    flash(f"已复制为新草稿单据 {new_reference_no}，请检查后审核。", "success")
    return redirect(f"{detail_base}/{new_reference_no}")


_COPY_NOW = object()


def _copy_clean_business_value(column, value):
    if column in {"remark", "note", "usage_reason"}:
        return _inventory_copy_clean_text(value)
    return value


def _insert_copied_row(table, source, overrides=None, exclude=None, returning="id", execute_fn=None, execute_return_fn=None):
    overrides = overrides or {}
    exclude = set(exclude or ()) | {"id"}
    cols = []
    exprs = []
    params = []
    for row in _table_columns(table):
        col = row.get("column_name")
        if not col:
            continue
        if col in exclude:
            continue
        if col in overrides:
            value = overrides[col]
        elif col in source:
            value = _copy_clean_business_value(col, source.get(col))
        else:
            continue
        cols.append(col)
        if value is _COPY_NOW:
            exprs.append("NOW()")
        else:
            exprs.append("%s")
            params.append(value)
    sql = f"INSERT INTO {table} ({', '.join(cols)}) VALUES ({', '.join(exprs)})"
    if returning:
        sql += f" RETURNING {returning}"
        fn = execute_return_fn or _execute_and_return
        return fn(sql, tuple(params))
    fn = execute_fn or _execute_db
    fn(sql, tuple(params))
    return None


def _document_copy_excluded_fields():
    return {
        "created_at",
        "updated_at",
        "posted",
        "posted_at",
        "posted_by",
        "audited_at",
        "audited_by",
        "approved_at",
        "approved_by",
        "submitted_at",
        "submitted_by",
        "rejected_at",
        "rejected_by",
        "completed_at",
        "closed_at",
        "closed_by",
        "cancelled_at",
        "cancelled_by",
        "voided_at",
        "voided_by",
        "reverse_posted_at",
        "reverse_posted_by",
        "inventory_posted",
        "wo_complete_item_id",
    }


def _copy_child_rows(child_table, source_fk, source_id, target_fk, target_id, extra_overrides=None, execute_fn=None):
    child_columns = {row.get("column_name") for row in _table_columns(child_table)}
    if not child_columns or source_fk not in child_columns or target_fk not in child_columns:
        return 0
    rows = _safe_rows(f"SELECT * FROM {child_table} WHERE {source_fk}=%s ORDER BY id", (source_id,))
    for row in rows:
        overrides = dict(extra_overrides or {})
        overrides[target_fk] = target_id
        if "created_at" in _columns(child_table):
            overrides["created_at"] = _COPY_NOW
        _insert_copied_row(
            child_table,
            row,
            overrides=overrides,
            exclude={"id", source_fk, "created_at", "updated_at", "posted_qty"},
            returning=None,
            execute_fn=execute_fn,
        )
    return len(rows)


