def _copy_header_lines_document(config, record_id):
    order = _safe_one(f"SELECT * FROM {config['table']} WHERE id=%s", (record_id,))
    if not order:
        flash(f"{config['name']}不存在，不能复制。", "warning")
        return redirect(config["list_url"])
    lines = _safe_rows(f"SELECT * FROM {config['line_table']} WHERE {config['line_fk']}=%s ORDER BY id", (record_id,))
    if not lines:
        flash(f"原{config['name']}没有明细，不能复制。", "warning")
        return redirect(f"{config['detail_base']}/{record_id}")
    new_no = _next_doc_no(config["prefix"], config["table"], config["no_field"])

    def operation(cursor):
        _query_one, _query_rows, execute_db, execute_return = _registry_transaction_callables(cursor)
        overrides = {
            config["no_field"]: new_no,
            config["date_field"]: datetime.now().date().isoformat(),
            "status": INVENTORY_STATUS_PENDING,
            "created_at": _COPY_NOW,
        }
        if "created_by" in _columns(config["table"]):
            overrides["created_by"] = session.get("user_id") or order.get("created_by")
        if "approval_status" in _columns(config["table"]):
            overrides["approval_status"] = "not_required"
        new_doc = _insert_copied_row(config["table"], order, overrides=overrides, exclude=_document_copy_excluded_fields(), execute_return_fn=execute_return)
        new_id = new_doc.get("id")
        for line in lines:
            _insert_copied_row(config["line_table"], line, overrides={config["line_fk"]: new_id}, exclude={"id", config["line_fk"], "created_at", "updated_at", "posted_qty"}, returning=None, execute_fn=execute_db)
        return new_id

    new_id = _run_registry_transaction(operation)
    _log_action(f"复制{config['name']}", f"{order.get(config['no_field'])} -> {new_no}")
    flash(f"已复制为新草稿单据 {new_no}，请检查后审核。", "success")
    return redirect(f"{config['detail_base']}/{new_id}")


