def _post_inventory_adjustment(adjustment_id):
    _ensure_inventory_workflow_columns()
    order = _safe_one("SELECT * FROM inventory_adjustments WHERE id=%s", (adjustment_id,))
    if not order:
        flash("库存调整单不存在。", "warning")
        return redirect("/adjustments")
    adj_no = order.get("adj_no")
    status = order.get("status") or ""
    if status == INVENTORY_STATUS_POSTED:
        flash("库存调整单已过账，不能重复过账。", "info")
        return redirect(f"/adjustments/{adjustment_id}")
    if status not in INVENTORY_PENDING_STATUSES:
        flash(f"库存调整单状态为 {status or '-'}，不能过账。", "warning")
        return redirect(f"/adjustments/{adjustment_id}")
    try:
        # 二次确认防重：在过账前再读一次状态（数据库视角）
        fresh = _safe_one("SELECT status FROM inventory_adjustments WHERE id=%s FOR UPDATE", (adjustment_id,))
        if not fresh or fresh.get("status") == INVENTORY_STATUS_POSTED:
            flash("库存调整单已过账，不能重复过账。", "info")
            return redirect(f"/adjustments/{adjustment_id}")
        if _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s LIMIT 1", (adj_no,)):
            _execute_db("UPDATE inventory_adjustments SET status='已过账', posted_at=NOW(), posted_by=%s WHERE adj_no=%s", (session.get("user_id"), adj_no))
            _log_action("库存调整过账（恢复）", adj_no)
            return redirect(f"/adjustments/{adjustment_id}")
        for row in _safe_rows("SELECT * FROM inventory_adjustments WHERE adj_no=%s ORDER BY id", (adj_no,)):
            _validate_inventory_location_or_raise(row.get("warehouse_id"), row.get("location_id"), "仓库")
            _apply_inventory_movement(row.get("product_id"), row.get("diff_quantity"), row.get("unit_cost"), (f"库存调整 {row.get('adj_type')}" if (row.get('adj_type') or '').strip() and (row.get('adj_type') or '').strip() != '库存调整' else '库存调整'), adj_no, row.get("remark") or "", row.get("warehouse_id"), row.get("location_id"), row.get("lot_no") or "", row.get("serial_no") or row.get("reference_no") or "", row.get("adj_date"), row.get("project_code") or "")
        _execute_db("UPDATE inventory_adjustments SET status='已过账', posted_at=NOW(), posted_by=%s WHERE adj_no=%s", (session.get("user_id"), adj_no))
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(f"/adjustments/{adjustment_id}")
    _log_action("库存调整过账", adj_no)
    flash(f"库存调整单 {adj_no} 已过账。", "success")
    return redirect(f"/adjustments/{adjustment_id}")


def _unaudit_inventory_adjustment(adjustment_id):
    _ensure_inventory_workflow_columns()
    order = _safe_one("SELECT * FROM inventory_adjustments WHERE id=%s", (adjustment_id,))
    if not order:
        return redirect("/adjustments")
    if order.get("status") != INVENTORY_STATUS_POSTED:
        flash("只有已过账单据可以反审。", "warning")
        return redirect(f"/adjustments/{adjustment_id}")
    adj_no = order.get("adj_no")

    def operation(cursor):
        query_one, query_rows, execute_db, _ = _registry_transaction_callables(cursor)
        fresh = query_one("SELECT status FROM inventory_adjustments WHERE adj_no=%s FOR UPDATE", (adj_no,))
        if not fresh or fresh.get("status") != INVENTORY_STATUS_POSTED:
            raise ValueError("单据状态已变化，反审已停止。")
        reversed_count = _reverse_stock_transactions_for_reference(adj_no, query_rows=query_rows, query_one=query_one, execute_db_fn=execute_db)
        execute_db("UPDATE inventory_adjustments SET status=%s, posted_at=NULL, posted_by=NULL WHERE adj_no=%s", (INVENTORY_STATUS_PENDING, adj_no))
        return reversed_count

    try:
        reversed_count = _run_registry_transaction(operation)
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(f"/adjustments/{adjustment_id}")
    _log_action("inventory_adjustment_reverse_audit", adj_no)
    flash(f"反审完成，已回滚 {reversed_count} 条库存流水。", "success")
    return redirect(f"/adjustments/{adjustment_id}")


def _close_inventory_adjustment(adjustment_id):
    order = _safe_one("SELECT * FROM inventory_adjustments WHERE id=%s", (adjustment_id,))
    if not order:
        return redirect("/adjustments")
    status = order.get("status") or ""
    if status != "已过账":
        flash("只有已过账的库存调整单可以关闭。", "warning")
        return redirect(f"/adjustments/{adjustment_id}")
    _execute_db("UPDATE inventory_adjustments SET status='已关闭', closed_at=NOW(), closed_by=%s WHERE adj_no=%s", (session.get("user_id"), order.get("adj_no")))
    return redirect(f"/adjustments/{adjustment_id}")


def _cancel_inventory_adjustment(adjustment_id):
    order = _safe_one("SELECT * FROM inventory_adjustments WHERE id=%s", (adjustment_id,))
    if not order:
        return redirect("/adjustments")
    if not _inventory_cancel_allowed(order.get("status")):
        flash("只有待过账的库存调整单可以取消。", "warning")
        return redirect(f"/adjustments/{adjustment_id}")
    _execute_db("UPDATE inventory_adjustments SET status='已取消', cancelled_at=NOW(), cancelled_by=%s WHERE adj_no=%s", (session.get("user_id"), order.get("adj_no")))
    return redirect(f"/adjustments/{adjustment_id}")


def _delete_inventory_adjustment_draft(adjustment_id):
    order = _safe_one("SELECT * FROM inventory_adjustments WHERE id=%s", (adjustment_id,))
    if not order:
        flash("库存调整单不存在或已删除。", "warning")
        return redirect("/adjustments")
    adj_no = order.get("adj_no")
    if not _inventory_cancel_allowed(order.get("status")):
        flash("当前状态不能删除；已过账单据请先反审。", "warning")
        return redirect(f"/adjustments/{adjustment_id}")
    if _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s LIMIT 1", (adj_no,)):
        flash("该库存调整单已有库存流水，不能直接删除。", "warning")
        return redirect(f"/adjustments/{adjustment_id}")
    _execute_db("DELETE FROM inventory_adjustments WHERE adj_no=%s", (adj_no,))
    _log_action("删除库存调整单草稿", adj_no)
    flash(f"库存调整单 {adj_no} 已删除。", "success")
    return redirect("/adjustments")


def _normalize_transfer_line_locations(items, back_url):
    normalized_items = []
    for idx, item in enumerate(items, start=1):
        item = dict(item)
        from_warehouse_id = item.get("from_warehouse_id")
        to_warehouse_id = item.get("to_warehouse_id")
        from_location_id = item.get("from_location_id")
        to_location_id = item.get("to_location_id")
        for warehouse_id, location_id, label in (
            (from_warehouse_id, from_location_id, f"第{idx}行调出仓库"),
            (to_warehouse_id, to_location_id, f"第{idx}行调入仓库"),
        ):
            location_error = _require_inventory_location_or_redirect(warehouse_id, location_id, back_url, label)
            if location_error:
                return None, location_error
        if from_warehouse_id == to_warehouse_id and from_location_id == to_location_id:
            flash(f"第{idx}行调出仓库库位和调入仓库库位不能完全相同。", "warning")
            return None, redirect(back_url)
        if from_location_id and not _warehouse_has_locations(from_warehouse_id):
            item["from_location_id"] = 0
        if to_location_id and not _warehouse_has_locations(to_warehouse_id):
            item["to_location_id"] = 0
        normalized_items.append(item)
    return normalized_items, None


def _create_inventory_transfer():
    _ensure_inventory_workflow_columns()
    _ensure_transfer_item_table()
    back_url = "/transfers/new"
    save_action = _form_text("save_action", "save")
    if save_action == "unaudit":
        flash("反审请在已过账库存调拨单详情页执行。", "warning")
        return redirect(back_url)
    project_code = _form_text("project_code")
    project_header_error = _require_project_serial_values_or_redirect(project_code, "pending-line-check", back_url)
    if project_header_error:
        return project_header_error
    items = _transfer_form_items()
    if not items:
        flash("请录入至少一条有效的调拨明细。", "warning")
        return redirect(back_url)
    items, line_location_error = _normalize_transfer_line_locations(items, back_url)
    if line_location_error:
        return line_location_error
    header_item = items[0]
    from_warehouse_id = header_item.get("from_warehouse_id")
    to_warehouse_id = header_item.get("to_warehouse_id")
    from_location_id = header_item.get("from_location_id")
    to_location_id = header_item.get("to_location_id")
    transfer_no = _next_doc_no("TR", "transfer_orders", "transfer_no")
    transfer = _execute_and_return(
        """
        INSERT INTO transfer_orders
            (transfer_no, transfer_date, from_warehouse_id, to_warehouse_id, from_location_id, to_location_id,
             project_code, status, remark, created_by, completed_at)
        VALUES (%s,%s,%s,%s,%s,%s,%s,'待过账',%s,%s,NULL)
        RETURNING id
        """,
        (transfer_no, _form_text("transfer_date", datetime.now().date().isoformat()), from_warehouse_id, to_warehouse_id, from_location_id, to_location_id, project_code, _form_text("remark"), session.get("user_id")),
    )
    transfer_id = transfer.get("id")
    for item in items:
        project_serial_error = _require_project_serial_values_or_redirect(project_code, item["serial_no"], back_url)
        if project_serial_error:
            return project_serial_error
        item_project_code = item.get("line_project_code") or project_code
        _execute_db(
            """
            INSERT INTO transfer_order_items
                (transfer_id, product_id, quantity, lot_no, serial_no, unit_cost, amount,
                 from_warehouse_id, to_warehouse_id, from_location_id, to_location_id,
                 line_project_code, source_line_no, remark)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """,
            (transfer_id, item["product_id"], item["quantity"], item["lot_no"], item["serial_no"],
             item["unit_cost"], item["amount"], item.get("from_warehouse_id") or None, item.get("to_warehouse_id") or None,
             item.get("from_location_id"), item.get("to_location_id"),
             item_project_code, item.get("source_line_no"), item.get("remark") or _form_text("remark")),
        )
    _save_document_custom_payload("inventory_transfer", transfer_id)
    _log_action("库存调拨保存", transfer_no)
    flash(f"已保存库存调拨单 {transfer_no}，请复核后确认过账。", "success")
    return redirect(f"/transfers/{transfer_id}")


