def _close_inventory_check(check_id):
    order = _safe_one("SELECT * FROM inventory_check_orders WHERE id=%s", (check_id,))
    if not order:
        return redirect("/inventory_checks")
    if order.get("status") != "已过账":
        flash("只有已过账的库存盘点单可以关闭。", "warning")
        return redirect(f"/inventory_checks/{check_id}")
    _execute_db("UPDATE inventory_check_orders SET status='已关闭', closed_at=NOW(), closed_by=%s WHERE id=%s", (session.get("user_id"), check_id))
    return redirect(f"/inventory_checks/{check_id}")


def _cancel_inventory_check(check_id):
    order = _safe_one("SELECT * FROM inventory_check_orders WHERE id=%s", (check_id,))
    if not order:
        return redirect("/inventory_checks")
    if not _inventory_cancel_allowed(order.get("status")):
        flash("只有待过账的库存盘点单可以取消。", "warning")
        return redirect(f"/inventory_checks/{check_id}")
    _execute_db("UPDATE inventory_check_orders SET status='已取消', cancelled_at=NOW(), cancelled_by=%s WHERE id=%s", (session.get("user_id"), check_id))
    return redirect(f"/inventory_checks/{check_id}")


def _delete_inventory_check_draft(check_id):
    _ensure_inventory_check_item_table()
    order = _safe_one("SELECT * FROM inventory_check_orders WHERE id=%s", (check_id,))
    if not order:
        flash("库存盘点单不存在或已删除。", "warning")
        return redirect("/inventory_checks")
    check_no = order.get("check_no")
    if not _inventory_cancel_allowed(order.get("status")):
        flash("当前状态不能删除；已过账单据请先反审。", "warning")
        return redirect(f"/inventory_checks/{check_id}")
    if _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s LIMIT 1", (check_no,)):
        flash("该库存盘点单已有库存流水，不能直接删除。", "warning")
        return redirect(f"/inventory_checks/{check_id}")
    _execute_db("DELETE FROM inventory_check_order_items WHERE check_id=%s", (check_id,))
    _execute_db("DELETE FROM inventory_check_orders WHERE id=%s", (check_id,))
    _log_action("删除库存盘点单草稿", check_no)
    flash(f"库存盘点单 {check_no} 已删除。", "success")
    return redirect("/inventory_checks")


def _inventory_assembly_meta(doc_type):
    if doc_type == "disassembly":
        return {"doc_type": "disassembly", "prefix": "DA", "title": "库存拆卸单", "list_url": "/disassembly-orders", "new_url": "/disassembly-orders/new", "detail_base": "/disassembly-orders", "parent_label": "拆卸主件", "line_label": "拆卸后子件", "out_tx": "拆卸出库", "in_tx": "拆卸入库", "document_kind": "inventory_disassembly"}
    return {"doc_type": "assembly", "prefix": "AS", "title": "库存组装单", "list_url": "/assembly-orders", "new_url": "/assembly-orders/new", "detail_base": "/assembly-orders", "parent_label": "组装主件", "line_label": "组装子件", "out_tx": "组装领料出库", "in_tx": "组装入库", "document_kind": "inventory_assembly"}


def _ensure_inventory_assembly_tables():
    _execute_db(
        """
        CREATE TABLE IF NOT EXISTS inventory_assembly_orders (
            id SERIAL PRIMARY KEY,
            assembly_no VARCHAR(120) NOT NULL UNIQUE,
            doc_type VARCHAR(30) NOT NULL DEFAULT 'assembly',
            doc_date DATE NOT NULL DEFAULT CURRENT_DATE,
            warehouse_id INTEGER,
            location_id INTEGER,
            product_id INTEGER NOT NULL,
            quantity NUMERIC(14, 3) NOT NULL DEFAULT 0,
            unit_cost NUMERIC(14, 4) DEFAULT 0,
            lot_no VARCHAR(120),
            serial_no VARCHAR(120),
            project_code VARCHAR(120),
            status VARCHAR(80) NOT NULL DEFAULT '待过账',
            remark TEXT,
            created_by INTEGER,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            posted_at TIMESTAMP,
            posted_by INTEGER
        )
        """
    )
    _execute_db("ALTER TABLE inventory_assembly_orders ALTER COLUMN status SET DEFAULT '待过账'")
    for ddl in (
        "ALTER TABLE inventory_assembly_orders ADD COLUMN IF NOT EXISTS closed_at TIMESTAMP",
        "ALTER TABLE inventory_assembly_orders ADD COLUMN IF NOT EXISTS closed_by INTEGER",
        "ALTER TABLE inventory_assembly_orders ADD COLUMN IF NOT EXISTS cancelled_at TIMESTAMP",
        "ALTER TABLE inventory_assembly_orders ADD COLUMN IF NOT EXISTS cancelled_by INTEGER",
    ):
        _execute_db(ddl)
    _execute_db(
        """
        CREATE TABLE IF NOT EXISTS inventory_assembly_items (
            id SERIAL PRIMARY KEY,
            order_id INTEGER NOT NULL REFERENCES inventory_assembly_orders(id) ON DELETE CASCADE,
            product_id INTEGER NOT NULL,
            quantity NUMERIC(14, 3) NOT NULL DEFAULT 0,
            unit_cost NUMERIC(14, 4) DEFAULT 0,
            lot_no VARCHAR(120),
            serial_no VARCHAR(120),
            line_role VARCHAR(30) NOT NULL DEFAULT 'component',
            remark TEXT
        )
        """
    )
    for ddl in (
        "ALTER TABLE inventory_assembly_items ADD COLUMN IF NOT EXISTS source_line_no VARCHAR(80)",
        "ALTER TABLE inventory_assembly_items ADD COLUMN IF NOT EXISTS line_project_code VARCHAR(120)",
        "ALTER TABLE inventory_assembly_items ADD COLUMN IF NOT EXISTS line_warehouse_id INTEGER",
        "ALTER TABLE inventory_assembly_items ADD COLUMN IF NOT EXISTS line_location_id INTEGER",
        "ALTER TABLE inventory_assembly_items ADD COLUMN IF NOT EXISTS material_code VARCHAR(120)",
        "ALTER TABLE inventory_assembly_items ADD COLUMN IF NOT EXISTS material_name VARCHAR(255)",
        "ALTER TABLE inventory_assembly_items ADD COLUMN IF NOT EXISTS material_spec VARCHAR(255)",
        "ALTER TABLE inventory_assembly_items ADD COLUMN IF NOT EXISTS material_unit VARCHAR(80)",
        "ALTER TABLE inventory_assembly_items ADD COLUMN IF NOT EXISTS amount NUMERIC(14,2) DEFAULT 0",
    ):
        _execute_db(ddl)


def _render_inventory_assembly_form(doc_type="assembly", order=None, items=None, action_url=None, mode="new"):
    meta = _inventory_assembly_meta(doc_type)
    g.toolbar_extras = []
    bom_rows = _safe_rows(
        """
        SELECT b.product_id AS parent_product_id, bi.id AS bom_item_id, bi.product_id, bi.quantity,
               COALESCE(bi.loss_rate,0) AS loss_rate, p.standard_price AS unit_cost
        FROM boms b
        JOIN bom_items bi ON bi.bom_id=b.id
        LEFT JOIN products p ON p.id=bi.product_id
        WHERE COALESCE(b.status, '') NOT IN ('停用','inactive','disabled')
          AND COALESCE(bi.is_optional, FALSE)=FALSE
        ORDER BY b.product_id, bi.id
        LIMIT 5000
        """
    )
    return render_template("inventory_assembly_form.html", meta=meta, warehouses=_warehouse_options(), locations=_filter_clean_rows(_safe_rows("SELECT id, warehouse_id, code, name FROM locations WHERE COALESCE(is_active, TRUE)=TRUE ORDER BY code LIMIT 1000"), "code", "name"), product_options=_inventory_document_product_options(), bom_rows=bom_rows, order=order or {}, items=items or [], action_url=action_url or meta["new_url"], mode=mode)


def _create_inventory_assembly_document(doc_type="assembly"):
    _ensure_inventory_assembly_tables()
    meta = _inventory_assembly_meta(doc_type)
    save_action = _form_text("save_action", "save")
    if save_action == "unaudit":
        flash("反审请在已过账组装单详情页执行。", "warning")
        return redirect(meta["new_url"])
    project_code = _form_text("project_code")
    parent_serial_no = _form_text("serial_no")
    project_header_error = _require_project_serial_values_or_redirect(project_code, parent_serial_no, meta["new_url"])
    if project_header_error:
        return project_header_error
    warehouse_id = _form_int("warehouse_id")
    location_id = _form_int("location_id")
    if location_id and not _warehouse_has_locations(warehouse_id):
        location_id = 0
    location_error = _require_inventory_location_or_redirect(warehouse_id, location_id, meta["new_url"], meta["title"])
    if location_error:
        return location_error
    product_id = _form_int("product_id")
    quantity = _form_decimal("quantity")
    rows = [row for row in _inventory_form_lines("line_quantity") if row["quantity"] > 0]
    if not product_id or quantity <= 0 or not rows:
        flash(f"请录入{meta['parent_label']}和至少一条{meta['line_label']}。", "warning")
        return redirect(meta["new_url"])
    doc_no = _next_doc_no(meta["prefix"], "inventory_assembly_orders", "assembly_no")
    order = _execute_and_return(
        """
        INSERT INTO inventory_assembly_orders
            (assembly_no, doc_type, doc_date, warehouse_id, location_id, product_id,
             quantity, unit_cost, lot_no, serial_no, project_code, status, remark, created_by, posted_at, posted_by)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,'待过账',%s,%s,NULL,NULL)
        RETURNING id
        """,
        (doc_no, meta["doc_type"], _form_text("doc_date", datetime.now().date().isoformat()), warehouse_id, location_id, product_id, quantity, _form_decimal("unit_cost"), _form_text("lot_no"), parent_serial_no, project_code, _form_text("remark"), session.get("user_id")),
    )
    order_id = order.get("id")
    for row in rows:
        line_warehouse = row.get("warehouse_id") or warehouse_id
        line_location = row.get("location_id") or location_id
        if line_location and not _warehouse_has_locations(line_warehouse):
            line_location = 0
        _validate_inventory_location_or_raise(line_warehouse, line_location, meta["title"])
        project_serial_error = _require_project_serial_values_or_redirect(project_code, row["serial_no"], meta["new_url"])
        if project_serial_error:
            return project_serial_error
        snapshot = _inventory_product_snapshot(row["product_id"])
        _execute_db(
            """
            INSERT INTO inventory_assembly_items
                (order_id, product_id, quantity, unit_cost, lot_no, serial_no, line_role, remark,
                 source_line_no, line_project_code, line_warehouse_id, line_location_id,
                 material_code, material_name, material_spec, material_unit, amount)
            VALUES (%s,%s,%s,%s,%s,%s,'component',%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            """,
            (order_id, row["product_id"], row["quantity"], row["unit_cost"], row["lot_no"], row["serial_no"], row.get("remark") or _form_text("remark"), row.get("source_line_no") or "", row.get("project_code") or project_code, line_warehouse, line_location, snapshot["material_code"], snapshot["material_name"], snapshot["material_spec"], snapshot["material_unit"], row["quantity"] * row["unit_cost"]),
        )
    _save_document_custom_payload(meta["document_kind"], order_id)
    return redirect(f"{meta['detail_base']}/{order_id}")


def _edit_inventory_assembly_document(order_id, doc_type="assembly"):
    _ensure_inventory_assembly_tables()
    meta = _inventory_assembly_meta(doc_type)
    order = _safe_one("SELECT * FROM inventory_assembly_orders WHERE id=%s AND doc_type=%s", (order_id, meta["doc_type"]))
    if not order:
        flash(f"{meta['title']}不存在。", "warning")
        return redirect(meta["list_url"])
    if not _document_can_edit_status(order.get("status"), INVENTORY_PENDING_STATUSES):
        flash(f"{meta['title']}已审核、已过账、已关闭、已作废或已取消，不能普通编辑。", "warning")
        return redirect(f"{meta['detail_base']}/{order_id}")
    if _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s LIMIT 1", (order.get("assembly_no"),)):
        flash(f"{meta['title']}已有库存流水，不能普通编辑。", "warning")
        return redirect(f"{meta['detail_base']}/{order_id}")
    back_url = f"{meta['detail_base']}/{order_id}/edit"
    save_action = _form_text("save_action", "save")
    if save_action == "unaudit":
        flash("反审请在已过账组装单详情页执行。", "warning")
        return redirect(back_url)
    project_code = _form_text("project_code")
    parent_serial_no = _form_text("serial_no")
    project_header_error = _require_project_serial_values_or_redirect(project_code, parent_serial_no, back_url)
    if project_header_error:
        return project_header_error
    warehouse_id = _form_int("warehouse_id")
    location_id = _form_int("location_id")
    if location_id and not _warehouse_has_locations(warehouse_id):
        location_id = 0
    location_error = _require_inventory_location_or_redirect(warehouse_id, location_id, back_url, meta["title"])
    if location_error:
        return location_error
    product_id = _form_int("product_id")
    quantity = _form_decimal("quantity")
    rows = [row for row in _inventory_form_lines("line_quantity") if row["quantity"] > 0]
    if not product_id or quantity <= 0 or not rows:
        flash(f"请录入{meta['parent_label']}和至少一条{meta['line_label']}。", "warning")
        return redirect(back_url)
    try:
        for row in rows:
            line_warehouse = row.get("warehouse_id") or warehouse_id
            line_location = row.get("location_id") or location_id
            if line_location and not _warehouse_has_locations(line_warehouse):
                line_location = 0
            _validate_inventory_location_or_raise(line_warehouse, line_location, meta["title"])
            project_serial_error = _require_project_serial_values_or_redirect(project_code, row["serial_no"], back_url)
            if project_serial_error:
                return project_serial_error
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(back_url)
    def operation(_cursor):
        _execute_db(
            """
            UPDATE inventory_assembly_orders
            SET doc_date=%s, warehouse_id=%s, location_id=%s, product_id=%s,
                quantity=%s, unit_cost=%s, lot_no=%s, serial_no=%s, project_code=%s, remark=%s
            WHERE id=%s
            """,
            (_form_text("doc_date", datetime.now().date().isoformat()), warehouse_id, location_id, product_id, quantity, _form_decimal("unit_cost"), _form_text("lot_no"), parent_serial_no, project_code, _form_text("remark"), order_id),
        )
        _execute_db("DELETE FROM inventory_assembly_items WHERE order_id=%s", (order_id,))
        for row in rows:
            line_warehouse = row.get("warehouse_id") or warehouse_id
            line_location = row.get("location_id") or location_id
            if line_location and not _warehouse_has_locations(line_warehouse):
                line_location = 0
            snapshot = _inventory_product_snapshot(row["product_id"])
            _execute_db(
                """
                INSERT INTO inventory_assembly_items
                    (order_id, product_id, quantity, unit_cost, lot_no, serial_no, line_role, remark,
                     source_line_no, line_project_code, line_warehouse_id, line_location_id,
                     material_code, material_name, material_spec, material_unit, amount)
                VALUES (%s,%s,%s,%s,%s,%s,'component',%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                """,
                (order_id, row["product_id"], row["quantity"], row["unit_cost"], row["lot_no"], row["serial_no"], row.get("remark") or _form_text("remark"), row.get("source_line_no") or "", row.get("project_code") or project_code, line_warehouse, line_location, snapshot["material_code"], snapshot["material_name"], snapshot["material_spec"], snapshot["material_unit"], row["quantity"] * row["unit_cost"]),
            )

    _run_registry_transaction(operation)
    _log_action(f"编辑{meta['title']}", order.get("assembly_no") or str(order_id))
    flash(f"{meta['title']}已保存，尚未过账。", "success")
    return redirect(f"{meta['detail_base']}/{order_id}")


def _post_inventory_assembly_document(order_id, doc_type="assembly"):
    _ensure_inventory_assembly_tables()
    meta = _inventory_assembly_meta(doc_type)
    order = _safe_one("SELECT * FROM inventory_assembly_orders WHERE id=%s AND doc_type=%s", (order_id, meta["doc_type"]))
    if not order:
        return redirect(meta["list_url"])
    status = order.get("status") or ""
    if status == INVENTORY_STATUS_POSTED:
        flash(f"{meta['title']}已过账，不能重复过账。", "info")
        return redirect(f"{meta['detail_base']}/{order_id}")
    if status not in INVENTORY_PENDING_STATUSES:
        flash(f"{meta['title']}状态为 {status or '-'}，不能过账。", "warning")
        return redirect(f"{meta['detail_base']}/{order_id}")
    try:
        def operation(cursor):
            query_db, execute_db, _ = cursor_db_helpers(cursor)
            query_one = lambda sql, params=None: query_db(sql, params, one=True)
            # Concurrency contract marker: SELECT status FROM inventory_assembly_orders WHERE id=%s AND doc_type=%s FOR UPDATE
            fresh = query_one("SELECT * FROM inventory_assembly_orders WHERE id=%s AND doc_type=%s FOR UPDATE", (order_id, meta["doc_type"]))
            if not fresh or fresh.get("status") == INVENTORY_STATUS_POSTED:
                return "already_posted"
            reference_no = fresh.get("assembly_no")
            if query_one("SELECT id FROM stock_transactions WHERE reference_no=%s LIMIT 1", (reference_no,)):
                execute_db(
                    "UPDATE inventory_assembly_orders SET status=%s, posted_at=NOW(), posted_by=%s WHERE id=%s",
                    (INVENTORY_STATUS_POSTED, session.get("user_id"), order_id),
                )
                return "already_posted"
            _validate_inventory_location_or_raise(fresh.get("warehouse_id"), fresh.get("location_id"), meta["title"])
            for item in query_db("SELECT * FROM inventory_assembly_items WHERE order_id=%s ORDER BY id", (order_id,)):
                line_warehouse = item.get("line_warehouse_id") or fresh.get("warehouse_id")
                line_location = item.get("line_location_id") or fresh.get("location_id")
                if line_location and not _warehouse_has_locations(line_warehouse):
                    line_location = 0
                _validate_inventory_location_or_raise(line_warehouse, line_location, meta["title"])
                qty = _as_decimal(item.get("quantity"))
                move_qty = qty if doc_type == "disassembly" else -qty
                tx_type = meta["in_tx"] if doc_type == "disassembly" else meta["out_tx"]
                _apply_inventory_movement(item.get("product_id"), move_qty, item.get("unit_cost"), tx_type, reference_no, item.get("remark") or fresh.get("remark") or "", line_warehouse, line_location, item.get("lot_no") or "", item.get("serial_no") or "", fresh.get("doc_date"), item.get("line_project_code") or fresh.get("project_code") or "", query_one=query_one, execute_db_fn=execute_db)
            parent_qty = -_as_decimal(fresh.get("quantity")) if doc_type == "disassembly" else _as_decimal(fresh.get("quantity"))
            parent_tx = meta["out_tx"] if doc_type == "disassembly" else meta["in_tx"]
            parent_location = fresh.get("location_id")
            if parent_location and not _warehouse_has_locations(fresh.get("warehouse_id")):
                parent_location = 0
            _apply_inventory_movement(fresh.get("product_id"), parent_qty, fresh.get("unit_cost"), parent_tx, reference_no, fresh.get("remark") or "", fresh.get("warehouse_id"), parent_location, fresh.get("lot_no") or "", fresh.get("serial_no") or "", fresh.get("doc_date"), fresh.get("project_code") or "", query_one=query_one, execute_db_fn=execute_db)
            execute_db(
                "UPDATE inventory_assembly_orders SET status=%s, posted_at=NOW(), posted_by=%s WHERE id=%s",
                (INVENTORY_STATUS_POSTED, session.get("user_id"), order_id),
            )
            return "posted"

        result = current_app.extensions["run_in_transaction"](operation)
        if result == "already_posted":
            flash(f"{meta['title']}已过账，不能重复过账。", "info")
        return redirect(f"{meta['detail_base']}/{order_id}")
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(f"{meta['detail_base']}/{order_id}")


def _unaudit_inventory_assembly_document(order_id, doc_type="assembly"):
    _ensure_inventory_assembly_tables()
    meta = _inventory_assembly_meta(doc_type)
    order = _safe_one("SELECT * FROM inventory_assembly_orders WHERE id=%s AND doc_type=%s", (order_id, meta["doc_type"]))
    if not order:
        return redirect(meta["list_url"])
    if order.get("status") != INVENTORY_STATUS_POSTED:
        flash("只有已过账单据可以反审。", "warning")
        return redirect(f"{meta['detail_base']}/{order_id}")
    assembly_no = order.get("assembly_no")

    def operation(cursor):
        query_one, query_rows, execute_db, _ = _registry_transaction_callables(cursor)
        fresh = query_one("SELECT status FROM inventory_assembly_orders WHERE id=%s AND doc_type=%s FOR UPDATE", (order_id, meta["doc_type"]))
        if not fresh or fresh.get("status") != INVENTORY_STATUS_POSTED:
            raise ValueError("单据状态已变化，反审已停止。")
        reversed_count = _reverse_stock_transactions_for_reference(assembly_no, query_rows=query_rows, query_one=query_one, execute_db_fn=execute_db)
        execute_db("UPDATE inventory_assembly_orders SET status=%s, posted_at=NULL, posted_by=NULL WHERE id=%s", (INVENTORY_STATUS_PENDING, order_id))
        return reversed_count

    try:
        reversed_count = _run_registry_transaction(operation)
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(f"{meta['detail_base']}/{order_id}")
    _log_action(f"{meta['doc_type']}_reverse_audit", assembly_no)
    flash(f"反审完成，已回滚 {reversed_count} 条库存流水。", "success")
    return redirect(f"{meta['detail_base']}/{order_id}")


