def _delete_inventory_assembly_draft(order_id, doc_type="assembly"):
    _ensure_inventory_assembly_tables()
    meta = _inventory_assembly_meta(doc_type)
    order = _safe_one("SELECT * FROM inventory_assembly_orders WHERE id=%s AND doc_type=%s", (order_id, meta["doc_type"]))
    if not order:
        flash(f"{meta['title']}不存在或已删除。", "warning")
        return redirect(meta["list_url"])
    assembly_no = order.get("assembly_no")
    if not _inventory_cancel_allowed(order.get("status")):
        flash("当前状态不能删除；已过账单据请先反审。", "warning")
        return redirect(f"{meta['detail_base']}/{order_id}")
    if _safe_one("SELECT id FROM stock_transactions WHERE reference_no=%s LIMIT 1", (assembly_no,)):
        flash(f"该{meta['title']}已有库存流水，不能直接删除。", "warning")
        return redirect(f"{meta['detail_base']}/{order_id}")
    _execute_db("DELETE FROM inventory_assembly_items WHERE order_id=%s", (order_id,))
    _execute_db("DELETE FROM inventory_assembly_orders WHERE id=%s", (order_id,))
    _log_action(f"删除{meta['title']}草稿", assembly_no)
    flash(f"{meta['title']} {assembly_no} 已删除。", "success")
    return redirect(meta["list_url"])


def _inventory_bulk_actions(doc_type):
    return {
        "endpoint": "/inventory/bulk-action",
        "doc_type": doc_type,
        "return_url": request.path,
        "actions": [
            {"value": "post", "label": "批量确认过账", "class": "btn-outline-primary"},
            {"value": "close", "label": "批量关闭", "class": "btn-outline-secondary"},
            {"value": "cancel", "label": "批量取消", "class": "btn-outline-danger"},
            {"value": "print", "label": "批量打印/导出提示", "class": "btn-outline-info"},
        ],
    }


def _inventory_bulk_action_config(doc_type):
    return {
        "adjustment": {
            "post": _post_inventory_adjustment,
            "close": _close_inventory_adjustment,
            "cancel": _cancel_inventory_adjustment,
            "print_url": "/adjustments/{id}/print",
        },
        "transfer": {
            "post": _post_inventory_transfer,
            "close": _close_inventory_transfer,
            "cancel": _cancel_inventory_transfer,
            "print_url": "/transfers/{id}/print",
        },
        "check": {
            "post": _post_inventory_check,
            "close": _close_inventory_check,
            "cancel": _cancel_inventory_check,
            "print_url": "/inventory_checks/{id}/print",
        },
        "assembly": {
            "post": lambda record_id: _post_inventory_assembly_document(record_id, "assembly"),
            "close": lambda record_id: _close_inventory_assembly_document(record_id, "assembly"),
            "cancel": lambda record_id: _cancel_inventory_assembly_document(record_id, "assembly"),
            "print_url": "/assembly-orders/{id}/print",
        },
        "disassembly": {
            "post": lambda record_id: _post_inventory_assembly_document(record_id, "disassembly"),
            "close": lambda record_id: _close_inventory_assembly_document(record_id, "disassembly"),
            "cancel": lambda record_id: _cancel_inventory_assembly_document(record_id, "disassembly"),
            "print_url": "/disassembly-orders/{id}/print",
        },
        "sales_return": {
            "post": lambda record_id: _post_inventory_return("sales_returns", record_id, "sales"),
            "close": lambda record_id: _close_inventory_return("sales_returns", record_id, "sales"),
            "cancel": lambda record_id: _cancel_inventory_return("sales_returns", record_id, "sales"),
            "print_url": "/sales-returns/{id}/print",
        },
        "purchase_return": {
            "post": lambda record_id: _post_inventory_return("purchase_returns", record_id, "purchase"),
            "close": lambda record_id: _close_inventory_return("purchase_returns", record_id, "purchase"),
            "cancel": lambda record_id: _cancel_inventory_return("purchase_returns", record_id, "purchase"),
            "print_url": "/purchase-returns/{id}/print",
        },
    }.get(doc_type)


def _inventory_bulk_action():
    allowed_return_urls = {"/adjustments", "/transfers", "/inventory_checks", "/assembly-orders", "/disassembly-orders", "/sales-returns", "/purchase-returns"}
    doc_type = _form_text("doc_type")
    action = _form_text("action")
    return_url = _form_text("return_url") or "/inventory"
    if return_url not in allowed_return_urls:
        return_url = "/inventory"
    ids = [_as_int(value) for value in request.form.getlist("ids") if _as_int(value)]
    config = _inventory_bulk_action_config(doc_type)
    if not config or action not in {"post", "close", "cancel", "print"}:
        flash("批量操作类型无效。", "warning")
        return redirect(return_url)
    if not ids:
        flash("请先选择要批量处理的单据。", "warning")
        return redirect(return_url)
    if action == "print":
        flash("批量打印/导出提示：请逐张打开单据打印，或使用列表导出。", "info")
        return redirect(config["print_url"].format(id=ids[0]))
    for record_id in ids:
        config[action](record_id)
    flash(f"已提交 {len(ids)} 张单据的批量操作。", "success")
    return redirect(return_url)


def _render_inventory_assembly_list(doc_type="assembly"):
    _ensure_inventory_assembly_tables()
    meta = _inventory_assembly_meta(doc_type)
    rows = _safe_rows(
        """
        SELECT iao.id, iao.assembly_no, iao.doc_date, iao.project_code, iao.serial_no,
               iao.quantity, iao.status, p.name AS product_name, p.specification, p.unit, w.name AS warehouse_name,
               CASE WHEN iao.status='待过账' THEN '复核后确认过账'
                    WHEN iao.status='已过账' THEN '库存已更新，可关闭'
                    WHEN iao.status='已关闭' THEN '流程已完成'
                    WHEN iao.status='已取消' THEN '单据已取消'
                    ELSE '检查状态' END AS next_step
        FROM inventory_assembly_orders iao
        LEFT JOIN products p ON p.id=iao.product_id
        LEFT JOIN warehouses w ON w.id=iao.warehouse_id
        WHERE iao.doc_type=%s
        ORDER BY iao.doc_date DESC, iao.id DESC
        LIMIT 300
        """,
        (meta["doc_type"],),
    )
    return render_template("simple_list.html", title=f"{meta['title']}列表", subtitle="保存后待过账，确认过账后才写入库存流水。", rows=rows, columns=_columns(("assembly_no", meta["title"]), ("doc_date", "单据日期"), ("product_name", "物料名称"), ("specification", "规格"), ("unit", "单位"), ("quantity", "数量"), ("project_code", "项目号"), ("serial_no", "机号"), ("warehouse_name", "仓库"), ("status", "状态"), ("next_step", "下一步")), detail_base=meta["detail_base"], add_url=meta["new_url"], bulk_actions=_inventory_bulk_actions(meta["doc_type"]))


def _render_inventory_assembly_detail(order_id, doc_type="assembly"):
    _ensure_inventory_assembly_tables()
    meta = _inventory_assembly_meta(doc_type)
    order = _safe_one(
        """
        SELECT iao.*, p.code AS product_code, p.name AS product_name, p.specification, p.unit,
               w.name AS warehouse_name, l.code AS location_code, l.name AS location_name
        FROM inventory_assembly_orders iao
        LEFT JOIN products p ON p.id=iao.product_id
        LEFT JOIN warehouses w ON w.id=iao.warehouse_id
        LEFT JOIN locations l ON l.id=iao.location_id
        WHERE iao.id=%s AND iao.doc_type=%s
        """,
        (order_id, meta["doc_type"]),
    )
    if not order:
        return redirect(meta["list_url"])
    items = _safe_rows(
        """
        SELECT iai.*, p.code AS product_code, p.name AS product_name, p.specification, p.unit,
               COALESCE(pc.name, p.category, '') AS product_family
        FROM inventory_assembly_items iai
        LEFT JOIN products p ON p.id=iai.product_id
        LEFT JOIN product_categories pc ON pc.id=p.category_id
        WHERE iai.order_id=%s
        ORDER BY iai.id
        """,
        (order_id,),
    )
    transactions = _safe_rows(
        """
        SELECT st.*, p.code AS product_code, p.name AS product_name, w.name AS warehouse_name, l.code AS location_code
        FROM stock_transactions st
        LEFT JOIN products p ON p.id=st.product_id
        LEFT JOIN warehouses w ON w.id=st.warehouse_id
        LEFT JOIN locations l ON l.id=st.location_id
        WHERE st.reference_no=%s
        ORDER BY st.id
        """,
        (order.get("assembly_no"),),
    )
    return render_template(
        "inventory_assembly_detail.html",
        meta=meta,
        order=order,
        items=items,
        transactions=transactions,
        back_url=meta["list_url"],
        print_url=f"{meta['detail_base']}/{order_id}/print",
        action_prefix=meta["detail_base"],
        doc_kind=meta["document_kind"],
        attachments=_document_attachments(meta["document_kind"], order_id),
        activity_logs=_document_activity_logs(meta["document_kind"], order),
    )


def _render_inventory_assembly_detail_readonly(order_id, back_url="/assembly-orders"):
    return _render_inventory_assembly_detail(order_id, "assembly")


def _render_inventory_disassembly_detail(order_id, back_url="/disassembly-orders"):
    return _render_inventory_assembly_detail(order_id, "disassembly")


