    @app.post("/purchase_receipts/<int:receipt_id>/audit", endpoint="purchase_receipt_audit")
    @_login_required
    def purchase_receipt_audit(receipt_id):
        receipt = _safe_one("SELECT * FROM purchase_receipts WHERE id=%s", (receipt_id,))
        if not receipt:
            return redirect("/purchase_receipts")
        receipt_no = receipt.get("receipt_no")
        if not receipt_no:
            flash("Purchase receipt has no document number; audit stopped.", "warning")
            return redirect(f"/purchase_receipts/{receipt_id}")
        existing = _safe_one(
            "SELECT id FROM stock_transactions WHERE reference_no=%s LIMIT 1",
            (receipt_no,),
        )
        if existing:
            flash("Purchase receipt is already audited.", "info")
            return redirect(f"/purchase_receipts/{receipt_id}")
        lines = _safe_rows(
            """
            SELECT pri.*, p.current_cost, p.standard_price
            FROM purchase_receipt_items pri
            LEFT JOIN products p ON p.id=pri.product_id
            WHERE pri.receipt_id=%s
            ORDER BY pri.id
            """,
            (receipt_id,),
        )
        if not lines:
            flash("Purchase receipt has no lines.", "warning")
            return redirect(f"/purchase_receipts/{receipt_id}")
        receipt_amount = Decimal("0")
        for line in lines:
            qty = _as_decimal(line.get("quantity"))
            if qty <= 0:
                continue
            receipt_amount += _as_decimal(line.get("amount_with_tax"))
            unit_cost = _as_decimal(line.get("unit_cost") or line.get("current_cost") or line.get("standard_price"))
            _apply_inventory_movement(
                product_id=line.get("product_id"),
                quantity=qty,
                unit_cost=unit_cost,
                tx_type="采购入库",
                reference_no=receipt_no,
                remark=receipt.get("remark") or "采购入库",
                warehouse_id=line.get("warehouse_id") or receipt.get("warehouse_id"),
                location_id=line.get("location_id"),
                lot_no=line.get("lot_no") or "",
                serial_no=receipt.get("serial_no") or "",
                project_code=receipt.get("project_code") or "",
                tx_date=receipt.get("receipt_date"),
            )
            if line.get("order_item_id"):
                _execute_db(
                    """
                    UPDATE purchase_order_items
                    SET received_qty=COALESCE(received_qty,0)+%s
                    WHERE id=%s
                    """,
                    (qty, line.get("order_item_id")),
                )
        if receipt.get("order_id"):
            remaining = _safe_one(
                """
                SELECT COALESCE(SUM(GREATEST(COALESCE(quantity,0)-COALESCE(received_qty,0),0)), 0) AS pending_qty
                FROM purchase_order_items
                WHERE order_id=%s
                """,
                (receipt.get("order_id"),),
            ) or {}
            new_status = "已收货" if _as_decimal(remaining.get("pending_qty")) <= 0 else "部分收货"
            _execute_db(
                """
                UPDATE purchase_orders
                SET received_amount=COALESCE(received_amount,0)+%s, status=%s
                WHERE id=%s
                """,
                (receipt_amount, new_status, receipt.get("order_id")),
            )
        _execute_db("UPDATE purchase_receipts SET status=%s WHERE id=%s", (INVENTORY_STATUS_POSTED, receipt_id))
        _log_action("purchase_receipt_audit", receipt_no)
        flash("Purchase receipt audited.", "success")
        return redirect(f"/purchase_receipts/{receipt_id}")

