    @app.get("/purchase_request/<int:req_id>/print", endpoint="purchase_requisition_print")
    @_login_required
    def purchase_requisition_print(req_id):
        req = _safe_one(
            """
            SELECT pr.*, u.username AS requester_name
            FROM purchase_requisitions pr
            LEFT JOIN users u ON u.id=pr.requester_id
            WHERE pr.id=%s
            """,
            (req_id,),
        )
        if not req:
            flash("采购申请不存在。", "warning")
            return redirect("/purchase_request")
        req = dict(req)
        items = _safe_rows(
            """
            SELECT pri.*, p.code AS product_code, p.name AS product_name, p.specification,
                   COALESCE(p.unit, '') AS unit, s.name AS supplier_name
            FROM purchase_requisition_items pri
            LEFT JOIN products p ON p.id=pri.product_id
            LEFT JOIN suppliers s ON s.id=pri.suggested_supplier_id
            WHERE pri.req_id=%s
            ORDER BY pri.id
            """,
            (req_id,),
        )
        status_map = {
            "pending": "待提交", "draft": "待提交", "submitted": "已提交",
            "approved": "已审核", "completed": "已关闭", "closed": "已关闭",
            "void": "已作废", "cancelled": "已作废",
        }
        status_val = status_map.get((req.get("status") or "").strip(), req.get("status") or "")
        doc = {
            "title": "采购申请单",
            "subtitle": "物料需求申请",
            "number": req.get("req_no") or "",
            "number_label": "申请单号",
            "date": req.get("req_date") or req.get("created_at"),
            "date_label": "申请日期",
            "status_label": status_val,
            "info": [
                ("申请人", req.get("requester_name") or "-"),
                ("项目号", req.get("project_code") or "-"),
                ("机号", req.get("serial_no") or "-"),
                ("备注", req.get("remark") or "-"),
            ],
            "columns": [
                ("product_code", "物料编码", ""),
                ("product_name", "物料名称", ""),
                ("specification", "规格", ""),
                ("unit", "单位", "center"),
                ("quantity", "数量", "right"),
                ("need_date", "期望到货日期", "center"),
                ("supplier_name", "建议供应商", ""),
                ("remark", "备注", ""),
            ],
            "rows": [dict(row) for row in items],
            "total_quantity": sum(_as_decimal(row.get("quantity")) for row in items),
            "total_amount": None,
            "amount_label": None,
        }
        return render_template("document_print.html", doc=doc)

