    @app.get("/chart-of-accounts", endpoint="chart_of_accounts_list")
    @_login_required
    def chart_of_accounts_list():
        return _render_chart_of_accounts()

    @app.post("/chart-of-accounts/add", endpoint="chart_of_accounts_add")
    @_login_required
    def chart_of_accounts_add():
        code = (request.form.get("code") or "").strip()
        name = (request.form.get("name") or "").strip()
        if not code or not name:
            return jsonify({"ok": False, "error": "科目编码和名称必填。"})
        existing = _safe_one("SELECT id FROM chart_of_accounts WHERE code=%s", (code,))
        if existing:
            return jsonify({"ok": False, "error": f"科目编码 {code} 已存在。"})
        parent_id = request.form.get("parent_id") or None
        if parent_id:
            parent_id = int(parent_id)
        account_type = (request.form.get("account_type") or "资产类").strip()
        balance_direction = (request.form.get("balance_direction") or "借方").strip()
        is_leaf = request.form.get("is_leaf", "1") == "1"
        remark = (request.form.get("remark") or "").strip()
        try:
            row = _execute_and_return(
                """INSERT INTO chart_of_accounts (code, name, parent_id, account_type,
                   balance_direction, is_leaf, remark)
                   VALUES (%s,%s,%s,%s,%s,%s,%s) RETURNING id""",
                (code, name, parent_id, account_type, balance_direction, is_leaf, remark),
            )
            _log_action("新增会计科目", f"{code} {name}")
            new_id = row.get("id") if isinstance(row, dict) else (row[0] if row else None)
            return jsonify({"ok": True, "id": new_id})
        except Exception as e:
            return jsonify({"ok": False, "error": str(e)})

    @app.get("/chart-of-accounts/<int:account_id>/json", endpoint="chart_of_accounts_json")
    @_login_required
    def chart_of_accounts_json(account_id):
        acct = _safe_one("SELECT * FROM chart_of_accounts WHERE id=%s", (account_id,))
        if not acct:
            return jsonify({"error": "科目不存在。"})
        parent_accounts = _safe_rows(
            "SELECT id, code, name FROM chart_of_accounts WHERE status='active' AND is_leaf=FALSE AND id!=%s ORDER BY code",
            (account_id,),
        )
        return jsonify({"account": acct, "parent_accounts": parent_accounts})

    @app.post("/chart-of-accounts/<int:account_id>/edit", endpoint="chart_of_accounts_edit")
    @_login_required
    def chart_of_accounts_edit(account_id):
        acct = _safe_one("SELECT * FROM chart_of_accounts WHERE id=%s", (account_id,))
        if not acct:
            return jsonify({"ok": False, "error": "科目不存在。"})
        code = (request.form.get("code") or "").strip()
        name = (request.form.get("name") or "").strip()
        if not code or not name:
            return jsonify({"ok": False, "error": "科目编码和名称必填。"})
        dup = _safe_one("SELECT id FROM chart_of_accounts WHERE code=%s AND id!=%s", (code, account_id))
        if dup:
            return jsonify({"ok": False, "error": f"科目编码 {code} 已存在。"})
        parent_id = request.form.get("parent_id") or None
        if parent_id:
            parent_id = int(parent_id)
            if parent_id == account_id:
                return jsonify({"ok": False, "error": "上级科目不能选择自己。"})
        account_type = (request.form.get("account_type") or acct["account_type"]).strip()
        balance_direction = (request.form.get("balance_direction") or acct["balance_direction"]).strip()
        is_leaf = request.form.get("is_leaf", "0") == "1"
        status = (request.form.get("status") or "active").strip()
        remark = (request.form.get("remark") or "").strip()
        try:
            _execute_db(
                """UPDATE chart_of_accounts SET code=%s, name=%s, parent_id=%s, account_type=%s,
                   balance_direction=%s, is_leaf=%s, status=%s, remark=%s, updated_at=NOW()
                   WHERE id=%s""",
                (code, name, parent_id, account_type, balance_direction, is_leaf, status, remark, account_id),
            )
            _log_action("更新会计科目", f"{code} {name}")
            return jsonify({"ok": True})
        except Exception as e:
            return jsonify({"ok": False, "error": str(e)})

    @app.post("/chart-of-accounts/<int:account_id>/delete", endpoint="chart_of_accounts_delete")
    @_login_required
    def chart_of_accounts_delete(account_id):
        acct = _safe_one("SELECT * FROM chart_of_accounts WHERE id=%s", (account_id,))
        if not acct:
            return jsonify({"ok": False, "error": "科目不存在。"})
        children = _safe_one("SELECT COUNT(*) as cnt FROM chart_of_accounts WHERE parent_id=%s", (account_id,))
        if children and children.get("cnt", 0) > 0:
            return jsonify({"ok": False, "error": "该科目下存在子科目，不能删除。"})
        try:
            _execute_db("DELETE FROM chart_of_accounts WHERE id=%s", (account_id,))
            _log_action("删除会计科目", f"{acct['code']} {acct['name']}")
            return jsonify({"ok": True})
        except Exception as e:
            return jsonify({"ok": False, "error": str(e)})


